import { useState, useEffect } from 'react';
import { supabase } from '../../shared/lib/supabase';
import {
    Settings as SettingsIcon,
    Users as UsersIcon,
    Trash2,
    ShieldCheck,
    AlertTriangle
} from 'lucide-react';
import { useAuth } from '../../shared/hooks/useAuth';

interface Profile {
    id: string;
    full_name: string;
    email?: string;
    role: 'owner' | 'admin' | 'encoder';
    branch_id?: string;
    updated_at: string;
}

export default function Settings() {
    const { role, user } = useAuth();
    const [profiles, setProfiles] = useState<Profile[]>([]);
    const [loading, setLoading] = useState(true);
    const [confirmDelete, setConfirmDelete] = useState<string | null>(null);

    const fetchProfiles = async () => {
        setLoading(true);
        const { data, error } = await supabase.from('profiles').select('*').order('full_name');
        if (error) console.error('Error fetching profiles:', error);
        else setProfiles(data as Profile[] || []);
        setLoading(false);
    };

    useEffect(() => {
        fetchProfiles();
    }, []);

    const handleRoleChange = async (id: string, newRole: string) => {
        // Try RPC first (updates both profiles AND auth.users metadata)
        const { error: rpcError } = await supabase.rpc('update_user_role', {
            target_user_id: id,
            new_role: newRole
        });

        if (rpcError) {
            // Fallback: update profiles table directly
            console.warn('RPC not available, falling back to direct update:', rpcError.message);
            const { error } = await supabase.from('profiles').update({ role: newRole }).eq('id', id);
            if (error) {
                alert('Error updating role: ' + error.message);
                return;
            }
        }
        fetchProfiles();
    };

    const handleDeleteAccount = async (id: string, name: string) => {
        if (id === user?.id) {
            alert('You cannot delete your own account.');
            return;
        }
        if (!window.confirm(`Are you sure you want to remove "${name}"? This will permanently delete their account from the system.`)) return;

        // Try RPC first (deletes from both profiles AND auth.users)
        const { error: rpcError } = await supabase.rpc('delete_user_account', {
            target_user_id: id
        });

        if (rpcError) {
            // Fallback: delete from profiles only
            console.warn('RPC not available, falling back to direct delete:', rpcError.message);
            const { error } = await supabase.from('profiles').delete().eq('id', id);
            if (error) {
                alert('Error removing account: ' + error.message);
                return;
            }
        }
        setConfirmDelete(null);
        fetchProfiles();
    };

    const roleColors: Record<string, string> = {
        owner: 'bg-brand-red/10 text-brand-red border-brand-red/20',
        admin: 'bg-blue-500/10 text-blue-600 border-blue-500/20',
        encoder: 'bg-bg-subtle text-text-muted border-border-default'
    };

    return (
        <div className="space-y-6 animate-fade-in pb-12">
            <div className="flex items-center gap-3">
                <div className="w-11 h-11 bg-bg-surface rounded-[18px] flex items-center justify-center shadow-lg border border-border-default">
                    <SettingsIcon className="text-brand-red" size={24} />
                </div>
                <div>
                    <h1 className="text-xl font-black text-text-primary tracking-tight">Branch Management</h1>
                    <p className="text-[10px] font-black text-text-muted uppercase tracking-[0.2em]">Manage accounts, roles & access control</p>
                </div>
            </div>

            {/* User Access Table */}
            <div className="bg-bg-surface rounded-[24px] border border-border-default shadow-sm overflow-hidden">
                <div className="p-5 border-b border-border-default flex items-center justify-between bg-bg-subtle/30">
                    <h3 className="text-xs font-black text-text-primary uppercase tracking-widest flex items-center gap-2">
                        <UsersIcon size={14} className="text-brand-red" /> Registered Accounts
                    </h3>
                    <span className="px-3 py-1 bg-brand-red/10 text-brand-red text-[10px] font-black rounded-full uppercase tracking-widest border border-brand-red/20">
                        {profiles.length} accounts
                    </span>
                </div>
                <div className="overflow-x-auto">
                    <table className="min-w-full">
                        <thead>
                            <tr className="bg-bg-subtle/30 border-b border-border-default">
                                <th className="px-5 py-3 text-left text-[9px] font-black uppercase tracking-widest text-text-muted">User</th>
                                <th className="px-5 py-3 text-left text-[9px] font-black uppercase tracking-widest text-text-muted">Role</th>
                                <th className="px-5 py-3 text-center text-[9px] font-black uppercase tracking-widest text-text-muted">Change Role</th>
                                <th className="px-5 py-3 text-right text-[9px] font-black uppercase tracking-widest text-text-muted">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-border-default/30">
                            {loading ? (
                                [1, 2, 3].map(i => (
                                    <tr key={i}><td colSpan={4} className="px-5 py-4"><div className="h-12 skeleton rounded-xl" /></td></tr>
                                ))
                            ) : profiles.map((p) => {
                                const isCurrentUser = p.id === user?.id;
                                return (
                                    <tr key={p.id} className="hover:bg-bg-subtle/50 transition-colors group">
                                        <td className="px-5 py-3.5 whitespace-nowrap">
                                            <div className="flex items-center gap-3">
                                                <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-brand-red to-brand-red-dark flex items-center justify-center text-white text-xs font-black shadow-md">
                                                    {p.full_name?.charAt(0).toUpperCase() || '?'}
                                                </div>
                                                <div className="flex flex-col">
                                                    <span className="text-xs font-black text-text-primary flex items-center gap-1.5">
                                                        {p.full_name || 'Unknown'}
                                                        {isCurrentUser && <span className="text-[8px] font-black text-brand-red">(You)</span>}
                                                    </span>
                                                    <span className="text-[9px] text-text-muted font-data">{p.id.slice(0, 12)}...</span>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-5 py-3.5 whitespace-nowrap">
                                            <span className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${roleColors[p.role] || roleColors.encoder}`}>
                                                {p.role === 'owner' && <ShieldCheck size={10} />}
                                                {p.role}
                                            </span>
                                        </td>
                                        <td className="px-5 py-3.5 text-center whitespace-nowrap">
                                            {role === 'owner' && !isCurrentUser ? (
                                                <select
                                                    value={p.role}
                                                    onChange={(e) => handleRoleChange(p.id, e.target.value)}
                                                    className="bg-bg-subtle border border-border-default rounded-xl px-3 py-1.5 text-[10px] font-black text-text-primary uppercase tracking-widest cursor-pointer focus:outline-none focus:ring-2 focus:ring-brand-red/30 transition-all"
                                                >
                                                    <option value="encoder">Encoder</option>
                                                    <option value="admin">Admin</option>
                                                    <option value="owner">Owner</option>
                                                </select>
                                            ) : (
                                                <span className="text-[9px] text-text-muted font-bold">—</span>
                                            )}
                                        </td>
                                        <td className="px-5 py-3.5 text-right whitespace-nowrap">
                                            {role === 'owner' && !isCurrentUser ? (
                                                confirmDelete === p.id ? (
                                                    <div className="flex items-center gap-2 justify-end animate-fade-in">
                                                        <button
                                                            onClick={() => handleDeleteAccount(p.id, p.full_name)}
                                                            className="flex items-center gap-1 px-3 py-1.5 bg-red-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-red-700 transition-all active:scale-95"
                                                        >
                                                            <AlertTriangle size={10} /> Confirm
                                                        </button>
                                                        <button
                                                            onClick={() => setConfirmDelete(null)}
                                                            className="px-3 py-1.5 bg-bg-subtle text-text-muted rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-bg-muted transition-all"
                                                        >
                                                            Cancel
                                                        </button>
                                                    </div>
                                                ) : (
                                                    <button
                                                        onClick={() => setConfirmDelete(p.id)}
                                                        className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-bg-subtle border border-border-default hover:border-red-500/30 rounded-xl text-[9px] font-black uppercase tracking-widest text-text-muted hover:text-red-600 transition-all active:scale-95"
                                                    >
                                                        <Trash2 size={12} /> Remove
                                                    </button>
                                                )
                                            ) : (
                                                <span className="text-[9px] text-text-muted font-bold">—</span>
                                            )}
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

import { useState, useCallback, Fragment } from 'react';
import { supabase } from '../../shared/lib/supabase';
import { useCustomers } from './hooks/useCustomers';
import { useAuth } from '../../shared/hooks/useAuth';
import {
    Users, Plus, Search, Edit, Trash2, Mail, Phone, MapPin,
    CreditCard, Loader2, PackageSearch,
    AlertCircle, CheckCircle2, Receipt, ChevronDown, ShoppingBag,
    RotateCcw, Clock, Truck, Calendar, TrendingUp, Filter,
    ArrowRight
} from 'lucide-react';
import { useBranch } from '../../shared/lib/BranchContext';
import CustomerModal from './components/CustomerModal';
import SalesModal from '../sales/components/SalesModal';
import type { Customer, CustomerInsert } from '../../shared/types';
import { format } from 'date-fns';

// ────────────────────────────────────────────
// Types
// ────────────────────────────────────────────
interface SaleRecord {
    id: string;
    product_id: string;
    quantity: number;
    unit_price: number;
    total_price: number;
    date: string;
    invoice_number: string;
    customer_name: string;
    customer_id: string | null;
    fulfillment_status: 'pickup' | 'delivered' | 'out';
    payment_mode: string;
    is_os: boolean;
    vat_amount: number;
    discount_amount: number;
    is_discounted: boolean;
    delivery_fee: number;
    edited_at: string | null;
    products: { name: string; brand?: string };
}

interface GroupedInvoice {
    invoice_number: string;
    date: string;
    customer_name: string;
    fulfillment_status: 'pickup' | 'delivered' | 'out';
    payment_mode: string;
    is_os: boolean;
    items: SaleRecord[];
    total: number;
    delivery_fee: number;
    discount: number;
    grand_total: number;
}

type Tab = 'overview' | 'history' | 'ledger';

// ────────────────────────────────────────────
// Component
// ────────────────────────────────────────────
export default function Customers() {
    const { role } = useAuth();
    const { activeBranchId } = useBranch();
    const { customers, isLoading, createCustomer, updateCustomer, deleteCustomer } = useCustomers();
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState<'all' | 'active' | 'hold'>('all');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedCustomer, setSelectedCustomer] = useState<Customer | null>(null);
    const [activeTab, setActiveTab] = useState<Tab>('overview');
    const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null);

    // Purchase history state
    const [customerSales, setCustomerSales] = useState<GroupedInvoice[]>([]);
    const [salesLoading, setSalesLoading] = useState(false);
    const [expandedInvoices, setExpandedInvoices] = useState<Set<string>>(new Set());

    // Sales Modal state (for repeat orders)
    const [isSalesModalOpen, setIsSalesModalOpen] = useState(false);
    const [repeatOrderData, setRepeatOrderData] = useState<{
        invoiceNumber: string;
        customerName?: string;
        customer_id?: string | null;
        fulfillmentStatus?: string;
        paymentMode?: string;
        items: { product_id: string; quantity: number; unit_price: number; total_price: number; name?: string; brand?: string }[];
        isVatEnabled: boolean;
        isDiscountEnabled: boolean;
        is_os?: boolean;
        delivery_fee?: number;
    } | null>(null);

    // ── Helpers ──
    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'delivered': return <CheckCircle2 className="text-emerald-500" size={12} />;
            case 'out': return <Truck className="text-amber-500" size={12} />;
            default: return <Clock className="text-slate-400" size={12} />;
        }
    };

    const getStatusText = (status: string) => {
        switch (status) {
            case 'delivered': return 'Delivered';
            case 'out': return 'In Transit';
            default: return 'Store Pickup';
        }
    };

    // ── Filtering ──
    const filteredCustomers = customers.filter(c => {
        const search = searchTerm.toLowerCase();
        const matchesSearch = c.name.toLowerCase().includes(search) || c.email?.toLowerCase().includes(search) || c.phone?.toLowerCase().includes(search);
        const matchesStatus = statusFilter === 'all' || (statusFilter === 'active' ? c.is_active : !c.is_active);
        return matchesSearch && matchesStatus;
    });

    // ── Fetch customer purchase history ──
    const fetchCustomerSales = useCallback(async (customer: Customer) => {
        setSalesLoading(true);
        setCustomerSales([]);
        try {
            let query = supabase
                .from('sales')
                .select('*, products(name, brand)')
                .or(`customer_name.eq.${customer.name},customer_id.eq.${customer.id}`)
                .order('date', { ascending: false });

            if (activeBranchId) {
                query = query.eq('branch_id', activeBranchId);
            }

            const { data, error } = await query;

            if (error) throw error;

            // Group by invoice
            const groups: Record<string, GroupedInvoice> = {};
            (data || []).forEach((sale: SaleRecord) => {
                const key = sale.invoice_number;
                if (!key) return;
                if (!groups[key]) {
                    groups[key] = {
                        invoice_number: key,
                        date: sale.date,
                        customer_name: sale.customer_name || customer.name,
                        fulfillment_status: sale.fulfillment_status || 'pickup',
                        payment_mode: sale.payment_mode || 'cash',
                        is_os: sale.is_os || false,
                        items: [],
                        total: 0,
                        delivery_fee: Number(sale.delivery_fee) || 0,
                        discount: 0,
                        grand_total: 0
                    };
                }
                groups[key].items.push(sale);
                groups[key].total += Number(sale.total_price);
                groups[key].discount += Number(sale.discount_amount || 0);
            });
            Object.values(groups).forEach(g => {
                g.grand_total = g.total - g.discount + g.delivery_fee;
            });

            setCustomerSales(Object.values(groups).sort((a, b) =>
                new Date(b.date).getTime() - new Date(a.date).getTime()
            ));
        } catch (err) {
            console.error('Error fetching customer sales:', err);
        } finally {
            setSalesLoading(false);
        }
    }, []);

    // ── Select customer ──
    const handleSelectCustomer = (customer: Customer) => {
        setSelectedCustomer(customer);
        setActiveTab('overview');
        setExpandedInvoices(new Set());
        fetchCustomerSales(customer);
    };

    // ── CRUD ──
    const handleAdd = () => { setEditingCustomer(null); setIsModalOpen(true); };
    const handleEdit = (customer: Customer) => { setEditingCustomer(customer); setIsModalOpen(true); };
    const handleDelete = async (id: string) => {
        if (confirm('Are you sure you want to delete this customer?')) {
            await deleteCustomer(id);
            if (selectedCustomer?.id === id) setSelectedCustomer(null);
        }
    };
    const handleSubmit = async (data: CustomerInsert) => {
        if (editingCustomer) {
            await updateCustomer({ id: editingCustomer.id, updates: data });
        } else {
            await createCustomer(data);
        }
        setIsModalOpen(false);
    };

    // ── Repeat order ──
    const handleRepeatOrder = (invoice: GroupedInvoice) => {
        setRepeatOrderData({
            invoiceNumber: '', // blank = new sale, auto-assign
            customerName: selectedCustomer?.name,
            customer_id: selectedCustomer?.id,
            fulfillmentStatus: invoice.fulfillment_status,
            paymentMode: invoice.payment_mode,
            items: invoice.items.map(item => ({
                product_id: item.product_id,
                quantity: item.quantity,
                unit_price: item.unit_price,
                total_price: item.total_price,
                name: item.products?.name,
                brand: item.products?.brand
            })),
            isVatEnabled: !invoice.is_os,
            isDiscountEnabled: invoice.discount > 0,
            is_os: invoice.is_os,
            delivery_fee: invoice.delivery_fee
        });
        setIsSalesModalOpen(true);
    };

    // ── Toggle invoice expand ──
    const toggleExpand = (inv: string) => {
        setExpandedInvoices(prev => {
            const next = new Set(prev);
            if (next.has(inv)) next.delete(inv); else next.add(inv);
            return next;
        });
    };

    // ── Stats ──
    const totalOrders = customerSales.length;
    const totalSpent = customerSales.reduce((s, i) => s + i.grand_total, 0);
    const avgOrder = totalOrders > 0 ? totalSpent / totalOrders : 0;
    const lastPurchase = customerSales.length > 0 ? customerSales[0].date : null;

    // ── Loading screen ──
    if (isLoading && customers.length === 0) {
        return (
            <div className="h-[60vh] flex items-center justify-center">
                <div className="flex flex-col items-center gap-4">
                    <Loader2 size={40} className="text-brand-red animate-spin" />
                    <p className="text-sm text-text-muted font-black uppercase tracking-widest">Loading Customer Database...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="space-y-6 animate-fade-in pb-10">
            {/* ── Header ── */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-bg-surface rounded-[24px] flex items-center justify-center shadow-xl border border-border-muted group transition-all hover:scale-105">
                        <Users className="text-brand-red group-hover:rotate-12 transition-transform" size={28} />
                    </div>
                    <div>
                        <h1 className="text-3xl font-black text-text-primary tracking-tight">Customers</h1>
                        <p className="text-sm text-text-secondary mt-1 font-medium">Accounts, purchase history & relationships</p>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <div className="relative group flex-1 md:flex-none">
                        <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-text-muted group-focus-within:text-brand-red transition-colors" size={18} />
                        <input
                            type="text"
                            placeholder="Search customers..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="bg-bg-surface border border-border-default rounded-2xl pl-12 pr-6 py-3.5 text-sm font-bold text-text-primary placeholder:text-text-muted focus:ring-4 focus:ring-brand-red/10 focus:border-brand-red outline-none transition-all w-full md:w-72 shadow-sm"
                        />
                    </div>
                    <div className="relative">
                        <button
                            onClick={() => setStatusFilter(statusFilter === 'all' ? 'active' : statusFilter === 'active' ? 'hold' : 'all')}
                            className={`px-4 py-3.5 border rounded-2xl transition-all shadow-sm flex items-center gap-2 font-bold text-xs ${statusFilter !== 'all' ? 'bg-brand-red text-white border-brand-red' : 'bg-bg-surface border-border-default text-text-secondary hover:bg-bg-subtle'}`}
                        >
                            <Filter size={16} /> {statusFilter === 'all' ? 'All' : statusFilter === 'active' ? 'Active' : 'On Hold'}
                        </button>
                    </div>
                    {role === 'owner' && (
                        <button onClick={handleAdd} className="flex items-center gap-2 bg-text-primary text-bg-base px-6 py-3.5 rounded-2xl font-black text-xs hover:opacity-90 transition-all shadow-lg active:scale-95 flex-shrink-0">
                            <Plus size={18} /> ADD CUSTOMER
                        </button>
                    )}
                </div>
            </div>

            {/* ── Master-Detail Layout ── */}
            <div className="flex flex-col lg:flex-row gap-6">
                {/* ── Left Panel: Customer List ── */}
                <div className={`${selectedCustomer ? 'lg:w-[420px]' : 'w-full'} flex-shrink-0 transition-all`}>
                    <div className="bg-bg-surface rounded-[32px] border border-border-muted shadow-sm overflow-hidden">
                        <div className="px-6 py-4 bg-bg-subtle/50 border-b border-border-muted flex items-center justify-between">
                            <span className="text-[10px] font-black text-text-primary uppercase tracking-widest">{filteredCustomers.length} Customers</span>
                            <span className="text-[10px] font-bold text-text-muted uppercase tracking-widest">₱{customers.reduce((s, c) => s + c.current_balance, 0).toLocaleString()} Total Exposure</span>
                        </div>
                        <div className="divide-y divide-border-muted max-h-[calc(100vh-280px)] overflow-y-auto custom-scrollbar">
                            {filteredCustomers.length === 0 ? (
                                <div className="p-12 flex flex-col items-center justify-center text-center">
                                    <div className="w-16 h-16 bg-bg-base rounded-[20px] flex items-center justify-center mb-4 border border-border-muted">
                                        <PackageSearch className="text-text-muted opacity-20" size={32} />
                                    </div>
                                    <h3 className="text-sm font-black text-text-primary uppercase tracking-tight">No Customers Found</h3>
                                    <p className="text-text-muted max-w-xs mt-1 text-xs font-medium">Adjust your search or add a new customer.</p>
                                </div>
                            ) : (
                                filteredCustomers.map(customer => (
                                    <button
                                        key={customer.id}
                                        onClick={() => handleSelectCustomer(customer)}
                                        className={`w-full text-left px-6 py-4 hover:bg-bg-subtle transition-all flex items-center gap-4 group ${selectedCustomer?.id === customer.id ? 'bg-brand-red/5 border-l-4 border-brand-red' : 'border-l-4 border-transparent'}`}
                                    >
                                        <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-sm font-black shadow-sm transition-all ${selectedCustomer?.id === customer.id ? 'bg-brand-red text-white' : customer.is_active ? 'bg-brand-red/10 text-brand-red' : 'bg-bg-base text-text-muted opacity-50'}`}>
                                            {customer.name.charAt(0).toUpperCase()}
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <p className="text-sm font-black text-text-primary uppercase tracking-tight truncate">{customer.name}</p>
                                            <div className="flex items-center gap-3 mt-0.5">
                                                <span className="text-[10px] font-bold text-text-muted opacity-50 font-data">{customer.phone || 'No phone'}</span>
                                                <span className={`text-[8px] font-black uppercase tracking-widest px-1.5 py-0.5 rounded-full ${customer.is_active ? 'bg-emerald-500/10 text-emerald-500' : 'bg-bg-base text-text-muted opacity-50'}`}>
                                                    {customer.is_active ? 'Active' : 'Hold'}
                                                </span>
                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <p className={`text-xs font-black font-data ${customer.current_balance > 0 ? 'text-brand-red' : 'text-text-muted opacity-50'}`}>
                                                ₱{customer.current_balance.toLocaleString()}
                                            </p>
                                            <p className="text-[9px] font-bold text-text-muted opacity-40 font-data">/ ₱{(customer.credit_limit || 0).toLocaleString()}</p>
                                        </div>
                                    </button>
                                ))
                            )}
                        </div>
                    </div>
                </div>

                {/* ── Right Panel: Detail ── */}
                {selectedCustomer ? (
                    <div className="flex-1 min-w-0 space-y-6">
                        {/* Customer Header Card */}
                        <div className="bg-bg-surface rounded-[32px] border border-border-muted shadow-sm p-8 relative overflow-hidden">
                            <div className="absolute top-0 right-0 w-40 h-40 bg-brand-red/5 rounded-full -mr-20 -mt-20" />
                            <div className="flex items-start justify-between relative z-10">
                                <div className="flex items-center gap-5">
                                    <div className="w-16 h-16 rounded-2xl bg-brand-red flex items-center justify-center text-white text-2xl font-black shadow-lg">
                                        {selectedCustomer.name.charAt(0).toUpperCase()}
                                    </div>
                                    <div>
                                        <h2 className="text-2xl font-black text-text-primary uppercase tracking-tight">{selectedCustomer.name}</h2>
                                        <div className="flex items-center gap-3 mt-1">
                                            <span className={`text-[10px] font-black uppercase tracking-widest px-2.5 py-1 rounded-full ${selectedCustomer.is_active ? 'bg-emerald-500/10 text-emerald-500' : 'bg-bg-base text-text-muted opacity-50'}`}>
                                                {selectedCustomer.is_active ? 'Account Eligible' : 'Account On Hold'}
                                            </span>
                                            <span className="text-[10px] font-bold text-text-muted opacity-50 font-data">Since {format(new Date(selectedCustomer.created_at), 'MMM yyyy')}</span>
                                        </div>
                                    </div>
                                </div>
                                {role === 'owner' && (
                                    <div className="flex items-center gap-2">
                                        <button onClick={() => handleEdit(selectedCustomer)} className="p-3 rounded-2xl hover:bg-bg-subtle text-text-muted hover:text-text-primary transition-all">
                                            <Edit size={18} />
                                        </button>
                                        <button onClick={() => handleDelete(selectedCustomer.id)} className="p-3 rounded-2xl hover:bg-brand-red/10 text-text-muted hover:text-brand-red transition-all">
                                            <Trash2 size={18} />
                                        </button>
                                    </div>
                                )}
                            </div>
                        </div>

                        {/* Tabs */}
                        <div className="flex gap-2">
                            {([
                                { id: 'overview', label: 'Overview', icon: Users },
                                { id: 'history', label: 'Purchase History', icon: Receipt },
                                { id: 'ledger', label: 'Ledger', icon: CreditCard }
                            ] as const).map(tab => (
                                <button
                                    key={tab.id}
                                    onClick={() => setActiveTab(tab.id)}
                                    className={`flex items-center gap-2 px-5 py-3 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${activeTab === tab.id ? 'bg-text-primary text-bg-base shadow-lg' : 'bg-bg-surface text-text-muted border border-border-muted hover:bg-bg-subtle'}`}
                                >
                                    <tab.icon size={14} /> {tab.label}
                                </button>
                            ))}
                        </div>

                        {/* ── TAB: Overview ── */}
                        {activeTab === 'overview' && (
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                {/* Contact Card */}
                                <div className="bg-bg-surface rounded-[28px] border border-border-muted shadow-sm p-6 space-y-5">
                                    <h3 className="text-[10px] font-black text-text-primary uppercase tracking-[0.2em] border-b border-border-muted pb-3">Contact Details</h3>
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-lg bg-bg-base/50 flex items-center justify-center"><Phone size={14} className="text-text-muted" /></div>
                                            <span className="text-sm font-bold text-text-primary font-data">{selectedCustomer.phone || 'N/A'}</span>
                                        </div>
                                        <div className="flex items-center gap-3">
                                            <div className="w-8 h-8 rounded-lg bg-bg-base/50 flex items-center justify-center"><Mail size={14} className="text-text-muted" /></div>
                                            <span className="text-sm font-bold text-text-primary truncate">{selectedCustomer.email || 'N/A'}</span>
                                        </div>
                                        <div className="flex items-start gap-3">
                                            <div className="w-8 h-8 rounded-lg bg-bg-base/50 flex items-center justify-center flex-shrink-0"><MapPin size={14} className="text-text-muted" /></div>
                                            <span className="text-sm font-medium text-text-secondary leading-relaxed">{selectedCustomer.address || 'No address registered'}</span>
                                        </div>
                                    </div>
                                </div>

                                {/* Credit Exposure Card */}
                                <div className="bg-bg-surface rounded-[28px] border border-border-muted shadow-sm p-6 space-y-5">
                                    <h3 className="text-[10px] font-black text-text-primary uppercase tracking-[0.2em] border-b border-border-muted pb-3 flex items-center gap-2"><CreditCard size={12} /> Credit Exposure</h3>
                                    <div className="space-y-4">
                                        <div>
                                            <div className="flex justify-between items-end mb-2">
                                                <span className="text-[9px] font-black text-text-muted uppercase tracking-widest">Outstanding Balance</span>
                                                <span className={`text-xl font-black font-data ${selectedCustomer.current_balance > 0 ? 'text-brand-red' : 'text-text-primary'}`}>₱{selectedCustomer.current_balance.toLocaleString()}</span>
                                            </div>
                                            <div className="w-full h-3 bg-bg-base rounded-full overflow-hidden border border-border-muted">
                                                <div
                                                    className={`h-full rounded-full transition-all duration-1000 ${selectedCustomer.current_balance > selectedCustomer.credit_limit ? 'bg-brand-red animate-pulse' : 'bg-brand-orange'}`}
                                                    style={{ width: `${Math.min((selectedCustomer.current_balance / (selectedCustomer.credit_limit || 1)) * 100, 100)}%` }}
                                                />
                                            </div>
                                        </div>
                                        <div className="flex justify-between items-center text-[10px] font-black text-text-muted uppercase tracking-widest">
                                            <span>Limit: ₱{(selectedCustomer.credit_limit || 0).toLocaleString()}</span>
                                            {selectedCustomer.current_balance > selectedCustomer.credit_limit && (
                                                <div className="flex items-center gap-1 text-brand-red"><AlertCircle size={14} className="animate-bounce" /> Over Limit</div>
                                            )}
                                        </div>
                                    </div>
                                </div>

                                {/* Stats Cards */}
                                <div className="md:col-span-2 grid grid-cols-2 md:grid-cols-4 gap-4">
                                    {[
                                        { label: 'Total Orders', value: totalOrders.toString(), icon: ShoppingBag, color: 'text-brand-red' },
                                        { label: 'Total Spent', value: `₱${totalSpent.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, icon: TrendingUp, color: 'text-emerald-500' },
                                        { label: 'Avg Order', value: `₱${avgOrder.toLocaleString(undefined, { minimumFractionDigits: 2 })}`, icon: Receipt, color: 'text-brand-orange' },
                                        { label: 'Last Purchase', value: lastPurchase ? format(new Date(lastPurchase), 'MMM d, yyyy') : 'Never', icon: Calendar, color: 'text-blue-500' }
                                    ].map((stat, idx) => (
                                        <div key={idx} className="bg-bg-surface rounded-[24px] border border-border-muted shadow-sm p-5 relative overflow-hidden">
                                            <div className="absolute top-0 right-0 w-16 h-16 bg-bg-base rounded-full -mr-8 -mt-8 opacity-50" />
                                            <stat.icon size={16} className={`${stat.color} mb-3`} />
                                            <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-1">{stat.label}</p>
                                            <p className={`text-sm font-black ${stat.color} font-data`}>{salesLoading ? '...' : stat.value}</p>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* ── TAB: Purchase History ── */}
                        {activeTab === 'history' && (
                            <div className="bg-bg-surface rounded-[32px] border border-border-muted shadow-sm overflow-hidden">
                                <div className="overflow-x-auto">
                                    <table className="w-full text-left">
                                        <thead>
                                            <tr className="bg-bg-subtle/50 border-b border-border-muted">
                                                <th className="px-6 py-4 text-[10px] font-black text-text-primary uppercase tracking-widest">Invoice</th>
                                                <th className="px-6 py-4 text-[10px] font-black text-text-primary uppercase tracking-widest">Date</th>
                                                <th className="px-6 py-4 text-[10px] font-black text-text-primary uppercase tracking-widest">Items</th>
                                                <th className="px-6 py-4 text-[10px] font-black text-text-primary uppercase tracking-widest">Payment</th>
                                                <th className="px-6 py-4 text-[10px] font-black text-text-primary uppercase tracking-widest text-right">Total</th>
                                                <th className="px-6 py-4 text-[10px] font-black text-text-primary uppercase tracking-widest w-28 text-center">Actions</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-border-muted">
                                            {salesLoading ? (
                                                [1, 2, 3].map(i => <tr key={i} className="animate-pulse"><td colSpan={6} className="px-6 py-8"><div className="h-4 bg-slate-100 rounded w-full" /></td></tr>)
                                            ) : customerSales.length > 0 ? (
                                                customerSales.map(invoice => (
                                                    <Fragment key={invoice.invoice_number}>
                                                        <tr onClick={() => toggleExpand(invoice.invoice_number)} className="group hover:bg-bg-subtle transition-all cursor-pointer">
                                                            <td className="px-6 py-4">
                                                                <div className="flex items-center gap-3">
                                                                    <div className="w-9 h-9 bg-bg-base/50 rounded-lg flex items-center justify-center text-text-muted group-hover:bg-brand-red group-hover:text-white transition-all"><Receipt size={16} /></div>
                                                                    <div>
                                                                        <p className="text-xs font-black text-text-primary uppercase font-data">{invoice.invoice_number}</p>
                                                                        <div className="flex gap-1 mt-0.5">
                                                                            {invoice.is_os && <span className="px-1.5 py-0.5 bg-brand-red text-white text-[7px] font-black rounded uppercase">OS</span>}
                                                                            {invoice.discount > 0 && <span className="px-1.5 py-0.5 bg-brand-orange text-white text-[7px] font-black rounded uppercase">DISC</span>}
                                                                        </div>
                                                                    </div>
                                                                </div>
                                                            </td>
                                                            <td className="px-6 py-4">
                                                                <p className="text-[11px] font-bold text-text-primary">{format(new Date(invoice.date), 'MMM d, yyyy')}</p>
                                                                <p className="text-[9px] font-bold text-text-muted">{format(new Date(invoice.date), 'p')}</p>
                                                            </td>
                                                            <td className="px-6 py-4">
                                                                <div className={`flex items-center gap-1.5 px-2 py-1 rounded-full w-fit ${invoice.fulfillment_status === 'delivered' ? 'bg-emerald-500/10 text-emerald-500' :
                                                                    invoice.fulfillment_status === 'out' ? 'bg-amber-500/10 text-amber-500' : 'bg-bg-base text-text-muted opacity-50'
                                                                    }`}>
                                                                    {getStatusIcon(invoice.fulfillment_status)}
                                                                    <span className="text-[8px] font-black uppercase tracking-tight">{getStatusText(invoice.fulfillment_status)}</span>
                                                                </div>
                                                            </td>
                                                            <td className="px-6 py-4">
                                                                <div className="flex items-center gap-2 px-2.5 py-1 bg-bg-base/50 rounded-full w-fit border border-border-muted">
                                                                    <div className="w-1.5 h-1.5 rounded-full bg-brand-red" />
                                                                    <span className="text-[9px] font-black text-text-primary uppercase tracking-wider">{invoice.payment_mode}</span>
                                                                </div>
                                                            </td>
                                                            <td className="px-6 py-4 text-right font-data font-black text-text-primary text-sm">₱{invoice.grand_total.toLocaleString(undefined, { minimumFractionDigits: 2 })}</td>
                                                            <td className="px-6 py-4">
                                                                <div className="flex items-center justify-center gap-1">
                                                                    <button
                                                                        onClick={(e) => { e.stopPropagation(); handleRepeatOrder(invoice); }}
                                                                        className="p-2 rounded-lg text-text-muted opacity-0 group-hover:opacity-100 hover:text-brand-red hover:bg-brand-red/10 transition-all"
                                                                        title="Repeat Order"
                                                                    >
                                                                        <RotateCcw size={14} />
                                                                    </button>
                                                                    <div className={`p-2 rounded-lg transition-all ${expandedInvoices.has(invoice.invoice_number) ? 'bg-brand-red text-white rotate-180' : 'bg-bg-base/50 text-text-muted opacity-50'}`}>
                                                                        <ChevronDown size={14} />
                                                                    </div>
                                                                </div>
                                                            </td>
                                                        </tr>
                                                        {expandedInvoices.has(invoice.invoice_number) && (
                                                            <tr>
                                                                <td colSpan={6} className="px-6 py-4 bg-bg-base/50">
                                                                    <div className="p-5 border-l-4 border-brand-red bg-bg-surface shadow-sm rounded-2xl space-y-4">
                                                                        <div className="flex items-center justify-between border-b border-border-muted pb-3">
                                                                            <h4 className="text-[10px] font-black uppercase text-text-primary tracking-widest flex items-center gap-2"><PackageSearch size={14} /> Invoice Items</h4>
                                                                            <button
                                                                                onClick={() => handleRepeatOrder(invoice)}
                                                                                className="text-[10px] font-black bg-text-primary text-bg-base hover:opacity-90 px-4 py-1.5 rounded-lg transition-all flex items-center gap-1.5"
                                                                            >
                                                                                <RotateCcw size={12} /> REPEAT ORDER
                                                                            </button>
                                                                        </div>
                                                                        <div className="space-y-2">
                                                                            {invoice.items.map(item => (
                                                                                <div key={item.id} className="flex justify-between items-start gap-4 text-xs p-2 rounded-lg hover:bg-bg-subtle">
                                                                                    <div className="flex-1">
                                                                                        <p className="font-bold text-text-primary">{item.products?.name}</p>
                                                                                        <p className="text-[9px] text-text-muted uppercase font-data">{item.products?.brand || 'No Brand'}</p>
                                                                                    </div>
                                                                                    <div className="text-right">
                                                                                        <p className="font-bold text-text-primary">x{item.quantity}</p>
                                                                                        <p className="text-[9px] text-text-muted font-data">UNIT: ₱{Number(item.unit_price).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                                                                        <p className="text-[10px] text-text-secondary font-data font-black">TOTAL: ₱{Number(item.total_price).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                                                                    </div>
                                                                                </div>
                                                                            ))}
                                                                        </div>
                                                                        <div className="pt-3 border-t border-border-muted flex justify-between items-center text-sm font-black text-text-primary">
                                                                            <span className="uppercase tracking-widest text-[10px]">Grand Total</span>
                                                                            <span className="text-xl font-data">₱{invoice.grand_total.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                                                        </div>
                                                                    </div>
                                                                </td>
                                                            </tr>
                                                        )}
                                                    </Fragment>
                                                ))
                                            ) : (
                                                <tr><td colSpan={6} className="py-16 text-center text-text-muted opacity-50">
                                                    <div className="flex flex-col items-center gap-3">
                                                        <PackageSearch size={32} className="text-text-muted opacity-20" />
                                                        <p className="text-sm font-black uppercase tracking-tight">No purchase history</p>
                                                        <p className="text-xs font-medium text-text-muted">This customer hasn't made any purchases yet.</p>
                                                    </div>
                                                </td></tr>
                                            )}
                                        </tbody>
                                    </table>
                                </div>
                            </div>
                        )}

                        {/* ── TAB: Ledger ── */}
                        {activeTab === 'ledger' && (
                            <div className="space-y-6">
                                {/* Balance Summary */}
                                <div className="bg-bg-surface rounded-[28px] border border-border-muted shadow-sm p-6">
                                    <div className="flex items-center justify-between mb-4">
                                        <h3 className="text-[10px] font-black text-text-primary uppercase tracking-[0.2em]">Account Ledger</h3>
                                        <div className="flex items-center gap-4">
                                            <div className="text-right">
                                                <p className="text-[9px] font-black text-text-muted uppercase tracking-widest">Outstanding</p>
                                                <p className={`text-xl font-black font-data ${selectedCustomer.current_balance > 0 ? 'text-brand-red' : 'text-emerald-500'}`}>
                                                    ₱{selectedCustomer.current_balance.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                                                </p>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                {/* Transaction List = Sales as charges */}
                                <div className="bg-bg-surface rounded-[28px] border border-border-muted shadow-sm overflow-hidden">
                                    <div className="px-6 py-4 bg-bg-subtle/50 border-b border-border-muted">
                                        <span className="text-[10px] font-black text-text-primary uppercase tracking-widest">Transaction History (Invoices)</span>
                                    </div>
                                    <div className="divide-y divide-border-muted max-h-[500px] overflow-y-auto custom-scrollbar">
                                        {salesLoading ? (
                                            <div className="p-8 text-center"><Loader2 className="animate-spin text-brand-red mx-auto" size={24} /></div>
                                        ) : customerSales.length > 0 ? (
                                            customerSales.map(invoice => (
                                                <div key={invoice.invoice_number} className="px-6 py-4 flex items-center gap-4">
                                                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${invoice.is_os ? 'bg-brand-red/10 text-brand-red' : 'bg-slate-100 text-slate-400'}`}>
                                                        <Receipt size={16} />
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        <div className="flex items-center gap-2">
                                                            <p className="text-xs font-black text-brand-charcoal uppercase font-data">{invoice.invoice_number}</p>
                                                            <span className="text-[9px] font-bold text-slate-400 bg-slate-100 px-2 py-0.5 rounded uppercase">{invoice.payment_mode}</span>
                                                        </div>
                                                        <p className="text-[10px] font-bold text-slate-400 mt-0.5">{format(new Date(invoice.date), 'MMM d, yyyy · p')} · {invoice.items.length} item{invoice.items.length > 1 ? 's' : ''}</p>
                                                    </div>
                                                    <div className="text-right">
                                                        <p className="text-sm font-black text-brand-charcoal font-data">₱{invoice.grand_total.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                                        <p className="text-[9px] font-black text-slate-300 uppercase">Charge</p>
                                                    </div>
                                                </div>
                                            ))
                                        ) : (
                                            <div className="p-12 text-center">
                                                <CreditCard size={32} className="text-slate-200 mx-auto mb-3" />
                                                <p className="text-sm font-black text-brand-charcoal uppercase tracking-tight">No transactions</p>
                                                <p className="text-xs font-medium text-slate-400 mt-1">No invoices found for this customer.</p>
                                            </div>
                                        )}
                                    </div>
                                    {customerSales.length > 0 && (
                                        <div className="px-6 py-4 bg-bg-subtle border-t border-border-muted flex justify-between items-center">
                                            <span className="text-[9px] font-black text-text-muted uppercase tracking-widest">Total Lifetime Value</span>
                                            <span className="text-lg font-black text-text-primary font-data">₱{totalSpent.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                ) : (
                    /* No customer selected - prompt */
                    !selectedCustomer && filteredCustomers.length > 0 && (
                        <div className="flex-1 flex items-center justify-center">
                            <div className="text-center p-12">
                                <div className="w-24 h-24 bg-bg-surface rounded-[32px] flex items-center justify-center mx-auto mb-6 shadow-xl border border-border-muted">
                                    <ArrowRight className="text-text-muted opacity-20 animate-pulse" size={40} />
                                </div>
                                <h3 className="text-xl font-black text-text-primary uppercase tracking-tight">Select a Customer</h3>
                                <p className="text-text-muted max-w-xs mt-2 text-sm font-medium mx-auto">Click a customer from the list to view their profile, purchase history, and account ledger.</p>
                            </div>
                        </div>
                    )
                )}
            </div>

            {/* ── Modals ── */}
            <CustomerModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onSubmit={handleSubmit}
                customer={editingCustomer}
            />
            <SalesModal
                isOpen={isSalesModalOpen}
                onClose={() => { setIsSalesModalOpen(false); setRepeatOrderData(null); }}
                onSuccess={() => {
                    setIsSalesModalOpen(false);
                    setRepeatOrderData(null);
                    if (selectedCustomer) fetchCustomerSales(selectedCustomer);
                }}
                editData={repeatOrderData || undefined}
            />
        </div>
    );
}

import { useEffect, useState, useCallback } from 'react';
import { supabase } from '../../shared/lib/supabase';
import { useBranch } from '../../shared/hooks/useBranch';
import { startOfDay, endOfDay, format } from 'date-fns';
import Calendar from '../../features/reports/components/Calendar';
import {
    TrendingUp, TrendingDown, DollarSign, ShoppingCart, Wallet, Package,
    Activity, Building2, BarChart3, X
} from 'lucide-react';

interface BranchData {
    branchId: string;
    branchName: string;
    sales: number;
    purchases: number;
    expenses: number;
    netProfit: number;
    salesCount: number;
    purchasesCount: number;
    expensesCount: number;
}

interface ActivityItem {
    id: string;
    type: 'sale' | 'purchase' | 'expense';
    description: string;
    amount: number;
    branch: string;
    branchId: string;
    time: string;
    invoiceNumber?: string;
}

export default function AdminCommandCenter() {
    const { branches } = useBranch();
    const [branchData, setBranchData] = useState<BranchData[]>([]);
    const [activities, setActivities] = useState<ActivityItem[]>([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState<'all' | 'sale' | 'purchase' | 'expense'>('all');
    const [selectedDate, setSelectedDate] = useState<Date>(new Date());
    const [selectedBranch, setSelectedBranch] = useState<string | null>(null); // null = all branches

    const fetchAllBranchData = useCallback(async (date?: Date) => {
        if (branches.length === 0) return;
        setLoading(true);

        const targetDate = date || selectedDate;
        const rangeStart = startOfDay(targetDate).toISOString();
        const rangeEnd = endOfDay(targetDate).toISOString();

        const allActivities: ActivityItem[] = [];
        const results: BranchData[] = await Promise.all(branches.map(async (branch) => {
            const [
                { data: salesData },
                { data: purchasesData },
                { data: expensesData }
            ] = await Promise.all([
                supabase
                    .from('sales')
                    .select('id, total_price, quantity, cost_price, date, invoice_number, products(name)')
                    .eq('branch_id', branch.id)
                    .gte('date', rangeStart)
                    .lte('date', rangeEnd)
                    .order('date', { ascending: false }),
                supabase
                    .from('purchases')
                    .select('id, total_price, discount_amount, date, invoice_number, products(name)')
                    .eq('branch_id', branch.id)
                    .gte('date', rangeStart)
                    .lte('date', rangeEnd)
                    .order('date', { ascending: false }),
                supabase
                    .from('expenses')
                    .select('id, amount, description, date, category')
                    .eq('branch_id', branch.id)
                    .gte('date', rangeStart)
                    .lte('date', rangeEnd)
                    .order('date', { ascending: false })
            ]);

            const sales = salesData || [];
            const purchases = purchasesData || [];
            const expenses = expensesData || [];

            const totalSales = sales.reduce((sum: number, s: any) => sum + (s.total_price || 0), 0);
            const totalCOGS = sales.reduce((sum: number, s: any) => sum + ((s.quantity || 0) * (s.cost_price || 0)), 0);
            const totalPurchases = purchases.reduce((sum: number, p: any) => sum + ((p.total_price || 0) - (p.discount_amount || 0)), 0);
            const totalExpenses = expenses.reduce((sum: number, e: any) => sum + (e.amount || 0), 0);

            // Build activity feed
            sales.forEach((s: any) => {
                const prod = Array.isArray(s.products) ? s.products[0] : s.products;
                allActivities.push({
                    id: s.id, type: 'sale',
                    description: prod?.name || s.invoice_number || 'Sale',
                    amount: s.total_price || 0,
                    branch: branch.name, branchId: branch.id,
                    time: s.date, invoiceNumber: s.invoice_number
                });
            });
            purchases.forEach((p: any) => {
                const prod = Array.isArray(p.products) ? p.products[0] : p.products;
                allActivities.push({
                    id: p.id, type: 'purchase',
                    description: prod?.name || p.invoice_number || 'Purchase',
                    amount: (p.total_price || 0) - (p.discount_amount || 0),
                    branch: branch.name, branchId: branch.id,
                    time: p.date, invoiceNumber: p.invoice_number
                });
            });
            expenses.forEach((e: any) => {
                allActivities.push({
                    id: e.id, type: 'expense',
                    description: e.description || e.category || 'Expense',
                    amount: e.amount || 0,
                    branch: branch.name, branchId: branch.id,
                    time: e.date
                });
            });

            return {
                branchId: branch.id,
                branchName: branch.name,
                sales: totalSales,
                purchases: totalPurchases,
                expenses: totalExpenses,
                netProfit: totalSales - totalCOGS - totalExpenses,
                salesCount: sales.length,
                purchasesCount: purchases.length,
                expensesCount: expenses.length
            };
        }));

        allActivities.sort((a: ActivityItem, b: ActivityItem) => new Date(b.time).getTime() - new Date(a.time).getTime());
        results.sort((a: BranchData, b: BranchData) => a.branchName.localeCompare(b.branchName, undefined, { numeric: true }));
        setBranchData(results);
        setActivities(allActivities);
        setLoading(false);
    }, [branches, selectedDate]);

    useEffect(() => {
        fetchAllBranchData();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [fetchAllBranchData]);

    const handleDateSelect = (date: Date) => {
        setSelectedDate(date);
        fetchAllBranchData(date);
    };

    const handleBranchClick = (branchId: string) => {
        setSelectedBranch(prev => prev === branchId ? null : branchId);
    };

    // Compute totals — respect branch filter
    const visibleBranches = selectedBranch ? branchData.filter(b => b.branchId === selectedBranch) : branchData;
    const totals = visibleBranches.reduce((acc, b) => ({
        sales: acc.sales + b.sales,
        purchases: acc.purchases + b.purchases,
        expenses: acc.expenses + b.expenses,
        netProfit: acc.netProfit + b.netProfit,
        salesCount: acc.salesCount + b.salesCount,
        purchasesCount: acc.purchasesCount + b.purchasesCount,
        expensesCount: acc.expensesCount + b.expensesCount
    }), { sales: 0, purchases: 0, expenses: 0, netProfit: 0, salesCount: 0, purchasesCount: 0, expensesCount: 0 });

    // Filter activities — respect branch + tab
    const branchFiltered = selectedBranch ? activities.filter(a => a.branchId === selectedBranch) : activities;
    const filteredActivities = activeTab === 'all' ? branchFiltered : branchFiltered.filter(a => a.type === activeTab);

    const selectedBranchName = selectedBranch ? branchData.find(b => b.branchId === selectedBranch)?.branchName : null;

    const fmt = (v: number) => `₱${v.toLocaleString('en-PH', { minimumFractionDigits: 2 })}`;

    const typeColors: Record<string, string> = {
        sale: 'bg-emerald-500/10 text-emerald-600',
        purchase: 'bg-blue-500/10 text-blue-600',
        expense: 'bg-amber-500/10 text-amber-600'
    };
    const typeIcons: Record<string, React.ReactNode> = {
        sale: <DollarSign size={12} />,
        purchase: <ShoppingCart size={12} />,
        expense: <Wallet size={12} />
    };

    return (
        <div className="animate-fade-in pb-8">
            {/* Header */}
            <div className="flex items-center justify-between mb-5">
                <div className="flex items-center gap-3">
                    <div className="w-11 h-11 bg-bg-surface rounded-[18px] flex items-center justify-center shadow-lg border border-border-default">
                        <BarChart3 className="text-brand-red" size={24} />
                    </div>
                    <div>
                        <h1 className="text-xl font-black text-text-primary tracking-tight">Command Center</h1>
                        <p className="text-[10px] font-black text-text-muted uppercase tracking-[0.2em]">{format(selectedDate, 'EEEE, MMMM d yyyy')}</p>
                    </div>
                </div>
                <button
                    onClick={() => fetchAllBranchData()}
                    className="flex items-center gap-2 px-4 py-2 rounded-2xl bg-bg-subtle hover:bg-bg-muted border border-border-default text-text-secondary text-[10px] font-black uppercase tracking-widest transition-all active:scale-95"
                >
                    <Activity size={14} /> Refresh
                </button>
            </div>

            <div className="flex flex-col lg:flex-row gap-5">
                {/* Left: Calendar */}
                <div className="flex-shrink-0 w-full lg:w-72">
                    <div className="sticky top-6 space-y-4">
                        <Calendar
                            selectedDate={selectedDate}
                            onDateSelect={handleDateSelect}
                        />

                        {/* Branch Filter Indicator */}
                        {selectedBranch && (
                            <div className="bg-brand-red/5 border border-brand-red/20 rounded-2xl p-3 flex items-center justify-between animate-fade-in">
                                <div className="flex items-center gap-2">
                                    <Building2 size={14} className="text-brand-red" />
                                    <span className="text-[10px] font-black text-brand-red uppercase tracking-widest">Filtering: {selectedBranchName}</span>
                                </div>
                                <button
                                    onClick={() => setSelectedBranch(null)}
                                    className="p-1 hover:bg-brand-red/10 rounded-lg transition-colors"
                                >
                                    <X size={14} className="text-brand-red" />
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                {/* Right: Main Content */}
                <div className="flex-1 min-w-0 space-y-5">
                    {/* Totals Strip */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                        <TotalChip label="Total Sales" value={totals.sales} count={totals.salesCount} color="emerald" loading={loading} />
                        <TotalChip label="Total Purchases" value={totals.purchases} count={totals.purchasesCount} color="blue" loading={loading} />
                        <TotalChip label="Total Expenses" value={totals.expenses} count={totals.expensesCount} color="amber" loading={loading} />
                        <TotalChip label="Net Profit" value={totals.netProfit} count={null} color={totals.netProfit >= 0 ? 'emerald' : 'red'} loading={loading} isProfit />
                    </div>

                    {/* Branch Cards Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                        {loading
                            ? [1, 2, 3].map(i => <div key={i} className="h-44 skeleton rounded-[24px]" />)
                            : branchData.map(b => (
                                <div
                                    key={b.branchId}
                                    onClick={() => handleBranchClick(b.branchId)}
                                    className={`bg-bg-surface rounded-[24px] border-2 shadow-sm p-5 hover:shadow-lg hover:-translate-y-0.5 transition-all cursor-pointer select-none ${
                                        selectedBranch === b.branchId
                                            ? 'border-brand-red shadow-red/10 ring-2 ring-brand-red/10'
                                            : selectedBranch && selectedBranch !== b.branchId
                                                ? 'border-border-default opacity-40'
                                                : 'border-border-default'
                                    }`}
                                >
                                    {/* Branch Header */}
                                    <div className="flex items-center justify-between mb-4">
                                        <div className="flex items-center gap-2.5">
                                            <div className={`w-8 h-8 rounded-xl flex items-center justify-center ${selectedBranch === b.branchId ? 'bg-brand-red text-white' : 'bg-brand-red/10 text-brand-red'}`}>
                                                <Building2 size={16} />
                                            </div>
                                            <h3 className="text-sm font-black text-text-primary uppercase tracking-tight">{b.branchName}</h3>
                                        </div>
                                        <div className={`flex items-center gap-1 px-2.5 py-1 rounded-full text-[10px] font-black ${b.netProfit >= 0 ? 'bg-emerald-500/10 text-emerald-600' : 'bg-red-500/10 text-red-600'}`}>
                                            {b.netProfit >= 0 ? <TrendingUp size={10} /> : <TrendingDown size={10} />}
                                            {fmt(Math.abs(b.netProfit))}
                                        </div>
                                    </div>

                                    {/* Metrics Row */}
                                    <div className="grid grid-cols-3 gap-2">
                                        <div className="bg-bg-subtle rounded-xl p-2.5 text-center">
                                            <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-0.5">Sales</p>
                                            <p className="text-xs font-black text-emerald-600 font-data">{fmt(b.sales)}</p>
                                            <p className="text-[8px] font-bold text-text-muted mt-0.5">{b.salesCount} txns</p>
                                        </div>
                                        <div className="bg-bg-subtle rounded-xl p-2.5 text-center">
                                            <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-0.5">Purchases</p>
                                            <p className="text-xs font-black text-blue-600 font-data">{fmt(b.purchases)}</p>
                                            <p className="text-[8px] font-bold text-text-muted mt-0.5">{b.purchasesCount} txns</p>
                                        </div>
                                        <div className="bg-bg-subtle rounded-xl p-2.5 text-center">
                                            <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-0.5">Expenses</p>
                                            <p className="text-xs font-black text-amber-600 font-data">{fmt(b.expenses)}</p>
                                            <p className="text-[8px] font-bold text-text-muted mt-0.5">{b.expensesCount} txns</p>
                                        </div>
                                    </div>

                                    {/* Profit Bar */}
                                    <div className="mt-3 bg-bg-subtle rounded-full h-1.5 overflow-hidden">
                                        <div
                                            className={`h-full rounded-full transition-all duration-700 ${b.netProfit >= 0 ? 'bg-emerald-500' : 'bg-red-500'}`}
                                            style={{ width: `${Math.min(100, Math.abs(b.sales > 0 ? (b.netProfit / b.sales) * 100 : 0))}%` }}
                                        />
                                    </div>
                                    <p className="text-[8px] font-black text-text-muted mt-1 text-right uppercase tracking-widest">
                                        {b.sales > 0 ? `${((b.netProfit / b.sales) * 100).toFixed(1)}% margin` : 'No sales'}
                                    </p>
                                </div>
                            ))
                        }
                    </div>

                    {/* Activity Feed */}
                    <div className="bg-bg-surface rounded-[24px] border border-border-default shadow-sm overflow-hidden">
                        {/* Tabs */}
                        <div className="flex items-center gap-1 p-3 border-b border-border-default bg-bg-subtle/30 flex-wrap">
                            {(['all', 'sale', 'purchase', 'expense'] as const).map(tab => {
                                const tabCount = tab === 'all' ? branchFiltered.length : branchFiltered.filter(a => a.type === tab).length;
                                return (
                                    <button
                                        key={tab}
                                        onClick={() => setActiveTab(tab)}
                                        className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${
                                            activeTab === tab
                                                ? 'bg-brand-charcoal text-white shadow-lg'
                                                : 'text-text-muted hover:text-text-primary hover:bg-bg-subtle'
                                        }`}
                                    >
                                        {tab === 'all' ? `All (${tabCount})` :
                                         tab === 'sale' ? `Sales (${tabCount})` :
                                         tab === 'purchase' ? `Purchases (${tabCount})` :
                                         `Expenses (${tabCount})`}
                                    </button>
                                );
                            })}
                            {selectedBranch && (
                                <span className="ml-auto text-[9px] font-black text-brand-red uppercase tracking-widest flex items-center gap-1">
                                    <Building2 size={10} /> {selectedBranchName} only
                                </span>
                            )}
                        </div>

                        {/* Activity List */}
                        <div className="divide-y divide-border-default max-h-[400px] overflow-y-auto custom-scrollbar">
                            {loading ? (
                                [1, 2, 3, 4, 5].map(i => <div key={i} className="p-4 h-14 skeleton" />)
                            ) : filteredActivities.length === 0 ? (
                                <div className="p-10 text-center">
                                    <Package size={28} className="mx-auto text-text-muted mb-2 opacity-30" />
                                    <p className="text-xs font-bold text-text-muted">No activity {selectedBranch ? `for ${selectedBranchName}` : ''} on this date</p>
                                </div>
                            ) : (
                                filteredActivities.slice(0, 50).map((item) => (
                                    <div key={`${item.type}-${item.id}`} className="flex items-center justify-between px-5 py-3 hover:bg-bg-subtle/50 transition-colors">
                                        <div className="flex items-center gap-3 min-w-0 flex-1">
                                            <div className={`w-7 h-7 rounded-lg flex items-center justify-center shrink-0 ${typeColors[item.type]}`}>
                                                {typeIcons[item.type]}
                                            </div>
                                            <div className="min-w-0 flex-1">
                                                <p className="text-xs font-bold text-text-primary truncate">{item.description}</p>
                                                <div className="flex items-center gap-2 mt-0.5">
                                                    {item.invoiceNumber && (
                                                        <span className="text-[9px] font-bold text-text-muted uppercase tracking-wider">{item.invoiceNumber}</span>
                                                    )}
                                                    <span className="text-[9px] font-bold text-text-muted">{format(new Date(item.time), 'h:mm a')}</span>
                                                </div>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-3 shrink-0">
                                            {!selectedBranch && (
                                                <span className="text-[9px] font-black px-2 py-0.5 rounded-full bg-bg-subtle text-text-muted uppercase tracking-wider">{item.branch}</span>
                                            )}
                                            <span className={`text-xs font-black font-data ${item.type === 'sale' ? 'text-emerald-600' : 'text-text-primary'}`}>
                                                {item.type === 'sale' ? '+' : '-'}{fmt(item.amount)}
                                            </span>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

function TotalChip({ label, value, count, color, loading, isProfit }: {
    label: string;
    value: number;
    count: number | null;
    color: string;
    loading: boolean;
    isProfit?: boolean;
}) {
    const fmt = (v: number) => `₱${Math.abs(v).toLocaleString('en-PH', { minimumFractionDigits: 2 })}`;

    return (
        <div className="bg-bg-surface p-3.5 rounded-[20px] border border-border-default shadow-sm">
            <p className="text-[9px] font-black text-text-muted uppercase tracking-widest mb-0.5">{label}</p>
            {loading ? (
                <div className="h-6 w-20 skeleton rounded-lg" />
            ) : (
                <>
                    <p className={`text-base font-black font-data tracking-tight ${
                        isProfit ? (value >= 0 ? 'text-emerald-600' : 'text-red-600') :
                        color === 'emerald' ? 'text-emerald-600' :
                        color === 'blue' ? 'text-blue-600' :
                        color === 'amber' ? 'text-amber-600' : 'text-text-primary'
                    }`}>
                        {isProfit && value >= 0 ? '+' : isProfit && value < 0 ? '-' : ''}{fmt(value)}
                    </p>
                    {count !== null && (
                        <p className="text-[8px] font-bold text-text-muted mt-0.5">{count} txns</p>
                    )}
                </>
            )}
        </div>
    );
}

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { supabase } from '../../shared/lib/supabase';
import {
    format, startOfMonth, endOfMonth,
    eachDayOfInterval, isSameDay, addMonths, subMonths,
    startOfWeek, endOfWeek, isToday
} from 'date-fns';
import {
    DollarSign, ArrowUpRight, ArrowDownRight,
    RefreshCw, Download, Calendar as CalendarIcon, TrendingUp, ChevronLeft, ChevronRight, ShoppingCart, Wallet
} from 'lucide-react';
import { exportToCSV } from '../../shared/lib/exportUtils';
import { useBranch } from '../../shared/lib/BranchContext';

interface DailyStats {
    date: string;
    sales: number;
    purchases: number;
    expenses: number;
    refunds: number;
    returns: number;
}

export default function DailySalesSummary() {
    const { activeBranchId } = useBranch();
    const [currentMonth, setCurrentMonth] = useState(new Date());
    const [selectedDate, setSelectedDate] = useState(new Date());
    const [stats, setStats] = useState<Record<string, DailyStats>>({});
    const [loading, setLoading] = useState(true);

    const fetchMonthlyData = useCallback(async (date: Date) => {
        setLoading(true);
        const start = startOfMonth(date);
        const end = endOfMonth(date);
        const startStr = format(start, 'yyyy-MM-dd');
        const endStr = format(end, 'yyyy-MM-dd');

        try {
            let salesQuery = supabase.from('sales').select('total_price, date').gte('date', startStr).lte('date', endStr);
            let purchasesQuery = supabase.from('purchases').select('total_price, date').gte('date', startStr).lte('date', endStr);
            let expensesQuery = supabase.from('expenses').select('amount, date').gte('date', startStr).lte('date', endStr);
            let refundsQuery = supabase.from('customer_refunds').select('total_price, date').gte('date', startStr).lte('date', endStr);
            let returnsQuery = supabase.from('supplier_returns').select('total_price, date').gte('date', startStr).lte('date', endStr);

            if (activeBranchId) {
                salesQuery = salesQuery.eq('branch_id', activeBranchId);
                purchasesQuery = purchasesQuery.eq('branch_id', activeBranchId);
                expensesQuery = expensesQuery.eq('branch_id', activeBranchId);
                refundsQuery = refundsQuery.eq('branch_id', activeBranchId);
                returnsQuery = returnsQuery.eq('branch_id', activeBranchId);
            }

            const [salesRes, purchasesRes, expensesRes, refundsRes, returnsRes] = await Promise.all([
                salesQuery,
                purchasesQuery,
                expensesQuery,
                refundsQuery,
                returnsQuery
            ]);

            const newStats: Record<string, DailyStats> = {};
            const getD = (d: string) => format(new Date(d), 'yyyy-MM-dd');

            salesRes.data?.forEach(s => {
                const d = getD(s.date);
                if (!newStats[d]) newStats[d] = { date: d, sales: 0, purchases: 0, expenses: 0, refunds: 0, returns: 0 };
                newStats[d].sales += s.total_price || 0;
            });

            purchasesRes.data?.forEach(p => {
                const d = getD(p.date);
                if (!newStats[d]) newStats[d] = { date: d, sales: 0, purchases: 0, expenses: 0, refunds: 0, returns: 0 };
                newStats[d].purchases += p.total_price || 0;
            });

            expensesRes.data?.forEach(e => {
                const d = getD(e.date);
                if (!newStats[d]) newStats[d] = { date: d, sales: 0, purchases: 0, expenses: 0, refunds: 0, returns: 0 };
                newStats[d].expenses += e.amount || 0;
            });

            refundsRes.data?.forEach(r => {
                const d = getD(r.date);
                if (!newStats[d]) newStats[d] = { date: d, sales: 0, purchases: 0, expenses: 0, refunds: 0, returns: 0 };
                newStats[d].refunds += r.total_price || 0;
            });

            returnsRes.data?.forEach(r => {
                const d = getD(r.date);
                if (!newStats[d]) newStats[d] = { date: d, sales: 0, purchases: 0, expenses: 0, refunds: 0, returns: 0 };
                newStats[d].returns += r.total_price || 0;
            });

            setStats(newStats);
        } catch (error) {
            console.error('Error fetching summary data:', error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchMonthlyData(currentMonth);
    }, [currentMonth, fetchMonthlyData]);

    const days = useMemo(() => {
        const start = startOfWeek(startOfMonth(currentMonth), { weekStartsOn: 0 });
        const end = endOfWeek(endOfMonth(currentMonth), { weekStartsOn: 0 });
        return eachDayOfInterval({ start, end });
    }, [currentMonth]);

    const handleExport = () => {
        const dataToExport = Object.values(stats).sort((a, b) => a.date.localeCompare(b.date)).map(s => ({
            Date: s.date,
            Sales: s.sales,
            Purchases: s.purchases,
            Expenses: s.expenses,
            Refunds: s.refunds,
            Returns: s.returns,
            'Net Cashflow': s.sales - s.purchases - s.expenses - s.refunds + s.returns
        }));
        exportToCSV(dataToExport, `Daily_Summary_${format(currentMonth, 'yyyy_MM')}`);
    };

    const selectedStats = stats[format(selectedDate, 'yyyy-MM-dd')] || {
        date: format(selectedDate, 'yyyy-MM-dd'),
        sales: 0, purchases: 0, expenses: 0, refunds: 0, returns: 0
    };

    const netCashflow = selectedStats.sales - selectedStats.purchases - selectedStats.expenses - selectedStats.refunds + selectedStats.returns;

    // Previous day stats for day-over-day comparison
    const prevDay = new Date(selectedDate);
    prevDay.setDate(prevDay.getDate() - 1);
    const prevDayStats = stats[format(prevDay, 'yyyy-MM-dd')] || undefined;

    // Monthly totals for Monthly Snapshot card
    const monthlyTotals = useMemo(() => {
        const vals = Object.values(stats);
        const totalSales = vals.reduce((a, s) => a + s.sales, 0);
        const activeDays = vals.filter(s => s.sales > 0 || s.purchases > 0).length;
        const peakSales = vals.reduce((max, s) => Math.max(max, s.sales), 0);
        return { sales: totalSales, activeDays, peakSales };
    }, [stats]);

    return (
        <div className="space-y-8 animate-fade-in pb-10 bg-base">
            {/* Standard Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-surface rounded-[24px] flex items-center justify-center shadow-xl border border-border-default group transition-all hover:scale-105 active:scale-95">
                        <CalendarIcon className="text-brand-red group-hover:rotate-12 transition-transform" size={28} />
                    </div>
                    <div>
                        <h1 className="text-3xl font-black text-text-primary tracking-tight uppercase">Daily Performance</h1>
                        <p className="text-sm text-text-secondary mt-1 font-medium">Track daily cash flow and transaction highlights</p>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <button onClick={handleExport} className="flex items-center gap-2 bg-surface border border-border-default text-text-secondary px-5 py-3 rounded-2xl font-bold text-sm hover:bg-subtle transition-all shadow-sm active:scale-95">
                        <Download size={18} /> EXPORT MONTH
                    </button>
                    <div className="flex items-center bg-surface border border-border-default rounded-2xl p-1.5 shadow-sm">
                        <button onClick={() => setCurrentMonth(subMonths(currentMonth, 1))} className="p-2 hover:bg-subtle rounded-xl text-text-muted transition-colors"><ChevronLeft size={20} /></button>
                        <span className="px-4 text-sm font-black text-text-primary min-w-[140px] text-center uppercase tracking-widest">{format(currentMonth, 'MMMM yyyy')}</span>
                        <button onClick={() => setCurrentMonth(addMonths(currentMonth, 1))} className="p-2 hover:bg-subtle rounded-xl text-text-muted transition-colors"><ChevronRight size={20} /></button>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-12 gap-6">
                <div className="col-span-12 lg:col-span-8 bg-surface p-6 rounded-[28px] border border-border-default shadow-sm">
                    <div className="grid grid-cols-7 gap-2 mb-6">
                        {['SUN', 'MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT'].map(day => (
                            <div key={day} className="text-center py-2 text-[10px] font-black text-text-muted tracking-[0.2em] uppercase">{day}</div>
                        ))}
                    </div>
                    <div className="grid grid-cols-7 gap-3">
                        {days.map(day => {
                            const dateStr = format(day, 'yyyy-MM-dd');
                            const dayStats = stats[dateStr];
                            const isSelected = isSameDay(day, selectedDate);
                            const isCurrentMonth = day.getMonth() === currentMonth.getMonth();
                            return (
                                <button key={dateStr} onClick={() => setSelectedDate(day)}
                                    className={`relative min-h-[90px] p-2.5 rounded-[20px] border-2 transition-all flex flex-col group ${isSelected ? 'border-brand-red bg-brand-red/10' : isCurrentMonth ? 'border-border-default bg-subtle/50 hover:border-brand-red/50 hover:bg-surface' : 'border-transparent opacity-30 pointer-events-none'}`}>
                                    <span className={`text-xs font-black ${isSelected ? 'text-brand-red' : 'text-text-muted'} ${isToday(day) ? 'bg-brand-red text-white w-5 h-5 flex items-center justify-center rounded-full' : ''}`}>{format(day, 'd')}</span>
                                    <div className="mt-auto space-y-1.5">
                                        {dayStats && dayStats.sales > 0 && <div className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-brand-red shadow-red" /><span className="text-[10px] font-black text-text-primary">₱{Math.round(dayStats.sales / 1000)}k</span></div>}
                                        {dayStats && dayStats.purchases > 0 && <div className="flex items-center gap-1.5"><div className="w-1.5 h-1.5 rounded-full bg-border-strong" /><span className="text-[10px] font-black text-text-secondary">₱{Math.round(dayStats.purchases / 1000)}k</span></div>}
                                    </div>
                                    {isSelected && <div className="absolute top-3 right-3 w-2 h-2 bg-brand-red rounded-full shadow-red animate-pulse" />}
                                </button>
                            );
                        })}
                    </div>
                </div>

                <div className="col-span-12 lg:col-span-4 flex flex-col gap-6">
                    <div className="bg-surface p-6 rounded-[28px] border border-border-default shadow-sm relative overflow-hidden">
                        <div className="absolute top-0 left-0 w-1 h-full bg-brand-red" />
                        <div className="flex items-center justify-between mb-6">
                            <h3 className="font-black text-text-primary text-xs uppercase tracking-[0.2em]">{format(selectedDate, 'MMMM d, yyyy')}</h3>
                            <div className="px-3 py-1 bg-subtle rounded-full text-[9px] font-black text-text-muted uppercase tracking-widest">{format(selectedDate, 'EEEE')}</div>
                        </div>

                        {/* Enhanced Detail Rows with Progress Bars */}
                        <div className="space-y-4">
                            <EnhancedDetailRow
                                icon={<DollarSign size={16} />}
                                label="Daily Sales"
                                value={selectedStats.sales}
                                color="text-brand-red"
                                bg="bg-brand-red/10"
                                barColor="bg-brand-red"
                                total={Math.max(selectedStats.sales, selectedStats.purchases, selectedStats.expenses, selectedStats.refunds, selectedStats.returns, 1)}
                                prevValue={prevDayStats?.sales}
                            />
                            <EnhancedDetailRow
                                icon={<ShoppingCart size={16} />}
                                label="Purchases"
                                value={selectedStats.purchases}
                                color="text-blue-600"
                                bg="bg-blue-500/10"
                                barColor="bg-blue-500"
                                total={Math.max(selectedStats.sales, selectedStats.purchases, selectedStats.expenses, selectedStats.refunds, selectedStats.returns, 1)}
                                prevValue={prevDayStats?.purchases}
                            />
                            <EnhancedDetailRow
                                icon={<Wallet size={16} />}
                                label="Expenses"
                                value={selectedStats.expenses}
                                color="text-amber-600"
                                bg="bg-amber-500/10"
                                barColor="bg-amber-500"
                                total={Math.max(selectedStats.sales, selectedStats.purchases, selectedStats.expenses, selectedStats.refunds, selectedStats.returns, 1)}
                                prevValue={prevDayStats?.expenses}
                            />
                            <EnhancedDetailRow
                                icon={<ArrowDownRight size={16} />}
                                label="Refunds"
                                value={selectedStats.refunds}
                                color="text-brand-orange"
                                bg="bg-warning-subtle"
                                barColor="bg-brand-orange"
                                total={Math.max(selectedStats.sales, selectedStats.purchases, selectedStats.expenses, selectedStats.refunds, selectedStats.returns, 1)}
                                prevValue={prevDayStats?.refunds}
                            />
                            <EnhancedDetailRow
                                icon={<ArrowUpRight size={16} />}
                                label="Returns"
                                value={selectedStats.returns}
                                color="text-purple-600"
                                bg="bg-purple-500/10"
                                barColor="bg-purple-500"
                                total={Math.max(selectedStats.sales, selectedStats.purchases, selectedStats.expenses, selectedStats.refunds, selectedStats.returns, 1)}
                                prevValue={prevDayStats?.returns}
                            />
                        </div>

                        {/* Net Cashflow with Status */}
                        <div className="mt-8 pt-6 border-t border-border-default">
                            <div className="flex items-center justify-between mb-4">
                                <div>
                                    <p className="text-[10px] font-black text-text-muted uppercase tracking-widest mb-1">Net Cashflow</p>
                                    <p className={`text-2xl font-black font-data ${netCashflow >= 0 ? 'text-emerald-600' : 'text-brand-red'}`}>₱{netCashflow.toLocaleString('en-PH', { minimumFractionDigits: 2 })}</p>
                                </div>
                                <div className={`w-12 h-12 rounded-[18px] flex items-center justify-center transition-all ${netCashflow >= 0 ? 'bg-emerald-500/10 text-emerald-600' : 'bg-brand-red/10 text-brand-red shadow-red-light'}`}>
                                    <TrendingUp size={24} className={netCashflow < 0 ? 'rotate-180' : ''} />
                                </div>
                            </div>
                            {/* Status Badge */}
                            <div className={`flex items-center gap-2 px-4 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest ${
                                netCashflow > 10000 ? 'bg-emerald-500/10 text-emerald-600 border border-emerald-500/20' :
                                netCashflow > 0 ? 'bg-subtle text-text-secondary border border-border-default' :
                                'bg-brand-red/10 text-brand-red border border-brand-red/20'
                            }`}>
                                <div className={`w-2 h-2 rounded-full ${netCashflow > 10000 ? 'bg-emerald-500 animate-pulse' : netCashflow > 0 ? 'bg-text-muted' : 'bg-brand-red animate-pulse'}`} />
                                {netCashflow > 10000 ? 'Strong Day' : netCashflow > 0 ? 'Normal Activity' : netCashflow === 0 ? 'No Activity' : 'Net Loss'}
                            </div>
                        </div>
                    </div>

                    {/* Monthly Summary Card */}
                    <div className="bg-surface p-6 rounded-[32px] border border-border-default shadow-sm">
                        <h4 className="text-[10px] font-black text-text-muted uppercase tracking-[0.2em] mb-4">Monthly Snapshot</h4>
                        <div className="grid grid-cols-2 gap-3">
                            <div className="bg-subtle rounded-2xl p-3 border border-border-default">
                                <p className="text-[9px] font-black text-text-muted uppercase tracking-widest mb-0.5">Total Sales</p>
                                <p className="text-sm font-black text-text-primary font-data">₱{monthlyTotals.sales.toLocaleString('en-PH', { minimumFractionDigits: 0 })}</p>
                            </div>
                            <div className="bg-subtle rounded-2xl p-3 border border-border-default">
                                <p className="text-[9px] font-black text-text-muted uppercase tracking-widest mb-0.5">Active Days</p>
                                <p className="text-sm font-black text-text-primary font-data">{monthlyTotals.activeDays} <span className="text-text-muted text-[9px] font-bold">days</span></p>
                            </div>
                            <div className="bg-subtle rounded-2xl p-3 border border-border-default">
                                <p className="text-[9px] font-black text-text-muted uppercase tracking-widest mb-0.5">Avg / Day</p>
                                <p className="text-sm font-black text-text-primary font-data">₱{monthlyTotals.activeDays > 0 ? Math.round(monthlyTotals.sales / monthlyTotals.activeDays).toLocaleString() : '0'}</p>
                            </div>
                            <div className="bg-subtle rounded-2xl p-3 border border-border-default">
                                <p className="text-[9px] font-black text-text-muted uppercase tracking-widest mb-0.5">Peak Day</p>
                                <p className="text-sm font-black text-brand-red font-data">₱{monthlyTotals.peakSales.toLocaleString()}</p>
                            </div>
                        </div>
                    </div>

                    {/* Efficiency Insight Card */}
                    <div className="bg-brand-charcoal p-8 rounded-[40px] text-white relative overflow-hidden group shadow-2xl">
                        <div className="absolute -top-10 -right-10 w-40 h-40 bg-brand-red/10 rounded-full transition-transform duration-700 group-hover:scale-125 blur-2xl" />
                        <div className="relative z-10">
                            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-4">Efficiency Insight</h3>
                            <div className="grid grid-cols-2 gap-4 mb-6">
                                <div>
                                    <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Sales Ratio</p>
                                    <p className="text-lg font-black font-data text-white">
                                        {selectedStats.sales > 0 && selectedStats.purchases > 0
                                            ? `${(selectedStats.sales / selectedStats.purchases).toFixed(1)}x`
                                            : '—'}
                                    </p>
                                </div>
                                <div>
                                    <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Expense Rate</p>
                                    <p className="text-lg font-black font-data text-brand-red">
                                        {selectedStats.sales > 0
                                            ? `${((selectedStats.purchases + selectedStats.expenses) / selectedStats.sales * 100).toFixed(0)}%`
                                            : '—'}
                                    </p>
                                </div>
                            </div>
                            <p className="text-xs text-slate-300 leading-relaxed font-medium">
                                "{netCashflow > 50000 ? 'Peak distribution performance. Maintain inventory buffers.' : netCashflow < 0 ? 'Liquidity warning. Optimize purchase cycles and overhead.' : 'Sustained throughput. Monitor daily transaction logs for outliers.'}"
                            </p>
                        </div>
                    </div>
                </div>
            </div>
            {loading && <div className="fixed inset-0 bg-surface/50 backdrop-blur-sm flex items-center justify-center z-50"><RefreshCw size={24} className="animate-spin text-brand-red" /></div>}
        </div>
    );
}

function EnhancedDetailRow({ icon, label, value, color, bg, barColor, total, prevValue }: { icon: React.ReactNode, label: string, value: number, color: string, bg: string, barColor: string, total: number, prevValue?: number }) {
    const pct = total > 0 ? Math.min((value / total) * 100, 100) : 0;
    const change = prevValue !== undefined && prevValue > 0 ? ((value - prevValue) / prevValue) * 100 : null;

    return (
        <div className="group">
            <div className="flex items-center justify-between mb-1.5">
                <div className="flex items-center gap-2.5">
                    <div className={`w-7 h-7 rounded-lg ${bg} flex items-center justify-center ${color} transition-transform group-hover:scale-110`}>{icon}</div>
                    <span className="text-[11px] font-bold text-text-secondary uppercase tracking-tight">{label}</span>
                </div>
                <div className="flex items-center gap-2">
                    {change !== null && (
                        <span className={`text-[9px] font-black flex items-center gap-0.5 ${change >= 0 ? 'text-emerald-600' : 'text-brand-red'}`}>
                            {change >= 0 ? <ArrowUpRight size={10} /> : <ArrowDownRight size={10} />}
                            {Math.abs(Math.round(change))}%
                        </span>
                    )}
                    <span className={`text-sm font-black font-data ${color}`}>₱{value.toLocaleString('en-PH', { minimumFractionDigits: 2 })}</span>
                </div>
            </div>
            {/* Progress bar */}
            <div className="h-1.5 bg-subtle rounded-full overflow-hidden ml-9">
                <div className={`h-full ${barColor} rounded-full transition-all duration-700`} style={{ width: `${pct}%` }} />
            </div>
        </div>
    );
}

import React, { useEffect, useState, useCallback, useMemo } from 'react';
import { supabase } from '../../shared/lib/supabase';
import { isSameDay, startOfDay, endOfDay, format } from 'date-fns';
import { useBranch } from '../../shared/lib/BranchContext';
import {
    BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip,
    ResponsiveContainer, AreaChart, Area
} from 'recharts';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../shared/hooks/useAuth';
import {
    DollarSign, Package, ArrowUpRight, ArrowDownRight,
    Clock,
    Plus, ShoppingCart, LayoutDashboard, RotateCcw,
    Lock, CheckCircle2, Zap, BarChart3, TrendingUp
} from 'lucide-react';
import { useTheme } from '../../shared/hooks/useTheme';
import ProductModal from '../inventory/components/ProductModal';
import SalesModal from '../sales/components/SalesModal';
import ReportModal from '../../features/reports/components/ReportModal';
import Calendar from '../../features/reports/components/Calendar';

interface DailyStat {
    totalSales: number;
    itemsSold: number;
    transactionCount: number;
    totalPurchases: number;
    totalRefunds: number;
}

interface LowStockItem {
    id: string;
    name: string;
    stock_available: number;
}

interface RecentSale {
    id: string;
    quantity: number;
    total_price: number;
    date: string;
    invoice_number: string;
    is_finalized?: boolean;
    customer_name?: string;
    fulfillment_status?: string;
    payment_mode?: string;
    is_os?: boolean;
    products: { name: string; brand?: string; id: string; selling_price: number; stock_available: number; } | null;
}

interface WeeklyPoint {
    day: string;
    sales: number;
    purchases: number;
}

interface SupabaseSale {
    total_price: number;
    date: string;
    quantity: number;
}

interface SupabasePurchase {
    total_price: number;
    discount_amount: number;
    date: string;
}

export default function Dashboard() {
    const [stats, setStats] = useState<DailyStat>({ totalSales: 0, itemsSold: 0, transactionCount: 0, totalPurchases: 0, totalRefunds: 0 });
    const [prevStats, setPrevStats] = useState<DailyStat>({ totalSales: 0, itemsSold: 0, transactionCount: 0, totalPurchases: 0, totalRefunds: 0 });
    const [weeklyData, setWeeklyData] = useState<WeeklyPoint[]>([]);
    const [lowStockItems, setLowStockItems] = useState<LowStockItem[]>([]);
    const [recentSales, setRecentSales] = useState<RecentSale[]>([]);
    const [dateRange, setDateRange] = useState<{ start: Date, end: Date }>({
        start: new Date(),
        end: new Date()
    });
    const [isDateRangeActive, setIsDateRangeActive] = useState(false);
    const [loading, setLoading] = useState(true);
    const { role } = useAuth();
    const { activeBranchId } = useBranch();
    const [selectedLowStockProduct, setSelectedLowStockProduct] = useState<LowStockItem | null>(null);
    const [isLowStockModalOpen, setIsLowStockModalOpen] = useState(false);
    const [isReportModalOpen, setIsReportModalOpen] = useState(false);
    const [isClosing, setIsClosing] = useState(false);
    const [isDayClosed, setIsDayClosed] = useState(false);
    const [selectedSaleForEdit, setSelectedSaleForEdit] = useState<any>(null);
    const [isSalesModalOpen, setIsSalesModalOpen] = useState(false);
    const navigate = useNavigate();
    const { theme } = useTheme();
    const isDark = theme === 'dark';
    const [chartMode, setChartMode] = useState<'bar' | 'area'>('bar');

    const chartColors = {
        grid: isDark ? '#30363D' : '#DEE2E6',
        text: isDark ? '#8B949E' : '#495057',
        tooltip: isDark ? '#161B22' : '#FFFFFF',
        series: ['#388BFD', '#3FB950', '#D29922', '#F85149', '#A371F7']
    };

    const fetchDashboardData = useCallback(async (start?: Date, end?: Date) => {
        setLoading(true);
        const filterStart = start || dateRange.start;
        const filterEnd = end || dateRange.end;

        const rangeStart = startOfDay(filterStart).toISOString();
        const rangeEnd = endOfDay(filterEnd).toISOString();

        // Previous period for trend calculation
        const diff = filterEnd.getTime() - filterStart.getTime();
        const prevEnd = new Date(filterStart.getTime() - 1);
        const prevStart = new Date(prevEnd.getTime() - diff);
        const yesterdayStart = startOfDay(prevStart).toISOString();
        const yesterdayEnd = endOfDay(prevEnd).toISOString();

        let sQuery = supabase
            .from('sales')
            .select('quantity, total_price, date, products(name)')
            .gte('date', rangeStart)
            .lte('date', rangeEnd);

        let psQuery = supabase
            .from('sales')
            .select('quantity, total_price')
            .gte('date', yesterdayStart)
            .lte('date', yesterdayEnd);

        let pQuery = supabase
            .from('purchases')
            .select('total_price, vat_amount, discount_amount, date')
            .gte('date', rangeStart)
            .lte('date', rangeEnd);

        let rQuery = supabase
            .from('customer_refunds')
            .select('total_price, date')
            .gte('date', rangeStart)
            .lte('date', rangeEnd);

        let prodQuery = supabase
            .from('products')
            .select('id, name, stock_available, low_stock_threshold')
            .order('stock_available', { ascending: true });

        let recentQuery = supabase
            .from('sales')
            .select('id, quantity, total_price, date, invoice_number, is_finalized, customer_name, fulfillment_status, payment_mode, is_os, products(id, name, brand, selling_price, stock_available)')
            .order('date', { ascending: false })
            .limit(10);

        if (activeBranchId) {
            sQuery = sQuery.eq('branch_id', activeBranchId);
            psQuery = psQuery.eq('branch_id', activeBranchId);
            pQuery = pQuery.eq('branch_id', activeBranchId);
            rQuery = rQuery.eq('branch_id', activeBranchId);
            prodQuery = prodQuery.eq('branch_id', activeBranchId);
            recentQuery = recentQuery.eq('branch_id', activeBranchId);
        }

        const [{ data: currentSales }, { data: previousSales }, { data: currentPurchases }, { data: currentRefunds }, { data: allProducts }, { data: recent }] = await Promise.all([
            sQuery, psQuery, pQuery, rQuery, prodQuery, recentQuery
        ]);

        const lowStock = (allProducts || []).filter(p => p.stock_available <= (p.low_stock_threshold || 10)).slice(0, 5);

        const sales = (currentSales as unknown as SupabaseSale[]) || [];
        const purchases = (currentPurchases as unknown as SupabasePurchase[]) || [];
        const prevSales = (previousSales as unknown as SupabaseSale[]) || [];

        const refunds = (currentRefunds as unknown as { total_price: number; date: string }[]) || [];

        const currentStats: DailyStat = {
            totalSales: sales.reduce((a, s) => a + (s.total_price || 0), 0),
            itemsSold: sales.reduce((a, s) => a + (s.quantity || 0), 0),
            transactionCount: sales.length,
            totalPurchases: purchases.reduce((a, p) => a + ((p.total_price || 0) - (p.discount_amount || 0)), 0),
            totalRefunds: refunds.reduce((a, r) => a + (r.total_price || 0), 0),
        };
        const pStats: DailyStat = {
            totalSales: prevSales.reduce((a, s) => a + (s.total_price || 0), 0),
            itemsSold: prevSales.reduce((a, s) => a + (s.quantity || 0), 0),
            transactionCount: prevSales.length,
            totalPurchases: 0,
            totalRefunds: 0,
        };

        setStats(currentStats);
        setPrevStats(pStats);

        // Map data for chart based on selection
        const chartData: WeeklyPoint[] = [];
        if (!isDateRangeActive || isSameDay(filterStart, filterEnd)) {
            // Show hourly trend if single day? Actually user asked for summary day ONLY.
            // Let's show day of week comparison or just the single point for now.
            chartData.push({
                day: format(filterStart, 'MMM d'),
                sales: currentStats.totalSales,
                purchases: currentStats.totalPurchases
            });
        } else {
            // Show trend over range — use ISO date keys for proper sorting
            const dayMap: Record<string, { sales: number; purchases: number }> = {};
            sales.forEach(s => {
                const day = format(new Date(s.date), 'yyyy-MM-dd');
                if (!dayMap[day]) dayMap[day] = { sales: 0, purchases: 0 };
                dayMap[day].sales += s.total_price || 0;
            });
            purchases.forEach(p => {
                const day = format(new Date(p.date), 'yyyy-MM-dd');
                if (!dayMap[day]) dayMap[day] = { sales: 0, purchases: 0 };
                dayMap[day].purchases += (p.total_price || 0) - (p.discount_amount || 0);
            });
            Object.entries(dayMap)
                .sort(([a], [b]) => a.localeCompare(b))
                .forEach(([isoDay, vals]) => {
                    chartData.push({ day: format(new Date(isoDay), 'MMM d'), ...vals });
                });
        }
        setWeeklyData(chartData);
        setLowStockItems((lowStock as LowStockItem[]) || []);
        setRecentSales((recent as unknown as RecentSale[]) || []);
        let closingQuery = supabase
            .from('daily_closings')
            .select('*')
            .eq('date', format(rangeStart, 'yyyy-MM-dd'));

        if (activeBranchId) {
            closingQuery = closingQuery.eq('branch_id', activeBranchId);
        }

        const { data: closing } = await closingQuery.maybeSingle();

        setIsDayClosed(!!closing);
        setLoading(false);
    }, [isDateRangeActive, dateRange, activeBranchId]);

    useEffect(() => {
        let mounted = true;
        const load = async () => {
            if (mounted) await fetchDashboardData();
        };
        load();
        const channel = supabase.channel('dashboard_updates')
            .on('postgres_changes', { event: '*', schema: 'public', table: 'sales' }, () => { if (mounted) fetchDashboardData(); })
            .on('postgres_changes', { event: '*', schema: 'public', table: 'purchases' }, () => { if (mounted) fetchDashboardData(); })
            .on('postgres_changes', { event: '*', schema: 'public', table: 'products' }, () => { if (mounted) fetchDashboardData(); })
            .subscribe();
        return () => {
            mounted = false;
            supabase.removeChannel(channel);
        };
    }, [fetchDashboardData]);

    const handleDateSelect = (date: Date) => {
        if (!isDateRangeActive) {
            const newRange = { start: date, end: date };
            setDateRange(newRange);
            fetchDashboardData(newRange.start, newRange.end);
            return;
        }

        if (!dateRange.start || (dateRange.start && dateRange.end && !isSameDay(dateRange.start, dateRange.end))) {
            setDateRange({ start: date, end: date });
        } else {
            const newRange = date < dateRange.start
                ? { start: date, end: dateRange.start }
                : { start: dateRange.start, end: date };
            setDateRange(newRange);
            fetchDashboardData(newRange.start, newRange.end);
        }
    };

    const activeDates = useMemo(() => {
        // This is expensive if we have 1000s of sales, but okay for overview
        return []; // Dynamic fetch would be better but let's keep it simple
    }, []);


    const getTrend = useCallback((current: number, previous: number) => {
        if (previous === 0) return current > 0 ? 100 : 0;
        return ((current - previous) / previous) * 100;
    }, []);

    const revenueTrend = useMemo(() => getTrend(stats.totalSales, prevStats.totalSales), [stats.totalSales, prevStats.totalSales, getTrend]);

    const handleCloseDay = async () => {
        if (isDayClosed) return;
        if (!window.confirm('Are you sure you want to close the register for today? This will finalize all transactions.')) return;

        setIsClosing(true);
        try {
            const today = format(dateRange.start, 'yyyy-MM-dd');

            // 1. Finalize transactions
            let sFinQuery = supabase.from('sales').update({ is_finalized: true }).eq('is_finalized', false).gte('date', startOfDay(dateRange.start).toISOString()).lte('date', endOfDay(dateRange.start).toISOString());
            let pFinQuery = supabase.from('purchases').update({ is_finalized: true }).eq('is_finalized', false).gte('date', startOfDay(dateRange.start).toISOString()).lte('date', endOfDay(dateRange.start).toISOString());

            if (activeBranchId) {
                sFinQuery = sFinQuery.eq('branch_id', activeBranchId);
                pFinQuery = pFinQuery.eq('branch_id', activeBranchId);
            }

            await Promise.all([
                sFinQuery,
                pFinQuery
            ]);

            // 2. Create closing entry
            const { error } = await supabase.from('daily_closings').insert({
                date: today,
                total_sales: stats.totalSales,
                closed_by: (await supabase.auth.getUser()).data.user?.id,
                branch_id: activeBranchId
            });

            if (error) throw error;
            setIsDayClosed(true);
            alert('Register closed successfully for ' + today);
        } catch (err) {
            console.error('Closing failed:', err);
            alert('Error closing register. Please run SQL migration if you haven\'t yet.');
        } finally {
            setIsClosing(true);
        }
    };

    const handleEditSale = (sale: RecentSale) => {
        if (sale.is_finalized) {
            alert('This transaction is finalized and cannot be edited.');
            return;
        }

        setSelectedSaleForEdit({
            invoiceNumber: sale.invoice_number,
            customerName: sale.customer_name,
            fulfillmentStatus: sale.fulfillment_status,
            paymentMode: sale.payment_mode,
            is_os: sale.is_os,
            date: sale.date,
            items: [{
                product_id: sale.products?.id || '',
                name: sale.products?.name || '',
                brand: sale.products?.brand || '',
                quantity: sale.quantity,
                unit_price: (sale.products?.selling_price || 0),
                total_price: sale.total_price,
                stock_available: sale.products?.stock_available || 0
            }],
            isVatEnabled: !sale.is_os,
            isDiscountEnabled: false
        });
        setIsSalesModalOpen(true);
    };

    return (
        <div className="space-y-6 animate-fade-in pb-10">
            {/* Calming Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-bg-surface rounded-[20px] flex items-center justify-center shadow-lg border border-border-default group transition-all hover:scale-105 active:scale-95">
                        <LayoutDashboard className="text-brand-red group-hover:rotate-12 transition-transform" size={28} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-black text-text-primary tracking-tight">Overview</h1>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <button
                        onClick={() => navigate('/express-sales')}
                        className="flex items-center gap-2 bg-emerald-600 text-white px-5 py-2.5 rounded-2xl font-black text-xs hover:bg-emerald-700 transition-all shadow-lg active:scale-95"
                    >
                        <Zap size={18} /> EXPRESS ENTRY
                    </button>
                    <button
                        onClick={handleCloseDay}
                        disabled={isDayClosed || isClosing}
                        className={`flex items-center gap-2 px-5 py-2.5 rounded-2xl font-black text-xs transition-all shadow-lg active:scale-95 ${isDayClosed ? 'bg-muted text-text-muted cursor-not-allowed' : 'bg-brand-red text-white hover:bg-brand-red-dark shadow-red'}`}
                    >
                        {isDayClosed ? <><CheckCircle2 size={18} /> REGISTER CLOSED</> : <><Lock size={18} /> {isClosing ? 'CLOSING...' : 'CLOSE REGISTER'}</>}
                    </button>
                    <button onClick={() => setIsReportModalOpen(true)} className="flex items-center gap-2 bg-text-primary text-text-inverse px-5 py-2.5 rounded-2xl font-black text-xs hover:opacity-90 transition-all shadow-lg active:scale-95">
                        <Plus size={18} /> GENERATE REPORT
                    </button>
                </div>
            </div>


            <div className="flex flex-col lg:flex-row gap-6">
                {/* Left Controls Sidebar */}
                <div className="flex-shrink-0 w-full lg:w-80">
                    <div className="sticky top-6 space-y-5">
                        {/* Dynamic Calendar */}
                        <div className="bg-bg-surface p-5 rounded-[28px] border border-border-default shadow-sm space-y-4">
                            <div className="space-y-4">
                                <div className="flex items-center justify-between">
                                    <h3 className="text-[10px] font-black text-text-secondary uppercase tracking-[0.2em]">Summary Period</h3>
                                    <button
                                        onClick={() => setIsDateRangeActive(!isDateRangeActive)}
                                        className={`text-[9px] font-black px-3 py-1 rounded-full uppercase transition-all ${isDateRangeActive ? 'bg-brand-red text-white shadow-red' : 'bg-muted text-text-muted'}`}
                                    >
                                        {isDateRangeActive ? 'Range' : 'Single Day'}
                                    </button>
                                </div>
                                <div className="flex items-center justify-between bg-bg-subtle/80 p-3 rounded-2xl border border-border-default/50">
                                    <span className="text-[10px] font-black text-text-muted uppercase tracking-widest">
                                        Active Selection
                                    </span>
                                    {(dateRange.start && dateRange.end) && (
                                        <span className="text-[10px] font-black text-brand-red">
                                            {isDateRangeActive && !isSameDay(dateRange.start, dateRange.end)
                                                ? `${format(dateRange.start, 'MMM d')} - ${format(dateRange.end, 'MMM d')}`
                                                : format(dateRange.start, 'MMM d, yyyy')}
                                        </span>
                                    )}
                                </div>
                                <Calendar
                                    selectedDate={dateRange.start}
                                    onDateSelect={handleDateSelect}
                                    rangeStart={isDateRangeActive ? dateRange.start : null}
                                    rangeEnd={isDateRangeActive ? dateRange.end : null}
                                    activeDates={activeDates}
                                />
                            </div>
                        </div>

                        {/* Low Stock Indicator */}
                        <div className="bg-bg-surface p-5 rounded-[28px] border border-border-default shadow-sm">
                            <div className="flex items-center justify-between mb-4">
                                <h3 className="text-[10px] font-black text-text-secondary uppercase tracking-[0.2em]">Critical Stock</h3>
                                <span className="text-[10px] font-bold bg-brand-orange/10 text-brand-orange px-2 py-0.5 rounded-full">{lowStockItems.length}</span>
                            </div>
                            <div className="space-y-4">
                                {loading ? [1, 2, 3].map(i => <div key={i} className="h-12 skeleton rounded-2xl" />) :
                                    lowStockItems.map(item => (
                                        <div key={item.id} className="flex items-center justify-between group cursor-pointer" onClick={() => navigate('/inventory')}>
                                            <div className="flex items-center gap-3">
                                                <div className="w-8 h-8 rounded-xl bg-orange-500/10 text-brand-orange flex items-center justify-center"><Package size={14} /></div>
                                                <p className="text-xs font-bold text-text-primary group-hover:text-brand-red transition-colors">{item.name}</p>
                                            </div>
                                            <span className="text-xs font-black text-brand-red font-data">{item.stock_available}</span>
                                        </div>
                                    ))
                                }
                            </div>
                        </div>
                    </div>
                </div>

                {/* Main Content Area */}
                <div className="flex-1 min-w-0 space-y-6">
                    {/* Key Metrics Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <MetricCard icon={<DollarSign size={18} />} label="Sales" value={stats.totalSales} trend={revenueTrend} loading={loading} onClick={() => navigate('/sales')} isCurrency />
                        <MetricCard icon={<ShoppingCart size={18} />} label="Purchases" value={stats.totalPurchases} trend={0} loading={loading} onClick={() => navigate('/purchases')} isCurrency />
                        <MetricCard icon={<RotateCcw size={18} />} label="Returns" value={stats.totalRefunds} trend={0} loading={loading} onClick={() => navigate('/customer-refunds')} isCurrency />
                    </div>

                    {/* Performance Visualization */}
                    <div className="bg-bg-surface p-6 rounded-[28px] border border-border-default shadow-sm">
                        <div className="flex items-center justify-between mb-6">
                            <div>
                                <h3 className="text-lg font-black text-text-primary uppercase tracking-tight">Flow Analysis</h3>
                            </div>
                            <div className="flex items-center gap-3">
                                <div className="flex gap-4 items-center mr-4">
                                    <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-brand-red shadow-red" /><span className="text-[10px] font-black text-text-secondary uppercase tracking-widest">Revenue</span></div>
                                    <div className="flex items-center gap-2"><div className="w-3 h-3 rounded-full bg-bg-muted border border-border-default" /><span className="text-[10px] font-black text-text-secondary uppercase tracking-widest">Expenses</span></div>
                                </div>
                                <div className="flex bg-subtle rounded-xl p-1 border border-border-default">
                                    <button
                                        onClick={() => setChartMode('bar')}
                                        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${chartMode === 'bar' ? 'bg-brand-charcoal text-white shadow-lg' : 'text-text-muted hover:text-text-primary'}`}
                                    >
                                        <BarChart3 size={12} /> Bar
                                    </button>
                                    <button
                                        onClick={() => setChartMode('area')}
                                        className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${chartMode === 'area' ? 'bg-brand-charcoal text-white shadow-lg' : 'text-text-muted hover:text-text-primary'}`}
                                    >
                                        <TrendingUp size={12} /> Area
                                    </button>
                                </div>
                            </div>
                        </div>

                        {/* Summary Stat Chips */}
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-3 mb-6">
                            <div className="bg-subtle rounded-2xl p-4 border border-border-default">
                                <p className="text-[9px] font-black text-text-muted uppercase tracking-widest mb-1">Total Revenue</p>
                                <p className="text-lg font-black text-text-primary font-data">₱{stats.totalSales.toLocaleString('en-PH', { minimumFractionDigits: 2 })}</p>
                            </div>
                            <div className="bg-subtle rounded-2xl p-4 border border-border-default">
                                <p className="text-[9px] font-black text-text-muted uppercase tracking-widest mb-1">Total Expenses</p>
                                <p className="text-lg font-black text-text-secondary font-data">₱{stats.totalPurchases.toLocaleString('en-PH', { minimumFractionDigits: 2 })}</p>
                            </div>
                            <div className="bg-subtle rounded-2xl p-4 border border-border-default">
                                <p className="text-[9px] font-black text-text-muted uppercase tracking-widest mb-1">Net Flow</p>
                                <p className={`text-lg font-black font-data ${(stats.totalSales - stats.totalPurchases) >= 0 ? 'text-emerald-600' : 'text-brand-red'}`}>
                                    {(stats.totalSales - stats.totalPurchases) >= 0 ? '+' : ''}₱{(stats.totalSales - stats.totalPurchases).toLocaleString('en-PH', { minimumFractionDigits: 2 })}
                                </p>
                            </div>
                            <div className="bg-subtle rounded-2xl p-4 border border-border-default">
                                <p className="text-[9px] font-black text-text-muted uppercase tracking-widest mb-1">Margin</p>
                                <p className={`text-lg font-black font-data ${stats.totalSales > 0 && ((stats.totalSales - stats.totalPurchases) / stats.totalSales * 100) > 0 ? 'text-emerald-600' : 'text-brand-red'}`}>
                                    {stats.totalSales > 0 ? `${(((stats.totalSales - stats.totalPurchases) / stats.totalSales) * 100).toFixed(1)}%` : '—'}
                                </p>
                            </div>
                        </div>

                        <div className="h-[300px]">
                            <ResponsiveContainer width="100%" height="100%">
                                {chartMode === 'bar' ? (
                                    <BarChart data={weeklyData} margin={{ top: 5, right: 5, left: -20, bottom: 0 }}>
                                        <CartesianGrid strokeDasharray="8 8" vertical={false} stroke={chartColors.grid} />
                                        <XAxis dataKey="day" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: chartColors.text }} />
                                        <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: chartColors.text }} tickFormatter={(v) => `₱${(v / 1000).toFixed(0)}k`} />
                                        <Tooltip
                                            cursor={{ fill: isDark ? '#FFFFFF05' : '#EE3E3E08' }}
                                            contentStyle={{
                                                borderRadius: '20px',
                                                border: 'none',
                                                boxShadow: '0 20px 40px rgba(0,0,0,0.15)',
                                                padding: '16px 20px',
                                                backgroundColor: chartColors.tooltip,
                                                color: chartColors.text
                                            }}
                                            formatter={(v: any, name: any) => [
                                                `₱${Number(v).toLocaleString()}`,
                                                name === 'Revenue' ? '● Revenue' : '● Expense'
                                            ]}
                                            itemStyle={{ fontWeight: 900, fontSize: 12 }}
                                            labelStyle={{ fontWeight: 900, textTransform: 'uppercase', letterSpacing: '0.1em', fontSize: 10, marginBottom: 6 }}
                                        />
                                        <Bar dataKey="sales" name="Revenue" fill="#EE3E3E" radius={[8, 8, 0, 0]} barSize={32} />
                                        <Bar dataKey="purchases" name="Expense" fill={isDark ? '#30363D' : '#CBD5E1'} radius={[8, 8, 0, 0]} barSize={32} />
                                    </BarChart>
                                ) : (
                                    <AreaChart data={weeklyData} margin={{ top: 5, right: 5, left: -20, bottom: 0 }}>
                                        <defs>
                                            <linearGradient id="salesGrad" x1="0" y1="0" x2="0" y2="1">
                                                <stop offset="0%" stopColor="#EE3E3E" stopOpacity={0.3} />
                                                <stop offset="100%" stopColor="#EE3E3E" stopOpacity={0.02} />
                                            </linearGradient>
                                            <linearGradient id="purchasesGrad" x1="0" y1="0" x2="0" y2="1">
                                                <stop offset="0%" stopColor={isDark ? '#30363D' : '#94A3B8'} stopOpacity={0.3} />
                                                <stop offset="100%" stopColor={isDark ? '#30363D' : '#94A3B8'} stopOpacity={0.02} />
                                            </linearGradient>
                                        </defs>
                                        <CartesianGrid strokeDasharray="8 8" vertical={false} stroke={chartColors.grid} />
                                        <XAxis dataKey="day" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: chartColors.text }} />
                                        <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 900, fill: chartColors.text }} tickFormatter={(v) => `₱${(v / 1000).toFixed(0)}k`} />
                                        <Tooltip
                                            contentStyle={{
                                                borderRadius: '20px',
                                                border: 'none',
                                                boxShadow: '0 20px 40px rgba(0,0,0,0.15)',
                                                padding: '16px 20px',
                                                backgroundColor: chartColors.tooltip,
                                                color: chartColors.text
                                            }}
                                            formatter={(v: any, name: any) => [
                                                `₱${Number(v).toLocaleString()}`,
                                                name === 'Revenue' ? '● Revenue' : '● Expense'
                                            ]}
                                            itemStyle={{ fontWeight: 900, fontSize: 12 }}
                                            labelStyle={{ fontWeight: 900, textTransform: 'uppercase', letterSpacing: '0.1em', fontSize: 10, marginBottom: 6 }}
                                        />
                                        <Area type="linear" dataKey="sales" name="Revenue" stroke="#EE3E3E" strokeWidth={3} fill="url(#salesGrad)" dot={{ r: 4, fill: '#EE3E3E', stroke: '#fff', strokeWidth: 2 }} activeDot={{ r: 6, fill: '#EE3E3E', stroke: '#fff', strokeWidth: 3 }} />
                                        <Area type="linear" dataKey="purchases" name="Expense" stroke={isDark ? '#4B5563' : '#94A3B8'} strokeWidth={2} fill="url(#purchasesGrad)" dot={{ r: 3, fill: isDark ? '#4B5563' : '#94A3B8', stroke: '#fff', strokeWidth: 2 }} />
                                    </AreaChart>
                                )}
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Activity & Health */}
                    <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                        {/* Recent Activity Mini-Feed */}
                        <div className="bg-bg-surface rounded-[28px] border border-border-default shadow-sm overflow-hidden">
                            <div className="p-5 border-b border-border-default flex items-center justify-between bg-bg-subtle/30">
                                <h3 className="text-xs font-black text-text-primary uppercase tracking-widest flex items-center gap-2">
                                    <Clock size={14} className="text-brand-red" /> Activity
                                </h3>
                                <button onClick={() => navigate('/sales')} className="text-[10px] font-black text-text-muted hover:text-brand-red transition-colors group">VIEW ALL <ArrowUpRight size={12} className="inline ml-1" /></button>
                            </div>
                            <div className="divide-y divide-border-default">
                                {loading ? [1, 2, 3].map(i => <div key={i} className="p-5 h-16 skeleton" />) :
                                    recentSales.slice(0, 5).map((sale) => (
                                        <div key={sale.id} className="p-5 flex items-center justify-between hover:bg-bg-subtle/80 transition-all group">
                                            <div className="flex items-center gap-4">
                                                <div className="w-10 h-10 rounded-xl bg-bg-muted text-text-muted flex items-center justify-center group-hover:bg-brand-red/10 group-hover:text-brand-red transition-all"><ShoppingCart size={18} /></div>
                                                <div>
                                                    <p className="text-xs font-black text-text-primary">{sale.products?.name}</p>
                                                    <p className="text-[10px] font-medium text-text-muted uppercase tracking-widest">{sale.invoice_number}</p>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-4">
                                                <div className="text-right">
                                                    <p className="text-xs font-black text-text-primary font-data">₱{sale.total_price.toLocaleString()}</p>
                                                    {sale.is_finalized ? (
                                                        <span className="text-[8px] font-black text-text-muted uppercase tracking-widest flex items-center gap-1 justify-end"><Lock size={8} /> LOCKED</span>
                                                    ) : (
                                                        <button
                                                            onClick={() => handleEditSale(sale)}
                                                            className="text-[8px] font-black text-brand-red hover:underline uppercase tracking-widest"
                                                        >
                                                            QUICK CORRECT
                                                        </button>
                                                    )}
                                                </div>
                                            </div>
                                        </div>
                                    ))
                                }
                            </div>
                        </div>

                        {/* Health Summary Card */}
                        <div className="bg-[#0D1117] rounded-[28px] p-6 text-[#E6EDF3] relative overflow-hidden flex flex-col justify-between group shadow-2xl">
                            <div className="absolute top-0 right-0 w-64 h-64 bg-brand-red/10 rounded-full blur-[80px] -mr-32 -mt-32 group-hover:bg-brand-red/20 transition-all duration-1000" />
                            <div className="relative z-10">
                                <h4 className="text-[10px] font-black text-text-secondary uppercase tracking-[0.3em] mb-4">Quick Health Summary</h4>
                                <div className="space-y-6">
                                    <div>
                                        <span className="text-5xl font-black font-data tracking-tight">{stats.transactionCount}</span>
                                        <p className="text-[10px] font-black text-brand-red uppercase tracking-[0.2em] mt-1">Confirmed Transactions</p>
                                    </div>
                                    <div className="grid grid-cols-2 gap-4 pt-6 border-t border-text-inverse/10">
                                        <div>
                                            <p className="text-[9px] font-black text-text-secondary uppercase mb-1">Items Dispatched</p>
                                            <p className="text-xl font-black font-data">{stats.itemsSold}</p>
                                        </div>
                                        <div>
                                            <p className="text-[9px] font-black text-text-secondary uppercase mb-1">Fulfillment Target</p>
                                            <p className="text-xl font-black font-data text-brand-red">94%</p>
                                        </div>
                                    </div>
                                </div>
                            </div>
                            <button onClick={() => setIsReportModalOpen(true)} className="relative z-10 w-full mt-8 py-4 bg-text-inverse/5 border border-text-inverse/10 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-brand-red hover:border-brand-red transition-all">Detailed Analysis Report</button>
                        </div>
                    </div>
                </div>
            </div>


            <ProductModal
                isOpen={isLowStockModalOpen}
                onClose={() => { setIsLowStockModalOpen(false); setSelectedLowStockProduct(null); }}
                // eslint-disable-next-line @typescript-eslint/no-explicit-any
                product={selectedLowStockProduct as any}
                onSuccess={() => fetchDashboardData()}
                role={role}
            />

            <ReportModal
                isOpen={isReportModalOpen}
                onClose={() => setIsReportModalOpen(false)}
            />

            <SalesModal
                isOpen={isSalesModalOpen}
                onClose={() => { setIsSalesModalOpen(false); setSelectedSaleForEdit(null); }}
                onSuccess={() => fetchDashboardData()}
                editData={selectedSaleForEdit}
            />
        </div>
    );
}

function MetricCard({ icon, label, value, trend, loading, onClick, isCurrency }: { icon: React.ReactNode; label: string; value: number; trend: number; loading: boolean; onClick?: () => void; isCurrency?: boolean; }) {
    const isPositive = trend >= 0;
    return (
        <div onClick={onClick} className="bg-bg-surface p-5 rounded-[24px] border border-border-default shadow-sm transition-all hover:shadow-xl hover:-translate-y-1 cursor-pointer group">
            <div className="flex items-center justify-between mb-3"><div className="w-9 h-9 bg-bg-subtle rounded-xl flex items-center justify-center text-text-muted group-hover:bg-brand-red group-hover:text-white transition-colors">{icon}</div>{!loading && (<div className={`flex items-center gap-1 px-2 py-0.5 rounded-lg text-[10px] font-black ${isPositive ? 'bg-green-500/10 text-green-500' : 'bg-brand-red/10 text-brand-red'}`}>{isPositive ? <ArrowUpRight size={10} /> : <ArrowDownRight size={10} />}{Math.abs(Math.round(trend))}%</div>)}</div>
            <div><p className="text-[10px] font-black text-text-secondary uppercase tracking-widest mb-0.5">{label}</p>{loading ? <div className="h-7 w-24 skeleton rounded-lg" /> : <p className="text-xl font-black text-text-primary font-data tracking-tight">{isCurrency ? `₱${value.toLocaleString('en-PH', { minimumFractionDigits: 2 })}` : value.toLocaleString()}</p>}</div>
        </div>
    );
}

import { useEffect, useState, useCallback } from 'react';
import { supabase } from '../../shared/lib/supabase';
import {
    BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer,
    PieChart, Pie, Cell
} from 'recharts';
import {
    TrendingUp, DollarSign, PieChart as PieChartIcon,
    Activity, Calendar as CalendarIcon
} from 'lucide-react';
import { startOfDay, endOfDay, format, isSameDay } from 'date-fns';
import Calendar from '../../features/reports/components/Calendar';
import { useBranch } from '../../shared/lib/BranchContext';
import { Building2 } from 'lucide-react';

interface ProfitStats {
    totalRevenue: number;
    totalCOGS: number;
    grossProfit: number;
    netProfit: number;
    totalExpenses: number;
    vatAmount: number;
}

interface CategoryProfit {
    name: string;
    profit: number;
    revenue: number;
}

interface SupabaseSale {
    total_price: number;
    quantity: number;
    vat_amount: number;
    date: string;
    cost_price: number;
    products: {
        name: string;
    } | null;
}

interface GroupedSale {
    total_price: number;
    quantity: number;
    vat_amount: number;
}

const COLORS = ['#EE3E3E', '#5A6E8C', '#F59E0B', '#10B981', '#6366F1', '#EC4899'];

export default function ProfitAnalysis() {
    const [stats, setStats] = useState<ProfitStats>({
        totalRevenue: 0,
        totalCOGS: 0,
        grossProfit: 0,
        netProfit: 0,
        totalExpenses: 0,
        vatAmount: 0
    });
    const [categoryData, setCategoryData] = useState<CategoryProfit[]>([]);
    const [loading, setLoading] = useState(true);
    const [dateRange, setDateRange] = useState<{ start: Date, end: Date }>({
        start: new Date(),
        end: new Date()
    });
    const [isDateRangeActive, setIsDateRangeActive] = useState(false);
    const [groupedSales, setGroupedSales] = useState<Record<string, GroupedSale>>({});

    const { branches } = useBranch();
    const [selectedBranchId, setSelectedBranchId] = useState<string | null>(null); // null = all branches

    const fetchProfitData = useCallback(async () => {
        setLoading(true);
        const rangeStart = startOfDay(dateRange.start).toISOString();
        const rangeEnd = endOfDay(dateRange.end).toISOString();

        // 1. Fetch Sales
        let salesQuery = supabase
            .from('sales')
            .select('total_price, quantity, vat_amount, date, cost_price, products(name)')
            .gte('date', rangeStart)
            .lte('date', rangeEnd);

        // 2. Fetch Expenses
        let expensesQuery = supabase
            .from('expenses')
            .select('amount, date')
            .gte('date', rangeStart)
            .lte('date', rangeEnd);
            
        const branchFilter = selectedBranchId || null;
        if (branchFilter) {
            salesQuery = salesQuery.eq('branch_id', branchFilter);
            expensesQuery = expensesQuery.eq('branch_id', branchFilter);
        }

        const { data: salesData } = await salesQuery;
        const { data: expensesData } = await expensesQuery;

        const sales = (salesData as unknown as SupabaseSale[]) || [];
        const expenses = expensesData || [];


        // Group sales for calendar highlights
        const salesByDate: Record<string, GroupedSale> = {};
        sales.forEach(s => {
            const d = format(new Date(s.date), 'yyyy-MM-dd');
            if (!salesByDate[d]) salesByDate[d] = { total_price: 0, quantity: 0, vat_amount: 0 };
            salesByDate[d].total_price += s.total_price;
            salesByDate[d].quantity += s.quantity;
            salesByDate[d].vat_amount += s.vat_amount || 0;
        });
        setGroupedSales(salesByDate);

        // All aggregated stats for the selected range
        const totalRevenue = sales.reduce((sum, s) => sum + s.total_price, 0);
        const totalVAT = sales.reduce((sum, s) => sum + (s.vat_amount || 0), 0);
        const totalCOGS = sales.reduce((sum, s) => sum + (s.quantity * (s.cost_price || 0)), 0);
        const totalExpenses = expenses.reduce((sum, e) => sum + e.amount, 0);

        setStats({
            totalRevenue,
            totalCOGS,
            grossProfit: totalRevenue - totalCOGS,
            netProfit: (totalRevenue - totalCOGS) - totalExpenses,
            totalExpenses,
            vatAmount: totalVAT
        });

        // Category Breakdown
        const cats: Record<string, { profit: number; revenue: number }> = {};
        sales.forEach(s => {
            const nameParts = s.products?.name.split(' > ') || ['Uncategorized'];
            const l1 = nameParts[0];
            if (!cats[l1]) cats[l1] = { profit: 0, revenue: 0 };
            const cost = s.cost_price || 0;
            cats[l1].revenue += s.total_price;
            cats[l1].profit += (s.total_price - (s.quantity * cost));
        });

        setCategoryData(Object.entries(cats).map(([name, data]) => ({
            name,
            profit: data.profit,
            revenue: data.revenue
        })).sort((a, b) => b.profit - a.profit));

        setLoading(false);
    }, [dateRange, selectedBranchId]);

    useEffect(() => {
        let mounted = true;
        const load = async () => {
            if (mounted) await fetchProfitData();
        };
        load();
        return () => { mounted = false; };
    }, [fetchProfitData]);

    const handleDateSelect = (date: Date) => {
        if (!isDateRangeActive) {
            setDateRange({ start: date, end: date });
            return;
        }

        if (!dateRange.start || (dateRange.start && dateRange.end && !isSameDay(dateRange.start, dateRange.end))) {
            setDateRange({ start: date, end: date });
        } else {
            const newRange = date < dateRange.start
                ? { start: date, end: dateRange.start }
                : { start: dateRange.start, end: date };
            setDateRange(newRange);
        }
    };

    const activeDates = Object.keys(groupedSales);

    return (
        <div className="space-y-8 animate-fade-in pb-10 bg-bg-base">
            {/* Standard Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-bg-surface rounded-[24px] flex items-center justify-center shadow-xl border border-border-muted group transition-all hover:scale-105 active:scale-95">
                        <TrendingUp className="text-brand-red group-hover:rotate-12 transition-transform" size={28} />
                    </div>
                    <div>
                        <h1 className="text-3xl font-black text-text-primary tracking-tight uppercase">Profit Analysis</h1>
                        <p className="text-sm text-text-secondary mt-1 font-medium">Real-time profitability and margin tracking</p>
                    </div>
                </div>
            </div>

            <div className="flex flex-col lg:flex-row gap-8">
                {/* Sidebar Controls */}
                <div className="flex-shrink-0 w-full lg:w-80">
                    <div className="sticky top-6 space-y-6">
                        <div className="bg-bg-surface p-6 rounded-[32px] border border-border-muted shadow-sm space-y-5">
                            <div className="flex items-center justify-between">
                                <h3 className="text-[10px] font-black text-text-muted uppercase tracking-[0.2em]">Summary Period</h3>
                                <button
                                    onClick={() => setIsDateRangeActive(!isDateRangeActive)}
                                    className={`text-[9px] font-black px-3 py-1 rounded-full uppercase transition-all ${isDateRangeActive ? 'bg-brand-red text-text-inverse shadow-red' : 'bg-bg-subtle text-text-muted'}`}
                                >
                                    {isDateRangeActive ? 'Range' : 'Single Day'}
                                </button>
                            </div>
                            <div className="flex items-center justify-between bg-bg-subtle p-3 rounded-2xl border border-border-muted/50">
                                <span className="text-[10px] font-black text-text-muted uppercase tracking-widest">
                                    Selection
                                </span>
                                {(dateRange.start && dateRange.end) && (
                                    <span className="text-[10px] font-black text-brand-red">
                                        {isDateRangeActive && !isSameDay(dateRange.start, dateRange.end)
                                            ? `${format(dateRange.start, 'MMM d')} - ${format(dateRange.end, 'MMM d')}`
                                            : format(dateRange.start, 'MMM d, yyyy')}
                                    </span>
                                )}
                            </div>
                            <Calendar
                                selectedDate={dateRange.start}
                                onDateSelect={handleDateSelect}
                                rangeStart={isDateRangeActive ? dateRange.start : null}
                                rangeEnd={isDateRangeActive ? dateRange.end : null}
                                activeDates={activeDates}
                            />
                        </div>

                        {/* Branch Filter */}
                        <div className="bg-bg-surface p-5 rounded-[28px] border border-border-muted shadow-sm">
                            <h3 className="text-[10px] font-black text-text-muted uppercase tracking-[0.2em] mb-3">Branch Filter</h3>
                            <div className="space-y-1.5">
                                <button
                                    onClick={() => setSelectedBranchId(null)}
                                    className={`w-full flex items-center gap-2 px-3 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${!selectedBranchId ? 'bg-brand-red text-white shadow-red' : 'bg-bg-subtle text-text-muted hover:bg-bg-muted'}`}
                                >
                                    <Building2 size={12} /> All Branches
                                </button>
                                {branches.map(b => (
                                    <button
                                        key={b.id}
                                        onClick={() => setSelectedBranchId(b.id)}
                                        className={`w-full flex items-center gap-2 px-3 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${selectedBranchId === b.id ? 'bg-brand-red text-white shadow-red' : 'bg-bg-subtle text-text-muted hover:bg-bg-muted'}`}
                                    >
                                        <Building2 size={12} /> {b.name}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="bg-bg-surface p-7 rounded-[32px] border border-border-muted shadow-sm">
                            <h3 className="text-[10px] font-black text-text-muted border-b border-border-muted pb-4 mb-5 uppercase tracking-[0.2em]">Efficiency KPIs</h3>
                            <div className="space-y-6">
                                <div>
                                    <p className="text-[10px] font-black text-text-secondary uppercase tracking-widest mb-2">Effective Gross Margin</p>
                                    <p className="text-2xl font-black text-emerald-500 font-data">
                                        {stats.totalRevenue > 0 ? ((stats.grossProfit / stats.totalRevenue) * 100).toFixed(1) : '0.0'}%
                                    </p>
                                </div>
                                <div className="pt-4 border-t border-border-muted">
                                    <p className="text-[10px] font-black text-text-secondary uppercase tracking-widest mb-2">VAT Liability (Estimated)</p>
                                    <p className="text-2xl font-black text-text-primary font-data">
                                        ₱{stats.vatAmount.toLocaleString('en-PH', { minimumFractionDigits: 2 })}
                                    </p>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex-1 space-y-8 min-w-0">
                    <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-6">
                        <MetricCard icon={<DollarSign size={20} />} label="Total Revenue" value={stats.totalRevenue} color="text-text-primary" loading={loading} />
                        <MetricCard icon={<Activity size={20} />} label="Cost of Goods" value={stats.totalCOGS} color="text-text-secondary" loading={loading} />
                        <MetricCard icon={<TrendingUp size={20} />} label="Gross Profit" value={stats.grossProfit} color="text-emerald-500" loading={loading} />
                        <MetricCard icon={<TrendingUp size={20} />} label="Net Profit" value={stats.netProfit} color="text-blue-500" loading={loading} />
                    </div>

                    <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
                        {/* CHART 1: Category Breakdown */}
                        <div className="bg-bg-surface p-8 rounded-[40px] border border-border-muted shadow-sm relative overflow-hidden group">
                            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                                <PieChartIcon size={64} className="text-brand-red" />
                            </div>
                            <div className="mb-10">
                                <h3 className="text-sm font-black text-text-primary uppercase tracking-[0.1em]">Profit by Master Category</h3>
                                <p className="text-xs text-text-secondary font-medium mt-1">Weighted distribution of net earnings</p>
                            </div>
                            <div className="h-[320px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie data={categoryData} cx="50%" cy="50%" innerRadius={70} outerRadius={110} paddingAngle={8} dataKey="profit" stroke="none">
                                            {categoryData.map((_, index) => (<Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />))}
                                        </Pie>
                                        <Tooltip
                                            contentStyle={{ backgroundColor: 'var(--bg-surface)', borderRadius: '20px', border: '1px solid var(--border-muted)', boxShadow: '0 10px 30px rgba(0,0,0,0.1)', padding: '15px' }}
                                            formatter={(v: any) => [`₱${Number(v).toLocaleString()}`, 'Profit']}
                                        />
                                        <Legend verticalAlign="bottom" height={40} iconType="circle" wrapperStyle={{ fontSize: '10px', fontWeight: 800, textTransform: 'uppercase', letterSpacing: '1px', paddingTop: '20px' }} />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        {/* CHART 2: Revenue vs Profit */}
                        <div className="bg-bg-surface p-8 rounded-[40px] border border-border-muted shadow-sm">
                            <div className="mb-10">
                                <h3 className="text-sm font-black text-text-primary uppercase tracking-[0.1em]">Revenue vs Margin</h3>
                                <p className="text-xs text-text-secondary font-medium mt-1">Comparative top-line and bottom-line growth</p>
                            </div>
                            <div className="h-[320px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={categoryData.slice(0, 5)} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="var(--border-muted)" />
                                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 800, fill: 'var(--text-muted)' }} />
                                        <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 10, fontWeight: 800, fill: 'var(--text-muted)' }} />
                                        <Tooltip cursor={{ fill: 'var(--bg-subtle)' }} contentStyle={{ backgroundColor: 'var(--bg-surface)', border: '1px solid var(--border-muted)', borderRadius: '12px' }} formatter={(v: any) => `₱${Number(v).toLocaleString()}`} />
                                        <Bar dataKey="revenue" fill="var(--color-brand-red)" radius={[10, 10, 0, 0]} barSize={28} name="Revenue" />
                                        <Bar dataKey="profit" fill="var(--color-success)" radius={[10, 10, 0, 0]} barSize={28} name="Profit" />
                                    </BarChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

function MetricCard({ icon, label, value, color, loading }: { icon: React.ReactNode, label: string, value: number, color: string, loading: boolean }) {
    return (
        <div className="bg-bg-surface p-6 rounded-3xl border border-border-muted shadow-sm hover:border-brand-red/30 transition-colors group">
            <div className="flex items-center justify-between mb-4">
                <div className="w-10 h-10 bg-bg-base/50 rounded-xl flex items-center justify-center text-text-muted transition-colors group-hover:bg-brand-red/10 group-hover:text-brand-red">{icon}</div>
                <div className="flex items-center gap-1 text-[10px] font-bold text-text-muted uppercase tracking-widest"><CalendarIcon size={12} /> Today</div>
            </div>
            <p className="text-[10px] font-bold text-text-muted uppercase tracking-[0.2em] mb-1">{label}</p>
            {loading ? <div className="h-8 bg-bg-subtle animate-pulse rounded w-24"></div> : <p className={`text-2xl font-black ${color} font-data`}>₱{value.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>}
        </div>
    );
}

import { useEffect, useState } from 'react';
import { supabase } from '../../shared/lib/supabase';
import { Wallet, Plus, Search, Filter, Trash2, Calendar as CalendarIcon, Edit3 } from 'lucide-react';
import { format, isSameDay } from 'date-fns';
import ExpenseModal from './components/ExpenseModal';
import { useAuth } from '../../shared/hooks/useAuth';
import Calendar from '../../features/reports/components/Calendar';
import { useBranch } from '../../shared/lib/BranchContext';

interface Expense {
    id: string;
    category: 'Salary' | 'Donation' | 'Others';
    description: string;
    amount: number;
    date: string;
    invoice_number: string;
}

export default function Expenses() {
    const { role } = useAuth();
    const { activeBranchId } = useBranch();
    const [expenses, setExpenses] = useState<Expense[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [categoryFilter, setCategoryFilter] = useState<string>('All');
    const [selectedDate, setSelectedDate] = useState<Date>(new Date());
    const [editExpense, setEditExpense] = useState<Expense | null>(null);

    const fetchExpenses = async (silent = false) => {
        if (!silent) setLoading(true);
        let query = supabase
            .from('expenses')
            .select('*')
            .order('date', { ascending: false });

        if (activeBranchId) {
            query = query.eq('branch_id', activeBranchId);
        }

        const { data, error } = await query;

        if (error) console.error('Error fetching expenses:', error);
        else setExpenses(data || []);
        setLoading(false);
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm('Delete this expense record?')) return;
        const { error } = await supabase.from('expenses').delete().eq('id', id);
        if (error) alert('Error: ' + error.message);
        else fetchExpenses();
    };

    useEffect(() => {
        let mounted = true;
        const load = async () => {
            if (mounted) await fetchExpenses();
        };
        load();

        const channel = supabase
            .channel('expense_changes')
            .on(
                'postgres_changes',
                { event: '*', schema: 'public', table: 'expenses' },
                () => { if (mounted) fetchExpenses(true); }
            )
            .subscribe();

        return () => {
            mounted = false;
            supabase.removeChannel(channel);
        };
    }, [activeBranchId]);

    const filtered = expenses.filter(ex => {
        const matchesSearch =
            ex.description.toLowerCase().includes(searchTerm.toLowerCase()) ||
            ex.invoice_number?.toLowerCase().includes(searchTerm.toLowerCase()) ||
            ex.category.toLowerCase().includes(searchTerm.toLowerCase());

        const matchesCategory = categoryFilter === 'All' || ex.category === categoryFilter;
        const matchesDate = isSameDay(new Date(ex.date), selectedDate);

        return matchesSearch && matchesCategory && matchesDate;
    });

    const activeDates = Array.from(new Set(expenses.map(ex => format(new Date(ex.date), 'yyyy-MM-dd'))));
    const totalExpenses = filtered.reduce((sum, ex) => sum + ex.amount, 0);

    return (
        <div className="space-y-8 animate-fade-in pb-10 bg-base">
            {/* Standard Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-surface rounded-[24px] flex items-center justify-center shadow-xl border border-border-default group transition-all hover:scale-105 active:scale-95">
                        <Wallet className="text-brand-red group-hover:rotate-12 transition-transform" size={28} />
                    </div>
                    <div>
                        <h1 className="text-3xl font-black text-text-primary tracking-tight uppercase">Operating Expenses</h1>
                        <p className="text-sm text-text-secondary mt-1 font-medium">Track daily payouts, salaries, and donations</p>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <button
                        onClick={() => setIsModalOpen(true)}
