                                                                        </td>
                                                                        <td className="px-6 py-3 text-center">
                                                                            {p.brand && (
                                                                                <span className="inline-flex px-1.5 py-0.5 rounded bg-bg-subtle text-[8px] font-black text-text-muted uppercase tracking-widest border border-border-muted/50">
