import { useEffect, useState, useCallback, useMemo } from 'react';
import { supabase } from '../../shared/lib/supabase';
import {
    RefreshCw,
    History, Search, Edit3, Filter
} from 'lucide-react';
import { format, startOfDay, endOfDay, isToday } from 'date-fns';
import Calendar from '../../features/reports/components/Calendar';
import { ShoppingCart, ArrowDownRight, RotateCcw, Package, AlertCircle } from 'lucide-react';
import { useAudit } from '../../shared/hooks/useAudit';
import { useBranch } from '../../shared/lib/BranchContext';

interface InventorySnap {
    id: string;
    name: string;
    opening: number;
    inwards: number;
    outwards: number;
    returns: number;
    adjustments: number;
    ending: number;
    transfers?: {
        type: 'in' | 'out';
        branch_name: string;
        quantity: number;
    }[];
}

export default function DailyInventorySummary() {
    const { activeBranchId } = useBranch();
    const [summary, setSummary] = useState<InventorySnap[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedDate, setSelectedDate] = useState<Date>(new Date());
    const [showOnlyMoved, setShowOnlyMoved] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [isReconcileMode, setIsReconcileMode] = useState(false);
    const [actualCounts, setActualCounts] = useState<Record<string, string>>({});
    const [isProcessing, setIsProcessing] = useState(false);
    const { logAction } = useAudit();

    const fetchHistory = useCallback(async () => {
        setLoading(true);
        try {
            // 1. Get ALL products (current state)
            let productsQuery = supabase
                .from('products')
                .select('id, name, sku, stock_available');
            
            if (activeBranchId) {
                productsQuery = productsQuery.eq('branch_id', activeBranchId);
            }

            const { data: products } = await productsQuery;

            if (!products) return;

            const targetStart = startOfDay(selectedDate);
            const targetEnd = endOfDay(selectedDate);

            // 2. Fetch ALL movements after the target date
            const afterStr = targetEnd.toISOString();
            let salesQuery = supabase.from('sales').select('product_id, quantity, date').gt('date', afterStr);
            let purchasesQuery = supabase.from('purchases').select('product_id, quantity, date').eq('status', 'received').gt('date', afterStr);
            let returnsQuery = supabase.from('supplier_returns').select('product_id, quantity, date').gt('date', afterStr);
            let refundsQuery = supabase.from('customer_refunds').select('product_id, quantity, date').gt('date', afterStr);
            let adjustmentsQuery = supabase.from('inventory_adjustments').select('product_id, difference, created_at').gt('created_at', afterStr);

            if (activeBranchId) {
                salesQuery = salesQuery.eq('branch_id', activeBranchId);
                purchasesQuery = purchasesQuery.eq('branch_id', activeBranchId);
                returnsQuery = returnsQuery.eq('branch_id', activeBranchId);
                refundsQuery = refundsQuery.eq('branch_id', activeBranchId);
                adjustmentsQuery = adjustmentsQuery.eq('branch_id', activeBranchId);
            }

            let transfersOutQuery = supabase
                .from('purchases')
                .select('quantity, date, products(sku), branches:branch_id(name)')
                .eq('source_branch_id', activeBranchId)
                .eq('status', 'received')
                .gt('date', afterStr);

            const [salesRes, purchasesRes, returnsRes, refundsRes, adjustmentsRes, transfersOutRes] = await Promise.all([
                salesQuery,
                purchasesQuery,
                returnsQuery,
                refundsQuery,
                adjustmentsQuery,
                transfersOutQuery
            ]);

            const sales = salesRes.data;
            const purchases = purchasesRes.data;
            const returns = returnsRes.data;
            const refunds = refundsRes.data;
            const adjustments = adjustmentsRes.data;
            const transfersOut = transfersOutRes.data;

            // 3. Fetch movements FOR THE TARGET DATE
            const isoTargetStart = targetStart.toISOString();
            const isoTargetEnd = targetEnd.toISOString();

            let dSalesQuery = supabase.from('sales').select('product_id, quantity').gte('date', isoTargetStart).lte('date', isoTargetEnd);
            let dPurchasesQuery = supabase.from('purchases').select('product_id, quantity, purchase_type, branches:source_branch_id(name)').eq('status', 'received').gte('date', isoTargetStart).lte('date', isoTargetEnd);
            let dReturnsQuery = supabase.from('supplier_returns').select('product_id, quantity').gte('date', isoTargetStart).lte('date', isoTargetEnd);
            let dRefundsQuery = supabase.from('customer_refunds').select('product_id, quantity').gte('date', isoTargetStart).lte('date', isoTargetEnd);
            let dAdjustmentsQuery = supabase.from('inventory_adjustments').select('product_id, difference').gte('created_at', isoTargetStart).lte('created_at', isoTargetEnd);

            if (activeBranchId) {
                dSalesQuery = dSalesQuery.eq('branch_id', activeBranchId);
                dPurchasesQuery = dPurchasesQuery.eq('branch_id', activeBranchId);
                dReturnsQuery = dReturnsQuery.eq('branch_id', activeBranchId);
                dRefundsQuery = dRefundsQuery.eq('branch_id', activeBranchId);
                dAdjustmentsQuery = dAdjustmentsQuery.eq('branch_id', activeBranchId);
            }

            let dTransfersOutQuery = supabase
                .from('purchases')
                .select('quantity, products(sku), branches:branch_id(name)')
                .eq('source_branch_id', activeBranchId)
                .eq('status', 'received')
                .gte('date', isoTargetStart)
                .lte('date', isoTargetEnd);

            const [dSalesRes, dPurchasesRes, dReturnsRes, dRefundsRes, dAdjustmentsRes, dTransfersOutRes] = await Promise.all([
                dSalesQuery,
                dPurchasesQuery,
                dReturnsQuery,
                dRefundsQuery,
                dAdjustmentsQuery,
                dTransfersOutQuery
            ]);

            const dSales = dSalesRes.data;
            const dPurchases = dPurchasesRes.data;
            const dReturns = dReturnsRes.data;
            const dRefunds = dRefundsRes.data;
            const dAdjustments = dAdjustmentsRes.data;
            const dTransfersOut = dTransfersOutRes.data;

            const snaps: InventorySnap[] = products.map(p => {
                const current = p.stock_available;

                // Adjust for movements AFTER the target date
                const salesAfter = sales?.filter(s => s.product_id === p.id).reduce((a, s) => a + s.quantity, 0) || 0;
                const purchasesAfter = purchases?.filter(s => s.product_id === p.id).reduce((a, s) => a + s.quantity, 0) || 0;
                const transfersOutAfter = transfersOut?.filter(s => {
                    const products = s.products as any;
                    const sku = Array.isArray(products) ? products[0]?.sku : products?.sku;
                    return sku === p.sku;
                }).reduce((a, s) => a + s.quantity, 0) || 0;
                const returnsAfter = returns?.filter(s => s.product_id === p.id).reduce((a, s) => a + s.quantity, 0) || 0;
                const refundsAfter = refunds?.filter(s => s.product_id === p.id).reduce((a, s) => a + s.quantity, 0) || 0;
                const adjustmentsAfter = adjustments?.filter(s => s.product_id === p.id).reduce((a, s) => a + s.difference, 0) || 0;

                // Past = Current + SalesAfter + TransfersOutAfter - PurchasesAfter + ReturnsAfter - RefundsAfter - AdjustmentsAfter
                const endingBalance = current + salesAfter + transfersOutAfter - purchasesAfter + returnsAfter - refundsAfter - adjustmentsAfter;

                // Movements ON Target Date
                const inwards = dPurchases?.filter(s => s.product_id === p.id).reduce((a, s) => a + s.quantity, 0) || 0;
                
                // Track individual transfers for UI
                const transfers: InventorySnap['transfers'] = [];
                
                // 1. Incoming Transfers
                dPurchases?.filter(s => s.product_id === p.id && (s as any).purchase_type === 'transfer')
                    .forEach(s => {
                        const bName = Array.isArray((s as any).branches) ? (s as any).branches[0]?.name : (s as any).branches?.name;
                        transfers.push({
                            type: 'in',
                            branch_name: bName || 'Other Branch',
                            quantity: s.quantity
                        });
                    });

                // 2. Outgoing Transfers
                const dTransfersOutMatches = dTransfersOut?.filter(s => {
                    const products = (s as any).products;
                    const sku = Array.isArray(products) ? products[0]?.sku : products?.sku;
                    return sku === p.sku;
                }) || [];

                dTransfersOutMatches.forEach(s => {
                    const bName = Array.isArray((s as any).branches) ? (s as any).branches[0]?.name : (s as any).branches?.name;
                    transfers.push({
                        type: 'out',
                        branch_name: bName || 'Other Branch',
                        quantity: s.quantity
                    });
                });

                const transfersOutTarget = dTransfersOutMatches.reduce((a, s) => a + s.quantity, 0);
                const outwards = (dSales?.filter(s => s.product_id === p.id).reduce((a, s) => a + s.quantity, 0) || 0) +
                    (dReturns?.filter(s => s.product_id === p.id).reduce((a, s) => a + s.quantity, 0) || 0) +
                    transfersOutTarget;
                const refundsTotal = dRefunds?.filter(s => s.product_id === p.id).reduce((a, s) => a + s.quantity, 0) || 0;
                const adjustmentsTotal = dAdjustments?.filter(s => s.product_id === p.id).reduce((a, s) => a + s.difference, 0) || 0;

                // Opening = Ending - In + Out - Refunds - Adjustments
                const opening = endingBalance - inwards + outwards - refundsTotal - adjustmentsTotal;

                return {
                    id: p.id,
                    name: p.name,
                    opening,
                    inwards,
                    outwards,
                    returns: refundsTotal,
                    adjustments: adjustmentsTotal,
                    ending: endingBalance,
                    transfers
                };
            });

            setSummary(snaps);
        } catch (err) {
            console.error('Error calculating history:', err);
        } finally {
            setLoading(false);
        }
    }, [selectedDate, activeBranchId]);

    const handleProcessReconciliation = async () => {
        if (!window.confirm('Are you sure you want to process these inventory adjustments? This will update physical stock levels.')) return;

        setIsProcessing(true);
        try {
            const adjustments = Object.entries(actualCounts).map(([pid, actual]) => {
                const item = summary.find(s => s.id === pid);
                if (!item) return null;
                const actualNum = parseFloat(actual);
                return {
                    product_id: pid,
                    previous_stock: item.ending,
                    actual_stock: actualNum,
                    difference: actualNum - item.ending,
                    type: 'Reconciliation',
                    reason: `Manual reconciliation for ${format(selectedDate, 'MMM d, yyyy')}`
                };
            }).filter(Boolean);

            for (const adj of adjustments) {
                // 1. Log adjustment
                const { error: adjError } = await supabase.from('inventory_adjustments').insert({
                    ...adj,
                    branch_id: activeBranchId,
                    adjusted_by: (await supabase.auth.getUser()).data.user?.id
                });
                if (adjError) throw adjError;

                // 2. Update product stock
                const { error: prodError } = await supabase.from('products').update({
                    stock_available: adj?.actual_stock
                }).eq('id', adj?.product_id);
                if (prodError) throw prodError;

                // 3. Audit Log
                await logAction({
                    action: 'INV_ADJUST',
                    table_name: 'products',
                    record_id: adj?.product_id || '',
                    old_data: { stock: adj?.previous_stock },
                    new_data: { stock: adj?.actual_stock }
                });
            }

            alert('Reconciliation complete! Stocks updated.');
            setActualCounts({});
            setIsReconcileMode(false);
            fetchHistory();
        } catch (err) {
            console.error('Reconciliation failed:', err);
            alert('Error processing adjustments.');
        } finally {
            setIsProcessing(false);
        }
    };

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.altKey && e.key.toLowerCase() === 'r' && isToday(selectedDate)) {
                e.preventDefault();
                setIsReconcileMode(prev => !prev);
            }

            if (e.ctrlKey && e.key === 'Enter' && isReconcileMode) {
                e.preventDefault();
                handleProcessReconciliation();
            }

            if (isReconcileMode && (e.key === 'ArrowUp' || e.key === 'ArrowDown')) {
                const target = e.target as HTMLElement;
                if (target.tagName === 'INPUT' && target.dataset.index !== undefined) {
                    e.preventDefault();
                    const currentIndex = parseInt(target.dataset.index);
                    const nextIndex = e.key === 'ArrowUp' ? currentIndex - 1 : currentIndex + 1;
                    const nextInput = document.querySelector(`input[data-index="${nextIndex}"]`) as HTMLInputElement;
                    if (nextInput) {
                        nextInput.focus();
                        nextInput.select();
                    }
                }
            }
        };

        document.addEventListener('keydown', handleKeyDown);
        return () => document.removeEventListener('keydown', handleKeyDown);
    }, [isReconcileMode, selectedDate, handleProcessReconciliation]);

    useEffect(() => {
        fetchHistory();
    }, [fetchHistory]);

    const filtered = useMemo(() => {
        return summary.filter(p => {
            const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
            if (!showOnlyMoved) return matchesSearch;
            const hasMovement = p.inwards !== 0 || p.outwards !== 0 || p.returns !== 0 || p.adjustments !== 0;
            return matchesSearch && hasMovement;
        });
    }, [summary, searchTerm, showOnlyMoved]);

    const totals = useMemo(() => {
        return {
            in: filtered.reduce((a, b) => a + b.inwards, 0),
            out: filtered.reduce((a, b) => a + b.outwards, 0),
            returns: filtered.reduce((a, b) => a + b.returns, 0),
            adjustments: filtered.reduce((a, b) => a + b.adjustments, 0)
        };
    }, [filtered]);

    return (
        <div className="space-y-8 animate-fade-in pb-10 bg-base">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-surface rounded-[24px] flex items-center justify-center shadow-xl border border-border-default group transition-all hover:scale-105 active:scale-95">
                        <History className="text-brand-red group-hover:rotate-12 transition-transform" size={28} />
                    </div>
                    <div>
                        <h1 className="text-3xl font-black text-text-primary tracking-tight uppercase">Inventory History</h1>
                        <p className="text-sm text-text-secondary mt-1 font-medium">Reconstruct historical stock balances at any point in time</p>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <button
                        onClick={() => setShowOnlyMoved(!showOnlyMoved)}
                        className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-black text-sm transition-all shadow-lg active:scale-95 ${showOnlyMoved ? 'bg-brand-red text-white shadow-red' : 'bg-surface text-text-secondary border border-border-default hover:bg-subtle'}`}
                    >
                        <Filter size={18} /> {showOnlyMoved ? 'MOVED ONLY' : 'ALL PRODUCTS'}
                    </button>
                    {isToday(selectedDate) && (
                        <button
                            onClick={() => setIsReconcileMode(!isReconcileMode)}
                            className={`flex items-center gap-2 px-6 py-3 rounded-2xl font-black text-sm transition-all shadow-lg active:scale-95 ${isReconcileMode ? 'bg-text-primary text-bg-surface' : 'bg-bg-surface text-text-primary border border-border-default hover:bg-bg-subtle'}`}
                        >
                            {isReconcileMode ? <><Package size={18} /> VIEW HISTORY</> : <><Edit3 size={18} /> RECONCILE STOCK</>}
                        </button>
                    )}
                </div>
            </div>

            <div className="flex flex-col lg:flex-row gap-8">
                <div className="flex-shrink-0 w-full lg:w-80">
                    <div className="sticky top-6 space-y-6">
                        <Calendar selectedDate={selectedDate} onDateSelect={setSelectedDate} activeDates={[format(new Date(), 'yyyy-MM-dd')]} />

                        <div className="bg-surface p-6 rounded-[32px] border border-border-default shadow-sm space-y-4">
                            <div className="flex items-center justify-between">
                                <h3 className="text-[10px] font-black text-text-muted uppercase tracking-[0.2em]">Logic Mode</h3>
                                <RefreshCw size={12} className="text-brand-orange animate-spin-slow" />
                            </div>
                            <p className="text-[11px] text-text-secondary leading-relaxed font-medium">
                                Reverse playback calculations start from real-time levels and mathematically undo every transaction back to <span className="text-text-primary font-black">{format(selectedDate, 'MMM d')}</span>.
                            </p>
                        </div>

                        {isReconcileMode && (
                            <div className="bg-brand-red/5 p-6 rounded-[32px] border border-brand-red/10 shadow-sm space-y-4">
                                <div className="flex items-center gap-2">
                                    <AlertCircle size={16} className="text-brand-red" />
                                    <h3 className="text-[10px] font-black text-brand-red uppercase tracking-[0.2em]">Reconcile Mode</h3>
                                </div>
                                <p className="text-[11px] text-text-secondary leading-relaxed font-medium">
                                    Enter the <strong>Physical Count</strong> from your shelves. The system will calculate the variance and allow you to adjust stocks to match reality.
                                </p>
                                <button
                                    onClick={handleProcessReconciliation}
                                    disabled={Object.keys(actualCounts).length === 0 || isProcessing}
                                    className="w-full bg-brand-red text-white py-3 rounded-xl font-black text-xs shadow-red hover:bg-brand-red-dark transition-all disabled:opacity-50"
                                >
                                    {isProcessing ? 'PROCESSING...' : 'PROCESS ADJUSTMENTS'}
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                <div className="flex-1 min-w-0 space-y-8">
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                        <div className="bg-surface p-6 rounded-[32px] border border-border-default shadow-sm flex items-center gap-4">
                            <div className="w-12 h-12 rounded-[18px] bg-success-subtle text-success flex items-center justify-center"><ShoppingCart size={20} /></div>
                            <div>
                                <p className="text-[10px] font-black text-text-muted uppercase tracking-widest mb-1">Inwards (+)</p>
                                <p className="text-2xl font-black font-data text-text-primary">+{totals.in}</p>
                            </div>
                        </div>
                        <div className="bg-surface p-6 rounded-[32px] border border-border-default shadow-sm flex items-center gap-4">
                            <div className="w-12 h-12 rounded-[18px] bg-danger-subtle text-brand-red flex items-center justify-center"><ArrowDownRight size={20} /></div>
                            <div>
                                <p className="text-[10px] font-black text-text-muted uppercase tracking-widest mb-1">Outwards (-)</p>
                                <p className="text-2xl font-black font-data text-text-primary">-{totals.out}</p>
                            </div>
                        </div>
                        <div className="bg-surface p-6 rounded-[32px] border border-border-default shadow-sm flex items-center gap-4">
                            <div className="w-12 h-12 rounded-[18px] bg-accent-subtle text-accent flex items-center justify-center"><RotateCcw size={20} /></div>
                            <div>
                                <p className="text-[10px] font-black text-text-muted uppercase tracking-widest mb-1">Returns (+)</p>
                                <p className="text-2xl font-black font-data text-text-primary">+{totals.returns}</p>
                            </div>
                        </div>
                        <div className="bg-surface p-6 rounded-[32px] border border-border-default shadow-sm flex items-center gap-4">
                            <div className="w-12 h-12 rounded-[18px] bg-warning-subtle text-amber-500 flex items-center justify-center"><Edit3 size={20} /></div>
                            <div>
                                <p className="text-[10px] font-black text-text-muted uppercase tracking-widest mb-1">Adjustments (±)</p>
                                <p className="text-2xl font-black font-data text-text-primary">{totals.adjustments > 0 ? '+' : ''}{totals.adjustments}</p>
                            </div>
                        </div>
                    </div>

                    <div className="relative group">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-text-muted group-focus-within:text-brand-red transition-colors" size={18} />
                        <input type="text" placeholder="Search products in historical snapshot..." className="w-full pl-12 pr-4 py-4 bg-surface border border-border-default rounded-[28px] text-sm text-text-primary focus:ring-2 focus:border-brand-red outline-none shadow-sm transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                    </div>

                    <div className="bg-surface rounded-[40px] border border-border-default shadow-sm overflow-hidden">
                        <div className="overflow-x-auto">
                            <table className="w-full text-left">
                                <thead>
                                    <tr className="bg-bg-subtle border-b border-border-muted font-bold">
                                        <th className="px-8 py-5 text-[11px] font-black text-text-muted uppercase tracking-[0.2em]">Product Detail</th>
                                        <th className="px-6 py-5 text-[11px] font-black text-text-muted uppercase tracking-[0.2em] text-center">Opening</th>
                                        <th className="px-6 py-5 text-[11px] font-black text-emerald-500 uppercase tracking-[0.2em] text-center bg-emerald-500/5">In (+)</th>
                                        <th className="px-6 py-5 text-[11px] font-black text-brand-red uppercase tracking-[0.2em] text-center bg-brand-red/5">Out (-)</th>
                                        <th className="px-6 py-5 text-[11px] font-black text-blue-500 uppercase tracking-[0.2em] text-center bg-blue-500/5">Return (+)</th>
                                        <th className="px-6 py-5 text-[11px] font-black text-amber-500 uppercase tracking-[0.2em] text-center bg-amber-500/5">Adj (±)</th>
                                        <th className="px-8 py-5 text-[11px] font-black text-text-primary uppercase tracking-[0.2em] text-center border-l border-border-muted bg-bg-subtle/20">Closing</th>
                                        {isReconcileMode && (
                                            <>
                                                <th className="px-8 py-5 text-[11px] font-black text-amber-500 uppercase tracking-[0.2em] text-center bg-amber-500/5 border-l border-border-muted font-bold">Physical</th>
                                                <th className="px-8 py-5 text-[11px] font-black text-text-primary uppercase tracking-[0.2em] text-center bg-bg-surface border-l border-border-muted font-bold">Variance</th>
                                            </>
                                        )}
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-border-default">
                                    {loading ? (
                                        [1, 2, 3, 4, 5].map(i => <tr key={i} className="animate-pulse"><td colSpan={7} className="px-8 py-8"><div className="h-4 bg-subtle rounded-full w-48"></div></td></tr>)
                                    ) : filtered.length > 0 ? filtered.map((item, idx) => {
                                        const actualStr = actualCounts[item.id] || '';
                                        const actualNum = parseFloat(actualStr);
                                        const variance = isNaN(actualNum) ? 0 : actualNum - item.ending;

                                        return (
                                            <tr key={item.id} className="hover:bg-subtle/50 transition-all font-data group">
                                                <td className="px-8 py-5">
                                                    <div className="flex items-center gap-3">
                                                        <div className="w-8 h-8 rounded-lg bg-subtle flex items-center justify-center text-text-muted group-hover:text-brand-red transition-colors"><Package size={14} /></div>
                                                        <p className="text-xs font-black text-text-primary leading-tight uppercase">{item.name}</p>
                                                    </div>
                                                </td>
                                                <td className="px-6 py-5 text-center font-bold text-text-muted">{item.opening}</td>
                                                 <td className="px-6 py-5 text-center font-black text-success bg-success-subtle/5">
                                                     {(() => {
                                                         const inTransfers = item.transfers?.filter(t => t.type === 'in') || [];
                                                         const inTransfersTotal = inTransfers.reduce((a, t) => a + t.quantity, 0);
                                                         const supplierPurchases = item.inwards - inTransfersTotal;
                                                         
                                                         return (
                                                             <div className="flex flex-col gap-1.5 items-center">
                                                                 {supplierPurchases > 0 && (
                                                                     <div className="flex flex-col items-center">
                                                                         <span className="text-xs">+{supplierPurchases}</span>
                                                                         <span className="text-[9px] text-text-muted font-black uppercase tracking-tighter">SUPP PURCHASE</span>
                                                                     </div>
                                                                 )}
                                                                 {inTransfers.map((t, i) => (
                                                                     <div key={i} className="flex items-center justify-center gap-1.5 px-3 py-1 rounded-full bg-emerald-500/10 text-emerald-600 text-[10px] font-black uppercase whitespace-nowrap border border-emerald-500/10">
                                                                         <span className="text-[12px]">↓</span> {t.quantity} FROM {t.branch_name}
                                                                     </div>
                                                                 ))}
                                                                 {item.inwards === 0 && <span className="text-text-muted/30 font-bold">0</span>}
                                                             </div>
                                                         );
                                                     })()}
                                                 </td>
                                                 <td className="px-6 py-5 text-center font-black text-brand-red bg-danger-subtle/5">
                                                     {(() => {
                                                         const outTransfers = item.transfers?.filter(t => t.type === 'out') || [];
                                                         const outTransfersTotal = outTransfers.reduce((a, t) => a + t.quantity, 0);
                                                         const regularOut = item.outwards - outTransfersTotal;

                                                         return (
                                                             <div className="flex flex-col gap-1.5 items-center">
                                                                 {regularOut > 0 && (
                                                                     <div className="flex flex-col items-center">
                                                                         <span className="text-xs">-{regularOut}</span>
                                                                         <span className="text-[9px] text-text-muted font-black uppercase tracking-tighter">SALES/RETS</span>
                                                                     </div>
                                                                 )}
                                                                 {outTransfers.map((t, i) => (
                                                                     <div key={i} className="flex items-center justify-center gap-1.5 px-3 py-1 rounded-full bg-red-500/10 text-red-600 text-[10px] font-black uppercase whitespace-nowrap border border-red-500/10">
                                                                         <span className="text-[12px]">↑</span> {t.quantity} TO {t.branch_name}
                                                                     </div>
                                                                 ))}
                                                                 {item.outwards === 0 && <span className="text-text-muted/30 font-bold">0</span>}
                                                             </div>
                                                         );
                                                     })()}
                                                 </td>
                                                <td className="px-6 py-5 text-center font-black text-accent bg-accent-subtle/5">+{item.returns}</td>
                                                <td className="px-6 py-5 text-center font-black text-amber-500 bg-warning-subtle/5">{item.adjustments > 0 ? '+' : ''}{item.adjustments}</td>
                                                <td className="px-8 py-5 text-center font-black text-text-primary border-l border-border-default bg-subtle/20 text-sm">{item.ending}</td>
                                                {isReconcileMode && (
                                                    <>
                                                        <td className="px-6 py-5 text-center border-l border-border-default bg-warning-subtle/5">
                                                            <input
                                                                type="number"
                                                                data-index={idx}
                                                                value={actualStr}
                                                                onChange={(e) => setActualCounts(prev => ({ ...prev, [item.id]: e.target.value }))}
                                                                onFocus={(e) => e.target.select()}
                                                                placeholder={item.ending.toString()}
                                                                className="w-20 px-3 py-2 bg-surface border border-border-default rounded-xl text-center font-black text-xs text-text-primary focus:ring-2 focus:ring-brand-orange outline-none"
                                                            />
                                                        </td>
                                                        <td className="px-6 py-5 text-center border-l border-border-default bg-subtle/10">
                                                            {!isNaN(actualNum) && (
                                                                <span className={`px-2 py-1 rounded-lg text-[10px] font-black ${variance === 0 ? 'bg-subtle text-text-muted' : variance > 0 ? 'bg-success-subtle text-success' : 'bg-danger-subtle text-brand-red'}`}>
                                                                    {variance > 0 ? '+' : ''}{variance}
                                                                </span>
                                                            )}
                                                        </td>
                                                    </>
                                                )}
                                            </tr>
                                        );
                                    }) : (
                                        <tr><td colSpan={isReconcileMode ? 9 : 7} className="px-8 py-24 text-center">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="w-12 h-12 bg-bg-subtle rounded-full flex items-center justify-center">
                                                    <Package size={20} className="text-text-muted" />
                                                </div>
                                                <p className="text-sm text-text-muted font-medium">No matching product history found</p>
                                            </div>
                                        </td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div >
    );
}

import { useEffect, useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { supabase } from '../../shared/lib/supabase';
import { useAuth } from '../../shared/hooks/useAuth';
import { useBranch } from '../../shared/lib/BranchContext';
import { ChevronDown, Plus, Search, Edit, Trash2, Package, Filter, FileUp, PackageSearch } from 'lucide-react';
import ProductModal from './components/ProductModal';
import { startOfDay } from 'date-fns';
import { parseExcelFile } from '../../shared/lib/ExcelImportService';
import type { RawProductData } from '../../shared/lib/ExcelImportService';
import { exportInventoryToExcel } from '../../shared/lib/exportUtils';

interface Product {
    id: string;
    name: string;
    stock_available: number;
    stock_reserved: number;
    stock_damaged: number;
    low_stock_threshold?: number;
    selling_price?: number;
    buying_price?: number;
    unit?: string;
    created_at: string;
}

export default function Inventory() {
    const { role } = useAuth();
    const { activeBranchId } = useBranch();
    const navigate = useNavigate();
    const location = useLocation();
    const [products, setProducts] = useState<Product[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
    const [initialModalData, setInitialModalData] = useState<{ l1?: string; l2?: string; l3?: string } | undefined>();
    const [movements, setMovements] = useState<Record<string, { sales: number, purchases: number, refunds: number }>>({});
    const [categoryFilter, setCategoryFilter] = useState('All');
    const [expandedCategories, setExpandedCategories] = useState<Set<string>>(new Set());
    const [expandedL1s, setExpandedL1s] = useState<Set<string>>(new Set());

    const toggleCategory = (cat: string) => {
        const newExpanded = new Set(expandedCategories);
        if (newExpanded.has(cat)) newExpanded.delete(cat);
        else newExpanded.add(cat);
        setExpandedCategories(newExpanded);
    };

    const toggleL1 = (l1: string) => {
        const newExpanded = new Set(expandedL1s);
        if (newExpanded.has(l1)) newExpanded.delete(l1);
        else newExpanded.add(l1);
        setExpandedL1s(newExpanded);
    };

    const handleImportExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (!window.confirm(`Import products from "${file.name}"? This will add or update items. Existing items will have their stock reset to 0 as requested.`)) {
            e.target.value = '';
            return;
        }

        setLoading(true);
        try {
            console.log('Using Import Logic Version: 1.2 (Explicit PK Conflict)');
            const productsToUpsert = await parseExcelFile(file);

            if (productsToUpsert.length === 0) {
                alert('No valid product data found. Please ensure it follows the Price List format.');
                return;
            }

            // Fetch current products for this branch to check for existing names (case-insensitive normalization)
            let existingQuery = supabase.from('products').select('id, name, stock_available');
            if (activeBranchId) {
                existingQuery = existingQuery.eq('branch_id', activeBranchId);
            }
            const { data: existingProducts, error: fetchError } = await existingQuery;
            if (fetchError) throw fetchError;

            // Normalize existing products into a map: NAME -> { id, stock }
            const existingMap = new Map();
            (existingProducts || []).forEach(p => {
                const upperName = p.name.toUpperCase();
                if (existingMap.has(upperName)) {
                    // This case handles existing duplicates in the DB if any
                    existingMap.get(upperName).stock += (p.stock_available || 0);
                    // Keep the first ID as primary
                } else {
                    existingMap.set(upperName, { id: p.id, stock: p.stock_available || 0 });
                }
            });

            // Normalize and group products from Excel (sums up duplicate names in the upload itself)
            const consolidateUpload = new Map<string, RawProductData>();
            productsToUpsert.forEach(item => {
                const name = item.name.toUpperCase();
                if (consolidateUpload.has(name)) {
                    const existing = consolidateUpload.get(name)!;
                    existing.stock_available += (item.stock_available || 0);
                } else {
                    consolidateUpload.set(name, { ...item, name });
                }
            });

            const updates = [];
            const inserts = [];

            for (const [name, item] of consolidateUpload) {
                if (existingMap.has(name)) {
                    const match = existingMap.get(name);
                    // 100-unit standard: if current < 100, set to 100. else keep current.
                    const currentStock = match.stock || 0;
                    const finalStock = currentStock < 100 ? 100 : currentStock;
                    
                    updates.push({
                        id: match.id,
                        ...item,
                        stock_available: finalStock
                    });
                } else {
                    inserts.push({
                        ...item,
                        sku: name,
                        stock_available: 100, // New items always 100
                        branch_id: activeBranchId
                    });
                }
            }

            // Perform batch operations with explicit onConflict for updates
            if (updates.length > 0) {
                const { error: updateError } = await supabase.from('products').upsert(updates, { onConflict: 'id' });
                if (updateError) throw updateError;
            }

            if (inserts.length > 0) {
                const { error: insertError } = await supabase.from('products').insert(inserts);
                if (insertError) throw insertError;
            }

            alert(`Successfully imported/updated ${productsToUpsert.length} products (${updates.length} updated, ${inserts.length} new).`);
            fetchData();
        } catch (err: unknown) {
            console.error('Import error:', err);
            const msg = err instanceof Error ? err.message : JSON.stringify(err);
            alert('Failed to import: ' + msg);
        } finally {
            setLoading(false);
            e.target.value = '';
        }
    };
    
    const handleExportExcel = async () => {
        setLoading(true);
        try {
            // Find current branch name
            const { data: branchData } = await supabase.from('branches').select('name').eq('id', activeBranchId).single();
            const branchName = branchData?.name || 'Current Branch';
            await exportInventoryToExcel(products, branchName);
        } catch (err) {
            console.error('Export error:', err);
            alert('Failed to export inventory.');
        } finally {
            setLoading(false);
        }
    };

    const fetchData = async () => {
        setLoading(true);
        let productsQuery = supabase.from('products').select('*').order('name');
        if (activeBranchId) {
            productsQuery = productsQuery.eq('branch_id', activeBranchId);
        }
        const { data: productsData, error: productsError } = await productsQuery;
        
        if (productsError) console.error('Error fetching inventory:', productsError);
        else setProducts(productsData || []);

        const todayStart = startOfDay(new Date()).toISOString();
        
        let salesQuery = supabase.from('sales').select('product_id, quantity').gte('date', todayStart);
        let purchasesQuery = supabase.from('purchases').select('product_id, quantity').gte('date', todayStart).eq('status', 'received');
        let refundsQuery = supabase.from('customer_refunds').select('product_id, quantity').gte('date', todayStart);

        if (activeBranchId) {
            salesQuery = salesQuery.eq('branch_id', activeBranchId);
            purchasesQuery = purchasesQuery.eq('branch_id', activeBranchId);
            refundsQuery = refundsQuery.eq('branch_id', activeBranchId);
        }

        const [salesRes, purchasesRes, refundsRes] = await Promise.all([
            salesQuery,
            purchasesQuery,
            refundsQuery
        ]);

        const movMap: Record<string, { sales: number, purchases: number, refunds: number }> = {};

        salesRes.data?.forEach(s => {
            const key = s.product_id;
            movMap[key] = { ...movMap[key] || { sales: 0, purchases: 0, refunds: 0 }, sales: (movMap[key]?.sales || 0) + s.quantity };
        });
        purchasesRes.data?.forEach(p => {
            const key = p.product_id;
            movMap[key] = { ...movMap[key] || { sales: 0, purchases: 0, refunds: 0 }, purchases: (movMap[key]?.purchases || 0) + p.quantity };
        });
        refundsRes.data?.forEach(r => {
            const key = r.product_id;
            movMap[key] = { ...movMap[key] || { sales: 0, purchases: 0, refunds: 0 }, refunds: (movMap[key]?.refunds || 0) + r.quantity };
        });

        setMovements(movMap);
        setLoading(false);
    };

    useEffect(() => { fetchData(); }, [activeBranchId]);

    // Handle global search focus from redirection
    useEffect(() => {
        if ((location.state as any)?.focusSearch) {
            const searchEl = document.getElementById('inventory-global-search') as HTMLInputElement | null;
            if (searchEl) {
                searchEl.focus();
                // Clear state
                navigate(location.pathname, { replace: true, state: {} });
            }
        }
    }, [location.state, navigate, location.pathname]);

    const naturalSort = (a: string, b: string) => {
        return a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' });
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm('Delete this product?')) return;
        const { error } = await supabase.from('products').delete().eq('id', id);
        if (error) alert('Error: ' + error.message);
        else fetchData();
    };

    const handleBulkDelete = async (filter: { master?: string, category?: string, subCat?: string }) => {
        let label = '';
        if (filter.subCat) label = `Sub-category: ${filter.subCat}`;
        else if (filter.category) label = `Category: ${filter.category}`;
        else if (filter.master) label = `Master Category: ${filter.master}`;

        if (!window.confirm(`STRICT WARNING: This will permanently delete ALL products in "${label}" for this branch. Proceed?`)) return;

        setLoading(true);
        try {
            let query = supabase.from('products').delete();
            if (activeBranchId) query = query.eq('branch_id', activeBranchId);
            
            // Construct name pattern for deletion
            let pattern = '';
            if (filter.subCat) pattern = `${filter.master} > ${filter.category} > ${filter.subCat} > %`;
            else if (filter.category) pattern = `${filter.master} > ${filter.category} > %`;
            else if (filter.master) pattern = `${filter.master} > %`;

            const { error } = await query.ilike('name', pattern);
            if (error) throw error;
            
            fetchData();
        } catch (err) {
            console.error('Bulk delete error:', err);
            alert('Bulk delete failed.');
        } finally {
            setLoading(false);
        }
    };

    const filtered = products.filter(p => {
        const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
        const category = p.name.split(' > ')[0] || 'Uncategorized';
        const matchesCategory = categoryFilter === 'All' || category === categoryFilter;
        return matchesSearch && matchesCategory;
    });

    useEffect(() => {
        if (searchTerm !== '' || categoryFilter !== 'All') {
            const newL1s = new Set(expandedL1s);
            const newCats = new Set(expandedCategories);
            
            filtered.forEach(p => {
                const parts = p.name.split(' > ');
                if (parts[0]) {
                    newL1s.add(parts[0]);
                    if (parts[1]) {
                        newCats.add(`${parts[0]} > ${parts[1]}`);
                        if (parts[2]) {
                            newCats.add(`${parts[0]} > ${parts[1]} > ${parts[2]}`);
                        }
                    }
                }
            });
            
            setExpandedL1s(newL1s);
            setExpandedCategories(newCats);
        }
    }, [searchTerm, categoryFilter, products.length > 0]);

    const getMasterColor = (master: string) => {
        const m = master.toUpperCase();
        if (m.includes('PLYWOOD')) return '#0369A1';
        if (m.includes('STEEL')) return '#1E8449';
        if (m.includes('ELECTRICAL')) return '#7C3AED';
        if (m.includes('ROOFING')) return '#B45309';
        return '#EF4444'; // Brand Red default
    };

    const groupedProducts = filtered.reduce((acc: Record<string, Record<string, Record<string, Product[]>>>, p) => {
        const parts = p.name.split(' > ');
        const master = parts[0] || 'UNCATEGORIZED';
        const category = parts[1] || 'GENERAL';
        const subCat = parts[2] || 'GENERAL';
        
        if (!acc[master]) acc[master] = {};
        if (!acc[master][category]) acc[master][category] = {};
        if (!acc[master][category][subCat]) acc[master][category][subCat] = [];
        
        acc[master][category][subCat].push(p);
        return acc;
    }, {});

    const sortedL1s = Object.keys(groupedProducts).sort(naturalSort);
    const allCategories = Array.from(new Set(products.map(p => p.name.split(' > ')[0] || 'Uncategorized'))).sort(naturalSort);

    const getStockStatus = (stock: number, threshold: number = 10) => {
        if (stock === 0) return { label: 'Out of Stock', cls: 'badge-out-of-stock' };
        if (stock <= threshold) return { label: 'Low Stock', cls: 'badge-low-stock' };
        return { label: 'In Stock', cls: 'badge-in-stock' };
    };

    const stats = {
        totalSKUs: products.length,
        lowStock: products.filter(p => p.stock_available > 0 && p.stock_available <= (p.low_stock_threshold || 10)).length,
        outOfStock: products.filter(p => p.stock_available === 0).length,
        totalValue: role === 'owner' ? products.reduce((acc, p) => acc + (p.stock_available * (p.selling_price || 0)), 0) : null
    };

    return (
        <div className="space-y-8 animate-fade-in max-w-none">
            {/* Header Title Row */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div>
                    <h1 className="text-3xl font-black text-text-primary tracking-tight flex items-center gap-3">
                        <div className="w-12 h-12 bg-brand-red rounded-2xl flex items-center justify-center shadow-red"><PackageSearch className="text-white" size={24} /></div>
                        Inventory Dashboard
                    </h1>
                    <p className="text-sm text-text-secondary mt-1 font-medium">Monitor stock levels, manage categories, and track movements</p>
                </div>
                <div className="flex items-center gap-3">
                    <button 
                        onClick={handleExportExcel}
                        className="flex items-center gap-2 bg-surface border border-border-default text-text-secondary px-5 py-3 rounded-2xl font-bold text-sm hover:bg-subtle transition-all shadow-sm"
                    >
                        <FileUp size={18} className="text-emerald-500" /> EXPORT
                    </button>
                    <label className="flex items-center gap-2 bg-surface border border-border-default text-text-secondary px-5 py-3 rounded-2xl font-bold text-sm hover:bg-subtle transition-all shadow-sm cursor-pointer">
                        <FileUp size={18} className="text-blue-500" /> IMPORT
                        <input type="file" accept=".xlsx" className="hidden" onChange={handleImportExcel} />
                    </label>
                    {role === 'owner' && (
                        <button onClick={() => { setSelectedProduct(null); setIsModalOpen(true); }} className="flex items-center gap-2 bg-brand-red text-white px-6 py-3 rounded-2xl font-black text-sm hover:bg-brand-red-dark transition-all shadow-red active:scale-95">
                            <Plus size={18} /> ADD PRODUCT
                        </button>
                    )}
                </div>
            </div>

            {/* Action Row */}
            <div className="flex flex-col sm:flex-row gap-4 relative">
                <div className="relative group flex-1">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-text-muted group-focus-within:text-brand-red transition-colors" size={18} />
                    <input 
                        id="inventory-global-search"
                        type="text" 
                        placeholder="Search inventory products..." 
                        className="w-full pl-12 pr-4 py-3 bg-surface border border-border-default rounded-2xl text-sm focus:ring-2 focus:border-brand-red outline-none transition-all shadow-sm placeholder:text-text-muted text-text-primary" 
                        value={searchTerm} 
                        onChange={(e) => setSearchTerm(e.target.value)} 
                    />
                </div>
            </div>

            <div className="flex flex-col lg:flex-row gap-6">
                {/* Stats Sidebar */}
                <div className="flex-shrink-0">
                    <div className="sticky top-6 space-y-4">
                        <div className="bg-surface p-6 rounded-3xl border border-border-default shadow-sm overflow-hidden relative w-full lg:w-64">
                            <div className="absolute top-0 right-0 w-24 h-24 bg-brand-red/5 rounded-full -mr-12 -mt-12" />
                            <h3 className="text-[10px] font-black text-text-primary border-b border-border-default pb-3 mb-4 uppercase tracking-[0.2em]">Summary Statistics</h3>
                            <div className="space-y-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-1">Total SKUs</p>
                                        <p className="text-lg font-black text-text-primary font-data">{stats.totalSKUs}</p>
                                    </div>
                                    <div>
                                        <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-1">Low Stock</p>
                                        <p className="text-lg font-black text-amber-500 font-data">{stats.lowStock}</p>
                                    </div>
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-1">Out Stock</p>
                                        <p className="text-lg font-black text-brand-red font-data">{stats.outOfStock}</p>
                                    </div>
                                    <div>
                                        <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-1">Daily Delta</p>
                                        <p className="text-lg font-black text-blue-500 font-data">{Object.values(movements).reduce((a, m) => a + (m.purchases - m.sales + m.refunds), 0)}</p>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Existing Categories Sidebar */}
                        <div className="hidden lg:block bg-surface p-4 rounded-3xl border border-border-default shadow-sm overflow-y-auto max-h-[calc(100vh-400px)] custom-scrollbar w-64">
                            <p className="text-[9px] font-black text-text-muted uppercase tracking-widest px-2 mb-3 px-3 pb-2 border-b border-border-default">Quick Categories</p>
                            <div className="space-y-1 mt-2">
                                <button onClick={() => setCategoryFilter('All')} className={`w-full text-left px-3 py-2 rounded-xl text-xs font-bold transition-all ${categoryFilter === 'All' ? 'bg-brand-red text-white shadow-sm' : 'text-text-secondary hover:bg-subtle'}`}>All Items</button>
                                {allCategories.map(cat => (
                                    <button key={cat} onClick={() => setCategoryFilter(cat)} className={`w-full text-left px-3 py-2 rounded-xl text-xs font-bold transition-all truncate ${categoryFilter === cat ? 'bg-brand-red text-white shadow-sm' : 'text-text-secondary hover:bg-subtle'}`}>{cat}</button>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex-1 min-w-0 space-y-6">
                    <div className="lg:hidden grid grid-cols-1 md:grid-cols-2 gap-3">
                        <div className="relative">
                            <Filter className="absolute left-3 top-1/2 -translate-y-1/2 text-text-muted" size={14} />
                            <select className="w-full bg-surface border border-border-default rounded-xl pl-9 pr-4 py-2 text-xs font-black text-text-primary appearance-none shadow-sm outline-none focus:ring-2 focus:ring-brand-red/10" value={categoryFilter} onChange={(e) => setCategoryFilter(e.target.value)}>
                                <option value="All">All Categories</option>
                                {allCategories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                            </select>
                        </div>
                    </div>
                    <div className="space-y-8">
                        {loading ? ([1, 2, 3].map(i => <div key={i} className="bento-card p-8 skeleton h-20" />)) : sortedL1s.length === 0 ? (
                            <div className="bg-surface rounded-3xl border border-border-default py-20 text-center shadow-sm">
                                <div className="flex flex-col items-center gap-3">
                                    <div className="w-12 h-12 bg-muted rounded-full flex items-center justify-center"><Package size={20} className="text-text-muted" /></div>
                                    <p className="text-sm text-text-secondary font-medium">No products found</p>
                                </div>
                            </div>
                        ) : (
                            sortedL1s.map(master => {
                                const isMasterExpanded = expandedL1s.has(master);
                                const categories = groupedProducts[master];
                                const mColor = getMasterColor(master);
                                return (
                                    <div key={master} className="space-y-4">
                                        <div 
                                            className="flex items-center justify-between border-l-4 pl-4 py-2 bg-brand-red/5 rounded-r-xl cursor-pointer" 
                                            style={{ borderLeftColor: mColor }}
                                            onClick={() => toggleL1(master)}
                                        >
                                            <div className="flex items-center gap-3">
                                                <h2 className="text-xl font-black text-text-primary tracking-tighter uppercase" style={{ color: mColor }}>{master}</h2>
                                                <span className="px-2 py-0.5 rounded-full bg-muted text-[10px] font-black text-text-primary uppercase tracking-widest">
                                                    {Object.values(categories).reduce((acc, cat) => acc + Object.values(cat).flat().length, 0)} items
                                                </span>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                {role === 'owner' && (
                                                    <div className="flex items-center gap-2">
                                                        <button 
                                                            onClick={(e) => { e.stopPropagation(); handleBulkDelete({ master }); }}
                                                            className="flex items-center justify-center w-8 h-8 rounded-lg text-text-muted/50 hover:text-brand-red hover:bg-brand-red/10 transition-all"
                                                            title="Delete Master Category"
                                                        >
                                                            <Trash2 size={16} />
                                                        </button>
                                                        <button onClick={(e) => { e.stopPropagation(); setInitialModalData({ l1: master }); setSelectedProduct(null); setIsModalOpen(true); }} className="flex items-center gap-1.5 text-[10px] font-black bg-text-primary text-text-inverse px-3 py-1.5 rounded-lg hover:bg-brand-red transition-all uppercase tracking-widest"><Plus size={12} /> ADD UNIT</button>
                                                    </div>
                                                )}
                                                <div className={`transition-transform duration-300 ${isMasterExpanded ? 'rotate-180' : ''}`}><ChevronDown size={20} className="text-text-muted" /></div>
                                            </div>
                                        </div>

                                        {isMasterExpanded && (
                                            <div className="space-y-6 ml-4 border-l-2 border-border-default/50 pl-6">
                                                {Object.keys(categories).sort(naturalSort).map(catName => {
                                                    const subCats = categories[catName];
                                                    const isCatExpanded = expandedCategories.has(`${master} > ${catName}`);
                                                    return (
                                                        <div key={catName} className="space-y-3">
                                                            <div className="flex items-center justify-between group">
                                                                <div className="flex items-center gap-2 cursor-pointer" onClick={() => toggleCategory(`${master} > ${catName}`)}>
                                                                    <div className={`p-1 rounded transition-colors ${isCatExpanded ? 'bg-brand-red text-white' : 'bg-subtle text-text-muted'}`}>
                                                                        <ChevronDown size={12} className={`transition-transform ${isCatExpanded ? 'rotate-0' : '-rotate-90'}`} />
                                                                    </div>
                                                                    <h3 className="text-sm font-black text-text-primary uppercase tracking-tight group-hover:text-brand-red transition-colors">{catName}</h3>
                                                                    <span className="text-[10px] font-bold text-text-secondary">({Object.values(subCats).flat().length})</span>
                                                                </div>
                                                                {role === 'owner' && (
                                                                    <button 
                                                                        onClick={(e) => { e.stopPropagation(); handleBulkDelete({ master, category: catName }); }}
                                                                        className="opacity-0 group-hover:opacity-100 p-1 text-text-muted/50 hover:text-brand-red transition-all"
                                                                        title="Delete Category"
                                                                    >
                                                                        <Trash2 size={12} />
                                                                    </button>
                                                                )}
                                                            </div>

                                                            {isCatExpanded && (
                                                                <div className="grid grid-cols-1 gap-4 ml-2">
                                                                    {Object.keys(subCats).sort(naturalSort).map((subName: string) => {
                                                                        const items: Product[] = subCats[subName];
                                                                        const isSubExpanded = expandedCategories.has(`${master} > ${catName} > ${subName}`);
                                                                        return (
                                                                            <div key={subName} className="bg-surface rounded-3xl border border-border-default overflow-hidden shadow-sm">
                                                                                <div onClick={() => toggleCategory(`${master} > ${catName} > ${subName}`)} className="px-5 py-2.5 bg-subtle/30 flex items-center justify-between cursor-pointer hover:bg-subtle transition-colors group/sub">
                                                                                    <div className="flex items-center gap-3">
                                                                                        <div className="flex items-center gap-2">
                                                                                            <h4 className="text-[11px] font-black text-text-secondary uppercase tracking-widest">{subName}</h4>
                                                                                            <span className="text-[9px] font-bold text-text-muted">{items.length} units</span>
                                                                                        </div>
                                                                                        {role === 'owner' && (
                                                                                            <button 
                                                                                                onClick={(e) => { e.stopPropagation(); handleBulkDelete({ master, category: catName, subCat: subName }); }}
                                                                                                className="opacity-0 group-hover/sub:opacity-100 p-1 text-text-muted/50 hover:text-brand-red transition-all"
                                                                                                title="Delete Sub-category"
                                                                                            >
                                                                                                <Trash2 size={12} />
                                                                                            </button>
                                                                                        )}
                                                                                    </div>
                                                                                    <ChevronDown size={14} className={`text-text-muted transition-transform ${isSubExpanded ? 'rotate-180' : ''}`} />
                                                                                </div>
                                                                                
                                                                                {isSubExpanded && (
                                                                                    <div className="overflow-x-auto">
                                                                                        <table className="min-w-full">
                                                                                            <thead>
                                                                                                <tr className="bg-subtle/20 border-b border-border-default">
                                                                                                    <th className="px-4 py-2 text-left text-[9px] font-black uppercase tracking-widest text-text-muted w-24">Status</th>
                                                                                                    <th className="px-4 py-2 text-left text-[9px] font-black uppercase tracking-widest text-text-muted">Item Description</th>
                                                                                                    <th className="px-4 py-2 text-center text-[9px] font-black uppercase tracking-widest text-text-muted w-20">Unit</th>
                                                                                                    <th className="px-4 py-2 text-right text-[9px] font-black uppercase tracking-widest text-text-muted w-24">WSP (₱)</th>
                                                                                                    <th className="px-4 py-2 text-right text-[9px] font-black uppercase tracking-widest text-text-muted w-24">SRP (₱)</th>
                                                                                                    <th className="px-4 py-2 text-center text-[9px] font-black uppercase tracking-widest text-text-muted w-24">Stock</th>
                                                                                                    <th className="px-4 py-2 text-right text-[9px] font-black uppercase tracking-widest text-text-muted w-20">Actions</th>
                                                                                                </tr>
                                                                                            </thead>
                                                                                            <tbody className="divide-y divide-subtle">
                                                                                                {items.map(product => {
                                                                                                    const status = getStockStatus(product.stock_available, product.low_stock_threshold);
                                                                                                    return (
                                                                                                        <tr key={product.id} className="hover:bg-subtle/50 transition-colors group">
                                                                                                            <td className="px-4 py-2">
                                                                                                                <span className={`px-1.5 py-0.5 rounded-[4px] text-[8px] font-black uppercase ${status.cls}`}>{status.label}</span>
                                                                                                            </td>
                                                                                                            <td className="px-4 py-2">
                                                                                                                <p className="text-[11px] font-black text-text-primary uppercase">{product.name.split(' > ').slice(-1)[0]}</p>
                                                                                                            </td>
                                                                                                            <td className="px-4 py-2 text-center">
                                                                                                                <span className="text-[10px] font-black text-text-muted uppercase tracking-widest">{product.unit || 'pc'}</span>
                                                                                                            </td>
                                                                                                            <td className="px-4 py-2 text-right">
                                                                                                                <span className="text-[11px] font-bold font-data text-text-secondary">
                                                                                                                    {product.buying_price ? `₱${product.buying_price.toLocaleString()}` : '-'}
                                                                                                                </span>
                                                                                                            </td>
                                                                                                            <td className="px-4 py-2 text-right">
                                                                                                                <span className="text-[11px] font-black font-data text-brand-red">
                                                                                                                    ₱{(product.selling_price || 0).toLocaleString()}
                                                                                                                </span>
                                                                                                            </td>
                                                                                                            <td className="px-4 py-2 text-center">
                                                                                                                <span className="text-[11px] font-bold font-data text-emerald-500 bg-emerald-500/10 px-2 py-1 rounded-md">{product.stock_available}</span>
                                                                                                            </td>
                                                                                                            <td className="px-4 py-2 text-right">
                                                                                                                <div className="flex justify-end gap-1">
                                                                                                                    <button onClick={() => { setSelectedProduct(product); setIsModalOpen(true); }} className="p-1 text-text-muted/50 hover:text-text-primary transition-all"><Edit size={14} /></button>
                                                                                                                    {role === 'owner' && <button onClick={() => handleDelete(product.id)} className="p-1 text-text-muted/50 hover:text-brand-red transition-all"><Trash2 size={14} /></button>}
                                                                                                                </div>
                                                                                                            </td>
                                                                                                        </tr>
                                                                                                    );
                                                                                                })}
                                                                                            </tbody>
                                                                                        </table>
                                                                                    </div>
                                                                                )}
                                                                            </div>
                                                                        );
                                                                    })}
                                                                </div>
                                                            )}
                                                        </div>
                                                    );
                                                })}
                                            </div>
                                        )}
                                    </div>
                                );
                            })
                        )}
                    </div>
                    <ProductModal isOpen={isModalOpen} onClose={() => { setIsModalOpen(false); setInitialModalData(undefined); }} onSuccess={fetchData} product={selectedProduct} role={role} initialData={initialModalData} />
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { supabase } from '../../../shared/lib/supabase';
import { X, Package, AlertTriangle, Info, Tag, DollarSign, Building2, Eye, Truck } from 'lucide-react';
import { useBranch } from '../../../shared/lib/BranchContext';
import CategoryRenameModal from './CategoryRenameModal';
import { encodePrice } from '../../../shared/lib/priceCodes';
import type { Supplier } from '../../suppliers/types/supplier';
import { supplierService } from '../../suppliers/services/supplierService';

interface Product {
    id?: string;
    name: string;
    stock_available: number;
    stock_reserved: number;
    stock_damaged: number;
    category?: string;
    brand?: string;
    description?: string;
    buying_price?: number;
    selling_price?: number;
    unit?: string;
    low_stock_threshold?: number;
    supplier_id?: string | null;
}

interface ProductModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
    product?: Product | null;
    role: 'owner' | 'admin' | 'encoder' | null;
    initialData?: { l1?: string; l2?: string; l3?: string };
}

export default function ProductModal(props: ProductModalProps) {
    const { isOpen, onClose, onSuccess, product, role } = props;
    const { activeBranchId } = useBranch();
    const [formData, setFormData] = useState<Product>({
        name: '',
        stock_available: 0,
        stock_reserved: 0,
        stock_damaged: 0,
        brand: '',
        description: '',
        buying_price: 0,
        selling_price: 0,
        unit: 'pc',
        low_stock_threshold: 10,
        supplier_id: null
    });
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);

    const [l2Choices, setL2Choices] = useState<string[]>([]);
    const [l3Choices, setL3Choices] = useState<string[]>([]);

    const [l1, setL1] = useState('');
    const [l2, setL2] = useState('');
    const [l3, setL3] = useState('');
    const [l4, setL4] = useState('');

    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const [renameState, setRenameState] = useState<{ isOpen: boolean; currentName: string; level: 1 | 2 | 3 | null }>({
        isOpen: false,
        currentName: '',
        level: null
    });

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.ctrlKey && e.key === 'Enter') {
                e.preventDefault();
                (document.getElementById('product-form') as HTMLFormElement)?.requestSubmit();
            }
        };

        if (isOpen) {
            document.body.classList.add('modal-open');
            document.addEventListener('keydown', handleKeyDown);
        } else {
            document.body.classList.remove('modal-open');
        }
        return () => {
            document.body.classList.remove('modal-open');
            document.removeEventListener('keydown', handleKeyDown);
        };
    }, [isOpen]);

    useEffect(() => {
        const fetchChoices = async () => {
            let query = supabase.from('products').select('name');
            if (activeBranchId) {
                query = query.eq('branch_id', activeBranchId);
            }
            const { data } = await query;
            if (data) {
                const l1s = new Set<string>();
                const l2s = new Set<string>();
                const l3s = new Set<string>();
                data.forEach(p => {
                    const parts = p.name.split(' > ');
                    if (parts.length >= 1) l1s.add(parts[0]);
                    if (parts.length >= 2) l2s.add(parts[1]);
                    if (parts.length >= 3) l3s.add(parts[2]);
                    if (p.name.includes(' - ') && !p.name.includes(' > ')) {
                        const legacyParts = p.name.split(' - ');
                        l2s.add(legacyParts[0]);
                    }
                });

                setL2Choices(Array.from(l2s).filter(Boolean).sort());
                setL3Choices(Array.from(l3s).filter(Boolean).sort());
            }
        };

        const fetchSuppliers = async () => {
            try {
                const data = await supplierService.getAll();
                setSuppliers(data);
            } catch (err) {
                console.error('Error fetching suppliers:', err);
            }
        };

        if (isOpen) {
            fetchChoices();
            fetchSuppliers();
        }

        if (product) {
            setFormData({
                ...product,
                brand: product.brand || '',
                description: product.description || '',
                buying_price: product.buying_price || 0,
                selling_price: product.selling_price || 0,
                unit: product.unit || 'pc',
                low_stock_threshold: product.low_stock_threshold || 10
            });
            const name = product.name;
            if (name.includes(' > ')) {
                const parts = name.split(' > ');
                setL1(parts[0] || '');
                setL2(parts[1] || '');
                setL3(parts[2] || '');
                setL4(parts[3] || '');
            } else if (name.includes(' - ')) {
                const [cat, type] = name.split(' - ');
                setL1('UNCATEGORIZED');
                setL2(cat);
                setL3('');
                setL4(type);
            } else {
                setL1('UNCATEGORIZED');
                setL2('');
                setL3('');
                setL4(name);
            }
        } else {
            setFormData({
                name: '',
                stock_available: 0,
                stock_reserved: 0,
                stock_damaged: 0,
                brand: '',
                description: '',
                buying_price: 0,
                selling_price: 0,
                unit: 'pc',
                low_stock_threshold: 10
            });
            setL1(props.initialData?.l1 || '');
            setL2(props.initialData?.l2 || '');
            setL3(props.initialData?.l3 || '');
            setL4('');
        }
        setError(null);
    }, [product, isOpen, props.initialData]);

    if (!isOpen) return null;
    const isEditing = !!product;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);
        try {
            const parts = [l1.trim(), l2.trim(), l3.trim(), l4.trim()].filter(p => p !== '');
            const finalName = parts.join(' > ').toUpperCase();
            if (!finalName) throw new Error('Product name cannot be empty');

            // PRICE VALIDATION
            if (formData.buying_price === 0) throw new Error('WSP (Buying Price) is required and cannot be 0.');
            if (formData.selling_price === 0) throw new Error('SRP (Selling Price) is required and cannot be 0.');
            if (formData.buying_price === formData.selling_price) throw new Error('WSP and SRP cannot be the same. There must be a profit margin.');

            const payload = {
                name: finalName,
                sku: finalName, // Satisfy NOT NULL constraint in DB
                stock_available: formData.stock_available,
                stock_reserved: formData.stock_reserved,
                stock_damaged: formData.stock_damaged,
                brand: formData.brand?.trim(),
                description: formData.description?.trim(),
                buying_price: formData.buying_price,
                selling_price: formData.selling_price,
                unit: formData.unit?.trim(),
                low_stock_threshold: formData.low_stock_threshold,
                supplier_id: formData.supplier_id || null,
                branch_id: activeBranchId
            };

            if (isEditing && product?.id) {
                const { error } = await supabase.from('products').update(payload).eq('id', product.id);
                if (error) throw error;
            } else {
                const { error } = await supabase.from('products').insert([payload]);
                if (error) throw error;
            }
            onSuccess();
            onClose();
        } catch (err) {
            setError(err instanceof Error ? err.message : (err as { message?: string })?.message || JSON.stringify(err));
        } finally {
            setLoading(false);
        }
    };

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/85 px-4 py-6">
            <div className="w-full max-w-2xl rounded-2xl bg-surface shadow-2xl border border-border-default overflow-hidden animate-slide-up flex flex-col max-h-[90vh]">
                <div className="flex items-center justify-between px-6 py-3 bg-text-primary">
                    <div className="flex items-center gap-3 text-text-inverse">
                        <div className="w-8 h-8 bg-brand-red rounded-lg flex items-center justify-center text-white"><Package size={16} /></div>
                        <h2 className="text-base font-bold">{isEditing ? 'Edit Product' : 'New Product'}</h2>
                    </div>
                    <button onClick={onClose} className="text-text-muted hover:text-text-inverse"><X size={18} /></button>
                </div>

                <div className="p-4 overflow-y-auto scrollbar-hide text-left">
                    {error && <div className="mb-4 p-3 bg-red-500/10 border border-red-500/20 text-red-500 text-sm rounded-xl flex items-center gap-2"><AlertTriangle size={16} /> {error}</div>}
                    <form id="product-form" onSubmit={handleSubmit} className="space-y-4">
                        {/* Section 1: Classification */}
                        <div className="space-y-3">
                            <h3 className="text-[10px] font-black text-text-primary uppercase tracking-[0.2em] flex items-center gap-2">
                                <Tag size={12} /> Classification & Identification
                            </h3>
                            <div className="p-3 bg-subtle rounded-xl border border-border-default grid grid-cols-1 md:grid-cols-2 gap-3">
                                <div>
                                    <div className="flex justify-between mb-1.5"><label className="text-[9px] font-black uppercase text-text-primary">Master Category</label></div>
                                    <select 
                                        required 
                                        className="modal-input text-xs bg-surface border border-border-default text-text-primary rounded-xl px-4 py-2 w-full outline-none focus:ring-2 focus:ring-brand-red/20 appearance-none" 
                                        value={l1} 
                                        onChange={e => setL1(e.target.value)}
                                    >
                                        <option value="" disabled>Select Master Category</option>
                                        <option value="STEEL">STEEL</option>
                                        <option value="PLYWOOD">PLYWOOD</option>
                                        <option value="ELECTRICALS">ELECTRICALS</option>
                                        <option value="ROOFING">ROOFING</option>
                                    </select>
                                </div>
                                <div>
                                    <div className="flex justify-between mb-1.5"><label className="text-[9px] font-black uppercase text-text-primary">Category</label>{l2 && <button type="button" onClick={() => setRenameState({ isOpen: true, currentName: l2, level: 2 })} className="text-[8px] font-bold text-amber-600 hover:underline">RENAME</button>}</div>
                                    <input type="text" list="l2-options" className="modal-input text-xs bg-surface border border-border-default text-text-primary rounded-xl px-4 py-2 w-full outline-none focus:ring-2 focus:ring-brand-red/20" value={l2} onChange={e => setL2(e.target.value.toUpperCase())} />
                                    <datalist id="l2-options">{l2Choices.map(c => <option key={c} value={c} />)}</datalist>
                                </div>
                                <div>
                                    <div className="flex justify-between mb-1.5"><label className="text-[9px] font-black uppercase text-text-primary">Subcategory</label>{l3 && <button type="button" onClick={() => setRenameState({ isOpen: true, currentName: l3, level: 3 })} className="text-[8px] font-bold text-amber-600 hover:underline">RENAME</button>}</div>
                                    <input type="text" list="l3-options" className="modal-input text-xs bg-surface border border-border-default text-text-primary rounded-xl px-4 py-2 w-full outline-none focus:ring-2 focus:ring-brand-red/20" value={l3} onChange={e => setL3(e.target.value.toUpperCase())} />
                                    <datalist id="l3-options">{l3Choices.map(c => <option key={c} value={c} />)}</datalist>
                                </div>
                                <div><label className="block text-[9px] font-black uppercase text-text-primary mb-1.5">Details / Size <span className="text-text-muted font-normal normal-case">(optional)</span></label><input type="text" className="modal-input text-xs bg-surface border border-border-default text-text-primary rounded-xl px-4 py-2 w-full outline-none focus:ring-2 focus:ring-brand-red/20" value={l4} onChange={e => setL4(e.target.value.toUpperCase())} /></div>
                            </div>
                        </div>

                        {/* Section 2: Extended Info */}
                        <div className="space-y-3">
                            <h3 className="text-[10px] font-black text-text-primary uppercase tracking-[0.2em] flex items-center gap-2">
                                <Info size={12} /> Extended Information
                            </h3>
                            <div className="p-3 bg-subtle rounded-xl border border-border-default grid grid-cols-1 md:grid-cols-3 gap-3">
                                <div className="md:col-span-1">
                                    <label className="block text-[9px] font-black uppercase text-text-secondary mb-1.5 flex items-center gap-1.5"><Building2 size={10} /> Brand</label>
                                    <input type="text" placeholder="e.g. Samsung, Nike" className="modal-input text-xs bg-surface border border-border-default text-text-primary rounded-xl px-4 py-2 w-full outline-none focus:ring-2 focus:ring-brand-red/20" value={formData.brand} onChange={e => setFormData({ ...formData, brand: e.target.value })} />
                                </div>
                                <div className="md:col-span-1">
                                    <label className="block text-[9px] font-black uppercase text-text-secondary mb-1.5">Unit (pc, sheet, length...)</label>
                                    <input type="text" placeholder="e.g. pc, roll" className="modal-input text-xs bg-surface border border-border-default text-text-primary rounded-xl px-4 py-2 w-full outline-none focus:ring-2 focus:ring-brand-red/20" value={formData.unit} onChange={e => setFormData({ ...formData, unit: e.target.value })} />
                                </div>
                                <div className="md:col-span-1">
                                    <label className="block text-[9px] font-black uppercase text-text-secondary mb-1.5">Description / Remarks</label>
                                    <input type="text" placeholder="Additional details..." className="modal-input text-xs bg-surface border border-border-default text-text-primary rounded-xl px-4 py-2 w-full outline-none focus:ring-2 focus:ring-brand-red/20" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                                </div>
                                <div className="md:col-span-3">
                                    <label className="block text-[9px] font-black uppercase text-text-secondary mb-1.5 flex items-center gap-1.5"><Truck size={10} /> Preferred Supplier</label>
                                    <select
                                        className="modal-input text-xs bg-surface border border-border-default text-text-primary rounded-xl px-4 py-2 w-full outline-none focus:ring-2 focus:ring-brand-red/20"
                                        value={formData.supplier_id || ''}
                                        onChange={e => setFormData({ ...formData, supplier_id: e.target.value || null })}
                                    >
                                        <option value="">No Preferred Supplier</option>
                                        {suppliers.map(s => (
                                            <option key={s.id} value={s.id}>{s.name}</option>
                                        ))}
                                    </select>
                                </div>
                            </div>
                        </div>

                        {/* Section 3: Financial & Stock */}
                        <div className="space-y-3">
                            <h3 className="text-[10px] font-black text-text-primary uppercase tracking-[0.2em] flex items-center gap-2">
                                <DollarSign size={12} /> Financial & Inventory
                            </h3>
                            <div className="p-3 bg-subtle rounded-xl border border-border-default space-y-3">
                                <div className="grid grid-cols-2 gap-3">
                                    <div>
                                        <label className="block text-[9px] font-black uppercase text-amber-600 mb-1.5">WSP (Buying Price / Cost)</label>
                                        <div className="relative group">
                                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-text-muted text-[10px]">₱</span>
                                            <input type="number" step="0.01" className="w-full bg-surface border border-border-default rounded-xl pl-6 pr-16 py-2 text-xs font-data text-text-primary outline-none focus:ring-2 focus:ring-brand-red/20 transition-all" value={formData.buying_price} onChange={e => setFormData({ ...formData, buying_price: parseFloat(e.target.value) || 0 })} onFocus={e => e.target.select()} />
                                            <div className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center gap-1.5 px-2 py-0.5 bg-muted rounded text-[9px] font-black pointer-events-none text-text-secondary border border-border-default">
                                                <Eye size={10} /> {encodePrice(formData.buying_price)}
                                            </div>
                                        </div>
                                    </div>
                                    <div>
                                        <label className="block text-[9px] font-black uppercase text-brand-red mb-1.5">SRP (Selling Price)</label>
                                        <div className="relative">
                                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-text-muted text-[10px]">₱</span>
                                            <input type="number" step="0.01" className="w-full bg-surface border border-border-default rounded-xl pl-6 pr-3 py-2 text-xs font-data text-text-primary outline-none focus:ring-2 focus:ring-brand-red/20 transition-all" value={formData.selling_price} onChange={e => setFormData({ ...formData, selling_price: parseFloat(e.target.value) || 0 })} onFocus={e => e.target.select()} />
                                        </div>
                                    </div>
                                </div>

                                <div className="grid grid-cols-2 gap-4 pt-2">
                                    <div>
                                        <label className="block text-[9px] font-bold uppercase text-text-secondary mb-1.5">Current Stock</label>
                                        <input type="number" min="0" required disabled={role !== 'owner' && isEditing} className="w-full bg-surface border border-border-default rounded-xl px-3 py-2 text-xs font-data text-text-primary focus:border-brand-red focus:ring-1 focus:ring-brand-red outline-none transition-all disabled:bg-muted disabled:text-text-muted" value={formData.stock_available} onChange={e => setFormData({ ...formData, stock_available: parseInt(e.target.value) || 0 })} onFocus={e => e.target.select()} />
                                    </div>
                                    <div>
                                        <label className="block text-[9px] font-bold uppercase text-orange-600 mb-1.5">Alert Trigger (Low Stock at)</label>
                                        <input type="number" min="0" required className="w-full bg-surface border border-orange-200 rounded-xl px-3 py-2 text-xs font-data text-text-primary focus:border-orange-500 focus:ring-1 focus:ring-orange-500 outline-none transition-all" value={formData.low_stock_threshold} onChange={e => setFormData({ ...formData, low_stock_threshold: parseInt(e.target.value) || 0 })} onFocus={e => e.target.select()} />
                                    </div>
                                </div>
                                {!isEditing && (
                                    <div className="bg-brand-red/10 rounded-xl p-2 flex items-center gap-2 border border-brand-red/20">
                                        <Info size={14} className="text-brand-red" />
                                        <p className="text-[10px] text-text-primary">Initial stock count for new items.</p>
                                    </div>
                                )}
                            </div>
                        </div>

                        <div className="flex justify-end gap-3 pt-3 border-t border-border-default">
                            <button type="button" onClick={onClose} className="px-5 py-2 border border-border-strong/20 text-text-secondary font-bold text-[10px] rounded-lg hover:bg-subtle transition-colors uppercase tracking-widest">Cancel</button>
                            <button type="submit" disabled={loading} className="px-6 py-2 bg-brand-red text-white text-[10px] font-black uppercase tracking-widest rounded-lg shadow-red hover:bg-brand-red-dark disabled:opacity-50 transition-all active:scale-95">
                                {loading ? 'SAVING...' : 'SAVE PRODUCT'}
                            </button>
                        </div>
                    </form>
                </div>
            </div>

            <CategoryRenameModal
                isOpen={renameState.isOpen}
                onClose={() => setRenameState({ ...renameState, isOpen: false })}
                onSuccess={() => window.location.reload()}
                currentName={renameState.currentName}
                level={renameState.level as 1 | 2 | 3}
            />
        </div>,
        document.body
    );
}

import { useEffect, useState, useCallback, Fragment } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { supabase } from '../../shared/lib/supabase';
import {
    Search, ChevronDown, ShoppingBag, Package, Download, Filter, CheckCircle2, Clock, Trash2, RotateCcw, Tag
} from 'lucide-react';
import { format, isSameDay } from 'date-fns';
import PurchaseModal from './components/PurchaseModal';
import Calendar from '../../features/reports/components/Calendar';
import { useAuth } from '../../shared/hooks/useAuth';
import { useBranch } from '../../shared/lib/BranchContext';

interface Purchase {
    id: string;
    transaction_label?: string;
    product_id: string;
    quantity: number;
    unit_price: number;
    total_price: number;
    date: string;
    invoice_number: string;
    supplier: string;
    status: 'pending' | 'received';
    received_date: string | null;
    vat_amount: number;
    discount_amount: number;
    payment_status: 'unpaid' | 'partial' | 'paid';
    payment_date: string | null;
    purchase_type: 'supplier' | 'transfer';
    products: {
        name: string;
    };
}

interface SupabasePurchase {
    id: string;
    transaction_label?: string;
    product_id: string;
    quantity: number;
    unit_price: number;
    total_price: number;
    date: string;
    invoice_number: string;
    supplier: string;
    status: 'pending' | 'received';
    received_date: string | null;
    vat_amount: number;
    discount_amount: number;
    payment_status: 'unpaid' | 'partial' | 'paid';
    payment_date: string | null;
    purchase_type: 'supplier' | 'transfer';
    products: {
        name: string;
    };
}

interface GroupedPurchase {
    invoice_number: string;
    date: string;
    supplier: string;
    status: 'pending' | 'received';
    payment_status: 'unpaid' | 'partial' | 'paid';
    purchase_type: 'supplier' | 'transfer';
    items: Purchase[];
    total_base: number;
    total_vat: number;
    total_discount: number;
    grand_total: number;
    transaction_label: string | null;
}

export default function Purchases() {
    const { role } = useAuth();
    const { activeBranchId } = useBranch();
    const navigate = useNavigate();
    const location = useLocation();
    const [groupedPurchases, setGroupedPurchases] = useState<GroupedPurchase[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [dateRange, setDateRange] = useState<{ start: Date; end: Date }>({
        start: new Date(),
        end: new Date()
    });
    const [isDateRangeActive, setIsDateRangeActive] = useState(false);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editData, setEditData] = useState<unknown>(null);
    const [expandedInvoices, setExpandedInvoices] = useState<Set<string>>(new Set());
    const [isFilterOpen, setIsFilterOpen] = useState(false);
    const [statusFilters, setStatusFilters] = useState<string[]>([]);
    const [paymentFilters, setPaymentFilters] = useState<string[]>([]);
    const [typeFilters, setTypeFilters] = useState<string[]>([]);
    const [returnedInvoices, setReturnedInvoices] = useState<Set<string>>(new Set());

    const fetchPurchases = useCallback(async (silent = false) => {
        if (!silent) setLoading(true);
        let purchasesQuery = supabase.from('purchases').select(`*, products(name)`).order('date', { ascending: false });
        let returnsQuery = supabase.from('supplier_returns').select('invoice_number');

        if (activeBranchId) {
            purchasesQuery = purchasesQuery.eq('branch_id', activeBranchId);
            returnsQuery = returnsQuery.eq('branch_id', activeBranchId);
        }

        const [purchasesRes, returnsRes] = await Promise.all([
            purchasesQuery,
            returnsQuery
        ]);

        if (returnsRes.data) {
            setReturnedInvoices(new Set(returnsRes.data.map(r => r.invoice_number).filter(Boolean)));
        }

        const { data, error } = purchasesRes;

        if (error) {
            console.error('Error fetching purchases:', error);
        } else {
            const groups: { [key: string]: GroupedPurchase } = {};
            (data as unknown as SupabasePurchase[]).forEach(purchase => {
                const key = purchase.invoice_number || `UNTRACKED-${purchase.id}`;
                if (!groups[key]) {
                    groups[key] = {
                        invoice_number: purchase.invoice_number,
                        date: purchase.date,
                        supplier: purchase.supplier || 'Unknown Supplier',
                        status: 'received',
                        payment_status: 'paid', // Default to paid, will be demoted
                        purchase_type: purchase.purchase_type || 'supplier',
                        items: [],
                        total_base: 0,
                        total_vat: 0,
                        total_discount: 0,
                        grand_total: 0,
                        transaction_label: purchase.transaction_label || null
                    };
                }
                const group = groups[key];
                group.items.push(purchase);
                group.total_base += purchase.total_price;
                group.total_vat += purchase.vat_amount || 0;
                group.total_discount += purchase.discount_amount || 0;
                if (purchase.status === 'pending') group.status = 'pending';

                // Track most restrictive payment status in group
                const pStatus = purchase.payment_status || 'unpaid';
                if (pStatus === 'unpaid') {
                    group.payment_status = 'unpaid';
                } else if (pStatus === 'partial' && group.payment_status === 'paid') {
                    group.payment_status = 'partial';
                }
            });

            Object.values(groups).forEach(group => {
                group.grand_total = group.total_base - group.total_discount;
            });

            setGroupedPurchases(Object.values(groups).sort((a, b) =>
                new Date(b.date).getTime() - new Date(a.date).getTime()
            ));
        }
        setLoading(false);
    }, [activeBranchId]);

    useEffect(() => {
        let mounted = true;
        const load = async () => { if (mounted) await fetchPurchases(); };
        load();
        const channel = supabase.channel('purchases_realtime').on('postgres_changes', { event: '*', schema: 'public', table: 'purchases' }, () => { if (mounted) fetchPurchases(true); }).subscribe();
        return () => { mounted = false; supabase.removeChannel(channel); };
    }, [fetchPurchases]);

    // Listen for global "P" shortcut to open purchase modal
    // Global Shortcuts & Navigation Redirection
    useEffect(() => {
        const handleOpenModal = () => { setEditData(null); setIsModalOpen(true); };
        window.addEventListener('open-purchase-modal', handleOpenModal);

        if ((location.state as any)?.openModal) {
            handleOpenModal();
            navigate(location.pathname, { replace: true, state: {} });
        }

        return () => window.removeEventListener('open-purchase-modal', handleOpenModal);
    }, [location.state, navigate, location.pathname]);

    const toggleExpand = (invoiceNumber: string) => {
        setExpandedInvoices(prev => {
            const next = new Set(prev);
            if (next.has(invoiceNumber)) next.delete(invoiceNumber);
            else next.add(invoiceNumber);
            return next;
        });
    };

    const handleMarkAsReceived = async (group: GroupedPurchase) => {
        try {
            const { error: updateError } = await supabase
                .from('purchases')
                .update({
                    status: 'received',
                    received_date: new Date().toISOString()
                })
                .eq('invoice_number', group.invoice_number);

            if (updateError) throw updateError;
            fetchPurchases(true);
        } catch (err) {
            console.error('Error marking as received:', err);
        }
    };

    const handleMarkAsPaid = async (group: GroupedPurchase) => {
        if (group.payment_status === 'paid') return;
        if (!confirm(`Mark invoice ${group.invoice_number} as FULLY PAID?`)) return;

        try {
            const { error } = await supabase
                .from('purchases')
                .update({
                    payment_status: 'paid',
                    payment_date: new Date().toISOString()
                })
                .eq('invoice_number', group.invoice_number);

            if (error) throw error;
            fetchPurchases(true);
        } catch (error: unknown) {
            const err = error as Error;
            console.error('Error updating payment status:', err);
            alert('Failed to update payment status: ' + err.message);
        }
    };

    const filteredPurchases = groupedPurchases.filter(group => {
        const search = searchTerm.toLowerCase();
        const matchesSearch = (
            (group.invoice_number?.toLowerCase().includes(search) ?? false) ||
            (group.supplier?.toLowerCase().includes(search) ?? false) ||
            group.items.some(item =>
                (item.products?.name?.toLowerCase().includes(search) ?? false)
            )
        );

        const purchaseDate = new Date(group.date);
        purchaseDate.setHours(0, 0, 0, 0); // Normalize to start of day

        const start = new Date(dateRange.start);
        const end = new Date(dateRange.end);
        start.setHours(0, 0, 0, 0); // Normalize to start of day
        end.setHours(23, 59, 59, 999); // Normalize to end of day

        const matchesDate = purchaseDate >= start && purchaseDate <= end;

        const isReturned = returnedInvoices.has(group.invoice_number);

        const matchesStatus = statusFilters.length === 0 ||
            (statusFilters.includes(group.status) && !statusFilters.includes('returned')) ||
            (statusFilters.includes('returned') && isReturned);

        const matchesPayment = paymentFilters.length === 0 || paymentFilters.includes(group.payment_status || 'unpaid');
        const matchesType = typeFilters.length === 0 || typeFilters.includes(group.purchase_type || 'supplier');

        return matchesSearch && matchesDate && matchesStatus && matchesPayment && matchesType;
    });

    const activeDates = Array.from(new Set(groupedPurchases.map(s => format(new Date(s.date), 'yyyy-MM-dd'))));

    const handleDateSelect = (date: Date) => {
        if (!isDateRangeActive) {
            setDateRange({ start: date, end: date });
            return;
        }

        if (!dateRange.start || (dateRange.start && dateRange.end && !isSameDay(dateRange.start, dateRange.end))) {
            // Start a new range
            setDateRange({ start: date, end: date });
        } else {
            // Complete the range
            if (date < dateRange.start) {
                setDateRange({ start: date, end: dateRange.start });
            } else {
                setDateRange({ ...dateRange, end: date });
            }
        }
    };

    const handleEditPurchase = (group: GroupedPurchase) => {
        setEditData({
            invoiceNumber: group.invoice_number,
            supplier: group.supplier,
            status: group.status,
            payment_status: group.payment_status,
            payment_date: group.items[0].payment_date,
            purchase_type: group.purchase_type,
            date: group.date,
            isVatEnabled: group.total_vat > 0,
            isDiscountEnabled: group.total_discount > 0,
            items: group.items.map(item => ({
                product_id: item.product_id,
                quantity: item.quantity,
                unit_price: item.unit_price,
                total_price: item.total_price,
                name: item.products?.name
            }))
        });
        setIsModalOpen(true);
    };

    const handleDeleteInvoice = async (invoiceNumber: string) => {
        if (!window.confirm(`Are you sure you want to delete purchase ${invoiceNumber}? This will reverse inventory changes.`)) return;

        setLoading(true);
        try {
            // 1. Delete purchase records
            const { error: deleteError } = await supabase
                .from('purchases')
                .delete()
                .eq('invoice_number', invoiceNumber);

            if (deleteError) throw deleteError;
            fetchPurchases();
        } catch (err) {
            console.error('Error deleting purchase:', err);
            alert('Error: ' + (err instanceof Error ? err.message : 'Unknown error'));
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-6 animate-fade-in pb-10">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div>
                    <h1 className="text-3xl font-black text-text-primary tracking-tight flex items-center gap-3">
                        <div className="w-12 h-12 bg-brand-red rounded-2xl flex items-center justify-center shadow-brand-red/20 shadow-lg"><ShoppingBag className="text-white" size={24} /></div>
                        Purchase Dashboard
                    </h1>
                    <p className="text-text-secondary mt-1 font-medium">Manage stock inwards and supplier invoices</p>
                </div>
                <div className="flex items-center gap-3">
                    <button className="flex items-center gap-2 bg-bg-surface border border-border-default text-text-secondary px-5 py-3 rounded-2xl font-bold text-sm hover:bg-bg-subtle transition-all shadow-sm"><Download size={18} /> Export</button>
                    <button onClick={() => { setEditData(null); setIsModalOpen(true); }} className="flex items-center gap-2 bg-brand-red text-white px-6 py-3 rounded-2xl font-black text-sm hover:bg-brand-red-dark transition-all shadow-red active:scale-95"><ShoppingBag size={18} /> CREATE PURCHASE</button>
                </div>
            </div>

            <div className="flex flex-col sm:flex-row gap-4 relative">
                <div className="relative group flex-1"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-text-muted group-focus-within:text-brand-red transition-colors" size={18} /><input type="text" placeholder="Search invoices or suppliers..." className="w-full pl-12 pr-4 py-3 bg-bg-surface border border-border-default rounded-2xl text-sm focus:ring-2 focus:border-brand-red outline-none transition-all shadow-sm placeholder:text-text-muted text-text-primary" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} /></div>

                <div className="relative">
                    <button
                        onClick={() => setIsFilterOpen(!isFilterOpen)}
                        className={`px-5 py-3 bg-bg-surface border border-border-default rounded-2xl text-text-primary hover:bg-bg-subtle transition-all shadow-sm flex items-center gap-2 font-bold text-sm ${isFilterOpen ? 'border-brand-red text-brand-red' : ''}`}
                    >
                        <Filter size={18} /> Filters {(statusFilters.length + paymentFilters.length + typeFilters.length) > 0 && <span className="w-5 h-5 bg-brand-red text-white rounded-full flex items-center justify-center text-[10px]">{statusFilters.length + paymentFilters.length + typeFilters.length}</span>}
                    </button>

                    {isFilterOpen && (
                        <div className="absolute right-0 top-full mt-2 w-64 bg-bg-surface rounded-2xl shadow-xl border border-border-muted p-4 z-[100] animate-slide-up">
                            <div className="space-y-4">
                                <div>
                                    <h4 className="text-[10px] font-black text-text-secondary uppercase tracking-widest mb-2">Order Status</h4>
                                    <div className="space-y-2">
                                        {['pending', 'received', 'returned'].map(s => (
                                            <label key={s} className="flex items-center gap-2 cursor-pointer group">
                                                <input
                                                    type="checkbox"
                                                    checked={statusFilters.includes(s)}
                                                    onChange={(e) => {
                                                        if (e.target.checked) setStatusFilters([...statusFilters, s]);
                                                        else setStatusFilters(statusFilters.filter(f => f !== s));
                                                    }}
                                                    className="w-4 h-4 rounded border-border-default text-brand-red focus:ring-brand-red cursor-pointer bg-bg-base"
                                                />
                                                <span className="text-xs font-bold text-text-secondary capitalize group-hover:text-brand-red transition-colors">{s}</span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                                <div className="pt-4 border-t border-border-muted">
                                    <h4 className="text-[10px] font-black text-text-secondary uppercase tracking-widest mb-2">Payment Status</h4>
                                    <div className="space-y-2">
                                        {['unpaid', 'partial', 'paid'].map(s => (
                                            <label key={s} className="flex items-center gap-2 cursor-pointer group">
                                                <input
                                                    type="checkbox"
                                                    checked={paymentFilters.includes(s)}
                                                    onChange={(e) => {
                                                        if (e.target.checked) setPaymentFilters([...paymentFilters, s]);
                                                        else setPaymentFilters(paymentFilters.filter(f => f !== s));
                                                    }}
                                                    className="w-4 h-4 rounded border-border-default text-brand-red focus:ring-brand-red cursor-pointer bg-bg-base"
                                                />
                                                <span className="text-xs font-bold text-text-secondary capitalize group-hover:text-brand-red transition-colors">{s === 'paid' ? 'Full' : s}</span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                                <div className="pt-4 border-t border-border-muted">
                                    <h4 className="text-[10px] font-black text-text-secondary uppercase tracking-widest mb-2">Purchase Type</h4>
                                    <div className="space-y-2">
                                        {[
                                            { id: 'supplier', label: 'Supplier' },
                                            { id: 'transfer', label: 'Transfer' }
                                        ].map(t => (
                                            <label key={t.id} className="flex items-center gap-2 cursor-pointer group">
                                                <input
                                                    type="checkbox"
                                                    checked={typeFilters.includes(t.id)}
                                                    onChange={(e) => {
                                                        if (e.target.checked) setTypeFilters([...typeFilters, t.id]);
                                                        else setTypeFilters(typeFilters.filter(f => f !== t.id));
                                                    }}
                                                    className="w-4 h-4 rounded border-border-default text-brand-red focus:ring-brand-red cursor-pointer bg-bg-base"
                                                />
                                                <span className="text-xs font-bold text-text-secondary capitalize group-hover:text-brand-red transition-colors">{t.label}</span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                                <button
                                    onClick={() => { setStatusFilters([]); setPaymentFilters([]); setTypeFilters([]); }}
                                    className="w-full py-2 text-[10px] font-black text-text-muted hover:text-brand-red uppercase tracking-widest text-center transition-colors"
                                >
                                    Reset Filters
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            <div className="flex flex-col lg:flex-row gap-6">
                <div className="flex-shrink-0">
                    <div className="sticky top-6 space-y-4">
                        <div className="bg-bg-surface p-6 rounded-3xl border border-border-muted shadow-sm space-y-4 w-full lg:w-72">
                            <div className="space-y-4">
                                <div className="flex items-center justify-between">
                                    <h3 className="text-[10px] font-black text-text-secondary uppercase tracking-[0.2em]">Date Filter</h3>
                                    <button
                                        onClick={() => setIsDateRangeActive(!isDateRangeActive)}
                                        className={`text-[9px] font-black px-2 py-0.5 rounded uppercase transition-all ${isDateRangeActive ? 'bg-brand-red text-white' : 'bg-bg-subtle text-text-muted'}`}
                                    >
                                        {isDateRangeActive ? 'Range' : 'Single'}
                                    </button>
                                </div>
                                <div className="flex items-center justify-between">
                                    <span className="text-[10px] font-black text-text-secondary uppercase tracking-widest">
                                        {isDateRangeActive ? 'Selected Range' : 'Selected Date'}
                                    </span>
                                    {(dateRange.start && dateRange.end) && (
                                        <span className="text-[9px] font-black text-brand-red bg-brand-red/10 px-2 py-0.5 rounded">
                                            {isDateRangeActive && !isSameDay(dateRange.start, dateRange.end)
                                                ? `${format(dateRange.start, 'MMM d')} - ${format(dateRange.end, 'MMM d')}`
                                                : format(dateRange.start, 'MMM d, yyyy')}
                                        </span>
                                    )}
                                </div>
                                <Calendar
                                    selectedDate={dateRange.start}
                                    onDateSelect={handleDateSelect}
                                    rangeStart={isDateRangeActive ? dateRange.start : null}
                                    rangeEnd={isDateRangeActive ? dateRange.end : null}
                                    activeDates={activeDates}
                                />
                            </div>
                        </div>

                        <div className="bg-bg-surface p-6 rounded-3xl border border-border-muted shadow-sm">
                            <h3 className="text-[10px] font-black text-text-secondary border-b border-border-muted pb-3 mb-4 uppercase tracking-[0.2em]">Summary</h3>
                            <div className="space-y-4">
                                <div><p className="text-[9px] font-black text-text-secondary uppercase tracking-widest mb-1">Total Cost</p><p className="text-xl font-black text-text-primary font-data">₱{filteredPurchases.reduce((sum, g) => sum + g.grand_total, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p></div>
                                <div><p className="text-[9px] font-black text-brand-red uppercase tracking-widest mb-1">Unpaid Amount</p><p className="text-xl font-black text-brand-red font-data">₱{filteredPurchases.filter(g => g.payment_status !== 'paid').reduce((sum, g) => sum + g.grand_total, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p></div>
                                <div><p className="text-[9px] font-black text-orange-500 uppercase tracking-widest mb-1">Pending Orders</p><p className="text-xl font-black text-orange-500 font-data">{filteredPurchases.filter(g => g.status === 'pending').length}</p></div>
                                <div><p className="text-[9px] font-black text-text-secondary uppercase tracking-widest mb-1">Complete Orders</p><p className="text-xl font-black text-text-primary font-data">{filteredPurchases.length}</p></div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex-1 min-w-0">
                    <div className="bg-bg-surface rounded-[32px] border border-border-muted shadow-sm overflow-hidden">
                        <div className="overflow-x-auto">
                            <table className="w-full text-left">
                                <thead>
                                    <tr className="bg-bg-subtle/50 border-b border-border-muted">
                                        <th className="px-8 py-5 text-[11px] font-black text-text-secondary uppercase tracking-widest pl-16">Created</th>
                                        <th className="px-8 py-5 text-[11px] font-black text-text-secondary uppercase tracking-widest">Invoice / Supplier</th>
                                        <th className="px-8 py-5 text-[11px] font-black text-text-secondary uppercase tracking-widest">Status / Payment</th>
                                        <th className="px-8 py-5 text-[11px] font-black text-text-secondary uppercase tracking-widest">Received Date</th>
                                        <th className="px-8 py-5 text-[11px] font-black text-text-primary uppercase tracking-widest text-right">Total Amount</th>
                                        <th className="px-8 py-5 text-[11px] font-black text-text-secondary uppercase tracking-widest w-10"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-border-muted">
                                    {loading ? (
                                        [1, 2, 3].map(i => <tr key={i} className="animate-pulse"><td colSpan={6} className="px-6 py-8"><div className="h-4 bg-bg-subtle rounded w-full"></div></td></tr>)
                                    ) : filteredPurchases.length > 0 ? (
                                        filteredPurchases.map((group) => {
                                            const creationDate = new Date(group.date);
                                            const itemsWithReceivedDate = group.items.filter(i => i.received_date);
                                            const receiptDate = itemsWithReceivedDate.length > 0 ? new Date(itemsWithReceivedDate[0].received_date!) : null;

                                            return (
                                                <Fragment key={group.invoice_number || group.date}>
                                                    <tr
                                                        onClick={() => toggleExpand(group.invoice_number)}
                                                        className={`hover:bg-bg-subtle/80 transition-all cursor-pointer group ${expandedInvoices.has(group.invoice_number) ? 'bg-bg-subtle/50' : ''}`}
                                                    >
                                                        <td className="px-8 py-7">
                                                            <div className="flex items-center gap-3">
                                                                <div className="w-8 h-8 rounded-lg bg-bg-base flex items-center justify-center text-text-muted group-hover:bg-brand-red/10 group-hover:text-brand-red transition-colors">
                                                                    <Clock size={16} />
                                                                </div>
                                                                <div>
                                                                    <p className="text-[10px] font-black text-text-primary uppercase tracking-wider">{format(creationDate, 'MMM d, yyyy')}</p>
                                                                    <p className="text-[9px] font-bold text-text-muted uppercase">{format(creationDate, 'p')}</p>
                                                                </div>
                                                            </div>
                                                        </td>
                                                        <td className="px-8 py-7">
                                                            <div className="flex items-center gap-4">
                                                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${group.status === 'received' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-orange-500/10 text-orange-500'}`}>
                                                                    {group.status === 'received' ? <CheckCircle2 size={18} /> : <Clock size={18} />}
                                                                </div>
                                                                <div>
                                                                    <div className="flex items-center gap-2">
                                                                        <p className="text-sm font-black text-text-primary uppercase font-data">{group.invoice_number || 'N/A'}</p>{group.transaction_label && (<span className="px-1.5 py-0.5 bg-brand-charcoal text-white text-[8px] font-black rounded uppercase tracking-tighter shadow-sm flex items-center gap-0.5 shrink-0"><Tag size={8} /> {group.transaction_label}</span>)}
                                                                        {returnedInvoices.has(group.invoice_number) && (
                                                                            <span className="px-1.5 py-0.5 bg-brand-red/10 text-brand-red text-[8px] font-black rounded uppercase tracking-tighter border border-brand-red/20 shadow-sm flex items-center gap-0.5 shrink-0">
                                                                                <RotateCcw size={8} /> RETURNED
                                                                            </span>
                                                                        )}
                                                                    </div>
                                                                    <p className="text-[10px] font-bold text-text-muted uppercase">{group.supplier}</p>
                                                                </div>
                                                            </div>
                                                        </td>
                                                        <td className="px-8 py-7">
                                                            <div className="flex flex-col gap-1">
                                                                {group.status === 'pending' ? (
                                                                    <button
                                                                        onClick={(e) => { e.stopPropagation(); handleMarkAsReceived(group); }}
                                                                        className="w-fit group/btn flex items-center gap-1.5 text-[8px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest border bg-orange-500/10 text-orange-500 border-orange-500/20 hover:bg-emerald-600 hover:text-white hover:border-emerald-700 transition-all shadow-sm"
                                                                    >
                                                                        <div className="w-1 h-1 rounded-full bg-orange-400 group-hover/btn:bg-white animate-pulse" />
                                                                        <span>{group.status}</span>
                                                                        <CheckCircle2 size={8} className="opacity-0 group-hover/btn:opacity-100 transition-opacity" />
                                                                    </button>
                                                                ) : (
                                                                    <span className="w-fit flex items-center gap-1.5 text-[8px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest border bg-emerald-500/10 text-emerald-500 border-emerald-500/20">
                                                                        <CheckCircle2 size={8} />
                                                                        <span>{group.status}</span>
                                                                    </span>
                                                                )}
                                                                {group.payment_status === 'paid' ? (
                                                                    <span className="w-fit text-[8px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest border bg-emerald-500/10 text-emerald-500 border-emerald-500/20 flex items-center gap-1">
                                                                        <CheckCircle2 size={8} />
                                                                        PAID
                                                                    </span>
                                                                ) : (
                                                                    <button
                                                                        onClick={(e) => { e.stopPropagation(); handleMarkAsPaid(group); }}
                                                                        className={`w-fit text-[8px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest border transition-all hover:scale-105 active:scale-95 ${group.payment_status === 'partial' ? 'bg-amber-500/10 text-amber-500 border-amber-500/20 hover:bg-emerald-500/10 hover:text-emerald-500 hover:border-emerald-500/20' : 'bg-brand-red/10 text-brand-red border-brand-red/20 hover:bg-emerald-500/10 hover:text-emerald-500 hover:border-emerald-500/20'}`}
                                                                        title="Click to toggle to FULLY PAID"
                                                                    >
                                                                        {group.payment_status || 'unpaid'}
                                                                    </button>
                                                                )}
                                                                {group.purchase_type === 'transfer' && (
                                                                    <span className="w-fit text-[8px] font-black px-2 py-0.5 rounded-full uppercase tracking-widest border bg-blue-500/10 text-blue-500 border-blue-500/20">TRANSFER</span>
                                                                )}
                                                            </div>
                                                        </td>
                                                        <td className="px-8 py-7">
                                                            {receiptDate ? (
                                                                <div className="flex flex-col">
                                                                    <p className="text-[10px] font-black text-text-primary uppercase tracking-wider">{format(receiptDate, 'MMM d, yyyy')}</p>
                                                                    <p className="text-[9px] font-bold text-text-muted uppercase">{format(receiptDate, 'p')}</p>
                                                                </div>
                                                            ) : (
                                                                <span className="text-[10px] font-bold text-text-muted opacity-50 uppercase">Pending</span>
                                                            )}
                                                        </td>
                                                        <td className="px-8 py-7 text-right font-data font-black text-text-primary">₱{group.grand_total.toLocaleString(undefined, { minimumFractionDigits: 2 })}</td>
                                                        <td className="px-8 py-7 text-right flex items-center justify-end gap-2">
                                                            {role === 'owner' && (
                                                                <button
                                                                    onClick={(e) => { e.stopPropagation(); if (confirm('Are you sure you want to delete this purchase?')) handleDeleteInvoice(group.invoice_number); }}
                                                                    className="p-2 text-text-muted hover:text-brand-red hover:bg-brand-red/10 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                                                                >
                                                                    <Trash2 size={16} />
                                                                </button>
                                                            )}
                                                            <div className={`p-2 rounded-lg transition-all ${expandedInvoices.has(group.invoice_number) ? 'bg-brand-red text-white rotate-180' : 'bg-bg-base text-text-muted'}`}><ChevronDown size={16} /></div>
                                                        </td>
                                                    </tr>
                                                    {expandedInvoices.has(group.invoice_number) && (
                                                        <tr>
                                                            <td colSpan={6} className="px-8 py-6 bg-bg-base/50">
                                                                <div className="p-9 border-l-4 border-brand-red bg-bg-surface shadow-inner rounded-3xl space-y-6">
                                                                    <div className="flex items-center justify-between border-b border-border-muted pb-2">
                                                                        <h4 className="text-[10px] font-black uppercase text-text-primary tracking-widest flex items-center gap-2"><Package size={14} /> Items</h4>
                                                                        <div className="flex gap-2">
                                                                            {group.status === 'pending' && <button onClick={(e) => { e.stopPropagation(); if (confirm('Mark this order as Received? This will update live inventory levels.')) handleMarkAsReceived(group); }} className="text-[9px] font-black bg-emerald-500 text-white px-3 py-1 rounded uppercase tracking-tighter hover:bg-emerald-600 transition-colors">MARK AS RECEIVED</button>}
                                                                            <button onClick={(e) => { e.stopPropagation(); handleEditPurchase(group); }} className="text-[9px] font-black bg-text-primary text-bg-base px-3 py-1 rounded uppercase tracking-tighter hover:opacity-90 transition-opacity">EDIT</button>
                                                                        </div>
                                                                    </div>
                                                                    <div className="space-y-3">
                                                                        {group.items.map((item, idx) => (
                                                                            <div key={idx} className="flex justify-between items-start text-xs border-b border-border-muted pb-2 last:border-0">
                                                                                <div>
                                                                                    <p className="font-bold text-text-primary">{item.products?.name}</p>
                                                                                    <p className="text-[9px] text-text-muted font-data">UNIT PRICE: ₱{Number(item.unit_price).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                                                                </div>
                                                                                <div className="text-right">
                                                                                    <p className="font-bold text-text-primary">x{item.quantity}</p>
                                                                                    <p className="text-[10px] text-text-secondary font-data font-black">₱{item.total_price.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                                                                </div>
                                                                            </div>
                                                                        ))}
                                                                    </div>
                                                                    <div className="pt-2 border-t border-border-muted flex flex-col items-end gap-1">{group.total_discount > 0 && <span className="text-[10px] text-brand-orange">Discount: -₱{group.total_discount.toLocaleString()}</span>}<span className="text-sm font-black text-brand-red font-data">Total: ₱{group.grand_total.toLocaleString()}</span></div>
                                                                </div>
                                                            </td>
                                                        </tr>
                                                    )}
                                                </Fragment>
                                            );
                                        })
                                    ) : (
                                        <tr><td colSpan={6} className="py-20 text-center text-text-muted">No purchases found for this filters.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div >

            {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
            <PurchaseModal isOpen={isModalOpen} onClose={() => { setIsModalOpen(false); setEditData(null); }} onSuccess={() => { fetchPurchases(); setEditData(null); }} editData={editData as any} />
        </div >
    );
}

import React, { useEffect, useState } from 'react';
import { supabase } from '../../shared/lib/supabase';
import { useAuth } from '../../shared/hooks/useAuth';
import {
    Plus, Search, ChevronDown, ChevronRight,
    Package, RotateCcw, Trash2
} from 'lucide-react';
import ReturnModal from './components/ReturnModal';
import { format, isSameDay, subDays } from 'date-fns';
import Calendar from '../../features/reports/components/Calendar';
import { useBranch } from '../../shared/lib/BranchContext';

interface ReturnItem {
    id: string;
    product_id: string;
    quantity: number;
    reason: string;
    date: string;
    invoice_number: string;
    unit_price: number;
    total_price: number;
    vat_amount: number;
    products: { name: string } | null;
}

interface GroupedReturn {
    invoice_number: string;
    date: string;
    reason: string;
    items: ReturnItem[];
    total_base: number;
    total_vat: number;
    grand_total: number;
}

export default function Returns() {
    const { role } = useAuth();
    const { activeBranchId } = useBranch();
    const [returns, setReturns] = useState<GroupedReturn[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [expandedRows, setExpandedRows] = useState<Set<string>>(new Set());
    const [dateRange, setDateRange] = useState<{ start: Date, end: Date }>({
        start: subDays(new Date(), 30),
        end: new Date()
    });
    const [isDateRangeActive, setIsDateRangeActive] = useState(false);

    const fetchReturns = async () => {
        setLoading(true);
        let query = supabase
            .from('supplier_returns')
            .select('*, products(name)')
            .order('date', { ascending: false });

        if (activeBranchId) {
            query = query.eq('branch_id', activeBranchId);
        }

        const { data, error } = await query;

        if (error) console.error('Error fetching returns:', error);
        else groupReturnsByInvoice(data || []);
        setLoading(false);
    };

    const groupReturnsByInvoice = (data: ReturnItem[]) => {
        const groups: { [key: string]: GroupedReturn } = {};

        data.forEach(item => {
            const key = item.invoice_number || 'UNGROUPED';
            if (!groups[key]) {
                groups[key] = {
                    invoice_number: key,
                    date: item.date,
                    reason: item.reason,
                    items: [],
                    total_base: 0,
                    total_vat: 0,
                    grand_total: 0
                };
            }
            const group = groups[key];
            group.items.push(item);
            group.total_base += item.total_price;
            group.total_vat += item.vat_amount || 0;
            group.grand_total = group.total_base;
        });

        setReturns(Object.values(groups));
    };

    useEffect(() => {
        let mounted = true;
        const fetch = async () => {
            setLoading(true);
            let query = supabase
                .from('supplier_returns')
                .select('*, products(name)')
                .order('date', { ascending: false });

            if (activeBranchId) {
                query = query.eq('branch_id', activeBranchId);
            }

            const { data, error } = await query;

            if (mounted) {
                if (error) console.error('Error fetching returns:', error);
                else {
                    const dataItems = data as ReturnItem[];
                    const groups: { [key: string]: GroupedReturn } = {};

                    dataItems.forEach(item => {
                        const key = item.invoice_number || 'UNGROUPED';
                        if (!groups[key]) {
                            groups[key] = {
                                invoice_number: key,
                                date: item.date,
                                reason: item.reason,
                                items: [],
                                total_base: 0,
                                total_vat: 0,
                                grand_total: 0
                            };
                        }
                        const group = groups[key];
                        group.items.push(item);
                        group.total_base += item.total_price;
                        group.total_vat += item.vat_amount || 0;
                        group.grand_total = group.total_base;
                    });

                    setReturns(Object.values(groups));
                }
                setLoading(false);
            }
        };
        fetch();
        return () => { mounted = false; };
    }, []);

    const toggleRow = (id: string) => {
        setExpandedRows(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            return next;
        });
    };

    const handleDelete = async (invoiceNumber: string) => {
        if (!window.confirm('Delete this return record? This will delete all items in this return.')) return;
        const { error } = await supabase
            .from('supplier_returns')
            .delete()
            .eq('invoice_number', invoiceNumber);
        if (error) alert('Error: ' + error.message);
        else fetchReturns();
    };

    const filtered = returns.filter(group => {
        const search = searchTerm.toLowerCase();
        const matchesSearch = (
            (group.invoice_number?.toLowerCase().includes(search) ?? false) ||
            (group.reason?.toLowerCase().includes(search) ?? false) ||
            group.items.some(item =>
                (item.products?.name?.toLowerCase().includes(search) ?? false)
            )
        );

        const returnDate = new Date(group.date);
        returnDate.setHours(0, 0, 0, 0);

        const start = new Date(dateRange.start);
        const end = new Date(dateRange.end);
        start.setHours(0, 0, 0, 0);
        end.setHours(23, 59, 59, 999);

        const matchesDate = returnDate >= start && returnDate <= end;

        return matchesSearch && matchesDate;
    });

    const activeDates = Array.from(new Set(returns.map(r => format(new Date(r.date), 'yyyy-MM-dd'))));

    const handleDateSelect = (date: Date) => {
        if (!isDateRangeActive) {
            setDateRange({ start: date, end: date });
            return;
        }

        if (!dateRange.start || (dateRange.start && dateRange.end && !isSameDay(dateRange.start, dateRange.end))) {
            setDateRange({ start: date, end: date });
        } else {
            if (date < dateRange.start) {
                setDateRange({ start: date, end: dateRange.start });
            } else {
                setDateRange({ start: dateRange.start, end: date });
            }
        }
    };

    const stats = {
        totalReturns: returns.length,
        totalItems: returns.reduce((acc, r) => acc + r.items.length, 0),
        totalValue: returns.reduce((acc, r) => acc + r.grand_total, 0)
    };

    return (
        <div className="space-y-8 animate-fade-in max-w-none">
            {/* Header Title Row */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-brand-red rounded-2xl flex items-center justify-center shadow-red">
                        <RotateCcw className="text-white" size={24} />
                    </div>
                    <div>
                        <h1 className="text-3xl font-black text-text-primary tracking-tight">Supplier Returns</h1>
                        <p className="text-sm text-text-secondary mt-1 font-medium">Track items sent back to suppliers and manage inventory adjustments</p>
                    </div>
                </div>
                <button
                    onClick={() => setIsModalOpen(true)}
                    className="flex items-center gap-2 bg-brand-red text-white px-6 py-3 rounded-2xl font-black text-sm hover:bg-brand-red-dark transition-all shadow-red active:scale-95"
                >
                    <Plus size={18} />
                    LOG NEW RETURN
                </button>
            </div>

            {/* Action Row - Fixed search centering */}
            <div className="relative group max-w-4xl">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-text-muted group-focus-within:text-brand-red transition-colors" size={18} />
                <input
                    type="text"
                    placeholder="Search by invoice, product, or reason..."
                    className="w-full pl-12 pr-4 py-3 bg-bg-surface border border-border-default rounded-2xl text-sm focus:ring-2 focus:border-brand-red outline-none transition-all shadow-sm placeholder:text-text-muted text-text-primary"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>

            <div className="flex flex-col lg:flex-row gap-6">
                {/* Filters & Stats Sidebar */}
                <div className="flex-shrink-0 w-full lg:w-72">
                    <div className="sticky top-6 space-y-4">
                        {/* Calendar Filter Widget */}
                        <div className="bg-bg-surface p-6 rounded-3xl border border-border-muted shadow-sm space-y-4">
                            <div className="space-y-4">
                                <div className="flex items-center justify-between">
                                    <h3 className="text-[10px] font-black text-text-secondary uppercase tracking-[0.2em]">Date Filter</h3>
                                    <button
                                        onClick={() => setIsDateRangeActive(!isDateRangeActive)}
                                        className={`text-[9px] font-black px-2 py-0.5 rounded uppercase transition-all ${isDateRangeActive ? 'bg-brand-red text-white' : 'bg-bg-subtle text-text-muted'}`}
                                    >
                                        {isDateRangeActive ? 'Range' : 'Single'}
                                    </button>
                                </div>
                                <div className="flex items-center justify-between">
                                    <span className="text-[10px] font-black text-text-secondary uppercase tracking-widest">
                                        {isDateRangeActive ? 'Selected Range' : 'Selected Date'}
                                    </span>
                                    {(dateRange.start && dateRange.end) && (
                                        <span className="text-[9px] font-black text-brand-red bg-brand-red/10 px-2 py-0.5 rounded">
                                            {isDateRangeActive && !isSameDay(dateRange.start, dateRange.end)
                                                ? `${format(dateRange.start, 'MMM d')} - ${format(dateRange.end, 'MMM d')}`
                                                : format(dateRange.start, 'MMM d, yyyy')}
                                        </span>
                                    )}
                                </div>
                                <Calendar
                                    selectedDate={dateRange.start}
                                    onDateSelect={handleDateSelect}
                                    rangeStart={isDateRangeActive ? dateRange.start : null}
                                    rangeEnd={isDateRangeActive ? dateRange.end : null}
                                    activeDates={activeDates}
                                />
                            </div>
                        </div>

                        <div className="bg-bg-surface p-6 rounded-3xl border border-border-muted shadow-sm overflow-hidden relative">
                            <div className="absolute top-0 right-0 w-24 h-24 bg-brand-red/5 rounded-full -mr-12 -mt-12" />
                            <h3 className="text-[10px] font-black text-text-primary border-b border-border-muted pb-3 mb-4 uppercase tracking-[0.2em]">Return Statistics</h3>
                            <div className="space-y-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-1">Total Returns</p>
                                        <p className="text-lg font-black text-text-primary font-data">{stats.totalReturns}</p>
                                    </div>
                                    <div>
                                        <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-1">Total Items</p>
                                        <p className="text-lg font-black text-text-primary font-data">{stats.totalItems}</p>
                                    </div>
                                </div>
                                <div className="pt-3 border-t border-border-muted">
                                    <p className="text-[9px] font-black text-text-secondary uppercase tracking-widest mb-1">Total Return Value</p>
                                    <p className="text-xl font-black text-text-primary font-data">₱{stats.totalValue.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex-1 min-w-0">
                    <div className="bg-bg-surface rounded-[32px] border border-border-muted shadow-sm overflow-hidden">
                        <table className="min-w-full">
                            <thead>
                                <tr className="bg-bg-subtle/50 border-b border-border-muted">
                                    <th className="px-5 py-3 text-left text-[10px] font-bold uppercase tracking-widest text-text-secondary">Date & Ref #</th>
                                    <th className="px-5 py-3 text-left text-[10px] font-bold uppercase tracking-widest text-text-secondary">Primary Reason</th>
                                    <th className="px-5 py-3 text-right text-[10px] font-bold uppercase tracking-widest text-text-secondary">Items</th>
                                    <th className="px-5 py-3 text-right text-[10px] font-bold uppercase tracking-widest text-text-secondary">Total Value</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-border-muted">
                                {loading ? (
                                    [1, 2, 3].map(i => <tr key={i}><td colSpan={4} className="px-5 py-3"><div className="h-10 skeleton rounded-lg" /></td></tr>)
                                ) : filtered.length === 0 ? (
                                    <tr>
                                        <td colSpan={4} className="px-5 py-12 text-center">
                                            <div className="flex flex-col items-center gap-3">
                                                <div className="w-12 h-12 bg-bg-subtle rounded-full flex items-center justify-center">
                                                    <RotateCcw size={20} className="text-text-muted" />
                                                </div>
                                                <p className="text-sm text-text-muted font-medium">No returns recorded yet</p>
                                            </div>
                                        </td>
                                    </tr>
                                ) : (
                                    filtered.map((group) => (
                                        <React.Fragment key={group.invoice_number}>
                                            <tr
                                                onClick={() => toggleRow(group.invoice_number)}
                                                className="hover:bg-bg-subtle/80 transition-colors cursor-pointer group"
                                            >
                                                <td className="px-5 py-4">
                                                    <div className="flex items-center gap-3">
                                                        <div className="transition-transform duration-200 group-hover:scale-110">
                                                            {expandedRows.has(group.invoice_number) ?
                                                                <ChevronDown size={14} className="text-brand-red" /> :
                                                                <ChevronRight size={14} className="text-text-muted opacity-50" />
                                                            }
                                                        </div>
                                                        <div>
                                                            <p className="text-xs font-black text-text-primary font-data uppercase">{group.invoice_number}</p>
                                                            <p className="text-[10px] font-medium text-text-muted">{format(new Date(group.date), 'MMM d, yyyy')}</p>
                                                        </div>
                                                    </div>
                                                </td>
                                                <td className="px-5 py-4">
                                                    <span className="text-sm font-medium text-text-secondary">{group.reason}</span>
                                                </td>
                                                <td className="px-5 py-4 text-right">
                                                    <span className="px-2 py-1 rounded-md bg-bg-base text-[10px] font-black font-data text-text-muted uppercase">
                                                        {group.items.length} {group.items.length === 1 ? 'Item' : 'Items'}
                                                    </span>
                                                </td>
                                                <td className="px-5 py-4 text-right">
                                                    <div className="flex items-center justify-end gap-3">
                                                        <p className="text-sm font-black text-text-primary font-data">₱{group.grand_total.toLocaleString()}</p>
                                                        {role === 'owner' && (
                                                            <button
                                                                onClick={(e) => { e.stopPropagation(); handleDelete(group.invoice_number); }}
                                                                className="p-1.5 rounded-lg text-text-muted hover:text-red-500 hover:bg-brand-red/10 transition-all opacity-0 group-hover:opacity-100"
                                                            >
                                                                <Trash2 size={14} />
                                                            </button>
                                                        )}
                                                    </div>
                                                </td>
                                            </tr>

                                            {expandedRows.has(group.invoice_number) && (
                                                <tr className="bg-bg-base animate-slide-up">
                                                    <td colSpan={4} className="px-6 py-0">
                                                        <div className="py-8 px-10 border-l-4 border-brand-red bg-bg-surface shadow-inner m-4 rounded-[24px] space-y-6">
                                                            <div className="flex items-center justify-between border-b border-border-muted pb-4">
                                                                <h4 className="text-[11px] font-black text-text-primary uppercase tracking-[0.2em] flex items-center gap-2">
                                                                    <Package size={14} className="text-brand-red" /> Returned Items
                                                                </h4>
                                                            </div>

                                                            <div className="space-y-3">
                                                                {group.items.map((item, idx) => (
                                                                    <div key={item.id} className="flex items-center justify-between py-2 border-b border-border-muted last:border-0 group/item">
                                                                        <div className="flex items-center gap-4">
                                                                            <span className="text-[10px] font-black text-text-muted font-data w-6">{(idx + 1).toString().padStart(2, '0')}</span>
                                                                            <div>
                                                                                <p className="text-sm font-bold text-text-primary">{item.products?.name}</p>
                                                                                <p className="text-[10px] font-black text-text-muted uppercase tracking-widest font-data">₱{item.unit_price.toLocaleString()} x {item.quantity}</p>
                                                                            </div>
                                                                        </div>
                                                                        <span className="text-sm font-black text-text-secondary font-data">₱{item.total_price.toLocaleString()}</span>
                                                                    </div>
                                                                ))}
                                                            </div>

                                                            <div className="bg-bg-base/50 rounded-3xl p-6 flex flex-col items-end gap-3 border border-border-muted">
                                                                <div className="flex items-center justify-between w-full max-w-xs">
                                                                    <span className="text-[10px] font-black text-text-muted uppercase tracking-widest">Gross Value (VAT Inclusive)</span>
                                                                    <span className="text-sm font-bold text-text-secondary font-data">₱{group.total_base.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                                                </div>
                                                                {group.total_vat > 0 && (
                                                                    <div className="flex items-center justify-between w-full max-w-xs">
                                                                        <span className="text-[10px] font-black text-text-muted uppercase tracking-widest">Less VAT (12%)</span>
                                                                        <span className="text-sm font-bold text-brand-red font-data">- ₱{group.total_vat.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                                                    </div>
                                                                )}
                                                                <div className="w-full max-w-xs border-t border-border-muted pt-3 flex items-center justify-between">
                                                                    <span className="text-[11px] font-black text-text-primary uppercase tracking-[0.2em]">Net Return Value</span>
                                                                    <span className="text-xl font-black text-text-primary font-data">₱{group.grand_total.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </td>
                                                </tr>
                                            )}
                                        </React.Fragment>
                                    ))
                                )}
                            </tbody>
                        </table>
                    </div>
                    <ReturnModal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} onSuccess={fetchReturns} />
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { createPortal } from 'react-dom';
import { supabase } from '../../../shared/lib/supabase';
import { Truck, AlertCircle, Plus, Trash2, ShieldCheck, Clock, Search, Building2, Store, ChevronDown, User, X, Tag } from 'lucide-react';
import { supplierService } from '../../suppliers/services/supplierService';
import type { Supplier } from '../../suppliers/types/supplier';
import { useBranch } from '../../../shared/lib/BranchContext';
import { useKeyboardNav } from '../../../shared/hooks/useKeyboardNav';
import { toast } from 'sonner';
import { isSmartMatch } from '../../../shared/lib/searchUtils';

interface Product {
    id: string;
    name: string;
    sku: string;
    stock_available: number;
    buying_price: number;
    price?: number;
}

interface PurchaseItem {
    product_id: string;
    quantity: number;
    unit_price: number;
    total_price: number;
    name?: string;
    stock_available?: number;
    searchQuery?: string;
    isSearchOpen?: boolean;
    highlightedIndex?: number;
    currentLevel?: 'master' | 'category' | 'subcategory' | 'product';
    selectedPath?: {
        master?: string;
    };
}

interface PurchaseRecord {
    id: string;
    product_id: string;
    quantity: number;
    unit_price: number;
    total_price: number;
    date: string;
    invoice_number: string;
    supplier: string;
    status: 'pending' | 'received';
    payment_status?: 'unpaid' | 'partial' | 'paid';
    payment_date?: string | null;
    purchase_type: 'supplier' | 'transfer';
}

interface PurchaseModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: (newPurchases?: unknown[]) => void;
    editData?: {
        invoiceNumber: string;
        supplier: string;
        items: PurchaseItem[];
        status: 'pending' | 'received';
        payment_status?: 'unpaid' | 'partial' | 'paid';
        payment_date?: string | null;
        received_date?: string | null;
        date?: string;
        isVatEnabled: boolean;
        isDiscountEnabled: boolean;
        purchase_type?: 'supplier' | 'transfer';
        supplier_id?: string | null;
        source_branch_id?: number | null;
    };
}

interface Branch {
    id: number;
    name: string;
    code: string | null;
}

const PURCHASE_LABELS = [
    { id: 'Purch1', label: 'Purch1 (Cash)' },
    { id: 'Purch2', label: 'Purch2 (Sister Co Debt)' },
    { id: 'Purch3', label: 'Purch3 (Supplier Credit)' }
];

export default function PurchaseModal({ isOpen, onClose, onSuccess, editData }: PurchaseModalProps) {
    const { activeBranchId } = useBranch();
    const [products, setProducts] = useState<Product[]>([]);
    const [invoiceNumber, setInvoiceNumber] = useState('');
    const [supplier, setSupplier] = useState('');
    const [supplierId, setSupplierId] = useState<string | null>(null);
    const [suppliers, setSuppliers] = useState<Supplier[]>([]);
    const [supplierSearchQuery, setSupplierSearchQuery] = useState('');
    const [isSupplierSearchOpen, setIsSupplierSearchOpen] = useState(false);
    const [purchaseType, setPurchaseType] = useState<'supplier' | 'transfer'>('supplier');
    const [items, setItems] = useState<PurchaseItem[]>([
        {
            product_id: '',
            quantity: 1,
            unit_price: 0,
            total_price: 0,
            searchQuery: '',
            isSearchOpen: false,
            currentLevel: 'master',
            selectedPath: {}
        }
    ]);
    const [isVatEnabled, setIsVatEnabled] = useState(false);
    const [isDiscountEnabled, setIsDiscountEnabled] = useState(false);
    const [status, setStatus] = useState<'pending' | 'received'>('pending');
    const [paymentStatus, setPaymentStatus] = useState<'unpaid' | 'partial' | 'paid'>('unpaid');
    const [paymentDate, setPaymentDate] = useState<string | null>(null);
    const [transactionLabel, setTransactionLabel] = useState<string>('');
    const [supplierVatRegistered, setSupplierVatRegistered] = useState(false);
    const [supplierTin, setSupplierTin] = useState('');
    const [branches, setBranches] = useState<Branch[]>([]);
    const [sourceBranchId, setSourceBranchId] = useState<number | null>(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);
    const [savedData, setSavedData] = useState<(PurchaseRecord & { products?: { name: string } })[]>([]);
    const [showLowStock, setShowLowStock] = useState(false);

    const dropdownRefs = useRef<(HTMLDivElement | null)[]>([]);
    const searchInputRefs = useRef<(HTMLInputElement | null)[]>([]);
    const quantityInputRefs = useRef<(HTMLInputElement | null)[]>([]);
    const unitPriceInputRefs = useRef<(HTMLInputElement | null)[]>([]);
    const supplierSearchInputRef = useRef<HTMLInputElement>(null);
    const supplierDropdownRef = useRef<HTMLDivElement>(null);
    const saveButtonRef = useRef<HTMLButtonElement>(null);

    const handleAddItem = useCallback(() => {
        setItems(prev => [...prev, {
            product_id: '',
            quantity: 1,
            unit_price: 0,
            total_price: 0,
            searchQuery: '',
            isSearchOpen: false,
            currentLevel: 'master',
            selectedPath: {}
        }]);

        // Auto-focus the new search input
        setTimeout(() => {
            if (searchInputRefs.current[items.length]) {
                searchInputRefs.current[items.length]?.focus();
            }
        }, 100);
    }, [items.length]);

    const handleRemoveItem = useCallback((index: number) => {
        setItems(prev => {
            if (prev.length === 1) return prev;
            return prev.filter((_, i) => i !== index);
        });
    }, []);

    // Keyboard navigation for line items
    const completedItems = items.filter(it => it.product_id);
    const {
        focusedIndex,
        deleteConfirmIndex,
        setEditingQtyIndex,
        handleListKeyDown,
        resetNav,
    } = useKeyboardNav({
        itemCount: completedItems.length,
        searchInputRef: { current: searchInputRefs.current[items.length - 1] || searchInputRefs.current[0] } as React.RefObject<HTMLInputElement | null>,
        saveButtonRef,
        onEditQuantity: (idx) => {
            const actualIdx = items.findIndex((_, i) => {
                let completedCount = 0;
                for (let j = 0; j <= i; j++) {
                    if (items[j].product_id) completedCount++;
                    if (completedCount === idx + 1) return true;
                }
                return false;
            });
            if (actualIdx !== -1) {
                quantityInputRefs.current[actualIdx]?.focus();
                quantityInputRefs.current[actualIdx]?.select();
                setEditingQtyIndex(idx);
            }
        },
        onRemoveItem: (idx) => {
            const actualIdx = items.findIndex((_, i) => {
                let completedCount = 0;
                for (let j = 0; j <= i; j++) {
                    if (items[j].product_id) completedCount++;
                    if (completedCount === idx + 1) return true;
                }
                return false;
            });
            if (actualIdx !== -1) handleRemoveItem(actualIdx);
        },
        onEmptySearchEnter: () => {
            saveButtonRef.current?.focus();
        },
    });

    const fetchProducts = useCallback(async () => {
        let query = supabase
            .from('products')
            .select('id, name, sku, stock_available, buying_price')
            .order('name');

        if (activeBranchId) {
            query = query.eq('branch_id', activeBranchId);
        }

        const { data, error: fetchError } = await query;

        if (fetchError) console.error('Error fetching products:', fetchError);
        else setProducts(data || []);
    }, [activeBranchId]);

    const fetchSuppliers = useCallback(async () => {
        try {
            const data = await supplierService.getAll(activeBranchId);
            setSuppliers(data);
        } catch (err) {
            console.error('Error fetching suppliers:', err);
        }
    }, [activeBranchId]);

    const fetchBranches = useCallback(async () => {
        const { data, error } = await supabase
            .from('branches')
            .select('id, name, code')
            .order('name');
        
        if (error) console.error('Error fetching branches:', error);
        else setBranches(data || []);
    }, []);

    useEffect(() => {
        if (isOpen) {
            fetchProducts();
            fetchSuppliers();
            fetchBranches();
            if (editData) {
                setInvoiceNumber(editData.invoiceNumber);
                setSupplier(editData.supplier);
                setPurchaseType(editData.purchase_type || 'supplier');
                setItems(editData.items.map(item => ({
                    ...item,
                    searchQuery: item.name || '',
                    isSearchOpen: false
                })));
                setStatus(editData.status);
                setPaymentStatus(editData.payment_status || 'unpaid');
                setPaymentDate(editData.payment_date || null);
                setIsVatEnabled(editData.isVatEnabled);
                setIsDiscountEnabled(editData.isDiscountEnabled);
                setTransactionLabel((editData as any).transactionLabel || (editData as any).transaction_label || '');
                setSupplierId(editData.supplier_id || null);
                setSourceBranchId(editData.source_branch_id || null);
                setSupplierSearchQuery(editData.supplier || '');
                // Attempt to find supplier details if editing
                const s = suppliers.find(sup => sup.id === editData.supplier_id);
                if (s) {
                    setSupplierVatRegistered((s as any).supplier_vat_registered || false);
                    setSupplierTin((s as any).supplier_tin || '');
                }
            } else {
                setInvoiceNumber('PUR-' + Math.random().toString(36).substring(2, 8).toUpperCase());
                setItems([{
                    product_id: '',
                    quantity: 1,
                    unit_price: 0,
                    total_price: 0,
                    searchQuery: '',
                    isSearchOpen: false,
                    currentLevel: 'master',
                    selectedPath: {}
                }]);
                setSupplier('');
                setPurchaseType('supplier');
                setStatus('pending');
                setPaymentStatus('unpaid');
                setPaymentDate(null);
                setIsDiscountEnabled(false);
                setSupplierId(null);
                setSourceBranchId(null);
                setSupplierSearchQuery('');
                setTransactionLabel('');
            }
            setError(null);
            setSuccess(false);
            setSavedData([]);
            resetNav();
            document.body.classList.add('modal-open');

            // Auto-focus supplier search input
            setTimeout(() => {
                supplierSearchInputRef.current?.focus();
            }, 100);
        } else {
            document.body.classList.remove('modal-open');
        }
        return () => {
            document.body.classList.remove('modal-open');
        };
    }, [isOpen, editData, fetchProducts, fetchSuppliers, fetchBranches, resetNav]);

    const handleItemChange = useCallback(<K extends keyof PurchaseItem>(index: number, field: K, value: PurchaseItem[K]) => {
        setItems(prev => {
            const newItems = [...prev];
            const item = { ...newItems[index], [field]: value };

            if (field === 'searchQuery') {
                item.isSearchOpen = true;
                if (!value) {
                    item.product_id = '';
                    item.name = '';
                    item.stock_available = 0;
                }
                item.highlightedIndex = 0;
            }

            if (field === 'quantity' || field === 'unit_price') {
                const q = field === 'quantity' ? (value as number) : item.quantity;
                const u = field === 'unit_price' ? (value as number) : item.unit_price;
                item.total_price = q * u;
            }

            newItems[index] = item;
            return newItems;
        });
    }, []);

    // Handle keyboard navigation for modal
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.ctrlKey && e.key === 'Enter') {
                e.preventDefault();
                (document.getElementById('purchase-form') as HTMLFormElement)?.requestSubmit();
            }

            if (e.altKey) {
                switch (e.key.toLowerCase()) {
                    case 'a':
                        e.preventDefault();
                        handleAddItem();
                        break;
                    case 'backspace':
                        e.preventDefault();
                        if (items.length > 1) {
                            handleRemoveItem(items.length - 1);
                        }
                        break;
                }
            }
        };

        const handleClickOutside = (event: MouseEvent) => {
            dropdownRefs.current.forEach((ref, index) => {
                if (ref && !ref.contains(event.target as Node)) {
                    setItems(prev => {
                        const next = [...prev];
                        if (next[index]) next[index].isSearchOpen = false;
                        return next;
                    });
                }
            });
            if (purchaseType === 'supplier' && isSupplierSearchOpen && 
                supplierSearchInputRef.current && !supplierSearchInputRef.current.contains(event.target as Node) &&
                supplierDropdownRef.current && !supplierDropdownRef.current.contains(event.target as Node)) {
                setIsSupplierSearchOpen(false);
            }
        };

        if (isOpen) {
            document.addEventListener('keydown', handleKeyDown);
            document.addEventListener('mousedown', handleClickOutside);
        }
        return () => {
            document.removeEventListener('keydown', handleKeyDown);
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [isOpen, items.length, handleAddItem, handleRemoveItem, isSupplierSearchOpen, purchaseType]);

    const selectProduct = (index: number, product: Product) => {
        const newItems = [...items];
        newItems[index] = {
            ...newItems[index],
            product_id: product.id,
            name: product.name,
            stock_available: product.stock_available,
            unit_price: product.buying_price || 0,
            total_price: (newItems[index].quantity || 1) * (product.buying_price || 0),
            searchQuery: product.name,
            isSearchOpen: false
        };
        setItems(newItems);

        // Auto-focus quantity input after selection
        setTimeout(() => {
            if (quantityInputRefs.current[index]) {
                quantityInputRefs.current[index]?.focus();
                quantityInputRefs.current[index]?.select();
            }
        }, 50);
    };

    const quickAddProduct = (product: Product) => {
        // If the last item is empty, use it. Otherwise add a new row.
        const lastItem = items[items.length - 1];
        if (!lastItem.product_id && !lastItem.searchQuery) {
            selectProduct(items.length - 1, product);
        } else {
            setItems([
                ...items,
                {
                    product_id: product.id,
                    name: product.name,
                    stock_available: product.stock_available,
                    searchQuery: product.name,
                    isSearchOpen: false,
                    quantity: 1,
                    unit_price: product.buying_price || 0,
                    total_price: product.buying_price || 0
                }
            ]);
        }
    };


    const selectSupplier = (selected: Supplier) => {
        setSupplier(selected.name);
        setSupplierId(selected.id);
        setSupplierSearchQuery(selected.name);
        setIsSupplierSearchOpen(false);
        setSupplierVatRegistered((selected as any).supplier_vat_registered || false);
        setSupplierTin((selected as any).supplier_tin || '');
        
        // Focus first product search input after selection
        setTimeout(() => {
            const firstInput = document.querySelector('input[placeholder="Search Product..."]') as HTMLInputElement;
            if (firstInput) firstInput.focus();
        }, 50);
    };

    const subtotal = items.reduce((sum, item) => sum + item.total_price, 0);
    const vatAmount = isVatEnabled ? (subtotal - (subtotal / 1.12)) : 0;
    const discountAmount = isDiscountEnabled ? (subtotal * 0.10) : 0;
    const grandTotal = subtotal - discountAmount;
    const lowStockProducts = products.filter(p => {
        const stk = Number(p.stock_available ?? 0);
        return stk <= 10;
    });
    const inputVatAmount = supplierVatRegistered ? (subtotal - (subtotal / 1.12)) : 0;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (loading || success) return;
        setLoading(true);
        setError(null);

        try {
            if (!invoiceNumber.trim()) throw new Error('Please enter a Reference/Invoice number');
            
            let currentSupplier = supplier;
            let currentSupplierId = supplierId;

            if (purchaseType === 'supplier') {
                if (!currentSupplier.trim()) throw new Error('Please enter a supplier name');
                
                // Handle new supplier creation
                if (!currentSupplierId) {
                    const existingSupplier = suppliers.find(s => s.name.toLowerCase() === currentSupplier.trim().toLowerCase());
                    if (existingSupplier) {
                        currentSupplierId = existingSupplier.id;
                    } else {
                        const { data: newSupplier, error: supplierError } = await supabase
                            .from('suppliers')
                            .insert({
                                name: currentSupplier.trim(),
                                branch_id: activeBranchId,
                                supplier_tin: supplierTin,
                                supplier_vat_registered: supplierVatRegistered
                            })
                            .select()
                            .single();
                        
                        if (supplierError) throw supplierError;
                        currentSupplierId = newSupplier.id;
                        // Refresh suppliers list
                        fetchSuppliers();
                    }
                }
            }

            if (purchaseType === 'transfer' && !sourceBranchId) throw new Error('Please select a source branch');
            if (purchaseType === 'transfer' && sourceBranchId === Number(activeBranchId)) throw new Error('Source branch cannot be the same as the current branch');
            
            if (items.some(item => !item.product_id)) throw new Error('Please select a product for all rows');
            if (items.some(item => item.quantity <= 0)) throw new Error('Quantity must be greater than zero');

            // Cross-branch validation if transfer
            if (purchaseType === 'transfer' && sourceBranchId) {
                const sourceBranchName = branches.find(b => b.id === sourceBranchId)?.name || 'Source Branch';
                for (const item of items) {
                    const destProduct = products.find(p => p.id === item.product_id);
                    if (!destProduct) continue;

                    // Check if product exists in source branch by SKU
                    // Since SKU might not be in our current 'products' list (which is filtered by branch),
                    // we need to check the database.
                    const { data: sourceProduct, error: productError } = await supabase
                        .from('products')
                        .select('id, stock_available')
                        .eq('sku', destProduct.sku || '')
                        .eq('branch_id', sourceBranchId)
                        .single();

                    if (productError || !sourceProduct) {
                        throw new Error(`Product "${destProduct.name}" does not exist in ${sourceBranchName}. Please create it there first.`);
                    }

                    if (sourceProduct.stock_available < item.quantity) {
                        throw new Error(`Insufficient stock for "${destProduct.name}" in ${sourceBranchName}. Available: ${sourceProduct.stock_available}`);
                    }
                }
            }

            const { data: { user } } = await supabase.auth.getUser();

            if (editData) {
                await supabase.from('purchases').delete().eq('invoice_number', editData.invoiceNumber);
            }

            const purchasesToInsert = items.map(item => {
                const itemRatio = subtotal > 0 ? (item.total_price / subtotal) : (1 / items.length);
                return {
                    product_id: item.product_id,
                    quantity: item.quantity,
                    unit_price: item.unit_price,
                    total_price: item.total_price,
                    invoice_number: invoiceNumber,
                    supplier: currentSupplier,
                    supplier_id: currentSupplierId,
                    status: status,
                    payment_status: paymentStatus,
                    payment_date: paymentStatus === 'paid' ? (paymentDate || new Date().toISOString()) : paymentDate,
                    user_id: user?.id,
                    vat_amount: isVatEnabled ? (vatAmount * itemRatio) : 0,
                    discount_amount: isDiscountEnabled ? (discountAmount * itemRatio) : 0,
                    is_discounted: isDiscountEnabled,
                    date: editData?.date || new Date().toISOString(),
                    received_date: status === 'received' ? (editData?.received_date || new Date().toISOString()) : null,
                    purchase_type: purchaseType,
                    source_branch_id: purchaseType === 'transfer' ? sourceBranchId : null,
                    supplier_tin: supplierTin,
                    supplier_vat_registered: supplierVatRegistered,
                    input_vat_amount: inputVatAmount * itemRatio,
                    branch_id: activeBranchId,
                    transaction_label: transactionLabel
                };
            });

            const { data: insertedData, error: insertError } = await supabase.from('purchases').insert(purchasesToInsert).select('*, products(name)');
            if (insertError) throw insertError;

            // Sync buying_price back to products table
            for (const item of items) {
                const { error: updateError } = await supabase
                    .from('products')
                    .update({ buying_price: item.unit_price })
                    .eq('id', item.product_id);
                
                if (updateError) {
                    console.error(`Error updating buying_price for product ${item.product_id}:`, updateError);
                }
            }

            setSavedData(insertedData as (PurchaseRecord & { products?: { name: string } })[]);
            setSuccess(true);
            toast.success('Purchase saved successfully');
        } catch (err: unknown) {
            const error = err as Error;
            console.error('Purchase Modal Error:', err);
            setError(error.message || 'An unexpected error occurred during sync.');
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/85 px-4">
            <div className="w-full max-w-6xl rounded-3xl bg-surface shadow-2xl border border-border-default overflow-hidden flex flex-col max-h-[95vh] animate-slide-up text-left">
                <div className="flex items-center justify-between px-10 py-8 bg-brand-charcoal">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-brand-red rounded-lg flex items-center justify-center text-white shadow-brand-red/20 shadow-lg"><Truck size={16} /></div>
                        <h2 className="text-base font-black text-white uppercase tracking-widest">{editData ? 'Edit Purchase' : 'Create Purchase'}</h2>
                    </div>
                    <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors"><X size={18} /></button>
                </div>

                <div className="flex-1 overflow-y-auto px-10 py-12 scrollbar-hide overflow-x-visible bg-surface">
                    {error && <div className="mb-4 p-3 bg-red-50 border border-red-200 text-red-700 text-sm rounded-xl flex items-center gap-2"><AlertCircle size={16} /> {error}</div>}
                    <form id="purchase-form" onSubmit={handleSubmit} className="space-y-10 pb-24">
                        <div className="grid grid-cols-1 md:grid-cols-12 gap-4">
                            <div className="md:col-span-3 p-2 bg-subtle rounded-xl border border-border-default flex flex-col gap-2 h-[68px]">
                                <div className="flex items-center justify-between p-1 bg-surface border border-border-default rounded-lg">
                                    <button
                                        type="button"
                                        onClick={() => setPurchaseType('supplier')}
                                        className={`flex-1 py-1 rounded-md text-[9px] font-black transition-all flex items-center justify-center gap-1.5 ${purchaseType === 'supplier' ? 'bg-brand-red text-white shadow-sm' : 'text-text-muted hover:bg-subtle'}`}
                                    >
                                        <Store size={12} /> SUPP
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => setPurchaseType('transfer')}
                                        className={`flex-1 py-1 rounded-md text-[9px] font-black transition-all flex items-center justify-center gap-1.5 ${purchaseType === 'transfer' ? 'bg-brand-red text-white shadow-sm' : 'text-text-muted hover:bg-subtle'}`}
                                    >
                                        <Building2 size={12} /> TRAN
                                    </button>
                                </div>
                                <div className="relative">
                                    <div className="absolute left-2 top-1/2 -translate-y-1/2 text-text-muted">
                                        {purchaseType === 'supplier' ? <User size={12} /> : <Building2 size={12} />}
                                    </div>
                                     {purchaseType === 'supplier' ? (
                                         <>
                                             <input
                                                 ref={supplierSearchInputRef}
                                                 type="text"
                                                 required
                                                 placeholder="Search Supplier..."
                                                 className="w-full bg-surface border border-border-default rounded-lg pl-7 pr-6 py-1 text-[11px] focus:ring-2 focus:ring-brand-red/10 outline-none shadow-sm font-medium text-text-primary uppercase h-[24px]"
                                                 value={supplierSearchQuery}
                                                 onChange={(e) => {
                                                     setSupplierSearchQuery(e.target.value);
                                                     setSupplier(e.target.value);
                                                     setIsSupplierSearchOpen(true);
                                                     if (!e.target.value) setSupplierId(null);
                                                 }}
                                                 onFocus={() => setIsSupplierSearchOpen(true)}
                                             />
                                             {isSupplierSearchOpen && purchaseType === 'supplier' && (
                                                 <div ref={supplierDropdownRef} className="absolute z-[110] left-0 right-0 top-full mt-1 bg-surface border border-border-default rounded-xl shadow-2xl max-h-[300px] overflow-y-auto animate-fade-in">
                                                     {suppliers.filter(s => isSmartMatch(s.name, supplierSearchQuery)).map(s => (
                                                         <button
                                                             key={s.id}
                                                             type="button"
                                                             onClick={() => selectSupplier(s)}
                                                             className="w-full text-left px-3 py-2 hover:bg-bg-subtle border-b border-border-muted last:border-0 flex flex-col gap-0.5"
                                                         >
                                                             <span className="text-[10px] font-black text-text-primary uppercase">{s.name}</span>
                                                             <span className="text-[8px] text-text-secondary uppercase">VAT: {(s as any).supplier_vat_registered ? 'YES' : 'NO'}</span>
                                                         </button>
                                                     ))}
                                                     {supplierSearchQuery.trim() && !suppliers.find(s => s.name.toLowerCase() === supplierSearchQuery.trim().toLowerCase()) && (
                                                         <button
                                                             type="button"
                                                             onClick={() => {
                                                                 setIsSupplierSearchOpen(false);
                                                                 toast.info(`New supplier "${supplierSearchQuery}" will be created on save`);
                                                             }}
                                                             className="w-full text-left px-3 py-3 hover:bg-brand-red-light/10 text-brand-red border-t border-brand-red/10 animate-pulse"
                                                         >
                                                             <div className="flex items-center gap-2">
                                                                 <Plus size={12} />
                                                                 <span className="text-[9px] font-black uppercase tracking-widest text-brand-red">Create New Supplier: {supplierSearchQuery.toUpperCase()}</span>
                                                             </div>
                                                         </button>
                                                     )}
                                                 </div>
                                             )}
                                         </>
                                    ) : (
                                        <select
                                            required
                                            className="w-full bg-surface border border-border-default rounded-lg pl-7 pr-4 py-1 text-[11px] focus:ring-2 focus:ring-brand-red/10 outline-none shadow-sm font-black text-text-primary appearance-none cursor-pointer uppercase h-[24px]"
                                            value={sourceBranchId || ''}
                                            onChange={(e) => {
                                                const bId = Number(e.target.value);
                                                setSourceBranchId(bId);
                                                const bName = branches.find(b => b.id === bId)?.name || '';
                                                setSupplier(bName);
                                            }}
                                        >
                                            <option value="" disabled>SELECT BRANCH</option>
                                            {branches.filter(branch => branch.id !== Number(activeBranchId)).map(branch => (<option key={branch.id} value={branch.id}>{branch.name.toUpperCase()}</option>))}
                                        </select>
                                    )}
                                </div>
                            </div>

                            <div className="md:col-span-2 p-2 bg-subtle rounded-xl border border-border-default h-[68px]">
                                <label className="block text-[10px] font-black text-text-secondary uppercase tracking-widest mb-1 flex items-center gap-2">Ref #</label>
                                <input type="text" required className="w-full bg-surface border border-border-default rounded-lg px-2 py-1 text-xs font-data outline-none tracking-widest text-text-primary focus:border-brand-red h-[32px]" value={invoiceNumber} onChange={(e) => setInvoiceNumber(e.target.value)} />
                            </div>

                            <div className="md:col-span-4 p-2 bg-subtle rounded-xl border border-border-default flex gap-3 h-[68px]">
                                <div className="flex-1 space-y-1">
                                    <label className="block text-[10px] font-black text-text-secondary uppercase tracking-widest mb-1">Status</label>
                                    <div className="grid grid-cols-2 gap-1.5">
                                        <button type="button" onClick={() => setStatus('pending')} className={`py-1 rounded-lg border text-[9px] font-black transition-all flex items-center justify-center gap-1.5 ${status === 'pending' ? 'bg-orange-500 text-white border-orange-600 shadow-sm' : 'bg-surface text-text-muted border-border-default hover:bg-subtle'}`}><Clock size={10} /> PND</button>
                                        <button type="button" onClick={() => setStatus('received')} className={`py-1 rounded-lg border text-[9px] font-black transition-all flex items-center justify-center gap-1.5 ${status === 'received' ? 'bg-emerald-600 text-white border-emerald-700 shadow-sm' : 'bg-surface text-text-muted border-border-default hover:bg-subtle'}`}><ShieldCheck size={10} /> REC</button>
                                    </div>
                                </div>
                                <div className="flex-1 space-y-1">
                                    <label className="block text-[10px] font-black text-text-secondary uppercase tracking-widest mb-1">Payment</label>
                                    <div className="grid grid-cols-3 gap-1">
                                        <button type="button" onClick={() => setPaymentStatus('unpaid')} className={`py-1 rounded-lg border text-[8px] font-black transition-all ${paymentStatus === 'unpaid' ? 'bg-red-500 text-white border-red-600 shadow-sm' : 'bg-surface text-text-muted border-border-default hover:bg-subtle'}`}>UN</button>
                                        <button type="button" onClick={() => setPaymentStatus('partial')} className={`py-1 rounded-lg border text-[8px] font-black transition-all ${paymentStatus === 'partial' ? 'bg-amber-500 text-white border-amber-600 shadow-sm' : 'bg-surface text-text-muted border-border-default hover:bg-subtle'}`}>PRT</button>
                                        <button type="button" onClick={() => setPaymentStatus('paid')} className={`py-1 rounded-lg border text-[8px] font-black transition-all ${paymentStatus === 'paid' ? 'bg-indigo-600 text-white border-indigo-700 shadow-sm' : 'bg-surface text-text-muted border-border-default hover:bg-subtle'}`}>FUL</button>
                                    </div>
                                </div>
                            </div>

                            <div className="md:col-span-3 p-2 bg-subtle rounded-xl border border-border-default h-[68px]">
                                <label className="block text-[10px] font-black text-text-secondary uppercase tracking-widest mb-1 flex items-center gap-2"><Tag size={12} /> Label</label>
                                <select 
                                    className="w-full bg-surface border border-border-default rounded-xl px-2 py-1 text-[11px] font-black text-text-primary outline-none focus:ring-2 focus:ring-brand-red/10 appearance-none cursor-pointer uppercase h-[32px]"
                                    value={transactionLabel}
                                    onChange={(e) => setTransactionLabel(e.target.value)}
                                >
                                    <option value="">NO LABEL</option>
                                    {PURCHASE_LABELS.map(label => (<option key={label.id} value={label.id}>{label.label}</option>))}
                                </select>
                            </div>
                        </div>

                        <div className="space-y-6">
                            <div className="flex justify-between items-center border-b border-border-default pb-4">
                                <div className="flex items-center gap-4">
                                    <h3 className="text-xs font-black uppercase text-text-primary tracking-widest">Stock Items</h3>
                                    {lowStockProducts.length > 0 && (
                                        <button
                                            type="button"
                                            onClick={() => setShowLowStock(!showLowStock)}
                                            className={`text-[9px] font-black px-2 py-1 rounded-lg transition-all flex items-center gap-1.5 ${showLowStock ? 'bg-brand-red text-white' : 'bg-brand-red/10 text-brand-red border border-brand-red/20'}`}
                                        >
                                            <AlertCircle size={12} />
                                            {showLowStock ? 'HIDE LOW STOCK' : `${lowStockProducts.length} LOW STOCK ITEMS`}
                                        </button>
                                    )}
                                </div>
                                <button type="button" onClick={handleAddItem} className="bg-brand-red-light/10 text-brand-red px-4 py-2 rounded-xl text-[10px] font-black hover:bg-brand-red hover:text-white transition-all border border-brand-red/20 shadow-sm">
                                    <Plus size={14} className="inline mr-1" /> ADD ITEM
                                </button>
                            </div>

                            {supplierVatRegistered && (
                                <div className="p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-2xl flex items-center justify-between">
                                    <div className="flex items-center gap-3">
                                        <div className="w-8 h-8 bg-emerald-500 rounded-lg flex items-center justify-center text-white"><ShieldCheck size={16} /></div>
                                        <div>
                                            <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest">VAT Registered Supplier</p>
                                            <p className="text-[9px] font-bold text-emerald-500/80">Input VAT will be auto-calculated for BIR compliance.</p>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[9px] font-black text-text-muted uppercase tracking-widest">Est. Input VAT</p>
                                        <p className="text-sm font-black text-emerald-500 font-data">₱{inputVatAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                    </div>
                                </div>
                            )}

                            {showLowStock && lowStockProducts.length > 0 && (
                                <div className="p-4 bg-brand-red/5 border border-brand-red/20 rounded-2xl animate-fade-in">
                                    <div className="flex items-center gap-2 mb-3">
                                        <AlertCircle className="text-brand-red" size={14} />
                                        <h4 className="text-[10px] font-black text-text-primary uppercase tracking-widest">Low Stock Alert</h4>
                                    </div>
                                    <div className="flex flex-wrap gap-2">
                                        {lowStockProducts.map(p => (
                                            <button
                                                key={p.id}
                                                type="button"
                                                onClick={() => quickAddProduct(p)}
                                                className="flex items-center gap-3 px-3 py-2 bg-surface border border-border-default rounded-xl hover:border-brand-red transition-all group shadow-sm"
                                            >
                                                <div className="text-left">
                                                    <p className="text-[10px] font-black text-text-primary leading-none mb-1 uppercase">{p.name}</p>
                                                    <div className="flex items-center gap-2">
                                                        <span className="text-[9px] font-black text-brand-red font-data">STK: {p.stock_available}</span>
                                                    </div>
                                                </div>
                                                <div className="w-6 h-6 rounded-lg bg-brand-red/10 text-brand-red flex items-center justify-center group-hover:bg-brand-red group-hover:text-white transition-colors">
                                                    <Plus size={14} />
                                                </div>
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}
                            <div 
                                className="space-y-5 outline-none" 
                                tabIndex={focusedIndex >= 0 ? 0 : -1} 
                                onKeyDown={focusedIndex >= 0 ? handleListKeyDown : undefined}
                            >
                                {items.map((item, index) => (
                                    <div key={index} className={`flex flex-col lg:flex-row gap-5 p-5 rounded-2xl shadow-sm transition-all group/item overflow-visible relative ${item.product_id && focusedIndex === completedItems.indexOf(item) ? 'bg-blue-50 border-2 border-brand-red/30' : 'bg-subtle border border-border-default hover:border-brand-red/30'}`}>
                                        {/* Keyboard shortcut indicators */}
                                        {item.product_id && focusedIndex === completedItems.indexOf(item) && (
                                            <div className="absolute -top-3 left-4 flex gap-2 animate-bounce-subtle z-10">
                                                <span className="bg-brand-red text-white text-[9px] font-black px-2 py-0.5 rounded-full shadow-lg flex items-center gap-1">
                                                    <kbd className="bg-white/20 px-1 rounded">Q</kbd> QTY
                                                </span>
                                                <span className="bg-brand-red text-white text-[9px] font-black px-2 py-0.5 rounded-full shadow-lg flex items-center gap-1">
                                                    <kbd className="bg-white/20 px-1 rounded">R</kbd> REPLACE
                                                </span>
                                                <span className="bg-brand-red text-white text-[9px] font-black px-2 py-0.5 rounded-full shadow-lg flex items-center gap-1">
                                                    <kbd className="bg-white/20 px-1 rounded">DEL</kbd> REMOVE
                                                </span>
                                                {deleteConfirmIndex === focusedIndex && (
                                                    <span className="bg-brand-charcoal text-white text-[9px] font-black px-2 py-0.5 rounded-full shadow-lg animate-pulse">
                                                        PRESS AGAIN TO REMOVE
                                                    </span>
                                                )}
                                            </div>
                                        )}
                                        <div className="flex-[4] relative" ref={el => { dropdownRefs.current[index] = el; }}>
                                            <label className="block text-[9px] font-black text-text-secondary mb-1.5 uppercase tracking-widest">Product</label>
                                            <div className="relative">
                                                <div className="absolute left-3 top-1/2 -translate-y-1/2 text-text-muted"><Search size={14} /></div>
                                                <input
                                                    ref={el => { searchInputRefs.current[index] = el; }}
                                                    type="text"
                                                    placeholder="Focus to search product..."
                                                    className="w-full bg-surface border border-border-default rounded-xl pl-9 pr-8 py-2.5 text-xs font-bold text-text-primary focus:ring-2 focus:ring-brand-red/10 focus:border-brand-red/30 outline-none"
                                                    value={item.searchQuery}
                                                    onChange={(e) => handleItemChange(index, 'searchQuery', e.target.value)}
                                                    onFocus={(e) => {
                                                        e.target.select();
                                                        handleItemChange(index, 'isSearchOpen', true);
                                                    }}
                                                    onKeyDown={(e) => {
                                                        const query = item.searchQuery || '';
                                                        const filtered = products.filter(p => isSmartMatch(p.name, query));

                                                        if (e.key === 'ArrowDown') {
                                                            e.preventDefault();
                                                            if (item.isSearchOpen) {
                                                                handleItemChange(index, 'highlightedIndex', Math.min((item.highlightedIndex || 0) + 1, filtered.length - 1));
                                                            } else {
                                                                handleItemChange(index, 'isSearchOpen', true);
                                                            }
                                                        } else if (e.key === 'ArrowUp') {
                                                            e.preventDefault();
                                                            handleItemChange(index, 'highlightedIndex', Math.max((item.highlightedIndex || 0) - 1, 0));
                                                        } else if (e.key === 'Enter') {
                                                            e.preventDefault();
                                                            if (item.isSearchOpen && filtered[item.highlightedIndex || 0]) {
                                                                selectProduct(index, filtered[item.highlightedIndex || 0]);
                                                            } else if (!item.searchQuery && completedItems.length > 0) {
                                                                saveButtonRef.current?.focus();
                                                            }
                                                        } else if (e.key === 'Escape') {
                                                            if (item.isSearchOpen) {
                                                                handleItemChange(index, 'isSearchOpen', false);
                                                            }
                                                        }
                                                    }}
                                                />
                                                {item.searchQuery && (
                                                    <button type="button" onClick={() => { const ni = [...items]; ni[index] = { ...ni[index], searchQuery: '', product_id: '', name: '', stock_available: 0, unit_price: 0, total_price: 0, currentLevel: 'master', selectedPath: {}, isSearchOpen: false }; setItems(ni); }} className="absolute right-3 top-1/2 -translate-y-1/2 text-text-muted hover:text-brand-red transition-colors">
                                                        <X size={14} />
                                                    </button>
                                                )}
                                            </div>

                                            {item.isSearchOpen && (
                                                <div className="absolute z-[100] left-0 right-0 top-full mt-1 bg-surface border border-border-default rounded-xl shadow-2xl max-h-[350px] overflow-hidden flex flex-col min-w-[400px] animate-fade-in">
                                                    {/* Back to Master Categories */}
                                                    {!item.searchQuery && item.currentLevel !== 'master' && (
                                                        <div className="px-4 py-2 bg-subtle border-b border-border-default flex items-center gap-2">
                                                            <button
                                                                type="button"
                                                                onClick={() => handleItemChange(index, 'currentLevel', 'master')}
                                                                className="flex items-center gap-1.5 text-[10px] font-black uppercase text-brand-red hover:text-brand-red-dark transition-colors"
                                                            >
                                                                <ChevronDown size={14} className="rotate-90" />
                                                                Back
                                                            </button>
                                                            <span className="text-[10px] font-black text-text-muted uppercase tracking-widest">
                                                                {item.selectedPath?.master}
                                                            </span>
                                                        </div>
                                                    )}

                                                    <div className="flex-1 overflow-y-auto overflow-x-hidden">
                                                        {item.searchQuery ? (
                                                            // Global Search Mode
                                                            products.filter(p =>
                                                                isSmartMatch(p.name, item.searchQuery || '')
                                                            ).length > 0 ? (
                                                                products.filter(p =>
                                                                    isSmartMatch(p.name, item.searchQuery || '')
                                                                ).map(p => (
                                                                    <button
                                                                        key={p.id}
                                                                        type="button"
                                                                        onClick={() => selectProduct(index, p)}
                                                                        className="w-full text-left px-3 py-2 hover:bg-bg-subtle border-b border-border-muted last:border-0 flex flex-col gap-0.5"
                                                                    >
                                                                        <div className="flex items-center justify-between">
                                                                            <span className="text-[10px] font-black text-text-primary uppercase">{p.name}</span>
                                                                        </div>
                                                                        <div className="flex items-center justify-between text-[9px]">
                                                                            <span className="text-text-secondary font-medium font-data">STK: <span className={p.stock_available <= 5 ? 'text-brand-red font-bold' : 'text-emerald-500'}>{p.stock_available}</span></span>
                                                                        </div>
                                                                    </button>
                                                                ))
                                                            ) : (
                                                                <div className="p-8 text-center bg-subtle rounded-xl">
                                                                    <div className="w-10 h-10 bg-base rounded-full flex items-center justify-center text-text-muted mx-auto mb-2"><Search size={16} /></div>
                                                                    <p className="text-[10px] font-bold text-text-muted uppercase tracking-widest">No products found</p>
                                                                </div>
                                                            )
                                                        ) : item.currentLevel === 'master' ? (
                                                            // Level 1: Master Categories
                                                            Array.from(new Set(products.map(p => p.name.split(' > ')[0]))).sort().map(m => (
                                                                <button
                                                                    key={m}
                                                                    type="button"
                                                                    onClick={() => {
                                                                        const newItems = [...items];
                                                                        newItems[index].selectedPath = { master: m };
                                                                        newItems[index].currentLevel = 'product';
                                                                        setItems(newItems);
                                                                    }}
                                                                    className="w-full text-left px-3 py-2.5 hover:bg-brand-red/10 border-b border-border-muted last:border-0 flex items-center justify-between group"
                                                                >
                                                                    <span className="text-[10px] font-black text-text-primary uppercase tracking-wider">{m}</span>
                                                                    <ChevronDown size={12} className="-rotate-90 text-text-muted group-hover:text-brand-red transition-colors" />
                                                                </button>
                                                            ))
                                                        ) : (
                                                            // Level 2: All products under selected master
                                                            products
                                                                .filter(p => p.name.split(' > ')[0] === item.selectedPath?.master)
                                                                .map(p => (
                                                                    <button
                                                                        key={p.id}
                                                                        type="button"
                                                                        onClick={() => selectProduct(index, p)}
                                                                        className="w-full text-left px-3 py-2 hover:bg-bg-subtle border-b border-border-muted last:border-0 flex flex-col gap-0.5"
                                                                    >
                                                                        <div className="flex items-center justify-between">
                                                                            <span className="text-[10px] font-black text-text-primary uppercase">
                                                                                {p.name.split(' > ').slice(1).join(' > ')}
                                                                            </span>
                                                                        </div>
                                                                        <div className="flex items-center justify-between text-[9px]">
                                                                            <span className="text-text-secondary font-medium font-data">STK: <span className={p.stock_available <= 5 ? 'text-brand-red font-bold' : 'text-emerald-500'}>{p.stock_available}</span></span>
                                                                        </div>
                                                                    </button>
                                                                ))
                                                        )}
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                        <div className="flex-[2]">
                                            <label className="block text-[9px] font-black text-text-secondary mb-1.5 uppercase tracking-widest">Unit Cost</label>
                                            <div className="relative">
                                                <span className="absolute left-2.5 top-1/2 -translate-y-1/2 text-text-muted text-[10px]">₱</span>
                                                <input
                                                    ref={el => { unitPriceInputRefs.current[index] = el; }}
                                                    type="number"
                                                    step="0.01"
                                                    className="w-full bg-bg-surface border border-border-default rounded-lg pl-5 pr-2 py-1.5 text-xs font-data focus:border-brand-red focus:ring-2 focus:ring-brand-red/10 outline-none text-text-primary shadow-inner h-[32px]"
                                                    value={item.unit_price}
                                                    onChange={(e) => handleItemChange(index, 'unit_price', parseFloat(e.target.value) || 0)}
                                                    onFocus={(e) => e.target.select()}
                                                    onKeyDown={(e) => {
                                                        if (e.key === 'Enter') {
                                                            e.preventDefault();
                                                            if (index === items.length - 1) {
                                                                handleAddItem();
                                                            } else {
                                                                searchInputRefs.current[index + 1]?.focus();
                                                            }
                                                        } else if (e.key === 'Escape') {
                                                            quantityInputRefs.current[index]?.focus();
                                                        }
                                                    }}
                                                />
                                            </div>
                                        </div>
                                        <div className="flex-[1.5]">
                                            <label className="block text-[9px] font-black text-text-secondary mb-1.5 uppercase tracking-widest">Qty</label>
                                            <input
                                                ref={el => { quantityInputRefs.current[index] = el; }}
                                                type="number"
                                                min="1"
                                                className="w-full bg-bg-surface border border-border-default rounded-lg px-2 py-1.5 text-xs font-data focus:border-brand-red focus:ring-2 focus:ring-brand-red/10 outline-none text-text-primary shadow-inner h-[32px]"
                                                value={item.quantity}
                                                onChange={(e) => handleItemChange(index, 'quantity', parseInt(e.target.value) || 0)}
                                                onFocus={(e) => e.target.select()}
                                                onKeyDown={(e) => {
                                                    if (e.key === 'Enter') {
                                                        e.preventDefault();
                                                        unitPriceInputRefs.current[index]?.focus();
                                                        unitPriceInputRefs.current[index]?.select();
                                                    } else if (e.key === 'Escape') {
                                                        searchInputRefs.current[index]?.focus();
                                                    }
                                                }}
                                            />
                                        </div>
                                        <div className="flex-[2.5] text-right min-w-[100px]">
                                            <label className="block text-[9px] font-black text-text-secondary mb-1.5 uppercase tracking-widest">Sub-Total</label>
                                            <div className="py-1 font-black text-base text-text-primary font-data">₱{item.total_price.toLocaleString(undefined, { minimumFractionDigits: 2 })}</div>
                                        </div>
                                        <div className="flex items-center justify-center lg:pt-4">
                                            <button type="button" onClick={() => handleRemoveItem(index)} disabled={items.length === 1} className="p-1.5 text-text-muted hover:text-brand-red hover:bg-brand-red/5 rounded-lg transition-all disabled:opacity-0"><Trash2 size={16} /></button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </form>
                </div>

                <div className="px-10 py-8 bg-brand-charcoal flex flex-col md:flex-row items-end md:items-center justify-between gap-6 relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-brand-red/10 rounded-full blur-3xl -mr-32 -mt-32" />
                    <div className="flex flex-wrap items-center gap-x-10 gap-y-4 text-white/60 relative z-10 w-full md:w-auto">
                        <div className="min-w-[120px]"><p className="text-[10px] font-black uppercase opacity-50 tracking-widest mb-1.5">Subtotal</p><p className="text-base lg:text-lg font-black font-data text-white whitespace-nowrap">₱{subtotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p></div>
                        <div className={`min-w-[120px] transition-all ${isDiscountEnabled ? 'opacity-100' : 'opacity-20'}`}>
                            <p className="text-[10px] font-black uppercase opacity-50 tracking-widest mb-1.5">Discount (10%)</p>
                            <p className="text-base lg:text-lg font-black font-data text-brand-orange whitespace-nowrap">- ₱{discountAmount.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                        </div>
                    </div>
                    <div className="flex flex-col items-end relative z-10 w-full md:w-auto max-w-full overflow-hidden">
                        <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.3em] mb-1 leading-none">Total Payable</p>
                        <div className="flex flex-wrap items-center justify-end gap-6 text-right">
                            <p className="text-3xl lg:text-4xl font-black text-white font-data shadow-sm whitespace-nowrap">₱{grandTotal.toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                            <button form="purchase-form" type="submit" ref={saveButtonRef} disabled={loading || success} className="px-8 py-4 bg-brand-red hover:bg-brand-red-dark text-white rounded-2xl font-black text-sm shadow-red active:scale-95 disabled:opacity-50 tracking-widest uppercase focus:ring-2 focus:ring-brand-red ring-offset-2 outline-none">
                                {loading ? 'SYNCING...' : success ? 'SAVED!' : 'SAVE PURCHASE'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>

            {/* Success Receipt Overlay */}
            {success && (
                <div className="fixed inset-0 z-[10000] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in">
                    <div className="bg-bg-surface rounded-3xl p-8 max-w-md w-full shadow-2xl border border-border-muted animate-slide-up relative overflow-hidden text-text-primary">
                        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-emerald-400 to-brand-red" />

                        <div className="text-center mb-8">
                            <div className="w-16 h-16 bg-emerald-500/10 text-emerald-500 rounded-2xl flex items-center justify-center mx-auto mb-4 border border-emerald-500/20">
                                <ShieldCheck size={32} />
                            </div>
                            <h3 className="text-2xl font-black text-text-primary uppercase tracking-tight">Purchase Saved</h3>
                            <p className="text-text-secondary text-sm font-bold">Check invoice details before saving</p>
                        </div>

                        <div className="border-2 border-dashed border-border-muted rounded-2xl p-6 space-y-6 bg-bg-subtle/50">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="text-[10px] font-black text-text-muted uppercase tracking-widest mb-4">INVOICE #</h3>
                                    <p className="text-sm font-black text-text-primary font-data">{invoiceNumber}</p>
                                </div>
                                <div className="text-right">
                                    <p className="text-[9px] font-black text-text-muted uppercase tracking-widest mb-1">{purchaseType === 'supplier' ? 'Supplier' : 'Source'}</p>
                                    <p className="text-sm font-black text-text-primary uppercase">{supplier}</p>
                                </div>
                            </div>

                            <div className="space-y-3">
                                <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest pb-1 border-b border-slate-100">Itemized List</p>
                                <div className="max-h-48 overflow-y-auto pr-2 space-y-2 scrollbar-hide">
                                    {savedData.map((item, idx) => (
                                        <div key={idx} className="flex justify-between text-[11px]">
                                            <div className="flex-1">
                                                <p className="font-bold text-slate-700 leading-tight">{item.products?.name}</p>
                                                <p className="text-[9px] text-slate-400 font-data">x{item.quantity} @ ₱{item.unit_price.toLocaleString()}</p>
                                            </div>
                                            <p className="font-black text-brand-charcoal font-data">₱{item.total_price.toLocaleString()}</p>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            <div className="pt-4 border-t-2 border-dashed border-border-muted space-y-2">
                                <div className="flex justify-between text-[10px]">
                                    <span className="font-black text-text-muted uppercase">Subtotal</span>
                                    <span className="font-black text-text-primary font-data">₱{subtotal.toLocaleString()}</span>
                                </div>
                                <div className="flex justify-between items-center pt-2">
                                    <span className="text-[11px] font-black text-text-primary uppercase tracking-widest">Total Cost</span>
                                    <span className="text-2xl font-black text-text-primary font-data tracking-tighter">₱{grandTotal.toLocaleString()}</span>
                                </div>
                            </div>

                            <div className="flex items-center justify-center gap-4 pt-2">
                                <span className={`text-[8px] font-black px-3 py-1 rounded-full uppercase tracking-widest border ${status === 'received' ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-orange-50 text-orange-600 border-orange-100'}`}>{status}</span>
                                <span className={`text-[8px] font-black px-3 py-1 rounded-full uppercase tracking-widest border ${purchaseType === 'transfer' ? 'bg-blue-50 text-blue-600 border-blue-100' : 'bg-brand-red/10 text-brand-red border-brand-red/20'}`}>{purchaseType}</span>
                            </div>
                        </div>

                        <button
                            onClick={() => {
                                onSuccess(savedData);
                                // Stay open but reset for next transaction
                                setInvoiceNumber('PUR-' + Math.random().toString(36).substring(2, 8).toUpperCase());
                                setItems([{
                                    product_id: '',
                                    quantity: 1,
                                    unit_price: 0,
                                    total_price: 0,
                                    searchQuery: '',
                                    isSearchOpen: false,
                                    currentLevel: 'master',
                                    selectedPath: {}
                                }]);
                                setSupplier('');
                                setSupplierId(null);
                                setSupplierSearchQuery('');
                                setSuccess(false);
                                resetNav();
                                setTimeout(() => supplierSearchInputRef.current?.focus(), 100);
                            }}
                            className="w-full mt-8 py-4 bg-brand-red text-white rounded-2xl font-black text-sm hover:bg-brand-red-dark transition-all active:scale-[0.98] uppercase tracking-[0.2em] shadow-xl shadow-brand-red/20"
                        >
                            CLOSE RECEIPT
                        </button>
                    </div>
                </div>
            )}
        </div>,
        document.body
    );
}

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { supabase } from '../../../shared/lib/supabase';
import { X, RotateCcw, Trash2, AlertTriangle, Package } from 'lucide-react';
import { useBranch } from '../../../shared/lib/BranchContext';

interface Product {
    id: string;
    name: string;
    selling_price: number;
    stock_available: number;
}

interface ReturnItem {
    productId: string;
    productName: string;
    quantity: number;
    unitPrice: number;
    totalPrice: number;
    maxQuantity?: number;
}

interface ReturnModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: (newReturn?: unknown[]) => void;
}

export default function ReturnModal({ isOpen, onClose, onSuccess }: ReturnModalProps) {
    const { activeBranchId } = useBranch();
    const [products, setProducts] = useState<Product[]>([]);
    const [items, setItems] = useState<ReturnItem[]>([]);
    const [invoiceNumber, setInvoiceNumber] = useState('');
    const [reason, setReason] = useState('');
    const [isVatEnabled, setIsVatEnabled] = useState(true);
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.ctrlKey && e.key === 'Enter') {
                e.preventDefault();
                (document.getElementById('return-form') as HTMLFormElement)?.requestSubmit();
            }

            if (e.altKey && e.key.toLowerCase() === 'i') {
                e.preventDefault();
                loadInvoiceItems();
            }
        };

        if (isOpen) {
            fetchProducts();
            const today = new Date().toLocaleDateString('en-CA'); // YYYY-MM-DD
            setItems([]);
            setInvoiceNumber('');
            setReason('');
            setDate(today);
            setError(null);
            document.body.classList.add('modal-open');
            document.addEventListener('keydown', handleKeyDown);
        } else {
            document.body.classList.remove('modal-open');
        }
        return () => {
            document.body.classList.remove('modal-open');
            document.removeEventListener('keydown', handleKeyDown);
        };
    }, [isOpen, invoiceNumber]);

    const fetchProducts = async () => {
        let query = supabase.from('products').select('id, name, selling_price, stock_available').order('name');
        if (activeBranchId) {
            query = query.eq('branch_id', activeBranchId);
        }
        const { data, error } = await query;
        if (error) console.error('Error fetching products:', error);
        else setProducts(data || []);
    };

    const updateItem = (index: number, updates: Partial<ReturnItem>) => {
        const newItems = [...items];
        const item = { ...newItems[index], ...updates };

        if (updates.productId) {
            const product = products.find(p => p.id === updates.productId);
            if (product) {
                item.productName = product.name;
            }
        }

        item.totalPrice = item.quantity * item.unitPrice;
        newItems[index] = item;
        setItems(newItems);
    };

    const removeItem = (index: number) => {
        setItems(items.filter((_, i) => i !== index));
    };

    const subtotal = items.reduce((sum, item) => sum + item.totalPrice, 0);
    const vatAmount = isVatEnabled ? (subtotal - (subtotal / 1.12)) : 0;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (loading) return;
        if (items.length === 0) { setError('Please add at least one item'); return; }
        if (items.some(item => !item.productId)) { setError('Please select products for all items'); return; }

        for (const item of items) {
            if (item.maxQuantity && item.quantity > item.maxQuantity) {
                setError(`Quantity for ${item.productName} cannot exceed original purchase quantity (${item.maxQuantity})`);
                return;
            }

            const product = products.find(p => p.id === item.productId);
            if (product && item.quantity > product.stock_available) {
                setError(`Insufficient stock for ${product.name}. Available: ${product.stock_available}`);
                return;
            }
        }

        setLoading(true);
        setError(null);

        try {
            const returnRecords = items.map(item => ({
                product_id: item.productId,
                quantity: item.quantity,
                reason: reason,
                invoice_number: invoiceNumber,
                unit_price: item.unitPrice,
                total_price: item.totalPrice,
                vat_amount: isVatEnabled ? (item.totalPrice - (item.totalPrice / 1.12)) : 0,
                date: date,
                branch_id: activeBranchId
            }));

            const { data, error: insertError } = await supabase.from('supplier_returns').insert(returnRecords).select('*, products(name)');
            if (insertError) throw insertError;

            setTimeout(() => {
                onSuccess(data as unknown as unknown[]);
                onClose();
            }, 500);
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Unknown error');
        } finally {
            setLoading(false);
        }
    };

    const loadInvoiceItems = async () => {
        if (!invoiceNumber) {
            setError('Please enter an invoice number first');
            return;
        }
        setLoading(true);
        setError(null);
        try {
            let query = supabase
                .from('purchases')
                .select('product_id, quantity, unit_price, products(name)')
                .eq('invoice_number', invoiceNumber);

            if (activeBranchId) {
                query = query.eq('branch_id', activeBranchId);
            }

            const { data, error } = await query;

            if (error) throw error;
            if (!data || data.length === 0) {
                setError('No purchases found for this invoice number');
                return;
            }

            const newItems: ReturnItem[] = data.map(item => ({
                productId: item.product_id,
                productName: (item.products as any)?.name || 'Unknown Product',
                quantity: item.quantity,
                unitPrice: item.unit_price,
                totalPrice: item.quantity * item.unit_price,
                maxQuantity: item.quantity
            }));

            setItems(newItems);
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to load invoice items');
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/85 px-4 text-left">
            <div className="w-full max-w-5xl rounded-2xl bg-surface shadow-2xl border border-border-muted flex flex-col max-h-[95vh] animate-slide-up overflow-hidden">
                <div className="flex items-center justify-between px-6 py-3 bg-brand-charcoal">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-brand-red rounded-lg flex items-center justify-center text-white"><RotateCcw size={16} /></div>
                        <h2 className="text-base font-bold text-white uppercase tracking-wider">Return to Supplier</h2>
                    </div>
                    <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors"><X size={18} /></button>
                </div>

                <div className="flex-1 overflow-y-auto p-4 scrollbar-hide text-left">
                    {error && <div className="mb-6 p-4 bg-red-50 border border-red-200 text-red-700 text-sm rounded-xl flex items-center gap-2"><AlertTriangle size={16} /> {error}</div>}
                    <form id="return-form" onSubmit={handleSubmit} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 p-4 bg-subtle rounded-xl border border-border-default items-end shadow-inner">
                            <div className="space-y-2">
                                <label className="block text-[10px] font-black uppercase text-text-secondary tracking-widest">Invoice #</label>
                                <div className="flex gap-2">
                                    <input type="text" value={invoiceNumber} onChange={e => setInvoiceNumber(e.target.value)} className="w-full bg-bg-surface border border-border-default rounded-xl px-4 py-2.5 text-xs font-bold text-text-primary font-data focus:ring-2 focus:ring-brand-red/10 focus:border-brand-red/30 outline-none" placeholder="e.g. INV-1234" required />
                                    <button
                                        type="button"
                                        onClick={loadInvoiceItems}
                                        disabled={loading}
                                        className="bg-brand-charcoal text-white px-4 py-2.5 rounded-xl text-[10px] font-black uppercase hover:bg-brand-red transition-all flex items-center gap-2 active:scale-95"
                                    >
                                        Import
                                    </button>
                                </div>
                            </div>
                            <div className="space-y-2">
                                <label className="block text-[10px] font-black uppercase text-text-secondary tracking-widest">Return Date</label>
                                <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-bg-surface border border-border-default rounded-xl px-4 py-2.5 text-xs font-bold text-text-primary font-data focus:ring-2 focus:ring-brand-red/10 focus:border-brand-red/30 outline-none" required />
                            </div>
                            <div className="space-y-2">
                                <label className="block text-[10px] font-black uppercase text-text-secondary tracking-widest">Reason</label>
                                <input type="text" value={reason} onChange={e => setReason(e.target.value)} className="w-full bg-bg-surface border border-border-default rounded-xl px-4 py-2.5 text-xs font-bold text-text-primary focus:ring-2 focus:ring-brand-red/10 focus:border-brand-red/30 outline-none" placeholder="e.g. Defective" required />
                            </div>
                        </div>

                        <div className="space-y-3">
                            <div className="flex justify-between items-center text-left border-b border-border-default pb-3">
                                <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-text-primary flex items-center gap-2">
