import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { purchaseService } from '../services/purchaseService';
import type { Purchase } from '../../../shared/types';

export const usePurchases = () => {
    const queryClient = useQueryClient();

    const purchasesQuery = useQuery({
        queryKey: ['purchases'],
        queryFn: purchaseService.getAll,
    });

    const returnsQuery = useQuery({
        queryKey: ['purchase_returns'],
        queryFn: purchaseService.getReturns,
    });

    const createPurchasesMutation = useMutation({
        mutationFn: (newPurchases: Omit<Purchase, 'id' | 'products'>[]) => purchaseService.create(newPurchases),
        onMutate: async (newPurchases) => {
            await queryClient.cancelQueries({ queryKey: ['purchases'] });
            const previousPurchases = queryClient.getQueryData<Purchase[]>(['purchases']);

            if (previousPurchases) {
                const optimisticPurchase: Purchase = {
                    id: crypto.randomUUID(),
                    invoice_number: newPurchases[0]?.invoice_number || 'PENDING',
                    created_at: new Date().toISOString(),
                    total_amount: newPurchases.reduce((sum, item) => sum + (item.total_price || 0), 0),
                    status: 'received',
                    items: newPurchases.map(item => ({
                        id: crypto.randomUUID(),
                        product_id: item.product_id,
                        quantity: item.quantity,
                        unit_price: item.unit_price,
                        total_price: item.total_price
                    })) as any
                } as any;

                queryClient.setQueryData<Purchase[]>(['purchases'], [optimisticPurchase, ...previousPurchases]);
            }

            return { previousPurchases };
        },
        onError: (_err, _newPurchases, context) => {
            if (context?.previousPurchases) {
                queryClient.setQueryData(['purchases'], context.previousPurchases);
            }
        },
        onSettled: () => {
            queryClient.invalidateQueries({ queryKey: ['purchases'] });
            queryClient.invalidateQueries({ queryKey: ['products'] });
        },
    });

    const updatePurchasesMutation = useMutation({
        mutationFn: ({ invoiceNumber, purchase }: { invoiceNumber: string; purchase: Partial<Omit<Purchase, 'id' | 'invoice_number' | 'products'>> }) =>
            purchaseService.updateByInvoice(invoiceNumber, purchase),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['purchases'] });
        },
    });

    const deletePurchasesMutation = useMutation({
        mutationFn: (invoiceNumber: string) => purchaseService.deleteByInvoice(invoiceNumber),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['purchases'] });
            queryClient.invalidateQueries({ queryKey: ['products'] });
        },
    });

    return {
        purchases: purchasesQuery.data ?? [],
        returns: returnsQuery.data ?? [],
        isLoading: purchasesQuery.isLoading || returnsQuery.isLoading,
        error: purchasesQuery.error || returnsQuery.error,
        createPurchases: createPurchasesMutation.mutateAsync,
        updatePurchases: updatePurchasesMutation.mutateAsync,
        deletePurchases: deletePurchasesMutation.mutateAsync,
        isAdding: createPurchasesMutation.isPending,
        isUpdating: updatePurchasesMutation.isPending,
        isDeleting: deletePurchasesMutation.isPending,
    };
};

import { useState, useEffect } from 'react';
import { format, addMonths, subMonths, startOfMonth, endOfMonth, startOfWeek, endOfWeek, isSameMonth, isSameDay, addDays } from 'date-fns';
import { ChevronLeft, ChevronRight, Calendar as CalendarIcon } from 'lucide-react';

interface CalendarProps {
    selectedDate: Date;
    onDateSelect: (date: Date) => void;
    activeDates?: string[]; // Array of 'yyyy-MM-dd' strings
    rangeStart?: Date | null;
    rangeEnd?: Date | null;
}

export default function Calendar({ selectedDate, onDateSelect, activeDates = [], rangeStart, rangeEnd }: CalendarProps) {
    const [currentMonth, setCurrentMonth] = useState(() => {
        const d = new Date(selectedDate);
        return isNaN(d.getTime()) ? new Date() : d;
    });

    // Sync currentMonth when selectedDate changes (e.g. when modal opens with new date)
    // eslint-disable-next-line react-hooks/exhaustive-deps
    useEffect(() => {
        const d = new Date(selectedDate);
        if (!isNaN(d.getTime())) {
            setCurrentMonth(startOfMonth(d));
        }
    }, [selectedDate]);

    const nextMonth = () => setCurrentMonth(addMonths(currentMonth, 1));
    const prevMonth = () => setCurrentMonth(subMonths(currentMonth, 1));

    const renderHeader = () => {
        return (
            <div className="flex items-center justify-between px-4 py-3 border-b border-border-default">
                <div className="flex items-center gap-2">
                    <CalendarIcon size={16} className="text-brand-red" />
                    <span className="text-sm font-black text-text-primary uppercase tracking-wider">
                        {format(currentMonth, 'MMMM yyyy')}
                    </span>
                </div>
                <div className="flex gap-1">
                    <button
                        onClick={prevMonth}
                        className="p-1.5 hover:bg-subtle rounded-lg text-text-muted hover:text-text-primary transition-colors"
                    >
                        <ChevronLeft size={18} />
                    </button>
                    <button
                        onClick={nextMonth}
                        className="p-1.5 hover:bg-subtle rounded-lg text-text-muted hover:text-text-primary transition-colors"
                    >
                        <ChevronRight size={18} />
                    </button>
                </div>
            </div>
        );
    };

    const renderDays = () => {
        const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
        return (
            <div className="grid grid-cols-7 border-b border-border-default/50">
                {days.map((day) => (
                    <div key={day} className="py-2 text-[10px] font-black text-text-muted text-center uppercase tracking-widest">
                        {day}
                    </div>
                ))}
            </div>
        );
    };

    const renderCells = () => {
        const monthStart = startOfMonth(currentMonth);
        const monthEnd = endOfMonth(monthStart);
        const startDate = startOfWeek(monthStart);
        const endDate = endOfWeek(monthEnd);

        const rows = [];
        let days = [];
        let day = startDate;
        let formattedDate = "";

        while (day <= endDate) {
            for (let i = 0; i < 7; i++) {
                const isCurrentMonth = isSameMonth(day, monthStart);
                const dayKey = format(day, 'yyyy-MM-dd');

                if (!isCurrentMonth) {
                    days.push(<div key={`empty-${dayKey}`} className="border-r border-b border-border-default/50 last:border-r-0"></div>);
                } else {
                    formattedDate = format(day, 'd');
                    const cloneDay = day;
                    const isSelected = isSameDay(day, selectedDate);
                    const hasActivity = activeDates.includes(dayKey);

                    // Range logic
                    const isInRange = rangeStart && rangeEnd && day >= rangeStart && day <= rangeEnd;
                    const isRangeStart = rangeStart && isSameDay(day, rangeStart);
                    const isRangeEnd = rangeEnd && isSameDay(day, rangeEnd);

                    days.push(
                        <div
                            key={dayKey}
                            className={`relative py-3 flex flex-col items-center cursor-pointer transition-all hover:bg-subtle border-r border-b border-border-default/50 last:border-r-0 text-text-secondary
                                ${isSelected || isRangeStart || isRangeEnd ? 'bg-brand-red !text-text-inverse font-black rounded-lg shadow-sm z-10' : ''}
                                ${isInRange && !isRangeStart && !isRangeEnd ? 'bg-danger-subtle !text-brand-red font-bold' : ''}
                            `}
                            onClick={() => onDateSelect(cloneDay)}
                        >
                            <span className="text-xs font-bold z-10">{formattedDate}</span>
                            {hasActivity && <div className={`absolute bottom-1 w-1.5 h-1.5 rounded-full shadow-sm animate-pulse ${isSelected || isRangeStart || isRangeEnd ? 'bg-text-inverse shadow-white/20' : 'bg-brand-red shadow-red/20'}`}></div>}
                        </div>
                    );
                }
                day = addDays(day, 1);
            }

            // Only push the row if it contains at least one day from the current month
            rows.push(
                <div className="grid grid-cols-7" key={day.toString()}>
                    {days}
                </div>
            );
            days = [];
        }
        return <div className="bg-surface">{rows}</div>;
    };

    return (
        <div className="bg-surface rounded-3xl border border-border-default shadow-sm overflow-hidden w-full max-w-[320px]">
            {renderHeader()}
            {renderDays()}
            {renderCells()}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { supabase } from '../../../shared/lib/supabase';
import { format } from 'date-fns';
import { X, FileText, Download, AlertTriangle, Loader2 } from 'lucide-react';
import Calendar from './Calendar';
import { exportToCSV } from '../../../shared/lib/exportUtils';

interface ReportRow {
    Section?: string;
    Detail?: string;
    Amount?: string | number;
    Info?: string;
    [key: string]: string | number | undefined;
}

interface ReportModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export default function ReportModal({ isOpen, onClose }: ReportModalProps) {
    const [selectedDate, setSelectedDate] = useState<Date>(new Date());
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (isOpen) {
            document.body.classList.add('modal-open');
        } else {
            document.body.classList.remove('modal-open');
        }
        return () => {
            document.body.classList.remove('modal-open');
        };
    }, [isOpen]);

    const generateReport = async () => {
        setLoading(true);
        setError(null);

        const dateStr = format(selectedDate, 'yyyy-MM-dd');

        try {
            // Fetch Sales
            const { data: sales, error: salesError } = await supabase
                .from('sales')
                .select('invoice_number, total_price, quantity, date, products(name)')
                .gte('date', dateStr)
                .lte('date', dateStr);

            if (salesError) throw salesError;

            // Fetch Expenses
            const { data: expenses, error: expensesError } = await supabase
                .from('expenses')
                .select('category, amount, description, date')
                .gte('date', dateStr)
                .lte('date', dateStr);

            if (expensesError) throw expensesError;

            // Fetch Purchases
            const { data: purchases, error: purchasesError } = await supabase
                .from('purchases')
                .select('total_price, quantity, date, products(name)')
                .gte('date', dateStr)
                .lte('date', dateStr);

            if (purchasesError) throw purchasesError;

            const reportData: ReportRow[] = [];
            let totalSales = 0;
            let totalExpenses = 0;
            let totalPurchases = 0;

            // Summary Section
            reportData.push({ Section: 'DAILY SUMMARY', Detail: format(selectedDate, 'MMMM dd, yyyy') });
            reportData.push({});

            // Sales Section
            reportData.push({ Section: 'SALES' });
            sales?.forEach(s => {
                totalSales += s.total_price;
                reportData.push({
                    Detail: (s.products as any)?.name || 'Unknown',
                    Amount: s.total_price,
                    Info: `Inv: ${s.invoice_number}, Qty: ${s.quantity}`
                });
            });
            reportData.push({ Detail: 'TOTAL SALES', Amount: totalSales });
            reportData.push({});

            // Expenses Section
            reportData.push({ Section: 'EXPENSES' });
            expenses?.forEach(e => {
                totalExpenses += e.amount;
                reportData.push({
                    Detail: e.category,
                    Amount: e.amount,
                    Info: e.description || ''
                });
            });
            reportData.push({ Detail: 'TOTAL EXPENSES', Amount: totalExpenses });
            reportData.push({});

            // Purchases Section
            reportData.push({ Section: 'PURCHASES' });
            purchases?.forEach(p => {
                totalPurchases += p.total_price;
                reportData.push({
                    Detail: (p.products as any)?.name || 'Unknown',
                    Amount: p.total_price,
                    Info: `Qty: ${p.quantity}`
                });
            });
            reportData.push({ Detail: 'TOTAL PURCHASES', Amount: totalPurchases });
            reportData.push({});

            // Net Section
            const netCash = totalSales - totalExpenses;
            reportData.push({ Section: 'NET POSITION' });
            reportData.push({ Detail: 'NET CASH (Sales - Expenses)', Amount: netCash });
            reportData.push({ Detail: 'NET FLOW (Sales - Expenses - Purchases)', Amount: netCash - totalPurchases });

            exportToCSV(reportData, `Daily_Report_${dateStr}`);
        } catch (err) {
            console.error('Error generating report:', err);
            setError(err instanceof Error ? err.message : 'Error generating report');
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/70 backdrop-blur-md px-4">
            <div className="w-full max-w-lg rounded-[32px] bg-white shadow-2xl border border-slate-100 flex flex-col animate-slide-up overflow-hidden">
                <div className="flex items-center justify-between px-8 py-6 bg-brand-charcoal">
                    <div className="flex items-center gap-3 text-white">
                        <div className="w-10 h-10 bg-brand-red rounded-xl flex items-center justify-center shadow-lg shadow-brand-red/20">
                            <FileText size={20} />
                        </div>
                        <div>
                            <h2 className="text-lg font-black uppercase tracking-widest">Daily Report</h2>
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Generate summary CSV</p>
                        </div>
                    </div>
                    <button
                        onClick={onClose}
                        className="w-10 h-10 flex items-center justify-center rounded-xl bg-white/5 text-slate-400 hover:text-white hover:bg-white/10 transition-all"
                    >
                        <X size={20} />
                    </button>
                </div>

                <div className="p-8 space-y-8">
                    {error && (
                        <div className="p-4 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-3 text-red-600 text-xs font-bold animate-shake">
                            <AlertTriangle size={16} />
                            {error}
                        </div>
                    )}

                    <div className="space-y-4">
                        <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Select Report Date</label>
                        <div className="p-2 bg-slate-50 rounded-3xl border border-slate-100">
                            <Calendar
                                selectedDate={selectedDate}
                                onDateSelect={setSelectedDate}
                            />
                        </div>
                    </div>

                    <div className="p-6 bg-brand-charcoal/5 rounded-3xl border border-brand-charcoal/5 space-y-4">
                        <div className="flex items-center justify-between">
                            <p className="text-[10px] font-black uppercase tracking-widest text-slate-500">Report Focus</p>
                            <span className="px-3 py-1 bg-brand-red/10 text-brand-red text-[9px] font-black rounded-full uppercase">All Active Modules</span>
                        </div>
                        <p className="text-xs text-slate-600 leading-relaxed font-medium">
                            Generating a report will compile all <span className="font-bold text-brand-charcoal">Sales</span>,
                            <span className="font-bold text-brand-charcoal ml-1">Expenses</span>, and
                            <span className="font-bold text-brand-charcoal ml-1">Purchases</span> for the selected date into a detailed CSV document.
                        </p>
                    </div>
                </div>

                <div className="p-8 bg-slate-50 border-t border-slate-100 flex gap-4">
                    <button
                        onClick={onClose}
                        className="flex-1 py-4 text-slate-500 font-bold text-xs uppercase tracking-widest hover:text-brand-charcoal transition-colors bg-white rounded-2xl border border-slate-200"
                    >
                        Cancel
                    </button>
                    <button
                        onClick={generateReport}
                        disabled={loading}
                        className="flex-[2] py-4 bg-brand-charcoal text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-brand-charcoal/20 hover:bg-brand-red transition-all active:scale-[0.98] disabled:opacity-50 flex items-center justify-center gap-2"
                    >
                        {loading ? (
                            <Loader2 size={16} className="animate-spin" />
                        ) : (
                            <Download size={16} />
                        )}
                        {loading ? 'Compiling...' : 'Generate Report'}
                    </button>
                </div>
            </div>
        </div>,
        document.body
    );
}

