            product_name: '',
            quantity: 1,
            unit_price: 0,
            total_price: 0,
            searchQuery: '',
            isSearchOpen: false,
            highlightedIndex: 0,
            payment_mode: 'cash',
            is_os: true,
            invoice_type: 'A'
        };
    }

    useEffect(() => {
        const fetchData = async () => {
            setLoading(true);
            const today = new Date().toISOString().split('T')[0];
            let prodQuery = supabase.from('products').select('*').order('name');
            let lastSalesQuery = supabase.from('sales').select('invoice_number').eq('is_os', true).gte('date', today).order('date', { ascending: false }).limit(1);

            if (activeBranchId) {
                prodQuery = prodQuery.eq('branch_id', activeBranchId);
                lastSalesQuery = lastSalesQuery.eq('branch_id', activeBranchId);
            }

            const [prodRes, lastSalesRes] = await Promise.all([
                prodQuery,
                lastSalesQuery
            ]);

            if (prodRes.data) setProducts(prodRes.data);

            if (lastSalesRes.data && lastSalesRes.data.length > 0) {
                const lastNum = lastSalesRes.data[0].invoice_number;
                const is_os = lastNum.startsWith('OS-');
                setRows(prev => prev.map((row, i) => i === 0 ? { ...row, invoice_number: incrementInvoice(lastNum), is_os } : row));
            } else {
                setRows(prev => prev.map((row, i) => i === 0 ? { ...row, invoice_number: 'OS-000001', is_os: true } : row));
            }
            setLoading(false);
            // Focus first search input when data is loaded
            setTimeout(() => {
                searchInputRefs.current[0]?.focus();
            }, 100);
        };
        fetchData();
    }, []);

    const incrementInvoice = (current: string) => {
        const num = parseInt(current.replace(/\D/g, '')) || 0;
        const nextNum = (num + 1).toString().padStart(6, '0');
        return current.startsWith('OS-') ? `OS-${nextNum}` : nextNum;
    };

    const handleAddRow = () => {
        const lastRow = rows[rows.length - 1];
        const newRow = createEmptyRow();
        newRow.invoice_number = incrementInvoice(lastRow.invoice_number);
        newRow.is_os = lastRow.is_os;
        newRow.invoice_type = lastRow.invoice_type;
        setRows([...rows, newRow]);
    };

    const handleRemoveRow = (index: number) => {
        if (rows.length === 1) return;
        setRows(rows.filter((_, i) => i !== index));
    };

    const updateRow = (index: number, updates: Partial<ExpressRow>) => {
        const newRows = [...rows];
        newRows[index] = { ...newRows[index], ...updates };

        if ('quantity' in updates || 'unit_price' in updates) {
            newRows[index].total_price = newRows[index].quantity * (newRows[index].unit_price || 0);
        }

        setRows(newRows);
    };

    const selectProduct = (index: number, product: Product) => {
        const currentRow = rows[index];
        const existingIndex = rows.findIndex((r, i) =>
            i !== index &&
            r.invoice_number === currentRow.invoice_number &&
            r.product_id === product.id
        );

        if (existingIndex !== -1) {
            // Merge duplicate
            const newRows = [...rows];
            newRows[existingIndex].quantity += currentRow.quantity;
            newRows[existingIndex].total_price = newRows[existingIndex].quantity * newRows[existingIndex].unit_price;

            // Remove current row if it was just used for selection
            if (rows.length > 1) {
                newRows.splice(index, 1);
            } else {
                newRows[index] = createEmptyRow();
                newRows[index].invoice_number = currentRow.invoice_number;
            }

            setRows(newRows);

            // Focus the existing quantity
            const focusIndex = existingIndex < index ? existingIndex : existingIndex - 1;
            setTimeout(() => {
                qtyInputRefs.current[focusIndex]?.focus();
                qtyInputRefs.current[focusIndex]?.select();
            }, 10);
            return;
        }

        if (product.stock_available <= 0) {
            toast.error(`"${product.name}" is out of stock`, {
                description: "Cannot add items with zero stock.",
                className: "font-black"
            });
            return;
        }

        updateRow(index, {
            product_id: product.id,
            product_name: product.name,
            unit_price: product.selling_price || 0,
            total_price: (product.selling_price || 0) * rows[index].quantity,
            searchQuery: product.name,
            isSearchOpen: false
        });

        setTimeout(() => {
            qtyInputRefs.current[index]?.focus();
        }, 10);
    };

    const handleSaveAll = async () => {
        if (saving) return;
        const validRows = rows.filter(r => r.product_id && r.invoice_number);
        if (validRows.length === 0) return;

        setSaving(true);
        try {
            const packageSales = validRows.map(r => ({
                invoice_number: r.invoice_number,
                customer_name: r.customer_name,
                customer_id: r.customer_id || null,
                product_id: r.product_id,
                quantity: r.quantity,
                unit_price: r.unit_price,
                total_price: r.total_price,
                payment_mode: r.payment_mode,
                is_os: r.is_os,
                fulfillment_status: 'pickup',
                date: new Date().toISOString(),
                or_number: r.invoice_number,
                invoice_type: r.is_os ? null : r.invoice_type,
                net_amount: r.total_price,
                branch_id: activeBranchId
            }));

            const { error } = await supabase.from('sales').insert(packageSales);
            if (error) throw error;

            // Audit Log - Log distinct invoices
            const distinctInvoices = Array.from(new Set(packageSales.map(s => s.invoice_number)));
            for (const inv of distinctInvoices) {
                await logAction({
                    action: 'CREATE_SALE',
                    table_name: 'sales',
                    record_id: inv,
                    new_data: packageSales.filter(s => s.invoice_number === inv)
                });
            }

            toast.success("Transactions saved successfully", {
                description: `${packageSales.length} entries have been recorded.`,
                className: "font-black"
            });

            // Reset Rows instead of navigating
            const firstInvoice = packageSales[0].invoice_number;
            const nextInvoice = incrementInvoice(firstInvoice);
            setRows([{ ...createEmptyRow(), invoice_number: nextInvoice }]);
            
            setTimeout(() => {
                searchInputRefs.current[0]?.focus();
            }, 100);

        } catch (err) {
            console.error('Save failed:', err);
            toast.error('Error saving transactions', {
                description: err instanceof Error ? err.message : 'Unknown error',
                className: "font-black"
            });
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="space-y-6 animate-fade-in pb-10">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <button onClick={() => navigate(-1)} className="p-2 bg-white border border-slate-200 rounded-xl text-slate-400 hover:text-brand-red transition-all">
                        <ArrowLeft size={18} />
                    </button>
                    <div>
                        <h1 className="text-2xl font-black text-brand-charcoal tracking-tight flex items-center gap-2">
                            <ShoppingCart className="text-brand-red" size={24} /> Express Sales Entry
                        </h1>
                        <p className="text-xs text-slate-500 font-medium">Bulk encode multiple receipts in a single view</p>
                    </div>
                </div>
                <div className="flex items-center gap-3">
                    <button
                        ref={saveButtonRef}
                        onClick={handleSaveAll}
                        disabled={saving || loading}
                        className="flex items-center gap-2 bg-brand-red text-white px-6 py-3 rounded-2xl font-black text-sm hover:bg-brand-red-dark transition-all shadow-red disabled:opacity-50 ring-offset-2 focus:ring-2 focus:ring-brand-red"
                        onKeyDown={(e) => {
                            if (e.key === 'Escape') {
                                searchInputRefs.current[rows.length - 1]?.focus();
                            }
                        }}
                    >
                        {saving ? 'SAVING...' : <><Save size={18} /> SAVE ALL ENTRIES</>}
                    </button>
                </div>
            </div>

            <div className="bg-white rounded-[32px] border border-slate-100 shadow-xl overflow-hidden min-h-[500px]">
                <table className="w-full text-left border-collapse">
                    <thead>
                        <tr className="bg-slate-50 border-b border-slate-100">
                            <th className="px-6 py-4 text-[10px] font-black text-brand-charcoal uppercase tracking-widest w-48 text-center">Invoice #</th>
                            <th className="px-6 py-4 text-[10px] font-black text-brand-charcoal uppercase tracking-widest">Product Search</th>
                            <th className="px-6 py-4 text-[10px] font-black text-brand-charcoal uppercase tracking-widest w-32 text-center">Qty</th>
                            <th className="px-6 py-4 text-[10px] font-black text-brand-charcoal uppercase tracking-widest w-40 text-right">Unit Price</th>
                            <th className="px-6 py-4 text-[10px] font-black text-brand-charcoal uppercase tracking-widest w-44 text-right">Total</th>
                            <th className="px-6 py-4 text-[10px] font-black text-slate-600 uppercase tracking-widest w-16"></th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {rows.map((row, index) => (
                            <tr key={row.id} className="hover:bg-slate-50/50 transition-colors group">
                                <td className="px-6 py-3">
                                    <div className="flex flex-col gap-1.5 items-center">
                                        <div className="flex items-center gap-1.5">
                                            <input
                                                type="text"
                                                className="w-24 bg-slate-50 border border-slate-200 rounded-lg px-2 py-1 text-xs font-data font-bold focus:border-brand-red outline-none text-center"
                                                value={row.invoice_number}
                                                ref={el => { invoiceInputRefs.current[index] = el; }}
                                                onChange={(e) => updateRow(index, { invoice_number: e.target.value })}
                                            />
                                            <button
                                                type="button"
                                                onClick={() => {
                                                    const newIsOs = !row.is_os;
                                                    const newInv = newIsOs 
                                                        ? (row.invoice_number.startsWith('OS-') ? row.invoice_number : `OS-${row.invoice_number}`)
                                                        : row.invoice_number.replace('OS-', '');
                                                    updateRow(index, { is_os: newIsOs, invoice_number: newInv });
                                                }}
                                                className={`px-1.5 py-0.5 rounded text-[8px] font-black transition-all ${row.is_os ? 'bg-brand-red text-white' : 'bg-slate-100 text-slate-400'}`}
                                            >
                                                OS
                                            </button>
                                        </div>
                                        <div className="flex bg-slate-100 border border-slate-200 rounded-md p-0.5 scale-90">
                                            <button
                                                type="button"
                                                onClick={() => updateRow(index, { invoice_type: 'A' })}
                                                className={`px-2 py-0.5 rounded text-[8px] font-black transition-all ${row.invoice_type === 'A' ? 'bg-white text-brand-charcoal shadow-sm' : 'text-slate-400'}`}
                                            >
                                                A
                                            </button>
                                            <button
                                                type="button"
                                                onClick={() => updateRow(index, { invoice_type: 'B' })}
                                                className={`px-2 py-0.5 rounded text-[8px] font-black transition-all ${row.invoice_type === 'B' ? 'bg-white text-brand-charcoal shadow-sm' : 'text-slate-400'}`}
                                            >
                                                B
                                            </button>
                                        </div>
                                    </div>
                                </td>
                                <td className="px-6 py-3 relative">
                                    <div className="relative">
                                        <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" />
                                        <input
                                            type="text"
                                            placeholder="Type product name..."
                                            className="w-full pl-9 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-xs font-medium focus:border-brand-red outline-none shadow-inner"
                                            value={row.searchQuery}
                                            ref={el => { searchInputRefs.current[index] = el; }}
                                            onFocus={() => updateRow(index, { isSearchOpen: true })}
                                            onChange={(e) => updateRow(index, { searchQuery: e.target.value, isSearchOpen: true })}
                                            onKeyDown={(e) => {
                                                const query = row.searchQuery.toLowerCase();
                                                const filtered = products
                                                    .filter(p => isSmartMatch(p.name, query))
                                                    .slice(0, 10);

                                                if (e.key === 'ArrowDown') {
                                                    e.preventDefault();
                                                    if (row.isSearchOpen) {
                                                        updateRow(index, { highlightedIndex: Math.min(row.highlightedIndex + 1, filtered.length - 1) });
                                                    } else {
                                                        updateRow(index, { isSearchOpen: true });
                                                    }
                                                } else if (e.key === 'ArrowUp') {
                                                    e.preventDefault();
                                                    updateRow(index, { highlightedIndex: Math.max(row.highlightedIndex - 1, 0) });
                                                } else if (e.key === 'Enter') {
                                                    e.preventDefault();
                                                    if (row.isSearchOpen && filtered[row.highlightedIndex]) {
                                                        selectProduct(index, filtered[row.highlightedIndex]);
                                                    } else if (!row.searchQuery && rows.some(r => r.product_id)) {
                                                        // Move focus to save button on empty search Enter
                                                        saveButtonRef.current?.focus();
                                                    }
                                                } else if (e.key === 'Escape') {
                                                    if (row.isSearchOpen) {
                                                        updateRow(index, { isSearchOpen: false });
                                                    } else {
                                                        updateRow(index, { searchQuery: '' });
                                                    }
                                                }
                                            }}
                                        />
                                        {row.isSearchOpen && (
                                            <div className="absolute z-50 left-0 right-0 top-full mt-1 bg-white border border-slate-200 rounded-lg shadow-2xl overflow-hidden max-h-60 overflow-y-auto">
                                                {products.filter(p => isSmartMatch(p.name, row.searchQuery)).slice(0, 10).map((p, pIdx) => (
                                                    <div
                                                        key={p.id}
                                                        className={`px-4 py-2 text-[11px] cursor-pointer flex justify-between items-center ${row.highlightedIndex === pIdx ? 'bg-brand-red/5 text-brand-red' : 'hover:bg-slate-50'}`}
                                                        onClick={() => selectProduct(index, p)}
                                                        onMouseEnter={() => updateRow(index, { highlightedIndex: pIdx })}
                                                    >
                                                        <span className="font-bold">{p.name} {p.brand ? `[${p.brand}]` : ''}</span>
                                                        <div className="flex gap-4">
                                                        <span className={`text-slate-400 font-data ${p.stock_available <= 0 ? 'text-brand-red font-bold animate-pulse' : ''}`}>STK: {p.stock_available}</span>
                                                        <span className="font-data font-black">₱{p.selling_price}</span>
                                                        </div>
                                                    </div>
                                                ))}
                                            </div>
                                        )}
                                    </div>
                                </td>
                                <td className="px-6 py-3">
                                    <input
                                        type="number"
                                        min="1"
                                        className="w-full bg-slate-50 border border-slate-200 rounded-lg px-3 py-2 text-xs font-data text-center focus:border-brand-red outline-none"
                                        value={row.quantity}
                                        ref={el => { qtyInputRefs.current[index] = el; }}
                                        onChange={(e) => updateRow(index, { quantity: parseInt(e.target.value) || 0 })}
                                        onKeyDown={(e) => {
                                            if (e.key === 'Enter') {
                                                e.preventDefault();
                                                if (index === rows.length - 1) {
                                                    handleAddRow();
                                                    setTimeout(() => searchInputRefs.current[index + 1]?.focus(), 50);
                                                } else {
                                                    searchInputRefs.current[index + 1]?.focus();
                                                }
                                            } else if (e.key === 'Escape') {
                                                searchInputRefs.current[index]?.focus();
                                                searchInputRefs.current[index]?.select();
                                            }
                                        }}
                                    />
                                </td>
                                <td className="px-6 py-3 text-right">
                                    <span className="text-xs font-data font-bold text-slate-600">₱{row.unit_price.toLocaleString()}</span>
                                </td>
                                <td className="px-6 py-3 text-right">
                                    <span className="text-sm font-data font-black text-brand-charcoal">₱{row.total_price.toLocaleString()}</span>
                                </td>
                                <td className="px-6 py-3 text-right">
                                    <button onClick={() => handleRemoveRow(index)} className="p-2 text-slate-300 hover:text-brand-red transition-colors opacity-0 group-hover:opacity-100">
                                        <Trash2 size={16} />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                <div className="p-6 bg-slate-50/50 border-t border-slate-100 flex justify-between items-center">
                    <button onClick={handleAddRow} className="flex items-center gap-2 text-xs font-black text-brand-red hover:text-brand-red-dark uppercase tracking-widest transition-all">
                        <Plus size={16} /> Add Receipt Line
                    </button>
                    <div className="text-right">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Grand Total ({rows.filter(r => r.product_id).length} Entries)</p>
                        <p className="text-3xl font-black text-brand-charcoal font-data tracking-tight">₱{rows.reduce((sum, r) => sum + r.total_price, 0).toLocaleString()}</p>
                    </div>
                </div>
            </div>
        </div >
    );
}

import { useNavigate, useLocation } from 'react-router-dom';
import { useEffect, useState, useCallback, Fragment } from 'react';
import { supabase } from '../../shared/lib/supabase';
import {
    Search, ChevronDown, Receipt, ShoppingBag, Download, Filter, Trash2, User, Truck, Clock, CheckCircle2, PackageSearch, RotateCcw, Grid, Tag
} from 'lucide-react';
import { format, isSameDay } from 'date-fns';
import SalesModal from './components/SalesModal';
import Calendar from '../../features/reports/components/Calendar';
import { useAuth } from '../../shared/hooks/useAuth';
import { useBranch } from '../../shared/lib/BranchContext';

interface Sale {
    id: string;
    transaction_label?: string;
    product_id: string;
    quantity: number;
    unit_price: number;
    total_price: number;
    date: string;
    invoice_number: string;
    user_id: string;
    vat_amount: number;
    discount_amount: number;
    is_discounted: boolean;
    is_os?: boolean;
    full_name: string;
    customer_name?: string;
    fulfillment_status?: 'pickup' | 'delivered' | 'out';
    payment_mode?: string;
    edited_at?: string;
    delivery_fee?: number;
    invoice_type?: string;
    products: {
        name: string;
        brand?: string;
    };
}

interface SupabaseSale {
    id: string;
    transaction_label?: string;
    product_id: string;
    quantity: number;
    unit_price: number;
    total_price: number;
    date: string;
    invoice_number: string;
    user_id: string;
    vat_amount: number;
    discount_amount: number;
    is_discounted: boolean;
    is_os?: boolean;
    customer_name?: string;
    fulfillment_status?: 'pickup' | 'delivered' | 'out';
    payment_mode?: string;
    edited_at?: string;
    delivery_fee?: number;
    invoice_type?: string;
    products: {
        name: string;
        brand?: string;
    };
}

interface GroupedSale {
    invoice_number: string;
    date: string;
    full_name: string;
    customer_name: string;
    fulfillment_status: 'pickup' | 'delivered' | 'out';
    payment_mode: string;
    items: Sale[];
    is_os: boolean;
    edited_at: string | null;
    total_base: number;
    total_vat: number;
    total_discount: number;
    delivery_fee: number;
    grand_total: number;
    invoice_type: string;
    transaction_label: string | null;
}

interface SalesEditData {
    invoiceNumber: string;
    customerName?: string;
    fulfillmentStatus?: string;
    paymentMode?: string;
    items: {
        product_id: string;
        quantity: number;
        unit_price: number;
        total_price: number;
        name?: string;
        brand?: string;
    }[];
    isVatEnabled: boolean;
    isDiscountEnabled: boolean;
    is_os?: boolean;
    date?: string;
    delivery_fee?: number;
    invoice_type?: string;
}

export default function Sales() {
    const { role } = useAuth();
    const navigate = useNavigate();
    const location = useLocation();
    const [groupedSales, setGroupedSales] = useState<GroupedSale[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editData, setEditData] = useState<SalesEditData | null>(null);
    const [expandedInvoices, setExpandedInvoices] = useState<Set<string>>(new Set());
    const [selectedDate, setSelectedDate] = useState<Date>(new Date());
    const [filterType, setFilterType] = useState<'all' | 'standard' | 'os' | 'discounted' | 'refunded'>('all');
    const [refundedInvoices, setRefundedInvoices] = useState<Set<string>>(new Set());
    const [isFilterOpen, setIsFilterOpen] = useState(false);

    const { activeBranchId } = useBranch();
    const fetchSales = useCallback(async (silent = false) => {
        if (!silent) setLoading(true);

        let salesQuery = supabase.from('sales').select(`*, products(name, brand)`).order('date', { ascending: false });
        let refundsQuery = supabase.from('customer_refunds').select('invoice_number');

        if (activeBranchId) {
            salesQuery = salesQuery.eq('branch_id', activeBranchId);
            refundsQuery = refundsQuery.eq('branch_id', activeBranchId);
        }

        const [salesRes, refundsRes] = await Promise.all([
            salesQuery,
            refundsQuery
        ]);

        if (refundsRes.data) {
            setRefundedInvoices(new Set(refundsRes.data.map(r => r.invoice_number).filter(Boolean)));
        }

        const { data, error } = salesRes;

        if (error) {
            console.error('Error fetching sales:', error);
        } else {
            const groups: { [key: string]: GroupedSale } = {};
            (data as unknown as SupabaseSale[]).forEach(sale => {
                const key = sale.invoice_number;
                if (!key) return;
                if (!groups[key]) {
                    groups[key] = {
                        invoice_number: key,
                        date: sale.date,
                        full_name: 'Staff',
                        customer_name: sale.customer_name || 'Walk-in Customer',
                        fulfillment_status: sale.fulfillment_status || 'pickup',
                        payment_mode: sale.payment_mode || 'cash',
                        is_os: sale.is_os || false,
                        edited_at: sale.edited_at || null,
                        items: [],
                        total_base: 0,
                        total_vat: 0,
                        total_discount: 0,
                        delivery_fee: sale.delivery_fee || 0,
                        grand_total: 0,
                        invoice_type: (sale as any).invoice_type || 'A',
                        transaction_label: (sale as any).transaction_label || null
                    };
                }
                const group = groups[key];
                const s = { ...sale, full_name: 'Staff' } as Sale;
                group.items.push(s);
                group.total_base += Number(s.total_price);
                group.total_vat += Number(s.vat_amount || 0);
                group.total_discount += Number(s.discount_amount || 0);
            });

            Object.values(groups).forEach(group => {
                group.grand_total = group.total_base - group.total_discount + Number(group.delivery_fee);
            });

            setGroupedSales(Object.values(groups).sort((a, b) =>
                new Date(b.date).getTime() - new Date(a.date).getTime()
            ));
        }
        setLoading(false);
    }, [activeBranchId]);

    useEffect(() => {
        let mounted = true;
        const load = async () => { if (mounted) await fetchSales(); };
        load();
        const channel = supabase.channel('sales_realtime').on('postgres_changes', { event: '*', schema: 'public', table: 'sales' }, () => { if (mounted) fetchSales(true); }).subscribe();
        return () => { mounted = false; supabase.removeChannel(channel); };
    }, [fetchSales]);

    // Listen for global shortcuts and navigation state
    useEffect(() => {
        const handleOpenModal = () => { setEditData(null); setIsModalOpen(true); };
        window.addEventListener('open-sales-modal', handleOpenModal);
        
        if ((location.state as any)?.openModal) {
            handleOpenModal();
            // Clear state immediately to prevent re-opening on refresh
            navigate(location.pathname, { replace: true, state: {} });
        }

        return () => window.removeEventListener('open-sales-modal', handleOpenModal);
    }, [location.state, navigate, location.pathname]);

    const toggleExpand = (invoiceNumber: string) => {
        setExpandedInvoices(prev => {
            const next = new Set(prev);
            if (next.has(invoiceNumber)) next.delete(invoiceNumber);
            else next.add(invoiceNumber);
            return next;
        });
    };

    const filteredSales = groupedSales.filter(group => {
        const search = searchTerm.toLowerCase();
        const matchesSearch = (
            (group.invoice_number?.toLowerCase().includes(search) ?? false) ||
            (group.customer_name?.toLowerCase().includes(search) ?? false) ||
            group.items.some(item =>
                (item.products?.name?.toLowerCase().includes(search) ?? false)
            )
        );
        return matchesSearch && isSameDay(new Date(group.date), selectedDate) && (
            filterType === 'all' ||
            (filterType === 'standard' && !group.is_os) ||
            (filterType === 'os' && group.is_os) ||
            (filterType === 'discounted' && group.total_discount > 0) ||
            (filterType === 'refunded' && refundedInvoices.has(group.invoice_number))
        );
    });

    const activeDates = Array.from(new Set(groupedSales.map(s => format(new Date(s.date), 'yyyy-MM-dd'))));

    const handleSuccess = () => { setEditData(null); fetchSales(); };

    const handleEditInvoice = (group: GroupedSale) => {
        setEditData({
            invoiceNumber: group.invoice_number,
            customerName: group.customer_name,
            fulfillmentStatus: group.fulfillment_status,
            paymentMode: group.payment_mode,
            items: group.items.map(item => ({
                product_id: item.product_id,
                quantity: item.quantity,
                unit_price: item.unit_price,
                total_price: item.total_price,
                name: item.products.name,
                brand: item.products.brand
            })),
            isVatEnabled: group.total_vat > 0,
            isDiscountEnabled: group.total_discount > 0,
            is_os: group.is_os,
            date: group.date,
            delivery_fee: group.delivery_fee,
            invoice_type: group.invoice_type
        });
        setIsModalOpen(true);
    };

    const handleDeleteInvoice = async (invoiceNumber: string) => {
        if (!window.confirm(`Are you sure you want to delete invoice ${invoiceNumber}? This will restore stock to inventory.`)) return;

        setLoading(true);
        try {
            // 1. Fetch the sale items BEFORE deleting so we know what stock to restore
            const { data: saleItems, error: fetchError } = await supabase
                .from('sales')
                .select('product_id, quantity')
                .eq('invoice_number', invoiceNumber);

            if (fetchError) throw fetchError;

            // 2. Restore stock for each product
            if (saleItems && saleItems.length > 0) {
                for (const item of saleItems) {
                    // Get current stock
                    const { data: product, error: prodError } = await supabase
                        .from('products')
                        .select('stock_available')
                        .eq('id', item.product_id)
                        .single();

                    if (prodError) {
                        console.error(`Error fetching product ${item.product_id}:`, prodError);
                        continue; // Skip this product but continue with others
                    }

                    // Increment stock by the quantity that was sold
                    const newStock = (product?.stock_available || 0) + item.quantity;
                    const { error: updateError } = await supabase
                        .from('products')
                        .update({ stock_available: newStock })
                        .eq('id', item.product_id);

                    if (updateError) {
                        console.error(`Error restoring stock for product ${item.product_id}:`, updateError);
                    }
                }
            }

            // 3. Delete the sale records
            const { error: deleteError } = await supabase
                .from('sales')
                .delete()
                .eq('invoice_number', invoiceNumber);

            if (deleteError) throw deleteError;

            fetchSales();
        } catch (err) {
            console.error('Error deleting sale:', err);
            alert('Error: ' + (err instanceof Error ? err.message : 'Unknown error'));
        } finally {
            setLoading(false);
        }
    };

    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'delivered': return <CheckCircle2 className="text-emerald-500" size={14} />;
            case 'out': return <Truck className="text-amber-500" size={14} />;
            default: return <Clock className="text-slate-400" size={14} />;
        }
    };

    const getStatusText = (status: string) => {
        switch (status) {
            case 'delivered': return 'Delivered';
            case 'out': return 'In Transit';
            default: return 'Store Pickup';
        }
    };

    return (
        <div className="space-y-6 animate-fade-in pb-10">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div>
                    <h1 className="text-3xl font-black text-text-primary tracking-tight flex items-center gap-3">
                        <div className="w-12 h-12 bg-brand-red rounded-2xl flex items-center justify-center shadow-red"><Receipt className="text-white" size={24} /></div>
                        Sales Dashboard
                    </h1>
                    <p className="text-text-secondary mt-1 font-medium">Customer Orders, List of Orders, Invoice & Inventory Sync</p>
                </div>
                <div className="flex items-center gap-3">
                    <button
                        onClick={() => navigate('/express-sales')}
                        className="flex items-center gap-2 bg-surface border border-border-default text-text-secondary px-5 py-3 rounded-2xl font-bold text-sm hover:bg-subtle transition-all shadow-sm"
                    >
                        <Grid size={18} /> EXPRESS ENCODING
                    </button>
                    <button className="flex items-center gap-2 bg-surface border border-border-default text-text-secondary px-5 py-3 rounded-2xl font-bold text-sm hover:bg-subtle transition-all shadow-sm"><Download size={18} /> Export</button>
                    <button onClick={() => { setEditData(null); setIsModalOpen(true); }} className="flex items-center gap-2 bg-brand-red text-white px-6 py-3 rounded-2xl font-black text-sm hover:bg-brand-red-dark transition-all shadow-red active:scale-95"><ShoppingBag size={18} /> CREATE SALE</button>
                </div>
            </div>

            <div className="flex flex-col sm:flex-row gap-4">
                <div className="relative group flex-1">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-text-muted group-focus-within:text-brand-red transition-colors" size={18} />
                    <input type="text" placeholder="Search by Invoice, Customer or Item..." className="w-full pl-12 pr-4 py-3 bg-surface border border-border-default rounded-2xl text-sm focus:ring-2 focus:border-brand-red outline-none transition-all shadow-sm placeholder:text-text-muted text-text-primary" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                </div>
                <div className="relative">
                    <button
                        onClick={() => setIsFilterOpen(!isFilterOpen)}
                        className={`px-5 py-3 border rounded-2xl transition-all shadow-sm flex items-center gap-2 font-bold text-sm ${filterType !== 'all' ? 'bg-brand-red text-white border-brand-red' : 'bg-surface border-border-default text-text-secondary hover:bg-subtle'}`}
                    >
                        <Filter size={18} /> {filterType === 'all' ? 'Filters' : filterType.toUpperCase()}
                    </button>
                    {isFilterOpen && (
                        <div className="absolute right-0 mt-2 w-48 bg-surface border border-border-default rounded-2xl shadow-xl z-50 overflow-hidden animate-slide-up">
                            {[
                                { id: 'all', label: 'All Invoices' },
                                { id: 'standard', label: 'Regular Invoices' },
                                { id: 'os', label: 'OS Invoices' },
                                { id: 'discounted', label: 'Discounted Sales' },
                                { id: 'refunded', label: 'Refunded' }
                            ].map(option => (
                                <button
                                    key={option.id}
                                    onClick={() => { setFilterType(option.id as 'all' | 'standard' | 'os' | 'discounted' | 'refunded'); setIsFilterOpen(false); }}
                                    className={`w-full text-left px-4 py-3 text-xs font-bold transition-colors ${filterType === option.id ? 'bg-brand-red text-white' : 'text-text-secondary hover:bg-subtle'}`}
                                >
                                    {option.label}
                                </button>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            <div className="flex flex-col lg:flex-row gap-6">
                <div className="flex-shrink-0">
                    <div className="sticky top-6 space-y-4">
                        <Calendar selectedDate={selectedDate} onDateSelect={setSelectedDate} activeDates={activeDates} />
                        <div className="bg-surface p-6 rounded-3xl border border-border-default shadow-sm overflow-hidden relative">
                            <div className="absolute top-0 right-0 w-24 h-24 bg-brand-red/5 rounded-full -mr-12 -mt-12" />
                            <h3 className="text-[10px] font-black text-text-primary border-b border-border-default pb-3 mb-4 uppercase tracking-[0.2em]">Summary Statistics</h3>
                            <div className="space-y-4">
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-1">Standard Invoices</p>
                                        <p className="text-sm font-black text-text-primary font-data">{filteredSales.filter(s => !s.is_os).length}</p>
                                        <p className="text-[10px] font-bold text-text-secondary font-data">₱{filteredSales.filter(s => !s.is_os).reduce((sum, g) => sum + g.grand_total, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                    </div>
                                    <div>
                                        <p className="text-[8px] font-black text-text-muted uppercase tracking-widest mb-1">OS Invoices</p>
                                        <p className="text-sm font-black text-brand-red font-data">{filteredSales.filter(s => s.is_os).length}</p>
                                        <p className="text-[10px] font-bold text-text-secondary font-data">₱{filteredSales.filter(s => s.is_os).reduce((sum, g) => sum + g.grand_total, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                    </div>
                                </div>
                                <div className="pt-3 border-t border-border-default">
                                    <p className="text-[9px] font-black text-text-primary uppercase tracking-widest mb-1">Total Revenue</p>
                                    <p className="text-xl font-black text-text-primary font-data">₱{filteredSales.reduce((sum, g) => sum + g.grand_total, 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>

                <div className="flex-1 min-w-0">
                    <div className="bg-surface rounded-[32px] border border-border-default shadow-sm overflow-hidden">
                        <div className="overflow-x-auto">
                            <table className="w-full text-left">
                                <thead>
                                    <tr className="bg-subtle/50 border-b border-border-default">
                                        <th className="px-6 py-2.5 text-[11px] font-black text-text-primary uppercase tracking-widest">Sales Details</th>
                                        <th className="px-6 py-2.5 text-[11px] font-black text-text-primary uppercase tracking-widest">Customer</th>
                                        <th className="px-6 py-2.5 text-[11px] font-black text-text-primary uppercase tracking-widest">Status</th>
                                        <th className="px-6 py-2.5 text-[11px] font-black text-text-primary uppercase tracking-widest">Payment</th>
                                        <th className="px-6 py-2.5 text-[11px] font-black text-text-primary uppercase tracking-widest text-right">Amount</th>
                                        <th className="px-6 py-2.5 text-[11px] font-black text-text-muted uppercase tracking-widest w-10"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-subtle">
                                    {loading ? (
                                        [1, 2, 3].map(i => <tr key={i} className="animate-pulse"><td colSpan={5} className="px-6 py-8"><div className="h-4 bg-slate-100 rounded w-full"></div></td></tr>)
                                    ) : filteredSales.length > 0 ? (
                                        filteredSales.map((sale) => (
                                            <Fragment key={sale.invoice_number}>
                                                <tr onClick={() => toggleExpand(sale.invoice_number)} className="group hover:bg-subtle transition-all cursor-pointer">
                                                    <td className="px-6 py-3.5">
                                                        <div className="flex items-center gap-4">
                                                            <div className="w-8 h-8 bg-muted rounded-xl flex items-center justify-center text-text-muted group-hover:bg-brand-red group-hover:text-white transition-all"><Receipt size={14} /></div>
                                                            <div>
                                                                    <div className="flex items-center gap-2">
                                                                        <p className="text-xs font-black text-text-primary uppercase font-data">{sale.invoice_number}</p>{sale.transaction_label && (<span className="px-1.5 py-0.5 bg-brand-charcoal text-white text-[8px] font-black rounded uppercase tracking-tighter shadow-sm flex items-center gap-0.5 shrink-0"><Tag size={8} /> {sale.transaction_label}</span>)}
                                                                        <div className="flex items-center gap-1">
                                                                            {sale.is_os && (
                                                                                <span className="px-1.5 py-0.5 bg-brand-red text-white text-[8px] font-black rounded uppercase tracking-tighter shadow-sm">OS</span>
                                                                            )}
                                                                            {!sale.is_os && (
                                                                                <span className={`px-1.5 py-0.5 ${sale.invoice_type === 'B' ? 'bg-indigo-600' : 'bg-slate-700'} text-white text-[8px] font-black rounded uppercase tracking-tighter shadow-sm`}>
                                                                                    TYPE {sale.invoice_type}
                                                                                </span>
                                                                            )}
                                                                            {sale.total_discount > 0 && (
                                                                                <span className="px-1.5 py-0.5 bg-brand-orange text-white text-[8px] font-black rounded uppercase tracking-tighter shadow-sm">DISC</span>
                                                                            )}
                                                                            {refundedInvoices.has(sale.invoice_number) && (
                                                                                <span className="px-1.5 py-0.5 bg-brand-red/10 text-brand-red text-[8px] font-black rounded uppercase tracking-tighter border border-brand-red/20 shadow-sm flex items-center gap-0.5 shrink-0">
                                                                                    <RotateCcw size={8} /> REFUNDED
                                                                                </span>
                                                                            )}
                                                                        </div>
                                                                    </div>
                                                                <p className="text-[10px] font-bold text-text-muted uppercase">{format(new Date(sale.date), 'MMM d, yyyy · p')}</p>
                                                            </div>
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-3.5">
                                                        <div className="flex items-center gap-2">
                                                            <User size={12} className="text-text-muted/30" />
                                                            <span className="text-[11px] font-black text-text-primary uppercase tracking-widest">{sale.customer_name}</span>
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-3.5">
                                                        <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full w-fit ${sale.fulfillment_status === 'delivered' ? 'bg-emerald-500/10 text-emerald-500' :
                                                            sale.fulfillment_status === 'out' ? 'bg-amber-500/10 text-amber-500' : 'bg-muted text-text-muted'
                                                            }`}>
                                                            {getStatusIcon(sale.fulfillment_status)}
                                                            <span className="text-[9px] font-black uppercase tracking-tight">{getStatusText(sale.fulfillment_status)}</span>
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-3.5">
                                                        <div className="flex items-center gap-2 px-3 py-1 bg-muted/50 rounded-full w-fit border border-border-strong/10">
                                                            <div className="w-1.5 h-1.5 rounded-full bg-brand-red shadow-[0_0_8px_rgba(239,68,68,0.4)]" />
                                                            <span className="text-[10px] font-black text-text-primary uppercase tracking-wider">{sale.payment_mode || 'CASH'}</span>
                                                        </div>
                                                    </td>
                                                    <td className="px-6 py-3.5 text-right font-data font-black text-text-primary text-base">₱{sale.grand_total.toLocaleString(undefined, { minimumFractionDigits: 2 })}</td>
                                                    <td className="px-6 py-3.5 text-right flex items-center justify-end gap-2">
                                                        {role === 'owner' && (
                                                            <button
                                                                onClick={(e) => { e.stopPropagation(); handleDeleteInvoice(sale.invoice_number); }}
                                                                className="p-2 text-text-muted/30 hover:text-brand-red hover:bg-red-500/10 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                                                            >
                                                                <Trash2 size={16} />
                                                            </button>
                                                        )}
                                                        <div className={`p-2 rounded-lg transition-all ${expandedInvoices.has(sale.invoice_number) ? 'bg-brand-red text-white rotate-180' : 'bg-muted text-text-muted/30'}`}><ChevronDown size={16} /></div>
                                                    </td>
                                                </tr>
                                                {expandedInvoices.has(sale.invoice_number) && (
                                                    <tr>
                                                        <td colSpan={5} className="px-6 py-4 bg-subtle/50">
                                                            <div className="p-6 border-l-4 border-brand-red bg-surface shadow-sm rounded-2xl space-y-6">
                                                                <div className="flex items-center justify-between border-b border-border-default pb-3">
                                                                    <div className="flex items-center gap-4">
                                                                        <h4 className="text-[10px] font-black uppercase text-text-primary tracking-widest flex items-center gap-2"><PackageSearch size={14} /> Invoice Breakdown</h4>
                                                                        {!sale.is_os && (
                                                                            <span className={`px-2 py-0.5 ${sale.invoice_type === 'B' ? 'bg-indigo-600' : 'bg-slate-700'} text-white text-[9px] font-black rounded uppercase tracking-tighter shadow-sm`}>
                                                                                TYPE {sale.invoice_type || 'A'}
                                                                            </span>
                                                                        )}
                                                                        <span className="text-[10px] font-bold text-text-muted bg-muted px-2 py-0.5 rounded uppercase">{sale.full_name}</span>
                                                                        {sale.edited_at && (
                                                                            <span className="text-[9px] font-bold text-brand-orange bg-brand-orange/5 px-2 py-0.5 rounded-lg border border-brand-orange/10 flex items-center gap-1">
                                                                                <Clock size={10} /> Edited {format(new Date(sale.edited_at), 'MMM d · p')}
                                                                            </span>
                                                                        )}
                                                                    </div>
                                                                    <button onClick={() => handleEditInvoice(sale)} className="text-[10px] font-black bg-text-primary text-text-inverse hover:bg-brand-red px-4 py-1.5 rounded-lg transition-all">EDIT INVOICE</button>
                                                                </div>

                                                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                                                    <div className="space-y-3">
                                                                        <p className="text-[9px] font-black text-text-muted uppercase tracking-widest">Purchased Items</p>
                                                                        <div className="space-y-2">
                                                                            {sale.items.map(item => (
                                                                                <div key={item.id} className="flex justify-between items-start gap-4 text-xs p-2 rounded-lg hover:bg-subtle">
                                                                                    <div className="flex-1">
                                                                                        <p className="font-bold text-text-primary">{item.products?.name}</p>
                                                                                        <p className="text-[9px] text-text-muted uppercase font-data">{item.products?.brand || 'No Brand'}</p>
                                                                                    </div>
                                                                                    <div className="text-right">
                                                                                        <p className="font-bold text-text-primary">x{item.quantity}</p>
                                                                                        <p className="text-[9px] text-text-muted font-data">UNIT: ₱{Number(item.unit_price).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                                                                        <p className="text-[10px] text-text-secondary font-data font-black">TOTAL: ₱{Number(item.total_price).toLocaleString(undefined, { minimumFractionDigits: 2 })}</p>
                                                                                    </div>
                                                                                </div>
                                                                            ))}
                                                                        </div>
                                                                    </div>

                                                                    <div className="bg-subtle/50 p-6 rounded-2xl space-y-4">
                                                                        <p className="text-[9px] font-black text-text-secondary uppercase tracking-widest">Financial Summary</p>
                                                                        <div className="space-y-2">
                                                                            <div className="flex justify-between text-[10px] items-center">
                                                                                <span className="text-text-muted font-bold uppercase tracking-tight">Payment Mode</span>
                                                                                <span className="bg-brand-red/10 text-brand-red px-3 py-1 rounded-full font-black uppercase text-[9px]">{sale.payment_mode}</span>
                                                                            </div>
                                                                            {!(sale.is_os || sale.grand_total < 101) && (
                                                                                <>
                                                                                    <div className="flex justify-between text-xs pt-2">
                                                                                        <span className="text-text-muted font-medium">VATable Sales (Tax Base)</span>
                                                                                        <span className="font-data font-bold">₱{(sale.total_vat > 0 ? (sale.total_base / 1.12) : 0).toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                                                                    </div>
                                                                                    <div className="flex justify-between text-xs">
                                                                                        <span className="text-text-muted font-medium">VAT Amount (12%)</span>
                                                                                        <span className="font-data font-bold text-brand-red">₱{sale.total_vat.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                                                                    </div>
                                                                                </>
                                                                            )}
                                                                            <div className="flex justify-between text-xs pt-1">
                                                                                <span className="text-text-muted font-medium">Initial Sub-Total</span>
                                                                                <span className="font-data font-bold">₱{sale.total_base.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                                                            </div>
                                                                            {sale.total_discount > 0 && (
                                                                                <div className="flex justify-between text-xs">
                                                                                    <span className="text-brand-orange font-medium">Applied Discount</span>
                                                                                    <span className="font-data font-bold text-brand-orange">- ₱{sale.total_discount.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                                                                </div>
                                                                            )}
                                                                            {Number(sale.delivery_fee) > 0 && (
                                                                                <div className="flex justify-between text-xs pt-1 border-t border-border-default/50 mt-1">
                                                                                    <span className="text-text-muted font-bold uppercase tracking-tighter text-[9px]">Delivery Fee</span>
                                                                                    <span className="font-data font-black text-blue-500">+ ₱{Number(sale.delivery_fee).toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                                                                </div>
                                                                            )}
                                                                            <div className="pt-3 border-t-2 border-border-default flex justify-between items-center text-sm font-black text-text-primary">
                                                                                <span className="uppercase tracking-widest text-[10px]">Grand Total</span>
                                                                                <span className="text-2xl font-data">₱{sale.grand_total.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                                                                            </div>
                                                                        </div>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        </td>
                                                    </tr>
                                                )}
                                            </Fragment>
                                        ))
                                    ) : (
                                        <tr><td colSpan={5} className="py-20 text-center text-text-muted transition-colors">No matching orders found for this date.</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>

            <SalesModal isOpen={isModalOpen} onClose={() => { setIsModalOpen(false); setEditData(null); }} onSuccess={handleSuccess} editData={editData || undefined} />
        </div >
    );
}

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { supabase } from '../../../shared/lib/supabase';
import { X, RotateCcw, Trash2, AlertTriangle, Package } from 'lucide-react';
import { useBranch } from '../../../shared/lib/BranchContext';

interface Product {
    id: string;
    name: string;
    selling_price: number;
}

interface RefundItem {
    productId: string;
    productName: string;
    quantity: number;
    unitPrice: number;
    totalPrice: number;
    maxQuantity?: number;
}

interface RefundModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: (newRefund?: unknown[]) => void;
}

export default function RefundModal({ isOpen, onClose, onSuccess }: RefundModalProps) {
    const { activeBranchId } = useBranch();
    const [products, setProducts] = useState<Product[]>([]);
    const [items, setItems] = useState<RefundItem[]>([]);
    const [invoiceNumber, setInvoiceNumber] = useState('');
    const [reason, setReason] = useState('');
    const [isVatEnabled, setIsVatEnabled] = useState(true);
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.ctrlKey && e.key === 'Enter') {
                e.preventDefault();
                (document.getElementById('refund-form') as HTMLFormElement)?.requestSubmit();
            }

            if (e.altKey && e.key.toLowerCase() === 'i') {
                e.preventDefault();
                loadInvoiceItems();
            }
        };

        if (isOpen) {
            fetchProducts();
            const today = new Date().toLocaleDateString('en-CA'); // YYYY-MM-DD
            setItems([]);
            setInvoiceNumber('');
            setReason('');
            setDate(today);
            setError(null);
            document.body.classList.add('modal-open');
            document.addEventListener('keydown', handleKeyDown);
        } else {
            document.body.classList.remove('modal-open');
        }
        return () => {
            document.body.classList.remove('modal-open');
            document.removeEventListener('keydown', handleKeyDown);
        };
    }, [isOpen, invoiceNumber]);

    const fetchProducts = async () => {
        let query = supabase.from('products').select('id, name, selling_price').order('name');
        if (activeBranchId) {
            query = query.eq('branch_id', activeBranchId);
        }
        const { data, error } = await query;
        if (error) console.error('Error fetching products:', error);
        else setProducts(data || []);
    };

    const updateItem = (index: number, updates: Partial<RefundItem>) => {
        const newItems = [...items];
        const item = { ...newItems[index], ...updates };

        if (updates.productId) {
            const product = products.find(p => p.id === updates.productId);
            if (product) {
                item.productName = product.name;
                item.unitPrice = product.selling_price;
            }
        }

        item.totalPrice = (item.quantity || 0) * (item.unitPrice || 0);
        newItems[index] = item;
        setItems(newItems);
    };

    const removeItem = (index: number) => {
        setItems(items.filter((_, i) => i !== index));
    };

    const subtotal = items.reduce((sum, item) => sum + item.totalPrice, 0);
    const vatAmount = isVatEnabled ? (subtotal - (subtotal / 1.12)) : 0;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (loading) return;
        if (items.length === 0) { setError('Please add at least one item'); return; }
        if (items.some(item => !item.productId)) { setError('Please select products for all items'); return; }

        for (const item of items) {
            if (item.maxQuantity && item.quantity > item.maxQuantity) {
                setError(`Quantity for ${item.productName} cannot exceed original invoice quantity (${item.maxQuantity})`);
                return;
            }
        }

        setLoading(true);
        setError(null);

        try {
            const { data: { user } } = await supabase.auth.getUser();
            const refundRecords = items.map(item => ({
                product_id: item.productId,
                quantity: item.quantity,
                reason: reason,
                invoice_number: invoiceNumber,
                unit_price: item.unitPrice,
                total_price: item.totalPrice,
                vat_amount: isVatEnabled ? (item.totalPrice - (item.totalPrice / 1.12)) : 0,
                user_id: user?.id,
                date: date,
                branch_id: activeBranchId
            }));

            const { data, error: insertError } = await supabase.from('customer_refunds').insert(refundRecords).select('*, products(name)');
            if (insertError) throw insertError;

            setTimeout(() => {
                onSuccess(data as unknown as unknown[]);
                onClose();
            }, 500);
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Unknown error');
        } finally {
            setLoading(false);
        }
    };

    const loadInvoiceItems = async () => {
        if (!invoiceNumber) {
            setError('Please enter an invoice number first');
            return;
        }
        setLoading(true);
        setError(null);
        try {
            let query = supabase
                .from('sales')
                .select('product_id, quantity, unit_price, products(name)')
                .eq('invoice_number', invoiceNumber);

            if (activeBranchId) {
                query = query.eq('branch_id', activeBranchId);
            }

            const { data, error } = await query;

            if (error) throw error;
            if (!data || data.length === 0) {
                setError('No sales found for this invoice number');
                return;
            }

            const newItems: RefundItem[] = data.map(item => ({
                productId: item.product_id,
                productName: (item.products as any)?.name || 'Unknown Product',
                quantity: item.quantity,
                unitPrice: item.unit_price,
                totalPrice: item.quantity * item.unit_price,
                maxQuantity: item.quantity
            }));

            setItems(newItems);
        } catch (err) {
            setError(err instanceof Error ? err.message : 'Failed to load invoice items');
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/85 px-4 text-left">
            <div className="w-full max-w-5xl rounded-2xl bg-surface shadow-2xl border border-border-default flex flex-col max-h-[90vh] animate-slide-up overflow-hidden">
                <div className="flex items-center justify-between px-6 py-3 bg-brand-charcoal">
                    <div className="flex items-center gap-3 text-white">
                        <div className="w-8 h-8 bg-brand-red rounded-lg flex items-center justify-center text-white"><RotateCcw size={16} /></div>
                        <h2 className="text-base font-bold uppercase tracking-wider">Customer Refund</h2>
                    </div>
                    <button onClick={onClose} className="text-white/40 hover:text-white transition-all"><X size={18} /></button>
                </div>

                <div className="flex-1 overflow-y-auto p-4 scrollbar-hide text-left bg-surface">
                    {error && <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 text-red-500 text-sm rounded-xl flex items-center gap-2"><AlertTriangle size={16} /> {error}</div>}
                    <form id="refund-form" onSubmit={handleSubmit} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 p-4 bg-subtle rounded-xl border border-border-default items-end">
                            <div className="space-y-2">
                                <label className="block text-xs font-black uppercase text-text-secondary">Invoice #</label>
                                <div className="flex gap-2">
                                    <input type="text" value={invoiceNumber} onChange={e => setInvoiceNumber(e.target.value)} className="modal-input font-data flex-1" placeholder="e.g. 000001" required />
                                    <button
                                        type="button"
                                        onClick={loadInvoiceItems}
                                        disabled={loading}
                                        className="bg-brand-charcoal text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase hover:bg-brand-red transition-all shadow-sm flex items-center gap-2 whitespace-nowrap"
                                    >
                                        Import
                                    </button>
                                </div>
                            </div>
                            <div className="space-y-2">
                                <label className="block text-xs font-black uppercase text-text-secondary">Refund Date</label>
                                <input type="date" value={date} onChange={e => setDate(e.target.value)} className="modal-input font-data" required />
                            </div>
                            <div className="space-y-2">
                                <label className="block text-xs font-black uppercase text-text-secondary">Reason</label>
                                <input type="text" value={reason} onChange={e => setReason(e.target.value)} className="modal-input" placeholder="e.g. Defective" required />
                            </div>
                        </div>

                        <div className="space-y-3">
                            {items.map((item, index) => (
                                <div key={index} className="flex gap-3 p-3 border border-border-default rounded-xl bg-surface hover:border-brand-red/30 transition-all items-center shadow-sm">
                                    <div className="flex-1 flex flex-col md:flex-row gap-4 items-center justify-between">
                                        <div className="flex items-center gap-3 flex-1">
                                            <div className="w-9 h-9 bg-brand-red/10 rounded-lg flex items-center justify-center text-brand-red"><Package size={16} /></div>
                                            <div className="flex-1 text-left">
                                                <p className="text-sm font-black text-text-primary uppercase">{item.productName}</p>
                                                <p className="text-[10px] text-text-muted font-data">INV QTY: {item.maxQuantity}</p>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-8">
                                            <div className="space-y-1">
                                                <label className="block text-[10px] font-black uppercase text-text-muted">Refund Qty</label>
                                                 <input
                                                     type="number"
                                                     min="1"
                                                     max={item.maxQuantity}
                                                     className={`modal-input font-data text-center w-24 ${item.maxQuantity && item.quantity > item.maxQuantity ? 'border-brand-red text-brand-red' : ''}`}
                                                     value={item.quantity}
                                                     onChange={e => updateItem(index, { quantity: parseInt(e.target.value) || 0 })}
                                                     onFocus={e => e.target.select()}
                                                     required
                                                 />
                                            </div>
                                            <div className="space-y-1">
                                                <label className="block text-[10px] font-black uppercase text-text-muted">Unit Price</label>
                                                <p className="text-sm font-black font-data text-text-secondary">₱{item.unitPrice.toLocaleString()}</p>
                                            </div>
                                            <div className="space-y-1">
                                                <label className="block text-[10px] font-black uppercase text-text-muted">Total</label>
                                                <p className="text-sm font-black font-data text-text-primary">₱{item.totalPrice.toLocaleString()}</p>
                                            </div>
                                        </div>
                                    </div>
                                    <button type="button" onClick={() => removeItem(index)} className="p-3 text-text-muted hover:text-brand-red transition-colors" title="Remove Item"><Trash2 size={20} /></button>
                                </div>
                            ))}
                            {items.length === 0 && !loading && invoiceNumber && (
                                <div className="p-12 text-center border-2 border-dashed border-border-default rounded-3xl bg-subtle">
                                    <Package className="mx-auto text-text-muted mb-4" size={40} />
                                    <p className="text-text-secondary font-bold">Enter Invoice # and click Import to load items</p>
                                </div>
                            )}
                        </div>
                    </form>
                </div>

                <div className="px-6 py-4 bg-brand-charcoal flex flex-col md:flex-row items-end md:items-center justify-between gap-6 relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-48 h-48 bg-brand-red/10 rounded-full blur-3xl -mr-24 -mt-24" />
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-6 text-white/60 relative z-10 text-left">
                        <div><p className="text-[10px] font-black uppercase opacity-50">Total</p><p className="text-base font-black font-data text-white">₱{subtotal.toLocaleString()}</p></div>
                        {isVatEnabled && <div><p className="text-[10px] font-black uppercase opacity-50">VAT Adj.</p><p className="text-base font-black font-data text-brand-red">- ₱{vatAmount.toLocaleString()}</p></div>}
                        <div className="flex items-center gap-2">
                            <span className="text-[9px] font-black uppercase opacity-50">VAT</span>
                            <button type="button" onClick={() => setIsVatEnabled(!isVatEnabled)} className={`w-10 h-5 rounded-full relative transition-all ${isVatEnabled ? 'bg-brand-red' : 'bg-white/10'}`}><div className={`w-3 h-3 bg-white rounded-full transition-all absolute top-1 ${isVatEnabled ? 'right-1' : 'left-1'}`} /></button>
                        </div>
                    </div>
                    <div className="flex gap-3 relative z-10">
                        <button type="button" onClick={onClose} className="px-4 py-2 border border-white/20 text-white font-bold text-[10px] rounded-lg hover:bg-white/10 transition-colors uppercase tracking-widest">Cancel</button>
                        <button type="submit" form="refund-form" disabled={loading || items.length === 0} className="px-6 py-2 bg-brand-red text-white rounded-lg font-black text-[10px] shadow-red transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest">{loading ? 'Logging...' : 'Complete Refund'}</button>
                    </div>
                </div>
            </div >
        </div >,
        document.body
    );
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { createPortal } from 'react-dom';
import { supabase } from '../../../shared/lib/supabase';
import { X, ShoppingCart, AlertCircle, Plus, Trash2, Percent, User, Truck, SendHorizonal, ChevronUp, ChevronDown, Search, Users, Tag, Receipt, CreditCard } from 'lucide-react';
import { customerService } from '../../customers/services/customerService';
import { encodePrice } from '../../../shared/lib/priceCodes';
import { useAudit } from '../../../shared/hooks/useAudit';
import { useKeyboardNav } from '../../../shared/hooks/useKeyboardNav';
import { computeOutputVat, type VatClassification } from '../../../lib/vatUtils';
import type { Customer } from '../../customers/types/customer';
import { useBranch } from '../../../shared/lib/BranchContext';
import { toast } from 'sonner';
import { isSmartMatch } from '../../../shared/lib/searchUtils';

interface Product {
    id: string;
    name: string;
    stock_available: number;
    selling_price: number;
    brand?: string;
    description?: string;
    buying_price?: number;
}

interface OrderItem {
    product_id: string;
    quantity: number;
    unit_price: number;
    total_price: number;
    name?: string;
    stock_available?: number;
    brand?: string;
    searchQuery?: string;
    isSearchOpen?: boolean;
    highlightedIndex?: number;
    currentLevel?: 'master' | 'category' | 'subcategory' | 'product';
    selectedPath?: {
        master?: string;
        category?: string;
        subcategory?: string;
    };
}

interface SalesModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: (newSales?: unknown[]) => void;
    editData?: {
        invoiceNumber: string;
        customerName?: string;
        fulfillmentStatus?: string;
        paymentMode?: string;
        items: OrderItem[];
        isVatEnabled: boolean;
        isDiscountEnabled: boolean;
        is_os?: boolean;
        date?: string;
        delivery_fee?: number;
        customer_id?: string | null;
    };
}

const PAYMENT_MODES = [
    { id: 'cash', label: 'Cash' },
    { id: 'gcash', label: 'GCash' },
    { id: 'cheque', label: 'Cheque' },
    { id: 'bank_transfer', label: 'Bank Transfer' },
    { id: 'others', label: 'Others' }
];

const AR_LABELS = [
    { id: 'AR', label: 'AR (General Credit)' },
    { id: 'AR Cash', label: 'AR Cash (Collection)' },
    { id: 'AR1', label: 'AR1 (Sister Co Debt)' },
    { id: 'AR2', label: 'AR2 (Customer Debt)' }
];

export default function SalesModal({ isOpen, onClose, onSuccess, editData }: SalesModalProps) {
    const { activeBranchId } = useBranch();
    const { logAction } = useAudit();
    const [products, setProducts] = useState<Product[]>([]);
    const [invoiceNumber, setInvoiceNumber] = useState('000000');
    const [customerName, setCustomerName] = useState('');
    const [customerId, setCustomerId] = useState<string | null>(null);
    const [customers, setCustomers] = useState<Customer[]>([]);
    const [customerSearchQuery, setCustomerSearchQuery] = useState('');
    const [isCustomerSearchOpen, setIsCustomerSearchOpen] = useState(false);
    const [fulfillmentStatus, setFulfillmentStatus] = useState<'pickup' | 'delivered' | 'out'>('pickup');
    const [paymentMode, setPaymentMode] = useState('cash');
    const [customerHighlightedIndex, setCustomerHighlightedIndex] = useState(0);
    const [isOs, setIsOs] = useState(false);
    const [invoiceType, setInvoiceType] = useState<'A' | 'B'>('A');
    const [rawInvoiceNum, setRawInvoiceNum] = useState(''); // Holds the numeric part during editing
    const [originalDate, setOriginalDate] = useState<string | null>(null);
    const [items, setItems] = useState<OrderItem[]>([
        {
            product_id: '',
            quantity: 1,
            unit_price: 0,
            total_price: 0,
            searchQuery: '',
            isSearchOpen: false,
            highlightedIndex: 0,
            currentLevel: 'master',
            selectedPath: {}
        }
    ]);
    const [vatClassification, setVatClassification] = useState<VatClassification>('vatable');
    const [orNumber, setOrNumber] = useState('');
    const [transactionLabel, setTransactionLabel] = useState<string>('');
    const [isDiscountEnabled, setIsDiscountEnabled] = useState(false);
    const [deliveryFee, setDeliveryFee] = useState(0);
    const [showDeliveryPrompt, setShowDeliveryPrompt] = useState(false);
    const [promptStep, setPromptStep] = useState<'confirm' | 'input'>('confirm');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);

    const dropdownRefs = useRef<(HTMLDivElement | null)[]>([]);
    const searchInputRefs = useRef<(HTMLInputElement | null)[]>([]);
    const quantityInputRefs = useRef<(HTMLInputElement | null)[]>([]);
    const customerSearchInputRef = useRef<HTMLInputElement>(null);
    const saveButtonRef = useRef<HTMLButtonElement>(null);

    // Keyboard navigation for line items
    const completedItems = items.filter(it => it.product_id);
    const {
        focusedIndex,
        deleteConfirmIndex,
        setEditingQtyIndex,
        handleListKeyDown,
        resetNav,
    } = useKeyboardNav({
        itemCount: completedItems.length,
        searchInputRef: { current: searchInputRefs.current[items.length - 1] || searchInputRefs.current[0] } as React.RefObject<HTMLInputElement | null>,
        saveButtonRef,
        onEditQuantity: (idx) => {
            // Find the actual item index for completed items
            const actualIdx = items.findIndex((it, i) => {
                let completedCount = 0;
                for (let j = 0; j <= i; j++) {
                    if (items[j].product_id) completedCount++;
                }
                return it.product_id && completedCount - 1 === idx;
            });
            if (actualIdx >= 0 && quantityInputRefs.current[actualIdx]) {
                quantityInputRefs.current[actualIdx]?.focus();
                quantityInputRefs.current[actualIdx]?.select();
            }
        },
        onReplaceItem: (idx) => {
            const actualIdx = items.findIndex((it, i) => {
                let completedCount = 0;
                for (let j = 0; j <= i; j++) {
                    if (items[j].product_id) completedCount++;
                }
                return it.product_id && completedCount - 1 === idx;
            });
            if (actualIdx >= 0) {
                handleItemChange(actualIdx, 'searchQuery', '');
                handleItemChange(actualIdx, 'product_id', '');
                handleItemChange(actualIdx, 'isSearchOpen', true);
                setTimeout(() => searchInputRefs.current[actualIdx]?.focus(), 50);
            }
        },
        onRemoveItem: (idx) => {
            const actualIdx = items.findIndex((it, i) => {
                let completedCount = 0;
                for (let j = 0; j <= i; j++) {
                    if (items[j].product_id) completedCount++;
                }
                return it.product_id && completedCount - 1 === idx;
            });
            if (actualIdx >= 0) handleRemoveItem(actualIdx);
        },
        onEmptySearchEnter: () => {
            saveButtonRef.current?.focus();
        },
    });

    const fetchProducts = useCallback(async () => {
        const query = supabase
            .from('products')
            .select('id, name, stock_available, selling_price, brand, description, buying_price')
            .order('name');
        
        if (activeBranchId) {
            query.eq('branch_id', activeBranchId);
        }

        const { data, error } = await query;

        if (error) console.error('Error fetching products:', error);
        else setProducts(data || []);
    }, []);

    const fetchCustomers = useCallback(async () => {
        try {
            const data = await customerService.getAll();
            setCustomers(data);
        } catch (err) {
            console.error('Error fetching customers:', err);
        }
    }, []);

    const fetchLatestInvoice = useCallback(async (osMode: boolean) => {
        try {
            const today = new Date().toISOString().split('T')[0];
            let query = supabase.from('sales').select('invoice_number');

            if (osMode) {
                query = query.eq('is_os', true).gte('date', today);
            } else {
                query = query.eq('is_os', false);
            }

            if (activeBranchId) {
                query = query.eq('branch_id', activeBranchId);
            }

            if (!osMode) {
                // Only filter by type for standard invoices
                query = query.eq('invoice_type', invoiceType);
            }

            const { data, error } = await query.order('date', { ascending: false }).limit(20);

            if (error) throw error;

            if (data && data.length > 0) {
                const lastInvoice = data[0].invoice_number;
                const numericPart = lastInvoice.replace(/\D/g, '');
                const nextNum = (parseInt(numericPart) || 0) + 1;
                const paddedNum = nextNum.toString().padStart(6, '0');
                const newInvoice = osMode ? `OS-${paddedNum}` : paddedNum;
                setInvoiceNumber(newInvoice);
                setRawInvoiceNum(paddedNum);
                setOrNumber(newInvoice);
            } else {
                const defaultNum = '000001';
                const newInvoice = osMode ? `OS-${defaultNum}` : defaultNum;
                setInvoiceNumber(newInvoice);
                setRawInvoiceNum(defaultNum);
                setOrNumber(newInvoice);
            }
        } catch (err) {
            console.error('Error fetching latest invoice:', err);
            const defaultNum = '000001';
            const newInvoice = osMode ? `OS-${defaultNum}` : defaultNum;
            setInvoiceNumber(newInvoice);
            setRawInvoiceNum(defaultNum);
            setOrNumber(newInvoice);
        }
    }, [activeBranchId, invoiceType]);

    useEffect(() => {
        if (isOpen) {
            fetchProducts();
            fetchCustomers();
            if (editData) {
                setInvoiceNumber(editData.invoiceNumber);
                setCustomerName(editData.customerName || '');
                setFulfillmentStatus((editData.fulfillmentStatus as 'pickup' | 'delivered' | 'out') || 'pickup');
                setPaymentMode(editData.paymentMode || 'cash');
                setItems(editData.items.map(item => ({ ...item, searchQuery: item.name || '', isSearchOpen: false })));
                setIsDiscountEnabled(editData.isDiscountEnabled);
                setVatClassification((editData as any).vat_classification || (editData.isVatEnabled ? 'vatable' : 'exempt'));
                setOrNumber((editData as any).or_number || '');
                setIsOs(editData.is_os || false);
                setInvoiceType(((editData as any).invoice_type as 'A' | 'B') || 'A');
                setOriginalDate(editData.date || null);
                setDeliveryFee(0); // Reset fee so it's re-added via prompt
                setCustomerId(editData.customer_id || null);
                setCustomerSearchQuery(editData.customerName || '');
                setTransactionLabel((editData as any).transaction_label || '');
            } else {
                setCustomerName('');
                setFulfillmentStatus('pickup');
                setPaymentMode('cash');
                setIsOs(false);
                setOriginalDate(null);
                setItems([{
                    product_id: '',
                    quantity: 1,
                    unit_price: 0,
                    total_price: 0,
                    searchQuery: '',
                    isSearchOpen: false,
                    highlightedIndex: 0,
                    currentLevel: 'master',
                    selectedPath: {}
                }]);
                setVatClassification('vatable');
                setOrNumber('');
                setIsDiscountEnabled(false);
                setCustomerId(null);
                setCustomerSearchQuery('');
                setDeliveryFee(0);
                setTransactionLabel('');
            }
            setError(null);
            setSuccess(false);
            setShowDeliveryPrompt(false);
            setPromptStep('confirm');
            document.body.classList.add('modal-open');

            // Auto-focus first search input
            setTimeout(() => {
                if (searchInputRefs.current[0]) {
                    searchInputRefs.current[0].focus();
                }
            }, 100);
        } else {
            document.body.classList.remove('modal-open');
            resetNav();
        }
        return () => {
            document.body.classList.remove('modal-open');
        };
    }, [isOpen, editData, fetchProducts]);

    // Listen for global Escape to close modal
    useEffect(() => {
        if (!isOpen) return;
        const handleCloseModal = () => {
            // Only close if no dropdown is open
            const anyDropdownOpen = items.some(it => it.isSearchOpen) || isCustomerSearchOpen;
            if (!anyDropdownOpen) {
                onClose();
            }
        };
        window.addEventListener('close-modal', handleCloseModal);
        return () => window.removeEventListener('close-modal', handleCloseModal);
    }, [isOpen, items, isCustomerSearchOpen, onClose]);

    useEffect(() => {
        if (isOpen && !editData) {
            fetchLatestInvoice(isOs);
        }
    }, [isOs, invoiceType, isOpen, editData, fetchLatestInvoice]);

    // Keep OR Number in sync with Invoice Number
    useEffect(() => {
        setOrNumber(invoiceNumber);
    }, [invoiceNumber]);


    const handleInvoiceChange = (val: string) => {
        // Strip everything but numbers
        const num = val.replace(/\D/g, '').slice(0, 6);
        setRawInvoiceNum(num);
        // Display value prefixing
        const newInvoice = isOs ? `OS-${num}` : num;
        setInvoiceNumber(newInvoice);
        setOrNumber(newInvoice);
    };

    const handleInvoiceBlur = () => {
        // Apply padding when focus is lost
        const paddedNum = rawInvoiceNum.padStart(6, '0');
        setRawInvoiceNum(paddedNum);
        const newInvoice = isOs ? `OS-${paddedNum}` : paddedNum;
        setInvoiceNumber(newInvoice);
        setOrNumber(newInvoice);
    };

    const stepInvoice = (dir: number) => {
        const current = parseInt(rawInvoiceNum) || 0;
        const next = Math.max(0, current + dir);
        const paddedNum = next.toString().padStart(6, '0');
        setRawInvoiceNum(paddedNum);
        const newInvoice = isOs ? `OS-${paddedNum}` : paddedNum;
        setInvoiceNumber(newInvoice);
        setOrNumber(newInvoice);
    };

    // --- Calculations Moved Up ---
    const subtotal = items.reduce((sum, item) => sum + item.total_price, 0);
    const { vatAmount } = computeOutputVat(subtotal, vatClassification);
    const finalVatAmount = isOs ? 0 : vatAmount;
    const finalDiscountAmount = isDiscountEnabled ? (subtotal > 1300 ? 65 : subtotal * 0.05) : 0;
    const currentVatClassification = vatClassification;
    const grandTotal = subtotal - finalDiscountAmount;

    // --- Logic Handlers ---
    const handleSubmit = useCallback(async () => {
        if (loading || success) return;
        setLoading(true);
        setError(null);

        try {
            if (!invoiceNumber.trim()) throw new Error('Please enter an invoice number');
            if (orNumber.trim()) {
                const { data: duplicateOr } = await supabase
                    .from('sales')
                    .select('or_number')
                    .eq('or_number', orNumber.trim())
                    .maybeSingle();

                if (duplicateOr && (!editData || (editData as any).or_number !== orNumber.trim())) {
                    throw new Error(`Duplicate OR Number detected: ${orNumber}. Please check or enter a new one.`);
                }
            }
            if (!orNumber.trim()) throw new Error('OR Number is required for BIR compliance');
            if (items.some(item => !item.product_id)) throw new Error('Please select a product for all rows');
            if (items.some(item => item.quantity <= 0)) throw new Error('Quantity must be greater than 0');

            const { data: { user } } = await supabase.auth.getUser();

            if (editData) {
                const { error: delError } = await supabase.from('sales').delete().eq('invoice_number', editData.invoiceNumber);
                if (delError) throw delError;
            }

            const { data: latestProducts } = await supabase.from('products').select('id, name, stock_available');
            for (const item of items) {
                const p = latestProducts?.find(prod => prod.id === item.product_id);
                if (p && item.quantity > (p.stock_available || 0)) throw new Error(`Insufficient stock for ${p.name}.`);
            }

            const salesToInsert = items.map(item => {
                const itemRatio = subtotal > 0 ? (item.total_price / subtotal) : (1 / items.length);
                const product = products.find(p => p.id === item.product_id);
                return {
                    product_id: item.product_id,
                    quantity: item.quantity,
                    unit_price: item.unit_price,
                    total_price: item.total_price,
                    invoice_number: invoiceNumber,
                    customer_name: customerName,
                    customer_id: customerId,
                    fulfillment_status: fulfillmentStatus,
                    payment_mode: paymentMode,
                    user_id: user?.id,
                    vat_amount: finalVatAmount * itemRatio,
                    discount_amount: finalDiscountAmount * itemRatio,
                    is_discounted: isDiscountEnabled,
                    cost_price: product?.buying_price || 0,
                    is_os: isOs,
                    delivery_fee: deliveryFee,
                    vat_classification: currentVatClassification,
                    or_number: orNumber,
                    invoice_type: isOs ? null : invoiceType,
                    net_amount: (item.total_price - (finalVatAmount * itemRatio)),
                    branch_id: activeBranchId,
                    transaction_label: transactionLabel,
                    ...(originalDate ? { date: originalDate, edited_at: new Date().toISOString() } : {})
                };
            });

            const { data: insertedData, error: insertError } = await supabase.from('sales').insert(salesToInsert).select('*, products(name, brand)');
            if (insertError) throw insertError;

            // Audit Log
            if (insertedData && insertedData.length > 0) {
                await logAction({
                    action: editData ? 'UPDATE_SALE' : 'CREATE_SALE',
                    table_name: 'sales',
                    record_id: invoiceNumber,
                    old_data: editData,
                    new_data: salesToInsert
                });
            }

            setSuccess(true);
            toast.success('Sale saved', { duration: 2000 });
            setTimeout(() => {
                onSuccess(insertedData as unknown as unknown[]);
                // Auto-reset for next sale instead of closing
                setSuccess(false);
                setError(null);
                setCustomerName('');
                setCustomerId(null);
                setCustomerSearchQuery('');
                setItems([{
                    product_id: '',
                    quantity: 1,
                    unit_price: 0,
                    total_price: 0,
                    searchQuery: '',
                    isSearchOpen: false,
                    highlightedIndex: 0,
                    currentLevel: 'master',
                    selectedPath: {}
                }]);
                setDeliveryFee(0);
                setShowDeliveryPrompt(false);
                setPromptStep('confirm');
                resetNav();
                // Re-fetch next invoice number
                fetchLatestInvoice(isOs);
                // Re-focus search input
                setTimeout(() => {
                    searchInputRefs.current[0]?.focus();
                }, 100);
            }, 800);

        } catch (err: any) {
            setError(err.message || 'Error processing transaction');
        } finally {
            setLoading(false);
        }
    }, [loading, success, invoiceNumber, orNumber, items, editData, subtotal, finalVatAmount, finalDiscountAmount, customerName, customerId, fulfillmentStatus, paymentMode, isDiscountEnabled, isOs, deliveryFee, currentVatClassification, invoiceType, activeBranchId, originalDate, products, logAction, onSuccess, onClose, transactionLabel]);

    const validateAndSubmit = useCallback((e?: React.FormEvent) => {
        if (e) e.preventDefault();
        if (grandTotal > 100 && grandTotal < 5001 && deliveryFee === 0 && !showDeliveryPrompt) {
            setPromptStep('input');
            setShowDeliveryPrompt(true);
        } else {
            handleSubmit();
        }
    }, [grandTotal, deliveryFee, showDeliveryPrompt, handleSubmit]);

    const handleAddItem = useCallback(() => {
        setItems(prev => [...prev, {
            product_id: '',
            quantity: 1,
            unit_price: 0,
            total_price: 0,
            searchQuery: '',
            isSearchOpen: false,
            highlightedIndex: 0,
            currentLevel: 'master',
            selectedPath: {}
        }]);

        // Auto-focus the new search input
        setTimeout(() => {
            if (searchInputRefs.current[items.length]) {
                searchInputRefs.current[items.length]?.focus();
            }
        }, 100);
    }, [items.length]);

    const handleRemoveItem = useCallback((index: number) => {
        setItems(prev => {
            if (prev.length === 1) return prev;
            return prev.filter((_, i) => i !== index);
        });
    }, []);

    const handleItemChange = useCallback(<K extends keyof OrderItem>(index: number, field: K, value: OrderItem[K]) => {
        setItems(prev => {
            const next = [...prev];
            const item = { ...next[index], [field]: value };

            if (field === 'quantity' || field === 'unit_price') {
                const q = field === 'quantity' ? (value as number) : item.quantity;
                const u = field === 'unit_price' ? (value as number) : item.unit_price;
                item.total_price = q * u;
            }

            if (field === 'searchQuery') {
                item.isSearchOpen = true;
                if (!value) {
                    item.product_id = '';
                    item.name = '';
                    item.unit_price = 0;
                    item.total_price = 0;
                    item.highlightedIndex = 0;
                }
            }

            if (field === 'isSearchOpen' && value === true) {
                item.highlightedIndex = 0;
            }

            next[index] = item;
            return next;
        });
    }, []);

    useEffect(() => {
        const handleGlobalKeyDown = (e: KeyboardEvent) => {
            // Modal level shortcuts
            if (e.ctrlKey && e.key === 'Enter') {
                e.preventDefault();
                validateAndSubmit();
            }

            if (e.altKey) {
                switch (e.key.toLowerCase()) {
                    case 'a':
                        e.preventDefault();
                        handleAddItem();
                        break;
                    case 'd':
                        e.preventDefault();
                        setIsDiscountEnabled(prev => !prev);
                        break;
                    case 'v':
                        e.preventDefault();
                        setVatClassification(prev => {
                            if (prev === 'vatable') return 'exempt';
                            if (prev === 'exempt') return 'zero_rated';
                            return 'vatable';
                        });
                        break;
                    case 'm':
                        e.preventDefault();
                        setPaymentMode(prev => {
                            const currentIndex = PAYMENT_MODES.findIndex(m => m.id === prev);
                            const nextIndex = (currentIndex + 1) % PAYMENT_MODES.length;
                            return PAYMENT_MODES[nextIndex].id;
                        });
                        break;
                    case 'backspace':
                        e.preventDefault();
                        if (items.length > 1) {
                            handleRemoveItem(items.length - 1);
                        }
                        break;
                }
            }
        };

        const handleClickOutside = (event: MouseEvent) => {
            dropdownRefs.current.forEach((ref, index) => {
                if (ref && !ref.contains(event.target as Node)) {
                    setItems(prev => {
                        const next = [...prev];
                        if (next[index]) next[index].isSearchOpen = false;
                        return next;
                    });
                }
            });
        };

        if (isOpen) {
            document.addEventListener('keydown', handleGlobalKeyDown);
            document.addEventListener('mousedown', handleClickOutside);
        }

        return () => {
            document.removeEventListener('keydown', handleGlobalKeyDown);
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [isOpen, items.length, validateAndSubmit, handleAddItem, handleRemoveItem]);

    const selectProduct = (index: number, product: Product) => {
        // Zero-stock blocking
        if (product.stock_available <= 0) {
            toast.error('Insufficient stock — item cannot be added', { duration: 2000 });
            return;
        }

        const existingIndex = items.findIndex((item, i) => i !== index && item.product_id === product.id);

        if (existingIndex !== -1) {
            // Merge duplicate
            const newItems = [...items];
            const existingItem = newItems[existingIndex];
            existingItem.quantity += items[index].quantity;
            existingItem.total_price = existingItem.quantity * existingItem.unit_price;

            // Remove current empty/partial row if it was just being used for selection
            if (items.length > 1) {
                newItems.splice(index, 1);
            } else {
                // If it's the only row, just reset it (though this case is rare for duplicates)
                newItems[index] = {
                    product_id: '',
                    quantity: 1,
                    unit_price: 0,
                    total_price: 0,
                    searchQuery: '',
                    isSearchOpen: false,
                    highlightedIndex: 0,
                    currentLevel: 'master',
                    selectedPath: {}
                };
            }

            setItems(newItems);

            // Focus the existing item's quantity
            const focusIndex = existingIndex < index ? existingIndex : existingIndex - 1;
            setTimeout(() => {
                if (quantityInputRefs.current[focusIndex]) {
                    quantityInputRefs.current[focusIndex]?.focus();
                    quantityInputRefs.current[focusIndex]?.select();
                }
            }, 50);
            return;
        }

        const newItems = [...items];
        newItems[index] = {
            ...newItems[index],
            product_id: product.id,
            name: product.name,
            stock_available: product.stock_available,
            unit_price: product.selling_price || 0,
            total_price: newItems[index].quantity * (product.selling_price || 0),
            brand: product.brand,
            searchQuery: product.name,
            isSearchOpen: false,
            highlightedIndex: 0
        };
        setItems(newItems);

        // Auto-focus quantity input after selection
        setTimeout(() => {
            if (quantityInputRefs.current[index]) {
                quantityInputRefs.current[index]?.focus();
                quantityInputRefs.current[index]?.select();
            }
        }, 50);
    };

    // Auto-switch to OS for orders <= 100 PHP (New Sales only)
    useEffect(() => {
        if (isOpen && !editData && grandTotal > 0) {
            const shouldBeOs = grandTotal <= 100;
            if (isOs !== shouldBeOs) {
                setIsOs(shouldBeOs);
            }
        }
    }, [grandTotal, isOpen, editData, isOs, setIsOs]);


    if (!isOpen) return null;

    return createPortal(
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/85 px-4 text-left">
            <div className="w-full max-w-5xl rounded-2xl bg-surface shadow-2xl border border-border-default overflow-hidden flex flex-col max-h-[95vh] animate-slide-up">
                <div className="flex items-center justify-between px-6 py-3 bg-brand-charcoal">
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-brand-red rounded-lg flex items-center justify-center text-white"><ShoppingCart size={16} /></div>
                        <h2 className="text-base font-bold text-white uppercase tracking-wider">{editData ? 'Edit Sale' : 'New Sale'}</h2>
                    </div>
                    <button onClick={onClose} className="text-slate-400 hover:text-white transition-colors"><X size={18} /></button>
                </div>

                <div className="flex-1 overflow-y-auto p-4 scrollbar-hide bg-surface">
                    {error && <div className="mb-4 p-3 bg-red-50 border border-red-200 text-red-700 text-sm rounded-xl flex items-center gap-2"><AlertCircle size={16} /> {error}</div>}
                    <form id="order-form" onSubmit={validateAndSubmit} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-4">
                            <div className="lg:col-span-4 p-3 bg-brand-charcoal rounded-2xl border border-border-strong px-4 flex items-center justify-between shadow-soft h-[68px]">
                                <div className="flex flex-col">
                                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1 flex items-center gap-2"><Receipt size={12} /> Invoice</label>
                                    <div className="flex items-center gap-4">
                                        <div className="relative group">
                                            <input
                                                type="text"
                                                className="w-28 bg-transparent text-white text-lg font-data font-black outline-none border-b-2 border-slate-700 focus:border-brand-red transition-all text-center tracking-widest h-[24px]"
                                                value={rawInvoiceNum}
                                                onChange={(e) => handleInvoiceChange(e.target.value)}
                                                onBlur={handleInvoiceBlur}
                                                onFocus={(e) => e.target.select()}
                                                placeholder={isOs ? 'OS-000001' : '000001'}
                                            />
                                            <div className="absolute right-[-48px] top-1/2 -translate-y-1/2 flex items-center gap-1.5 origin-left">
                                                <div className="flex bg-white/10 border border-white/10 rounded-lg p-1 shadow-md">
                                                    <button
                                                        type="button"
                                                        onClick={() => setInvoiceType('A')}
                                                        className={`px-2 py-1 rounded-md text-[10px] font-black transition-all ${invoiceType === 'A' ? 'bg-white text-brand-charcoal shadow-sm' : 'text-slate-400 hover:text-white'}`}
                                                    >
                                                        A
                                                    </button>
                                                    <button
                                                        type="button"
                                                        onClick={() => setInvoiceType('B')}
                                                        className={`px-2 py-1 rounded-md text-[10px] font-black transition-all ${invoiceType === 'B' ? 'bg-white text-brand-charcoal shadow-sm' : 'text-slate-400 hover:text-white'}`}
                                                    >
                                                        B
                                                    </button>
                                                </div>
                                            </div>
                                        </div>
                                        <button
                                            type="button"
                                            onClick={() => {
                                                const newIsOs = !isOs;
                                                setIsOs(newIsOs);
                                                fetchLatestInvoice(newIsOs);
                                            }}
                                            className={`ml-10 px-3 py-1.5 rounded-lg text-[10px] font-black tracking-widest transition-all ${isOs ? 'bg-brand-red text-white shadow-red ring-1 ring-brand-red/20' : 'bg-white/5 text-slate-400 border border-white/5 hover:text-white hover:bg-white/10'}`}
                                        >
                                            OS
                                        </button>
                                    </div>
                                </div>
                                <div className="flex flex-col gap-0.5 shrink-0">
                                    <button type="button" onClick={() => stepInvoice(1)} title="Increment" className="flex items-center justify-center w-6 h-4 bg-white/10 hover:bg-brand-red text-white rounded border border-white/5 transition-all">
                                        <ChevronUp size={10} strokeWidth={3} />
                                    </button>
                                    <button type="button" onClick={() => stepInvoice(-1)} title="Decrement" className="flex items-center justify-center w-6 h-4 bg-white/10 hover:bg-brand-red text-white rounded border border-white/5 transition-all">
                                        <ChevronDown size={10} strokeWidth={3} />
                                    </button>
                                </div>
                            </div>
                             <div className="lg:col-span-4 p-2 bg-subtle rounded-xl border border-border-default h-[68px]">
                                <label className="block text-[10px] font-black text-slate-700 uppercase tracking-widest mb-1.5 flex items-center gap-2"><Tag size={12} /> Accounting Label</label>
                                <select 
                                    className="w-full bg-surface border border-border-default rounded-xl px-2 py-1.5 text-xs font-black text-text-primary outline-none focus:ring-2 focus:ring-brand-red/10 appearance-none cursor-pointer uppercase"
                                    value={transactionLabel}
                                    onChange={(e) => setTransactionLabel(e.target.value)}
                                >
                                    <option value="">NO LABEL</option>
                                    {AR_LABELS.map(label => (
                                        <option key={label.id} value={label.id}>{label.label}</option>
                                    ))}
                                </select>
                            </div>

                             <div className="lg:col-span-4 p-2 bg-subtle rounded-xl border border-border-default relative h-[68px]">
                                <label className="block text-[10px] font-black text-slate-700 uppercase tracking-widest mb-1.5 flex items-center gap-2"><User size={12} /> Customer Name</label>
                                <div className="relative">
                                    <div className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400"><Users size={12} /></div>
                                    <input
                                        type="text"
                                        ref={customerSearchInputRef}
                                        placeholder="Enter customer..."
                                        className="w-full bg-surface border border-border-default rounded-xl pl-8 pr-7 py-1.5 text-xs focus:ring-2 focus:ring-brand-red/20 outline-none shadow-sm font-medium h-[32px]"
                                        value={customerSearchQuery}
                                        onChange={(e) => {
                                            setCustomerSearchQuery(e.target.value);
                                            setCustomerName(e.target.value);
                                            setIsCustomerSearchOpen(true);
                                            setCustomerHighlightedIndex(0);
                                            if (!e.target.value) setCustomerId(null);
                                        }}
                                        onFocus={(e) => {
                                            e.target.select();
                                            setIsCustomerSearchOpen(true);
                                        }}
                                        onKeyDown={(e) => {
                                            const filtered = customers.filter(c => c.name.toLowerCase().includes(customerSearchQuery.toLowerCase()));
                                            if (e.key === 'ArrowDown') {
                                                e.preventDefault();
                                                setCustomerHighlightedIndex(prev => Math.min(prev + 1, filtered.length - 1));
                                            } else if (e.key === 'ArrowUp') {
                                                e.preventDefault();
                                                setCustomerHighlightedIndex(prev => Math.max(prev - 1, 0));
                                            } else if (e.key === 'Enter') {
                                                if (isCustomerSearchOpen && filtered[customerHighlightedIndex]) {
                                                    e.preventDefault();
                                                    const c = filtered[customerHighlightedIndex];
                                                    setCustomerId(c.id);
                                                    setCustomerName(c.name);
                                                    setCustomerSearchQuery(c.name);
                                                    setIsCustomerSearchOpen(false);
                                                }
                                            } else if (e.key === 'Escape') {
                                                setIsCustomerSearchOpen(false);
                                            }
                                        }}
                                    />
                                    {isCustomerSearchOpen && (
                                        <div className="absolute z-[110] left-0 right-0 top-full mt-1 bg-surface border border-border-default rounded-xl shadow-xl max-h-[200px] overflow-y-auto overflow-x-hidden">
                                            {customers.filter(c => c.name.toLowerCase().includes(customerSearchQuery.toLowerCase())).length > 0 ? (
                                                customers.filter(c => c.name.toLowerCase().includes(customerSearchQuery.toLowerCase())).map((c, index) => (
                                                    <button
                                                        key={c.id}
                                                        type="button"
                                                        onMouseEnter={() => setCustomerHighlightedIndex(index)}
                                                        onClick={() => {
                                                            setCustomerId(c.id);
                                                            setCustomerName(c.name);
                                                            setCustomerSearchQuery(c.name);
                                                            setIsCustomerSearchOpen(false);
                                                        }}
                                                        className={`w-full text-left px-4 py-2 border-b border-slate-50 last:border-0 text-xs font-bold uppercase transition-colors ${customerHighlightedIndex === index ? 'bg-brand-red/5 text-brand-red' : 'text-brand-charcoal'}`}
                                                    >
                                                        {c.name}
                                                    </button>
                                                ))
                                            ) : (
                                                <div className="px-4 py-3 text-[10px] font-bold text-slate-400 text-center uppercase tracking-widest">
                                                    NEW CUSTOMER (TEXT ONLY)
                                                </div>
                                            )}
                                        </div>
                                    )}
                                </div>
                            </div>

                             <div className="lg:col-span-4 p-2 bg-slate-50 rounded-xl border border-slate-100 h-[68px]">
                                <label className="block text-[10px] font-black text-slate-700 uppercase tracking-widest mb-1.5 flex items-center gap-2"><Truck size={12} /> Fulfillment</label>
                                <select className="w-full bg-surface border border-border-default rounded-xl px-2 py-1.5 text-xs outline-none shadow-sm cursor-pointer font-bold h-[32px]" value={fulfillmentStatus} onChange={(e) => setFulfillmentStatus(e.target.value as 'pickup' | 'delivered' | 'out')}>
                                    <option value="pickup">Store Pickup</option>
                                    <option value="out">Product Out</option>
                                    <option value="delivered">Delivered</option>
                                </select>
                            </div>

                            <div className="lg:col-span-4 p-2 bg-slate-50 rounded-xl border border-slate-100 h-[68px]">
                                <label className="block text-[10px] font-black text-slate-700 uppercase tracking-widest mb-1.5 flex items-center gap-2"><CreditCard size={12} strokeWidth={2.5} /> Settlement</label>
                                <div className="grid grid-cols-2 gap-1.5">
                                    {PAYMENT_MODES.slice(0, 2).map(mode => (
                                        <button
                                            key={mode.id}
                                            type="button"
                                            onClick={() => setPaymentMode(mode.id)}
                                            className={`flex items-center justify-center px-1 py-1.5 rounded-lg border text-[8px] font-black transition-all ${paymentMode === mode.id ? 'bg-brand-red text-white border-brand-red shadow-sm' : 'bg-surface text-slate-400 border-border-default hover:border-slate-300'}`}
                                        >
                                            {mode.label}
                                        </button>
                                    ))}
                                    {PAYMENT_MODES.slice(2, 4).map(mode => (
                                        <button
                                            key={mode.id}
                                            type="button"
                                            onClick={() => setPaymentMode(mode.id)}
                                            className={`flex items-center justify-center px-1 py-1 rounded-lg border text-[8px] font-black transition-all ${paymentMode === mode.id ? 'bg-brand-red text-white border-brand-red shadow-sm' : 'bg-surface text-slate-400 border-border-default hover:border-slate-300'}`}
                                        >
                                            {mode.label}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div className="lg:col-span-4 p-2 bg-slate-50 rounded-xl border border-slate-100 h-[68px]">
                                <label className="block text-[10px] font-black text-slate-700 uppercase tracking-widest mb-1.5 flex items-center gap-2"><Percent size={12} /> Adjustments & Tax</label>
                                <div className="flex gap-2">
                                    <select
                                        className={`flex-1 py-1 px-1 rounded-lg border text-[8px] font-black tracking-widest transition-all outline-none ${vatClassification === 'vatable' ? 'bg-slate-800 text-white border-slate-800' : 'bg-surface text-text-muted border-border-default'}`}
                                        value={vatClassification}
                                        onChange={(e) => setVatClassification(e.target.value as VatClassification)}
                                    >
                                        <option value="vatable">VAT</option>
                                        <option value="exempt">EXE</option>
                                        <option value="zero_rated">ZERO</option>
                                    </select>
                                    <button type="button" onClick={() => setIsDiscountEnabled(!isDiscountEnabled)} className={`flex-1 py-1 rounded-lg border text-[8px] font-black tracking-widest transition-all ${isDiscountEnabled ? 'bg-brand-orange text-white border-brand-orange' : 'bg-surface text-text-muted border-border-default'}`}>DSC</button>
                                </div>
                            </div>
                        </div >



                        <div className="space-y-4">
                            <div className="flex justify-between items-center border-b pb-2"><h3 className="text-xs font-black uppercase text-brand-charcoal tracking-widest">Order Items</h3><button type="button" onClick={handleAddItem} className="bg-brand-red-light text-brand-red px-4 py-2 rounded-xl text-[10px] font-black hover:bg-brand-red hover:text-white transition-all"><Plus size={14} className="inline mr-1" /> ADD ITEM</button></div>
                            <div className="space-y-3 pb-40" tabIndex={focusedIndex >= 0 ? 0 : -1} onKeyDown={focusedIndex >= 0 ? handleListKeyDown : undefined} style={{ outline: 'none' }}>
                                {items.map((item, index) => (
                                    <div key={index} className={`flex flex-col lg:flex-row gap-2 p-2 rounded-xl shadow-sm transition-all group/item overflow-visible ${item.product_id && focusedIndex === completedItems.indexOf(item) ? 'bg-blue-50 border-2 border-accent-primary ring-2 ring-accent-subtle' : 'bg-white border border-slate-100 hover:border-brand-red/20'}`}>
                                        {/* Keyboard shortcut indicators for focused row */}
                                        {item.product_id && focusedIndex === completedItems.indexOf(item) && (
                                            <div className="flex items-center gap-2 text-[9px] font-black uppercase tracking-widest text-accent-primary mb-1 lg:mb-0">
                                                <span className="px-1.5 py-0.5 bg-accent-subtle rounded">Q</span> Qty
                                                <span className="px-1.5 py-0.5 bg-accent-subtle rounded">R</span> Replace
                                                <span className="px-1.5 py-0.5 bg-accent-subtle rounded">Del</span> Remove
                                                {deleteConfirmIndex === completedItems.indexOf(item) && (
                                                    <span className="px-2 py-0.5 bg-danger text-white rounded animate-pulse">Press Delete again to remove</span>
                                                )}
                                            </div>
                                        )}
                                        <div className="flex-[4] relative" ref={el => { dropdownRefs.current[index] = el; }}>
                                            <label className="block text-[9px] font-black text-brand-charcoal mb-1.5 uppercase">Product</label>
                                            <div className="relative">
                                                <div className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"><Search size={14} /></div>
                                                <input
                                                    type="text"
                                                    placeholder="Focus to search product..."
                                                    className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-9 pr-8 py-2.5 text-xs font-medium focus:ring-2 focus:ring-brand-red/10 focus:border-brand-red/30 outline-none"
                                                    value={item.searchQuery}
                                                    ref={el => { searchInputRefs.current[index] = el; }}
                                                    onChange={(e) => handleItemChange(index, 'searchQuery', e.target.value)}
                                                    onFocus={() => handleItemChange(index, 'isSearchOpen', true)}
                                                    onKeyDown={(e) => {
                                                        const query = item.searchQuery?.toLowerCase() || '';
                                                        const filtered = products
                                                            .filter(p => p.name.toLowerCase().includes(query) || (p.brand?.toLowerCase().includes(query) ?? false))
                                                            .sort((a, b) => {
                                                                const aName = a.name.toLowerCase();
                                                                const bName = b.name.toLowerCase();
                                                                const aExact = aName === query;
                                                                const bExact = bName === query;
                                                                if (aExact && !bExact) return -1;
                                                                if (!aExact && bExact) return 1;
                                                                const aPrefix = aName.startsWith(query);
                                                                const bPrefix = bName.startsWith(query);
                                                                if (aPrefix && !bPrefix) return -1;
                                                                if (!aPrefix && bPrefix) return 1;
                                                                return aName.localeCompare(bName);
                                                            });

                                                        if (e.key === 'ArrowDown') {
                                                            e.preventDefault();
                                                            if (item.isSearchOpen) {
                                                                handleItemChange(index, 'highlightedIndex', Math.min((item.highlightedIndex || 0) + 1, filtered.length - 1));
                                                            } else {
                                                                handleItemChange(index, 'isSearchOpen', true);
                                                            }
                                                        } else if (e.key === 'ArrowUp') {
                                                            e.preventDefault();
                                                            if ((item.highlightedIndex || 0) === 0 && item.isSearchOpen) {
                                                                // At top of suggestions, close and stay in search
                                                            } else {
                                                                handleItemChange(index, 'highlightedIndex', Math.max((item.highlightedIndex || 0) - 1, 0));
                                                            }
                                                        } else if (e.key === 'Enter') {
                                                            e.preventDefault();
                                                            if (item.isSearchOpen && filtered[item.highlightedIndex || 0]) {
                                                                selectProduct(index, filtered[item.highlightedIndex || 0]);
                                                            } else {
                                                                // Enter on empty search when items exist -> move to save
                                                                const isEmpty = !item.searchQuery;
                                                                const hasItems = completedItems.length > 0;
                                                                if (isEmpty && hasItems) {
                                                                    saveButtonRef.current?.focus();
                                                                }
                                                            }
                                                        } else if (e.key === 'Escape') {
                                                            if (item.isSearchOpen) {
                                                                handleItemChange(index, 'isSearchOpen', false);
                                                            }
                                                        }
                                                    }}
                                                />
                                                {item.searchQuery && (
                                                    <button type="button" onClick={() => { const ni = [...items]; ni[index] = { ...ni[index], searchQuery: '', product_id: '', unit_price: 0, currentLevel: 'master', selectedPath: {}, isSearchOpen: false }; setItems(ni); }} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-300 hover:text-brand-red transition-colors">
                                                        <X size={14} />
                                                    </button>
                                                )}
                                            </div>

                                            {item.isSearchOpen && (
                                                <div className="absolute z-[100] left-0 right-0 top-full mt-1 bg-white border border-slate-200 rounded-xl shadow-[0_20px_50px_rgba(0,0,0,0.15)] max-h-[350px] overflow-hidden flex flex-col min-w-[400px] animate-fade-in">
                                                    {/* Back to Master Categories */}
                                                    {!item.searchQuery && item.currentLevel !== 'master' && (
                                                        <div className="px-4 py-2 bg-slate-50 border-b flex items-center gap-2">
                                                            <button
                                                                type="button"
                                                                onClick={() => handleItemChange(index, 'currentLevel', 'master')}
