                                                                            className={`w-full text-left px-4 py-3 border-b border-slate-50 last:border-0 flex flex-col gap-0.5 transition-colors ${item.highlightedIndex === pIdx ? 'bg-brand-red/5' : 'hover:bg-slate-50'}`}
