                            </button>
                        </div>
                    </div>
                </div>
            </div >

            {/* Delivery Prompt Overlay */}
            {showDeliveryPrompt && (
                <div className="fixed inset-0 z-[10000] flex items-center justify-center p-4 bg-brand-charcoal/60 backdrop-blur-sm animate-fade-in">
