import { supabase } from '../lib/supabase';
import { useBranch } from '../lib/BranchContext';

export interface AuditLog {
    action: 'CREATE_SALE' | 'UPDATE_SALE' | 'DELETE_SALE' | 'CLOSE_DAY' | 'INV_ADJUST';
    table_name: string;
    record_id: string;
    old_data?: any;
    new_data?: any;
}

export function useAudit() {
    const { activeBranchId } = useBranch();
    const logAction = async (log: AuditLog) => {
        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return;

            const { error } = await supabase.from('audit_logs').insert({
                user_id: user.id,
                action: log.action,
                table_name: log.table_name,
                record_id: log.record_id,
                old_data: log.old_data,
                new_data: log.new_data,
                branch_id: activeBranchId
            });

            if (error) {
                console.error('Audit log failed:', error);
            }
        } catch (err) {
            console.error('Audit hook error:', err);
        }
    };

    return { logAction };
}

import React, { useEffect, useState } from 'react';
import { supabase } from './supabase';
import type { Session, User } from '@supabase/supabase-js';

import { AuthContext } from './AuthContextExports';
import type { AuthContextType } from './AuthContextExports';

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [session, setSession] = useState<Session | null>(null);
    const [user, setUser] = useState<User | null>(null);
    const [role, setRole] = useState<'owner' | 'admin' | 'encoder' | null>(null);
    const [branchId, setBranchId] = useState<string | null>(null);
    const [displayName, setDisplayName] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        let mounted = true;

        // Safety timeout to ensure loading screen eventually clears
        const timer = setTimeout(() => {
            if (mounted && loading) {
                console.warn('Auth loading timed out, forcing completion');
                setLoading(false);
            }
        }, 5000);

        const handleAuthAction = async (currSession: Session | null) => {
            if (!mounted) return;

            const currUser = currSession?.user ?? null;
            setSession(currSession);
            setUser(currUser);

            if (currUser) {
                try {
                    const { data, error } = await supabase
                        .from('profiles')
                        .select('role, branch_id, display_name')
                        .eq('id', currUser.id)
                        .maybeSingle();

                    if (mounted) {
                        if (error) {
                            console.error('Error fetching profile:', error);
                            setRole('encoder');
                            setBranchId(null);
                            setDisplayName(currUser.email?.split('@')[0] || 'User');
                        } else {
                            setRole(data?.role as 'owner' | 'admin' | 'encoder' ?? 'encoder');
                            setBranchId(data?.branch_id || null);
                            setDisplayName(data?.display_name || currUser.email?.split('@')[0] || 'User');
                        }
                    }
                } catch {
                    if (mounted) {
                        setRole('encoder');
                        setBranchId(null);
                    }
                } finally {
                    if (mounted) setLoading(false);
                }
            } else {
                if (mounted) {
                    setRole(null);
                    setBranchId(null);
                    setDisplayName(null);
                    setLoading(false);
                }
            }
        };

        // Get initial session
        supabase.auth.getSession().then(({ data: { session: initialSession } }) => {
            handleAuthAction(initialSession);
        }).catch(() => {
            if (mounted) setLoading(false);
        });

        // Listen for changes
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            handleAuthAction(session);
        });

        return () => {
            mounted = false;
            clearTimeout(timer);
            subscription.unsubscribe();
        };
    }, []); // Removed loading dependency to prevent infinite loops if loading changes

    const signOut = async () => {
        await supabase.auth.signOut();
        localStorage.removeItem('emc-active-branch'); // Clear active branch on logout as per SOP
    };

    const value: AuthContextType = {
        session,
        user,
        role,
        branchId,
        displayName,
        loading,
        signOut,
    };

    return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

